// ---------------------------------------------------------------------------
// BitSet - Efficient dirty tracking
// ---------------------------------------------------------------------------

/// Compact bitset for tracking dirty instances.
///
/// Uses 64-bit words for efficient bulk operations and iteration.
/// Designed for tracking which TLAS instances need updates.
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::BitSet;
///
/// let mut dirty = BitSet::new(1000);
/// dirty.set(42);
/// dirty.set(100);
/// assert!(dirty.test(42));
/// assert_eq!(dirty.count_set(), 2);
///
/// for idx in dirty.iter_set() {
///     println!("Dirty instance: {}", idx);
/// }
/// ```
#[derive(Debug, Clone)]
pub struct BitSet {
    /// Storage words (64 bits each).
    bits: Vec<u64>,
    /// Logical capacity (number of bits).
    len: usize,
    /// Cached count of set bits (updated lazily).
    cached_count: Option<usize>,
}

impl BitSet {
    /// Create a new bitset with the specified capacity.
    ///
    /// All bits are initially clear.
    ///
    /// # Arguments
    ///
    /// * `capacity` - Maximum number of bits
    pub fn new(capacity: usize) -> Self {
        let word_count = (capacity + 63) / 64;
        Self {
            bits: vec![0u64; word_count],
            len: capacity,
            cached_count: Some(0),
        }
    }

    /// Get the capacity of the bitset.
    #[inline]
    pub fn capacity(&self) -> usize {
        self.len
    }

    /// Set a bit at the specified index.
    ///
    /// # Panics
    ///
    /// Panics if `index >= capacity`.
    #[inline]
    pub fn set(&mut self, index: usize) {
        assert!(index < self.len, "BitSet index {} out of bounds (len={})", index, self.len);
        let word_idx = index / 64;
        let bit_idx = index % 64;
        let was_set = (self.bits[word_idx] >> bit_idx) & 1 != 0;
        self.bits[word_idx] |= 1u64 << bit_idx;
        if !was_set {
            self.cached_count = self.cached_count.map(|c| c + 1);
        }
    }

    /// Clear a bit at the specified index.
    ///
    /// # Panics
    ///
    /// Panics if `index >= capacity`.
    #[inline]
    pub fn clear(&mut self, index: usize) {
        assert!(index < self.len, "BitSet index {} out of bounds (len={})", index, self.len);
        let word_idx = index / 64;
        let bit_idx = index % 64;
        let was_set = (self.bits[word_idx] >> bit_idx) & 1 != 0;
        self.bits[word_idx] &= !(1u64 << bit_idx);
        if was_set {
            self.cached_count = self.cached_count.map(|c| c.saturating_sub(1));
        }
    }

    /// Test if a bit is set at the specified index.
    ///
    /// # Panics
    ///
    /// Panics if `index >= capacity`.
    #[inline]
    pub fn test(&self, index: usize) -> bool {
        assert!(index < self.len, "BitSet index {} out of bounds (len={})", index, self.len);
        let word_idx = index / 64;
        let bit_idx = index % 64;
        (self.bits[word_idx] >> bit_idx) & 1 != 0
    }

    /// Count the number of set bits.
    ///
    /// This operation is O(n/64) where n is the capacity.
    pub fn count_set(&mut self) -> usize {
        if let Some(count) = self.cached_count {
            return count;
        }
        let count = self.bits.iter().map(|w| w.count_ones() as usize).sum();
        self.cached_count = Some(count);
        count
    }

    /// Check if any bits are set.
    #[inline]
    pub fn any_set(&self) -> bool {
        self.bits.iter().any(|&w| w != 0)
    }

    /// Check if no bits are set.
    #[inline]
    pub fn none_set(&self) -> bool {
        !self.any_set()
    }

    /// Clear all bits.
    pub fn clear_all(&mut self) {
        self.bits.fill(0);
        self.cached_count = Some(0);
    }

    /// Set all bits.
    pub fn set_all(&mut self) {
        self.bits.fill(!0u64);
        // Mask out bits beyond capacity in the last word
        let remainder = self.len % 64;
        if remainder > 0 && !self.bits.is_empty() {
            let last_idx = self.bits.len() - 1;
            self.bits[last_idx] = (1u64 << remainder) - 1;
        }
        self.cached_count = Some(self.len);
    }

    /// Iterate over indices of set bits.
    ///
    /// Returns indices in ascending order.
    pub fn iter_set(&self) -> BitSetIterator<'_> {
        BitSetIterator {
            bitset: self,
            word_idx: 0,
            current_word: if self.bits.is_empty() { 0 } else { self.bits[0] },
            base_idx: 0,
        }
    }

    /// Get the underlying word storage (for serialization/debugging).
    #[inline]
    pub fn words(&self) -> &[u64] {
        &self.bits
    }
}

/// Iterator over set bits in a BitSet.
pub struct BitSetIterator<'a> {
    bitset: &'a BitSet,
    word_idx: usize,
    current_word: u64,
    base_idx: usize,
}

impl<'a> Iterator for BitSetIterator<'a> {
    type Item = usize;

    fn next(&mut self) -> Option<Self::Item> {
        // Skip empty words
        while self.current_word == 0 {
            self.word_idx += 1;
            if self.word_idx >= self.bitset.bits.len() {
                return None;
            }
            self.current_word = self.bitset.bits[self.word_idx];
            self.base_idx = self.word_idx * 64;
        }

        // Find lowest set bit
        let bit_pos = self.current_word.trailing_zeros() as usize;
        let index = self.base_idx + bit_pos;

        // Clear this bit for next iteration
        self.current_word &= self.current_word - 1;

        // Check bounds
        if index < self.bitset.len {
            Some(index)
        } else {
            None
        }
    }
}

// ---------------------------------------------------------------------------
// RebuildStrategy - Determines how to update TLAS
// ---------------------------------------------------------------------------

/// Strategy for TLAS rebuild/update based on dirty tracking.
///
/// The frame manager uses this to determine the optimal approach
/// for updating the TLAS each frame.
#[derive(Debug, Clone)]
pub enum RebuildStrategy {
    /// No instances changed; skip TLAS update entirely.
    Skip,

    /// Partial update - only rebuild affected instances.
    ///
    /// Used when a small percentage of instances changed
    /// and the TLAS was built with ALLOW_UPDATE.
    Update {
        /// Indices of dirty instances.
        indices: Vec<u32>,
    },

    /// Full rebuild of the TLAS.
    ///
    /// Used when:
    /// - Many instances changed (above threshold)
    /// - TLAS was not built with ALLOW_UPDATE
    /// - Structural changes occurred (instance count changed)
    FullRebuild {
        /// Human-readable reason for full rebuild.
        reason: String,
    },
}

impl RebuildStrategy {
    /// Check if this strategy requires any GPU work.
    #[inline]
    pub fn requires_update(&self) -> bool {
        !matches!(self, Self::Skip)
    }

    /// Check if this is a full rebuild.
    #[inline]
    pub fn is_full_rebuild(&self) -> bool {
        matches!(self, Self::FullRebuild { .. })
    }

    /// Get the number of dirty instances (0 for Skip, count for Update/FullRebuild).
    pub fn dirty_count(&self) -> usize {
        match self {
            Self::Skip => 0,
            Self::Update { indices } => indices.len(),
            Self::FullRebuild { .. } => 0, // Not applicable for full rebuild
        }
    }
}

impl std::fmt::Display for RebuildStrategy {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Skip => write!(f, "Skip (no changes)"),
            Self::Update { indices } => write!(f, "Update ({} instances)", indices.len()),
            Self::FullRebuild { reason } => write!(f, "FullRebuild: {}", reason),
        }
    }
}

// ---------------------------------------------------------------------------
// TlasUpdateStats - Performance statistics
// ---------------------------------------------------------------------------

/// Statistics from a TLAS update operation.
///
/// Used for profiling and performance monitoring.
#[derive(Debug, Clone)]
pub struct TlasUpdateStats {
    /// The strategy that was used.
    pub strategy: RebuildStrategy,

    /// Number of dirty instances.
    pub dirty_count: u32,

    /// Total number of instances in the TLAS.
    pub total_instances: u32,

    /// Time spent on the update operation in microseconds.
    pub update_time_us: u64,

    /// Frame number when this update occurred.
    pub frame_number: u64,

    /// Which buffer was written to (0 or 1).
    pub buffer_index: u8,
}

impl TlasUpdateStats {
    /// Calculate the dirty ratio (0.0 to 1.0).
    #[inline]
    pub fn dirty_ratio(&self) -> f32 {
        if self.total_instances == 0 {
            0.0
        } else {
            self.dirty_count as f32 / self.total_instances as f32
        }
    }
}

// ---------------------------------------------------------------------------
// TlasFrameManager - Per-frame TLAS management with double buffering
// ---------------------------------------------------------------------------

/// Per-frame TLAS manager with double buffering and dirty tracking.
///
/// This struct manages two TLAS buffers for ping-pong rendering,
/// tracks which instances have changed, and determines the optimal
/// rebuild strategy each frame.
///
/// # Double Buffering
///
/// Two TLAS buffers are maintained:
/// - `current`: The TLAS being used for rendering this frame
/// - `previous`: The TLAS from the last frame (for temporal effects)
///
/// Each frame, the buffers are swapped, and only dirty instances
/// are updated.
///
/// # Dirty Tracking
///
/// The manager tracks which instances have been modified since
/// the last update using a compact bitset. This enables:
/// - Skipping updates when nothing changed
/// - Partial updates for small changes
/// - Full rebuilds when many instances changed
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::{TlasFrameManager, TlasBuildFlags};
///
/// // Create manager for 1000 instances
/// let mut manager = TlasFrameManager::new(&device, 1000, TlasBuildFlags::default_dynamic())?;
///
/// // Each frame:
/// manager.begin_frame();
///
/// // Mark changed instances
/// manager.mark_dirty(42);
/// manager.mark_dirty(100);
///
/// // Determine strategy and update
/// let stats = manager.update(&device, &queue, &mut encoder, &instances, &mut scratch_pool)?;
/// println!("Update strategy: {}", stats.strategy);
///
/// // Use current TLAS for rendering
/// let tlas = manager.current();
///
/// manager.end_frame(frame_number);
/// ```
#[derive(Debug)]
pub struct TlasFrameManager {
    /// Double-buffered TLAS (ping-pong).
    buffers: [GpuTlas; 2],

    /// Current buffer index (0 or 1).
    current_frame: usize,

    /// Tracks which instances have been modified.
    dirty_instances: BitSet,

    /// Cached dirty count for strategy determination.
    dirty_count: u32,

    /// Threshold ratio for switching to full rebuild.
    /// Default: 0.3 (30% dirty triggers full rebuild).
    rebuild_threshold: f32,

    /// Frame number of last full rebuild.
    last_rebuild_frame: u64,

    /// Maximum instances this manager can handle.
    max_instances: u32,

    /// Build flags used for both buffers.
    flags: TlasBuildFlags,

    /// Statistics from the last update.
    last_stats: Option<TlasUpdateStats>,
}

impl TlasFrameManager {
    /// Default threshold for full rebuild (30% dirty).
    pub const DEFAULT_REBUILD_THRESHOLD: f32 = 0.3;

    /// Minimum dirty count before considering partial update.
    /// Below this, we always do partial updates (if supported).
    pub const MIN_PARTIAL_UPDATE_COUNT: u32 = 10;

    /// Create a new TLAS frame manager.
    ///
    /// Creates two TLAS buffers for double buffering.
    ///
    /// # Arguments
    ///
    /// * `device` - The wgpu device
    /// * `max_instances` - Maximum number of instances
    /// * `flags` - Build flags (should include ALLOW_UPDATE for partial updates)
    ///
    /// # Returns
    ///
    /// A new `TlasFrameManager` or an error if creation fails.
    pub fn new(
        device: &wgpu::Device,
        max_instances: u32,
        flags: TlasBuildFlags,
    ) -> Result<Self, TlasBuildError> {
        if max_instances == 0 {
            return Err(TlasBuildError::EmptyInstances);
        }

        // Create two TLAS buffers
        let build_sizes = TlasBuildSizes::estimate(max_instances, flags);

        let create_buffer = |idx: usize| -> (wgpu::Buffer, wgpu::Buffer) {
            let tlas_buffer = device.create_buffer(&wgpu::BufferDescriptor {
                label: Some(&format!("tlas_frame_{}", idx)),
                size: build_sizes.acceleration_structure_size,
                usage: wgpu::BufferUsages::STORAGE | wgpu::BufferUsages::COPY_SRC,
                mapped_at_creation: false,
            });

            let instance_buffer = device.create_buffer(&wgpu::BufferDescriptor {
                label: Some(&format!("tlas_instances_frame_{}", idx)),
                size: max_instances as u64 * TLAS_INSTANCE_SIZE as u64,
                usage: wgpu::BufferUsages::STORAGE | wgpu::BufferUsages::COPY_DST,
                mapped_at_creation: false,
            });

            (tlas_buffer, instance_buffer)
        };

        let (tlas0, instances0) = create_buffer(0);
        let (tlas1, instances1) = create_buffer(1);

        let buffer0 = GpuTlas {
            tlas_buffer: Arc::new(tlas0),
            instance_buffer: instances0,
            instance_count: 0,
            max_instances,
            build_sizes: build_sizes.clone(),
            flags,
        };

        let buffer1 = GpuTlas {
            tlas_buffer: Arc::new(tlas1),
            instance_buffer: instances1,
            instance_count: 0,
            max_instances,
            build_sizes,
            flags,
        };

        Ok(Self {
            buffers: [buffer0, buffer1],
            current_frame: 0,
            dirty_instances: BitSet::new(max_instances as usize),
            dirty_count: 0,
            rebuild_threshold: Self::DEFAULT_REBUILD_THRESHOLD,
            last_rebuild_frame: 0,
            max_instances,
            flags,
            last_stats: None,
        })
    }

    /// Get the current TLAS (for this frame's rendering).
    #[inline]
    pub fn current(&self) -> &GpuTlas {
        &self.buffers[self.current_frame]
    }

    /// Get the previous TLAS (from last frame, for temporal effects).
    #[inline]
    pub fn previous(&self) -> &GpuTlas {
        &self.buffers[1 - self.current_frame]
    }

    /// Get the current buffer index (0 or 1).
    #[inline]
    pub fn current_buffer_index(&self) -> usize {
        self.current_frame
    }

    /// Get the maximum instance count.
    #[inline]
    pub fn max_instances(&self) -> u32 {
        self.max_instances
    }

    /// Get the build flags.
    #[inline]
    pub fn flags(&self) -> TlasBuildFlags {
        self.flags
    }

    /// Get the rebuild threshold.
    #[inline]
    pub fn rebuild_threshold(&self) -> f32 {
        self.rebuild_threshold
    }

    /// Set the rebuild threshold.
    ///
    /// # Arguments
    ///
    /// * `threshold` - Ratio (0.0-1.0) of dirty instances that triggers full rebuild
    pub fn set_rebuild_threshold(&mut self, threshold: f32) {
        self.rebuild_threshold = threshold.clamp(0.0, 1.0);
    }

    /// Get the frame number of the last full rebuild.
    #[inline]
    pub fn last_rebuild_frame(&self) -> u64 {
        self.last_rebuild_frame
    }

    /// Get statistics from the last update.
    #[inline]
    pub fn last_stats(&self) -> Option<&TlasUpdateStats> {
        self.last_stats.as_ref()
    }

    /// Mark an instance as dirty (needs update).
    ///
    /// # Arguments
    ///
    /// * `instance_index` - Index of the modified instance
    ///
    /// # Panics
    ///
    /// Panics if the index exceeds max_instances.
    #[inline]
    pub fn mark_dirty(&mut self, instance_index: u32) {
        let idx = instance_index as usize;
        if !self.dirty_instances.test(idx) {
            self.dirty_instances.set(idx);
            self.dirty_count += 1;
        }
    }

    /// Mark all instances as dirty (forces full rebuild).
    pub fn mark_all_dirty(&mut self) {
        self.dirty_instances.set_all();
        self.dirty_count = self.max_instances;
    }

    /// Clear all dirty flags.
    pub fn clear_dirty(&mut self) {
        self.dirty_instances.clear_all();
        self.dirty_count = 0;
    }

    /// Get the current dirty count.
    #[inline]
    pub fn dirty_count(&self) -> u32 {
        self.dirty_count
    }

    /// Check if any instances are dirty.
    #[inline]
    pub fn has_dirty(&self) -> bool {
        self.dirty_count > 0
    }

    /// Determine the optimal rebuild strategy based on current state.
    ///
    /// # Returns
    ///
    /// The recommended `RebuildStrategy` for this frame.
    pub fn determine_strategy(&self) -> RebuildStrategy {
        // No changes - skip
        if self.dirty_count == 0 {
            return RebuildStrategy::Skip;
        }

        // Calculate dirty ratio
        let dirty_ratio = self.dirty_count as f32 / self.max_instances as f32;

        // Above threshold - full rebuild
        if dirty_ratio >= self.rebuild_threshold {
            return RebuildStrategy::FullRebuild {
                reason: format!(
                    "dirty ratio {:.1}% exceeds threshold {:.1}%",
                    dirty_ratio * 100.0,
                    self.rebuild_threshold * 100.0
                ),
            };
        }

        // Check if we can do partial updates
        if !self.flags.can_update() {
            return RebuildStrategy::FullRebuild {
                reason: "TLAS not built with ALLOW_UPDATE flag".to_string(),
            };
        }

        // Partial update - collect dirty indices
        let indices: Vec<u32> = self.dirty_instances.iter_set().map(|i| i as u32).collect();

        RebuildStrategy::Update { indices }
    }

    /// Begin a new frame.
    ///
    /// Swaps the double buffers. Call this at the start of each frame
    /// before making any changes.
    pub fn begin_frame(&mut self) {
        // Swap buffers
        self.current_frame = 1 - self.current_frame;
    }

    /// End the current frame.
    ///
    /// Records the frame number and clears dirty tracking for the next frame.
    ///
    /// # Arguments
    ///
    /// * `frame_number` - The current frame number
    pub fn end_frame(&mut self, frame_number: u64) {
        // Clear dirty flags for next frame
        self.clear_dirty();

        // Update last rebuild frame if we did a full rebuild
        if let Some(stats) = &self.last_stats {
            if stats.strategy.is_full_rebuild() {
                self.last_rebuild_frame = frame_number;
            }
        }
    }

    /// Update the TLAS based on the determined strategy.
    ///
    /// This method:
    /// 1. Determines the optimal rebuild strategy
    /// 2. Uploads instance data to the current buffer
    /// 3. Triggers GPU TLAS build/update (when wgpu RT is available)
    ///
    /// # Arguments
    ///
    /// * `device` - The wgpu device
    /// * `queue` - The wgpu queue
    /// * `encoder` - Command encoder for recording build commands
    /// * `instances` - Current instance data
    /// * `scratch_pool` - Scratch buffer pool for temporary allocations
    ///
    /// # Returns
    ///
    /// Statistics about the update operation.
    ///
    /// # Errors
    ///
    /// Returns `TlasBuildError` if the update fails.
    pub fn update(
        &mut self,
        device: &wgpu::Device,
        queue: &wgpu::Queue,
        _encoder: &mut wgpu::CommandEncoder,
        instances: &[TlasInstance],
        scratch_pool: &mut ScratchBufferPool,
    ) -> Result<TlasUpdateStats, TlasBuildError> {
        let start_time = std::time::Instant::now();

        // Validate instance count
        if instances.len() > self.max_instances as usize {
            return Err(TlasBuildError::TooManyInstances {
                requested: instances.len() as u32,
                max: self.max_instances,
            });
        }

        // Determine strategy
        let strategy = self.determine_strategy();

        // Get current buffer
        let current = &mut self.buffers[self.current_frame];

        match &strategy {
            RebuildStrategy::Skip => {
                // Nothing to do
            }

            RebuildStrategy::Update { indices } => {
                // Partial update - upload only dirty instances
                for &idx in indices {
                    if (idx as usize) < instances.len() {
                        let offset = idx as u64 * TLAS_INSTANCE_SIZE as u64;
                        queue.write_buffer(
                            &current.instance_buffer,
                            offset,
                            instances[idx as usize].as_bytes(),
                        );
                    }
                }

                // Acquire scratch for update (if needed)
                if current.can_update() {
                    let _scratch = scratch_pool.acquire(device, current.build_sizes.update_scratch_size)?;
                    // NOTE: When wgpu RT API stabilizes:
                    // encoder.update_acceleration_structure(&current.tlas, &scratch);
                }

                current.instance_count = instances.len() as u32;
            }

            RebuildStrategy::FullRebuild { .. } => {
                // Full upload
                let instance_bytes: &[u8] = unsafe {
                    std::slice::from_raw_parts(
                        instances.as_ptr() as *const u8,
                        instances.len() * TLAS_INSTANCE_SIZE,
                    )
                };
                queue.write_buffer(&current.instance_buffer, 0, instance_bytes);

                // Acquire scratch for build
                let _scratch = scratch_pool.acquire(device, current.build_sizes.build_scratch_size)?;

                // NOTE: When wgpu RT API stabilizes:
                // encoder.build_acceleration_structures(&[], &[...]);

                current.instance_count = instances.len() as u32;
            }
        }

        let elapsed = start_time.elapsed();

        let stats = TlasUpdateStats {
            strategy,
            dirty_count: self.dirty_count,
            total_instances: self.max_instances,
            update_time_us: elapsed.as_micros() as u64,
            frame_number: 0, // Will be set by end_frame
            buffer_index: self.current_frame as u8,
        };

        self.last_stats = Some(stats.clone());

        Ok(stats)
    }

    /// Force a full rebuild on the next update.
    ///
    /// Useful when structural changes occur (instance count changed, etc).
    pub fn force_full_rebuild(&mut self) {
        self.mark_all_dirty();
    }

    /// Check if a specific instance is marked dirty.
    #[inline]
    pub fn is_dirty(&self, instance_index: u32) -> bool {
        self.dirty_instances.test(instance_index as usize)
    }

    /// Get an iterator over dirty instance indices.
    pub fn dirty_indices(&self) -> impl Iterator<Item = u32> + '_ {
        self.dirty_instances.iter_set().map(|i| i as u32)
    }
}

// === End T-WGPU-P5.4.3: TLAS Per-Frame Rebuild ===

// === T-WGPU-P5.4.4: Instance Culling Integration ===
// ---------------------------------------------------------------------------
// Culling integration for TLAS instance visibility with frustum/occlusion
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// CullingConfig - Configuration for instance culling behavior
// ---------------------------------------------------------------------------

/// Configuration for TLAS instance culling.
///
/// Controls which culling techniques are enabled and their parameters.
/// Culling is performed before TLAS construction to reduce the number of
/// instances that need to be processed by the ray tracer.
///
/// # Culling Stages
///
/// 1. **Frustum Culling**: Removes instances outside the camera frustum
/// 2. **Screen Size Culling**: Removes instances that are too small to matter
/// 3. **Occlusion Culling**: Uses GPU visibility results to remove occluded instances
/// 4. **LOD Selection**: Chooses appropriate BLAS LOD based on distance/screen size
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::CullingConfig;
///
/// let config = CullingConfig::default()
///     .with_frustum_culling(true)
///     .with_occlusion_culling(true)
///     .with_lod(true)
///     .with_min_screen_percentage(0.001);
/// ```
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct CullingConfig {
    /// Enable frustum culling (cull instances outside camera view).
    pub frustum_culling_enabled: bool,

    /// Enable occlusion culling (use GPU visibility results).
    pub occlusion_culling_enabled: bool,

    /// Enable LOD selection based on distance/screen size.
    pub lod_enabled: bool,

    /// Minimum screen percentage before instance is culled (default 0.001 = 0.1%).
    /// Instances that would cover less than this percentage of screen are culled.
    pub min_screen_percentage: f32,
}

impl CullingConfig {
    /// Default minimum screen percentage (0.1%).
    pub const DEFAULT_MIN_SCREEN_PERCENTAGE: f32 = 0.001;

    /// Create a new culling config with all options disabled.
    pub const fn new() -> Self {
        Self {
            frustum_culling_enabled: false,
            occlusion_culling_enabled: false,
            lod_enabled: false,
            min_screen_percentage: Self::DEFAULT_MIN_SCREEN_PERCENTAGE,
        }
    }

    /// Enable or disable frustum culling.
    #[inline]
    pub const fn with_frustum_culling(mut self, enabled: bool) -> Self {
        self.frustum_culling_enabled = enabled;
        self
    }

    /// Enable or disable occlusion culling.
    #[inline]
    pub const fn with_occlusion_culling(mut self, enabled: bool) -> Self {
        self.occlusion_culling_enabled = enabled;
        self
    }

    /// Enable or disable LOD selection.
    #[inline]
    pub const fn with_lod(mut self, enabled: bool) -> Self {
        self.lod_enabled = enabled;
        self
    }

    /// Set the minimum screen percentage threshold.
    #[inline]
    pub const fn with_min_screen_percentage(mut self, percentage: f32) -> Self {
        self.min_screen_percentage = percentage;
        self
    }

    /// Create a configuration optimized for performance.
    /// Enables all culling techniques with aggressive screen size threshold.
    pub const fn for_performance() -> Self {
        Self {
            frustum_culling_enabled: true,
            occlusion_culling_enabled: true,
            lod_enabled: true,
            min_screen_percentage: 0.005, // 0.5% threshold
        }
    }

    /// Create a configuration optimized for quality.
    /// Enables frustum culling only with conservative threshold.
    pub const fn for_quality() -> Self {
        Self {
            frustum_culling_enabled: true,
            occlusion_culling_enabled: false,
            lod_enabled: true,
            min_screen_percentage: 0.0001, // 0.01% threshold
        }
    }

    /// Create a configuration with all culling disabled (useful for debugging).
    pub const fn disabled() -> Self {
        Self::new()
    }
}

impl Default for CullingConfig {
    fn default() -> Self {
        Self {
            frustum_culling_enabled: true,
            occlusion_culling_enabled: false,
            lod_enabled: true,
            min_screen_percentage: Self::DEFAULT_MIN_SCREEN_PERCENTAGE,
        }
    }
}

// ---------------------------------------------------------------------------
// BoundingSphere - Spherical bounding volume for culling
// ---------------------------------------------------------------------------

/// A bounding sphere for efficient culling tests.
///
/// Spheres are simpler than AABBs for frustum testing and provide
/// conservative bounds that work well with rotated geometry.
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::{BoundingSphere, Transform3x4};
///
/// let sphere = BoundingSphere::new([0.0, 0.0, 0.0], 5.0);
/// let transform = Transform3x4::from_translation(10.0, 0.0, 0.0);
/// let transformed = sphere.transform(&transform);
///
/// assert_eq!(transformed.center, [10.0, 0.0, 0.0]);
/// ```
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct BoundingSphere {
    /// Center point of the sphere in local space.
    pub center: [f32; 3],

    /// Radius of the sphere.
    pub radius: f32,
}

impl BoundingSphere {
    /// Create a new bounding sphere.
    #[inline]
    pub const fn new(center: [f32; 3], radius: f32) -> Self {
        Self { center, radius }
    }

    /// Create a bounding sphere at the origin with the given radius.
    #[inline]
    pub const fn from_radius(radius: f32) -> Self {
        Self {
            center: [0.0, 0.0, 0.0],
            radius,
        }
    }

    /// Create a bounding sphere from an axis-aligned bounding box.
    ///
    /// The resulting sphere fully contains the AABB but may be larger.
    pub fn from_aabb(aabb: &BoundingBox) -> Self {
        let center = aabb.center();
        let extents = aabb.extents();
        let radius =
            (extents[0] * extents[0] + extents[1] * extents[1] + extents[2] * extents[2]).sqrt();

        Self { center, radius }
    }

    /// Transform this bounding sphere by a 3x4 transformation matrix.
    ///
    /// The center is transformed as a point, and the radius is scaled by the
    /// maximum scale factor of the transform to ensure conservative bounds.
    pub fn transform(&self, transform: &Transform3x4) -> Self {
        // Transform the center
        let new_center = transform.transform_point(self.center);

        // Find the maximum scale factor to ensure the sphere still bounds the geometry
        // Extract scale from each row (magnitude of rotation/scale vectors)
        let scale_x = (transform.data[0][0] * transform.data[0][0]
            + transform.data[0][1] * transform.data[0][1]
            + transform.data[0][2] * transform.data[0][2])
        .sqrt();
        let scale_y = (transform.data[1][0] * transform.data[1][0]
            + transform.data[1][1] * transform.data[1][1]
            + transform.data[1][2] * transform.data[1][2])
        .sqrt();
        let scale_z = (transform.data[2][0] * transform.data[2][0]
            + transform.data[2][1] * transform.data[2][1]
            + transform.data[2][2] * transform.data[2][2])
        .sqrt();

        let max_scale = scale_x.max(scale_y).max(scale_z);
        let new_radius = self.radius * max_scale;

        Self {
            center: new_center,
            radius: new_radius,
        }
    }

    /// Check if this sphere is inside or intersects a frustum.
    ///
    /// Returns true if any part of the sphere is inside the frustum.
    #[inline]
    pub fn is_inside_frustum(&self, frustum: &Frustum) -> bool {
        frustum.contains_sphere(self)
    }

    /// Calculate the screen percentage this sphere would cover.
    ///
    /// Returns the approximate percentage of screen space (0.0 to 1.0) that
    /// this sphere would cover when viewed from the given position.
    ///
    /// # Arguments
    ///
    /// * `view_pos` - Camera/viewer position in world space
    /// * `fov_y` - Vertical field of view in radians
    /// * `aspect` - Aspect ratio (width / height)
    ///
    /// # Returns
    ///
    /// Screen percentage as a value between 0.0 and 1.0. Returns 1.0 if the
    /// viewer is inside the sphere.
    pub fn screen_percentage(&self, view_pos: [f32; 3], fov_y: f32, aspect: f32) -> f32 {
        // Calculate distance from view position to sphere center
        let dx = self.center[0] - view_pos[0];
        let dy = self.center[1] - view_pos[1];
        let dz = self.center[2] - view_pos[2];
        let distance_sq = dx * dx + dy * dy + dz * dz;
        let distance = distance_sq.sqrt();

        // If inside the sphere, it covers the whole screen
        if distance <= self.radius {
            return 1.0;
        }

        // Calculate angular diameter of the sphere
        let angular_radius = (self.radius / distance).asin();
        let angular_diameter = angular_radius * 2.0;

        // Calculate screen coverage
        // Vertical FOV in radians -> vertical screen angle
        let screen_angle_v = fov_y;
        let screen_angle_h = fov_y * aspect;

        // Sphere diameter as fraction of screen height
        let height_fraction = angular_diameter / screen_angle_v;
        let width_fraction = angular_diameter / screen_angle_h;

        // Approximate circular area coverage (pi * r^2 approximation)
        let radius_fraction = (height_fraction.min(width_fraction)) / 2.0;
        let area_fraction = std::f32::consts::PI * radius_fraction * radius_fraction;

        area_fraction.clamp(0.0, 1.0)
    }

    /// Calculate the distance from a point to this sphere's center.
    #[inline]
    pub fn distance_to(&self, point: [f32; 3]) -> f32 {
        let dx = self.center[0] - point[0];
        let dy = self.center[1] - point[1];
        let dz = self.center[2] - point[2];
        (dx * dx + dy * dy + dz * dz).sqrt()
    }

    /// Calculate the squared distance from a point to this sphere's center.
    #[inline]
    pub fn distance_sq_to(&self, point: [f32; 3]) -> f32 {
        let dx = self.center[0] - point[0];
        let dy = self.center[1] - point[1];
        let dz = self.center[2] - point[2];
        dx * dx + dy * dy + dz * dz
    }

    /// Check if this sphere intersects another sphere.
    #[inline]
    pub fn intersects(&self, other: &BoundingSphere) -> bool {
        let combined_radius = self.radius + other.radius;
        self.distance_sq_to(other.center) <= combined_radius * combined_radius
    }

    /// Merge this sphere with another to create a sphere that contains both.
    pub fn merge(&self, other: &BoundingSphere) -> BoundingSphere {
        let d = self.distance_to(other.center);

        // Check if one contains the other
        if d + other.radius <= self.radius {
            return *self;
        }
        if d + self.radius <= other.radius {
            return *other;
        }

        // Calculate new sphere
        let new_radius = (d + self.radius + other.radius) / 2.0;
        let t = (new_radius - self.radius) / d;

        let new_center = [
            self.center[0] + (other.center[0] - self.center[0]) * t,
            self.center[1] + (other.center[1] - self.center[1]) * t,
            self.center[2] + (other.center[2] - self.center[2]) * t,
        ];

        BoundingSphere {
            center: new_center,
            radius: new_radius,
        }
    }
}

impl Default for BoundingSphere {
    fn default() -> Self {
        Self {
            center: [0.0, 0.0, 0.0],
            radius: 1.0,
        }
    }
}

// ---------------------------------------------------------------------------
// Frustum - Camera frustum for visibility culling
// ---------------------------------------------------------------------------

/// A camera frustum defined by 6 planes for visibility testing.
///
/// The frustum is represented as 6 planes where each plane is defined by
/// a normal (xyz) and distance (w) in the form: `nx*x + ny*y + nz*z + d = 0`.
/// Points are inside the frustum if they are on the positive side of all planes.
///
/// # Plane Order
///
/// - 0: Left plane
/// - 1: Right plane
/// - 2: Bottom plane
/// - 3: Top plane
/// - 4: Near plane
/// - 5: Far plane
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::{Frustum, BoundingSphere};
///
/// // Create frustum from a view-projection matrix
/// let vp_matrix = calculate_view_projection();
/// let frustum = Frustum::from_view_projection(&vp_matrix);
///
/// // Test if a sphere is visible
/// let sphere = BoundingSphere::new([10.0, 0.0, -50.0], 5.0);
/// if frustum.contains_sphere(&sphere) {
///     println!("Sphere is visible!");
/// }
/// ```
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Frustum {
    /// The 6 frustum planes, each as [normal_x, normal_y, normal_z, distance].
    /// Planes are normalized so the normal has unit length.
    pub planes: [[f32; 4]; 6],
}

impl Frustum {
    /// Left plane index.
    pub const LEFT: usize = 0;
    /// Right plane index.
    pub const RIGHT: usize = 1;
    /// Bottom plane index.
    pub const BOTTOM: usize = 2;
    /// Top plane index.
    pub const TOP: usize = 3;
    /// Near plane index.
    pub const NEAR: usize = 4;
    /// Far plane index.
    pub const FAR: usize = 5;

    /// Create a frustum from a combined view-projection matrix.
    ///
    /// The matrix should be in row-major order (same as Transform3x4).
    /// Extracts planes using the Gribb/Hartmann method.
    ///
    /// # Arguments
    ///
    /// * `vp_matrix` - Combined view-projection matrix in row-major order
    pub fn from_view_projection(vp_matrix: &[[f32; 4]; 4]) -> Self {
        let m = vp_matrix;

        // Extract planes using Gribb/Hartmann method (row-major)
        // Left: row3 + row0
        // Right: row3 - row0
        // Bottom: row3 + row1
        // Top: row3 - row1
        // Near: row3 + row2 (or just row2 for DX-style)
        // Far: row3 - row2

        let planes = [
            // Left plane
            Self::normalize_plane([
                m[0][3] + m[0][0],
                m[1][3] + m[1][0],
                m[2][3] + m[2][0],
                m[3][3] + m[3][0],
            ]),
            // Right plane
            Self::normalize_plane([
                m[0][3] - m[0][0],
                m[1][3] - m[1][0],
                m[2][3] - m[2][0],
                m[3][3] - m[3][0],
            ]),
            // Bottom plane
            Self::normalize_plane([
                m[0][3] + m[0][1],
                m[1][3] + m[1][1],
                m[2][3] + m[2][1],
                m[3][3] + m[3][1],
            ]),
            // Top plane
            Self::normalize_plane([
                m[0][3] - m[0][1],
                m[1][3] - m[1][1],
                m[2][3] - m[2][1],
                m[3][3] - m[3][1],
            ]),
            // Near plane
            Self::normalize_plane([
                m[0][3] + m[0][2],
                m[1][3] + m[1][2],
                m[2][3] + m[2][2],
                m[3][3] + m[3][2],
            ]),
            // Far plane
            Self::normalize_plane([
                m[0][3] - m[0][2],
                m[1][3] - m[1][2],
                m[2][3] - m[2][2],
                m[3][3] - m[3][2],
            ]),
        ];

        Self { planes }
    }

    /// Create a frustum from a column-major view-projection matrix.
    ///
    /// Use this for matrices stored in column-major order (e.g., glam, cgmath).
    pub fn from_view_projection_column_major(vp_matrix: &[[f32; 4]; 4]) -> Self {
        // Transpose to row-major
        let m = [
            [vp_matrix[0][0], vp_matrix[1][0], vp_matrix[2][0], vp_matrix[3][0]],
            [vp_matrix[0][1], vp_matrix[1][1], vp_matrix[2][1], vp_matrix[3][1]],
            [vp_matrix[0][2], vp_matrix[1][2], vp_matrix[2][2], vp_matrix[3][2]],
            [vp_matrix[0][3], vp_matrix[1][3], vp_matrix[2][3], vp_matrix[3][3]],
        ];
        Self::from_view_projection(&m)
    }

    /// Normalize a plane so the normal has unit length.
    fn normalize_plane(plane: [f32; 4]) -> [f32; 4] {
        let len = (plane[0] * plane[0] + plane[1] * plane[1] + plane[2] * plane[2]).sqrt();
        if len < 1e-10 {
            return [0.0, 0.0, 1.0, 0.0]; // Degenerate plane fallback
        }
        let inv_len = 1.0 / len;
        [
            plane[0] * inv_len,
            plane[1] * inv_len,
            plane[2] * inv_len,
            plane[3] * inv_len,
        ]
    }

    /// Check if a point is inside the frustum.
    #[inline]
    pub fn contains_point(&self, point: [f32; 3]) -> bool {
        for plane in &self.planes {
            let dist = plane[0] * point[0] + plane[1] * point[1] + plane[2] * point[2] + plane[3];
            if dist < 0.0 {
                return false;
            }
        }
        true
    }

    /// Check if a bounding sphere is inside or intersects the frustum.
    ///
    /// Returns true if any part of the sphere is potentially visible.
    /// This is a conservative test - it may return true for some spheres
    /// that are actually outside the frustum (false positives), but will
    /// never return false for spheres that are inside (no false negatives).
    #[inline]
    pub fn contains_sphere(&self, sphere: &BoundingSphere) -> bool {
        for plane in &self.planes {
            let dist = plane[0] * sphere.center[0]
                + plane[1] * sphere.center[1]
                + plane[2] * sphere.center[2]
                + plane[3];

            // If the sphere is completely behind a plane, it's outside
            if dist < -sphere.radius {
                return false;
            }
        }
        true
    }

    /// Check if an axis-aligned bounding box is inside or intersects the frustum.
    #[inline]
    pub fn contains_aabb(&self, aabb: &BoundingBox) -> bool {
        for plane in &self.planes {
            // Find the positive vertex (the one most in the direction of the plane normal)
            let p = [
                if plane[0] >= 0.0 { aabb.max[0] } else { aabb.min[0] },
                if plane[1] >= 0.0 { aabb.max[1] } else { aabb.min[1] },
                if plane[2] >= 0.0 { aabb.max[2] } else { aabb.min[2] },
            ];

            let dist = plane[0] * p[0] + plane[1] * p[1] + plane[2] * p[2] + plane[3];
            if dist < 0.0 {
                return false;
            }
        }
        true
    }

    /// Get the signed distance from a point to a plane.
    ///
    /// Positive = in front of plane, negative = behind plane.
    #[inline]
    pub fn distance_to_plane(&self, plane_index: usize, point: [f32; 3]) -> f32 {
        let plane = &self.planes[plane_index];
        plane[0] * point[0] + plane[1] * point[1] + plane[2] * point[2] + plane[3]
    }
}

impl Default for Frustum {
    fn default() -> Self {
        // Default frustum that includes everything (all planes at infinity)
        Self {
            planes: [
                [-1.0, 0.0, 0.0, f32::MAX], // Left
                [1.0, 0.0, 0.0, f32::MAX],  // Right
                [0.0, -1.0, 0.0, f32::MAX], // Bottom
                [0.0, 1.0, 0.0, f32::MAX],  // Top
                [0.0, 0.0, -1.0, f32::MAX], // Near
                [0.0, 0.0, 1.0, f32::MAX],  // Far
            ],
        }
    }
}

// ---------------------------------------------------------------------------
// CullingStats - Statistics about culling operations
// ---------------------------------------------------------------------------

/// Statistics from a culling operation.
///
/// Provides insight into how many instances were culled by each technique,
/// useful for debugging and performance tuning.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct CullingStats {
    /// Total number of instances before culling.
    pub total_instances: u32,

    /// Number of instances that passed all culling tests.
    pub visible_count: u32,

    /// Number of instances culled by frustum test.
    pub frustum_culled: u32,

    /// Number of instances culled by occlusion test.
    pub occlusion_culled: u32,

    /// Number of instances culled by screen size threshold.
    pub screen_size_culled: u32,
}

impl CullingStats {
    /// Create empty culling statistics.
    pub const fn new() -> Self {
        Self {
            total_instances: 0,
            visible_count: 0,
            frustum_culled: 0,
            occlusion_culled: 0,
            screen_size_culled: 0,
        }
    }

    /// Calculate the total number of culled instances.
    #[inline]
    pub fn total_culled(&self) -> u32 {
        self.frustum_culled + self.occlusion_culled + self.screen_size_culled
    }

    /// Calculate the culling efficiency (percentage of instances culled).
    #[inline]
    pub fn culling_efficiency(&self) -> f32 {
        if self.total_instances == 0 {
            return 0.0;
        }
        (self.total_culled() as f32 / self.total_instances as f32) * 100.0
    }

    /// Calculate the visibility ratio (percentage of instances visible).
    #[inline]
    pub fn visibility_ratio(&self) -> f32 {
        if self.total_instances == 0 {
            return 0.0;
        }
        (self.visible_count as f32 / self.total_instances as f32) * 100.0
    }
}

// ---------------------------------------------------------------------------
// CullingResult - Result of culling operation
// ---------------------------------------------------------------------------

/// Result of an instance culling operation.
///
/// Contains the indices of visible instances, their selected LOD levels,
/// and statistics about the culling operation.
#[derive(Debug, Clone, Default)]
pub struct CullingResult {
    /// Indices of instances that passed all culling tests.
    pub visible_indices: Vec<u32>,

    /// Selected LOD level for each visible instance.
    /// Index corresponds to `visible_indices`.
    /// LOD 0 is highest detail, higher values are lower detail.
    pub selected_lods: Vec<u8>,

    /// Statistics from the culling operation.
    pub stats: CullingStats,
}

impl CullingResult {
    /// Create a new empty culling result.
    pub fn new() -> Self {
        Self {
            visible_indices: Vec::new(),
            selected_lods: Vec::new(),
            stats: CullingStats::new(),
        }
    }

    /// Create a culling result with pre-allocated capacity.
    pub fn with_capacity(capacity: usize) -> Self {
        Self {
            visible_indices: Vec::with_capacity(capacity),
            selected_lods: Vec::with_capacity(capacity),
            stats: CullingStats::new(),
        }
    }

    /// Get the number of visible instances.
    #[inline]
    pub fn visible_count(&self) -> usize {
        self.visible_indices.len()
    }

    /// Check if any instances are visible.
    #[inline]
    pub fn has_visible(&self) -> bool {
        !self.visible_indices.is_empty()
    }

    /// Iterate over visible instances with their LOD levels.
    pub fn iter(&self) -> impl Iterator<Item = (u32, u8)> + '_ {
        self.visible_indices
            .iter()
            .copied()
            .zip(self.selected_lods.iter().copied())
    }

    /// Clear the result for reuse.
    pub fn clear(&mut self) {
        self.visible_indices.clear();
        self.selected_lods.clear();
        self.stats = CullingStats::new();
    }
}

// ---------------------------------------------------------------------------
// TlasInstanceCuller - Main culling system
// ---------------------------------------------------------------------------

/// Maximum number of LOD levels supported.
pub const MAX_LOD_LEVELS: usize = 4;

/// TLAS instance culler for frustum and occlusion culling.
///
/// The culler maintains per-instance bounding spheres, LOD distances, and
/// visibility results. It performs multi-stage culling to reduce the number
/// of instances that need to be processed by the ray tracer.
///
/// # Culling Pipeline
///
/// 1. **Frustum Culling**: Test bounding sphere against camera frustum
/// 2. **Screen Size Culling**: Skip instances smaller than threshold
/// 3. **Occlusion Culling**: Use GPU visibility results (if enabled)
/// 4. **LOD Selection**: Choose appropriate BLAS LOD based on distance
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::{
///     TlasInstanceCuller, CullingConfig, BoundingSphere, Frustum
/// };
///
/// let config = CullingConfig::default();
/// let mut culler = TlasInstanceCuller::new(config, 1000);
///
/// // Set bounds for each instance
/// culler.set_instance_bounds(0, BoundingSphere::new([0.0, 0.0, -10.0], 5.0));
/// culler.set_instance_bounds(1, BoundingSphere::new([50.0, 0.0, -10.0], 2.0));
///
/// // Perform culling
/// let result = culler.cull(
///     &frustum,
///     [0.0, 0.0, 0.0],  // Camera position
///     std::f32::consts::FRAC_PI_4,  // 45 degree FOV
///     16.0 / 9.0,  // Aspect ratio
/// );
///
/// println!("Visible: {} / {}", result.visible_count(), result.stats.total_instances);
/// ```
#[derive(Debug, Clone)]
pub struct TlasInstanceCuller {
    /// Culling configuration.
    config: CullingConfig,

    /// Per-instance bounding spheres (in local space).
    bounds: Vec<BoundingSphere>,

    /// LOD switch distances for each instance.
    /// `lod_distances[i]` contains distances at which to switch LODs.
    /// `lod_distances[i][0]` is distance for LOD 1 (LOD 0 used before this).
    lod_distances: Vec<[f32; MAX_LOD_LEVELS]>,

    /// GPU occlusion query results (visibility flags).
    /// Bit N is set if instance N was visible in the previous frame.
    visibility_results: Vec<u32>,

    /// Maximum number of instances this culler supports.
    max_instances: u32,

    /// Number of actively tracked instances.
    active_count: u32,
}

impl TlasInstanceCuller {
    /// Create a new instance culler with the given configuration and capacity.
    ///
    /// # Arguments
    ///
    /// * `config` - Culling configuration
    /// * `max_instances` - Maximum number of instances to support
    pub fn new(config: CullingConfig, max_instances: u32) -> Self {
        let capacity = max_instances as usize;
        Self {
            config,
            bounds: vec![BoundingSphere::default(); capacity],
            lod_distances: vec![[f32::MAX; MAX_LOD_LEVELS]; capacity],
            visibility_results: vec![0xFFFFFFFF; (capacity + 31) / 32], // All visible initially
            max_instances,
            active_count: 0,
        }
    }

    /// Get the current culling configuration.
    #[inline]
    pub fn config(&self) -> &CullingConfig {
        &self.config
    }

    /// Set the culling configuration.
    #[inline]
    pub fn set_config(&mut self, config: CullingConfig) {
        self.config = config;
    }

    /// Get the maximum number of instances supported.
    #[inline]
    pub fn max_instances(&self) -> u32 {
        self.max_instances
    }

    /// Get the number of active instances being tracked.
    #[inline]
    pub fn active_count(&self) -> u32 {
        self.active_count
    }

    /// Set the number of active instances.
    ///
    /// # Panics
    ///
    /// Panics if count exceeds max_instances.
    pub fn set_active_count(&mut self, count: u32) {
        assert!(count <= self.max_instances, "count exceeds max_instances");
        self.active_count = count;
    }

    /// Set the bounding sphere for an instance.
    ///
    /// # Arguments
    ///
    /// * `index` - Instance index
    /// * `sphere` - Bounding sphere in local space
    pub fn set_instance_bounds(&mut self, index: u32, sphere: BoundingSphere) {
        if (index as usize) < self.bounds.len() {
            self.bounds[index as usize] = sphere;
            if index >= self.active_count {
                self.active_count = index + 1;
            }
        }
    }

    /// Get the bounding sphere for an instance.
    #[inline]
    pub fn get_instance_bounds(&self, index: u32) -> Option<&BoundingSphere> {
        self.bounds.get(index as usize)
    }

    /// Set the LOD switch distances for an instance.
    ///
    /// # Arguments
    ///
    /// * `index` - Instance index
    /// * `distances` - Distance thresholds for LOD switching.
    ///   `distances[0]` is where LOD 1 starts, etc.
    ///   Use `f32::MAX` for unused LOD levels.
    pub fn set_lod_distances(&mut self, index: u32, distances: [f32; MAX_LOD_LEVELS]) {
        if (index as usize) < self.lod_distances.len() {
            self.lod_distances[index as usize] = distances;
        }
    }

    /// Get the LOD distances for an instance.
    #[inline]
    pub fn get_lod_distances(&self, index: u32) -> Option<&[f32; MAX_LOD_LEVELS]> {
        self.lod_distances.get(index as usize)
    }

    /// Update visibility results from GPU occlusion queries.
    ///
    /// # Arguments
    ///
    /// * `results` - Packed visibility bits (bit N = instance N visible)
    pub fn update_visibility_results(&mut self, results: &[u32]) {
        let copy_len = results.len().min(self.visibility_results.len());
        self.visibility_results[..copy_len].copy_from_slice(&results[..copy_len]);
    }

    /// Check if an instance was visible in the previous frame.
    #[inline]
    pub fn was_visible(&self, index: u32) -> bool {
        let word_idx = (index / 32) as usize;
        let bit_idx = index % 32;
        if word_idx < self.visibility_results.len() {
            (self.visibility_results[word_idx] & (1 << bit_idx)) != 0
        } else {
            true // Assume visible if out of range
        }
    }

    /// Set an instance's visibility for occlusion culling.
    pub fn set_visibility(&mut self, index: u32, visible: bool) {
        let word_idx = (index / 32) as usize;
        let bit_idx = index % 32;
        if word_idx < self.visibility_results.len() {
            if visible {
                self.visibility_results[word_idx] |= 1 << bit_idx;
            } else {
                self.visibility_results[word_idx] &= !(1 << bit_idx);
            }
        }
    }

    /// Select the appropriate LOD level based on distance.
    fn select_lod(&self, index: u32, distance: f32) -> u8 {
        if !self.config.lod_enabled {
            return 0;
        }

        let distances = &self.lod_distances[index as usize];
        for (lod, &threshold) in distances.iter().enumerate() {
            if distance < threshold {
                return lod as u8;
            }
        }
        (MAX_LOD_LEVELS - 1) as u8
    }

    /// Perform culling on all active instances.
    ///
    /// # Arguments
    ///
    /// * `frustum` - Camera frustum for visibility testing
    /// * `view_position` - Camera position in world space
    /// * `fov_y` - Vertical field of view in radians
    /// * `aspect` - Aspect ratio (width / height)
    ///
    /// # Returns
    ///
    /// A `CullingResult` containing visible instance indices and their LOD levels.
    pub fn cull(
        &self,
        frustum: &Frustum,
        view_position: [f32; 3],
        fov_y: f32,
        aspect: f32,
    ) -> CullingResult {
        let count = self.active_count as usize;
        let mut result = CullingResult::with_capacity(count);
        result.stats.total_instances = self.active_count;

        for i in 0..count {
            let index = i as u32;
            let sphere = &self.bounds[i];

            // Stage 1: Frustum culling
            if self.config.frustum_culling_enabled && !frustum.contains_sphere(sphere) {
                result.stats.frustum_culled += 1;
                continue;
            }

            // Stage 2: Occlusion culling
            if self.config.occlusion_culling_enabled && !self.was_visible(index) {
                result.stats.occlusion_culled += 1;
                continue;
            }

            // Stage 3: Screen size culling
            let screen_pct = sphere.screen_percentage(view_position, fov_y, aspect);
            if screen_pct < self.config.min_screen_percentage {
                result.stats.screen_size_culled += 1;
                continue;
            }

            // Instance is visible - select LOD
            let distance = sphere.distance_to(view_position);
            let lod = self.select_lod(index, distance);

            result.visible_indices.push(index);
            result.selected_lods.push(lod);
        }

        result.stats.visible_count = result.visible_indices.len() as u32;
        result
    }

    /// Perform culling with transformed bounds.
    ///
    /// This version takes instance transforms and applies them to the local
    /// bounds before culling. Use this when instances have different transforms.
    ///
    /// # Arguments
    ///
    /// * `transforms` - Per-instance transforms (world transforms)
    /// * `frustum` - Camera frustum for visibility testing
    /// * `view_position` - Camera position in world space
    /// * `fov_y` - Vertical field of view in radians
    /// * `aspect` - Aspect ratio (width / height)
    pub fn cull_with_transforms(
        &self,
        transforms: &[Transform3x4],
        frustum: &Frustum,
        view_position: [f32; 3],
        fov_y: f32,
        aspect: f32,
    ) -> CullingResult {
        let count = (self.active_count as usize).min(transforms.len());
        let mut result = CullingResult::with_capacity(count);
        result.stats.total_instances = count as u32;

        for i in 0..count {
            let index = i as u32;
            let local_sphere = &self.bounds[i];
            let world_sphere = local_sphere.transform(&transforms[i]);

            // Stage 1: Frustum culling
            if self.config.frustum_culling_enabled && !frustum.contains_sphere(&world_sphere) {
                result.stats.frustum_culled += 1;
                continue;
            }

            // Stage 2: Occlusion culling
            if self.config.occlusion_culling_enabled && !self.was_visible(index) {
                result.stats.occlusion_culled += 1;
                continue;
            }

            // Stage 3: Screen size culling
            let screen_pct = world_sphere.screen_percentage(view_position, fov_y, aspect);
            if screen_pct < self.config.min_screen_percentage {
                result.stats.screen_size_culled += 1;
                continue;
            }

            // Instance is visible - select LOD based on distance
            let distance = world_sphere.distance_to(view_position);
            let lod = self.select_lod(index, distance);

            result.visible_indices.push(index);
            result.selected_lods.push(lod);
        }

        result.stats.visible_count = result.visible_indices.len() as u32;
        result
    }

    /// Reset the culler to its initial state.
    pub fn reset(&mut self) {
        for sphere in &mut self.bounds {
            *sphere = BoundingSphere::default();
        }
        for dist in &mut self.lod_distances {
            *dist = [f32::MAX; MAX_LOD_LEVELS];
        }
        for vis in &mut self.visibility_results {
            *vis = 0xFFFFFFFF;
        }
        self.active_count = 0;
    }
}

// === End T-WGPU-P5.4.4: Instance Culling Integration ===

// === T-WGPU-P5.5.1: AS Memory Manager ===

// ---------------------------------------------------------------------------
// AS Memory Manager Constants
// ---------------------------------------------------------------------------

/// Default alignment for AS allocations (256 bytes per wgpu requirement).
pub const AS_MEMORY_ALIGNMENT: u64 = 256;

/// Default initial pool size (64 MB).
pub const DEFAULT_INITIAL_POOL_SIZE: u64 = 64 * 1024 * 1024;

/// Default maximum pool size (256 MB).
pub const DEFAULT_MAX_POOL_SIZE: u64 = 256 * 1024 * 1024;

/// Default grow factor for pool resizing.
pub const DEFAULT_GROW_FACTOR: f32 = 1.5;

/// Default defragmentation threshold (30% fragmentation).
pub const DEFAULT_DEFRAG_THRESHOLD: f32 = 0.3;

// ---------------------------------------------------------------------------
// AsType
// ---------------------------------------------------------------------------

/// Type of acceleration structure allocation.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum AsType {
    /// Bottom-Level Acceleration Structure.
    Blas,
    /// Top-Level Acceleration Structure.
    Tlas,
}

impl AsType {
    /// Returns a human-readable name for this AS type.
    pub const fn name(&self) -> &'static str {
        match self {
            AsType::Blas => "BLAS",
            AsType::Tlas => "TLAS",
        }
    }
}

impl std::fmt::Display for AsType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.name())
    }
}

// ---------------------------------------------------------------------------
// AsAllocation
// ---------------------------------------------------------------------------

/// An allocation within the AS memory pool.
#[derive(Debug, Clone)]
pub struct AsAllocation {
    /// Offset within the pool buffer.
    pub offset: u64,
    /// Size of the allocation in bytes.
    pub size: u64,
    /// Type of acceleration structure (BLAS or TLAS).
    pub as_type: AsType,
    /// Unique allocation ID.
    pub id: u64,
}

impl AsAllocation {
    /// Create a new allocation.
    pub const fn new(offset: u64, size: u64, as_type: AsType, id: u64) -> Self {
        Self {
            offset,
            size,
            as_type,
            id,
        }
    }

    /// Returns the end offset of this allocation.
    #[inline]
    pub const fn end(&self) -> u64 {
        self.offset + self.size
    }

    /// Check if this allocation overlaps with another.
    pub const fn overlaps(&self, other: &AsAllocation) -> bool {
        self.offset < other.end() && other.offset < self.end()
    }
}

// ---------------------------------------------------------------------------
// FreeBlock
// ---------------------------------------------------------------------------

/// A free block within the memory pool.
#[derive(Debug, Clone, Copy)]
pub struct FreeBlock {
    /// Offset within the pool buffer.
    pub offset: u64,
    /// Size of the free block in bytes.
    pub size: u64,
}

impl FreeBlock {
    /// Create a new free block.
    pub const fn new(offset: u64, size: u64) -> Self {
        Self { offset, size }
    }

    /// Returns the end offset of this block.
    #[inline]
    pub const fn end(&self) -> u64 {
        self.offset + self.size
    }

    /// Check if this block can satisfy an allocation of the given size with alignment.
    pub const fn can_fit(&self, size: u64, alignment: u64) -> bool {
        let aligned_offset = (self.offset + alignment - 1) & !(alignment - 1);
        let padding = aligned_offset - self.offset;
        self.size >= size + padding
    }

    /// Calculate the aligned offset within this block.
    pub const fn aligned_offset(&self, alignment: u64) -> u64 {
        (self.offset + alignment - 1) & !(alignment - 1)
    }
}

// ---------------------------------------------------------------------------
// AsMemoryConfig
// ---------------------------------------------------------------------------

/// Configuration for the AS memory manager.
#[derive(Debug, Clone, Copy)]
pub struct AsMemoryConfig {
    /// Initial pool size in bytes (default 64MB).
    pub initial_pool_size: u64,
    /// Maximum pool size in bytes (default 256MB).
    pub max_pool_size: u64,
    /// Factor by which to grow pools (default 1.5).
    pub grow_factor: f32,
    /// Fragmentation threshold for triggering defragmentation (default 0.3 = 30%).
    pub defrag_threshold: f32,
    /// Minimum alignment for allocations (default 256 bytes).
    pub alignment: u64,
}

impl AsMemoryConfig {
    /// Create a new configuration with default values.
    pub const fn new() -> Self {
        Self {
            initial_pool_size: DEFAULT_INITIAL_POOL_SIZE,
            max_pool_size: DEFAULT_MAX_POOL_SIZE,
            grow_factor: DEFAULT_GROW_FACTOR,
            defrag_threshold: DEFAULT_DEFRAG_THRESHOLD,
            alignment: AS_MEMORY_ALIGNMENT,
        }
    }

    /// Set the initial pool size.
    pub const fn with_initial_pool_size(mut self, size: u64) -> Self {
        self.initial_pool_size = size;
        self
    }

    /// Set the maximum pool size.
    pub const fn with_max_pool_size(mut self, size: u64) -> Self {
        self.max_pool_size = size;
        self
    }

    /// Set the grow factor.
    pub const fn with_grow_factor(mut self, factor: f32) -> Self {
        self.grow_factor = factor;
        self
    }

    /// Set the defragmentation threshold.
    pub const fn with_defrag_threshold(mut self, threshold: f32) -> Self {
        self.defrag_threshold = threshold;
        self
    }

    /// Set the alignment.
    pub const fn with_alignment(mut self, alignment: u64) -> Self {
        self.alignment = alignment;
        self
    }

    /// Validate the configuration.
    pub fn validate(&self) -> Result<(), AsMemoryError> {
        if self.initial_pool_size == 0 {
            return Err(AsMemoryError::InvalidConfig(
                "initial_pool_size must be > 0".to_string(),
            ));
        }
        if self.max_pool_size < self.initial_pool_size {
            return Err(AsMemoryError::InvalidConfig(
                "max_pool_size must be >= initial_pool_size".to_string(),
            ));
        }
        if self.grow_factor <= 1.0 {
            return Err(AsMemoryError::InvalidConfig(
                "grow_factor must be > 1.0".to_string(),
            ));
        }
        if !(0.0..=1.0).contains(&self.defrag_threshold) {
            return Err(AsMemoryError::InvalidConfig(
                "defrag_threshold must be in [0.0, 1.0]".to_string(),
            ));
        }
        if self.alignment == 0 || !self.alignment.is_power_of_two() {
            return Err(AsMemoryError::InvalidConfig(
                "alignment must be a power of 2".to_string(),
            ));
        }
        Ok(())
    }
}

impl Default for AsMemoryConfig {
    fn default() -> Self {
        Self::new()
    }
}

// ---------------------------------------------------------------------------
// AsMemoryStats
// ---------------------------------------------------------------------------

/// Statistics about the AS memory manager.
#[derive(Debug, Clone, Default)]
pub struct AsMemoryStats {
    /// Total capacity across all pools in bytes.
    pub total_capacity: u64,
    /// Total allocated memory in bytes.
    pub total_allocated: u64,
    /// Total free memory in bytes.
    pub total_free: u64,
    /// Fragmentation ratio (0.0 = no fragmentation, 1.0 = fully fragmented).
    pub fragmentation_ratio: f32,
    /// Number of pools.
    pub pool_count: usize,
    /// Total number of allocations.
    pub allocation_count: usize,
    /// Number of BLAS allocations.
    pub blas_count: usize,
    /// Number of TLAS allocations.
    pub tlas_count: usize,
}

impl AsMemoryStats {
    /// Create new empty stats.
    pub const fn new() -> Self {
        Self {
            total_capacity: 0,
            total_allocated: 0,
            total_free: 0,
            fragmentation_ratio: 0.0,
            pool_count: 0,
            allocation_count: 0,
            blas_count: 0,
            tlas_count: 0,
        }
    }

    /// Returns the utilization percentage (allocated / capacity).
    pub fn utilization(&self) -> f32 {
        if self.total_capacity == 0 {
            0.0
        } else {
            (self.total_allocated as f32 / self.total_capacity as f32) * 100.0
        }
    }

    /// Returns the free percentage (free / capacity).
    pub fn free_percentage(&self) -> f32 {
        if self.total_capacity == 0 {
            100.0
        } else {
            (self.total_free as f32 / self.total_capacity as f32) * 100.0
        }
    }

    /// Check if defragmentation is recommended.
    pub fn needs_defrag(&self, threshold: f32) -> bool {
        self.fragmentation_ratio >= threshold
    }
}

impl std::fmt::Display for AsMemoryStats {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "AsMemoryStats {{ capacity: {} MB, allocated: {} MB ({:.1}%), \
             fragmentation: {:.1}%, pools: {}, allocations: {} (BLAS: {}, TLAS: {}) }}",
            self.total_capacity / (1024 * 1024),
            self.total_allocated / (1024 * 1024),
            self.utilization(),
            self.fragmentation_ratio * 100.0,
            self.pool_count,
            self.allocation_count,
            self.blas_count,
            self.tlas_count
        )
    }
}

// ---------------------------------------------------------------------------
// AsMemoryError
// ---------------------------------------------------------------------------

/// Errors that can occur during AS memory operations.
#[derive(Debug)]
pub enum AsMemoryError {
    /// Out of memory - no pool can satisfy the allocation.
    OutOfMemory { requested: u64, available: u64 },
    /// Allocation not found.
    AllocationNotFound(u64),
    /// Invalid pool index.
    InvalidPoolIndex(usize),
    /// Pool resize failed.
    PoolResizeFailed(String),
    /// Invalid configuration.
    InvalidConfig(String),
    /// Allocation too large for any single pool.
    AllocationTooLarge { requested: u64, max_pool_size: u64 },
    /// Buffer creation failed.
    BufferCreationFailed(String),
}

impl std::fmt::Display for AsMemoryError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::OutOfMemory {
                requested,
                available,
            } => {
                write!(
                    f,
                    "out of memory: requested {} bytes, only {} available",
                    requested, available
                )
            }
            Self::AllocationNotFound(id) => {
                write!(f, "allocation with id {} not found", id)
            }
            Self::InvalidPoolIndex(idx) => {
                write!(f, "invalid pool index: {}", idx)
            }
            Self::PoolResizeFailed(msg) => {
                write!(f, "pool resize failed: {}", msg)
            }
            Self::InvalidConfig(msg) => {
                write!(f, "invalid configuration: {}", msg)
            }
            Self::AllocationTooLarge {
                requested,
                max_pool_size,
            } => {
                write!(
                    f,
                    "allocation of {} bytes exceeds max pool size of {} bytes",
                    requested, max_pool_size
                )
            }
            Self::BufferCreationFailed(msg) => {
                write!(f, "buffer creation failed: {}", msg)
            }
        }
    }
}

impl std::error::Error for AsMemoryError {}

// ---------------------------------------------------------------------------
// AsMemoryPool
// ---------------------------------------------------------------------------

/// A single memory pool for AS allocations.
///
/// Uses a first-fit allocation strategy with coalescing of adjacent free blocks.
pub struct AsMemoryPool {
    /// The backing GPU buffer.
    buffer: wgpu::Buffer,
    /// Total capacity in bytes.
    capacity: u64,
    /// Currently allocated bytes.
    allocated: u64,
    /// Active allocations.
    allocations: Vec<AsAllocation>,
    /// Free blocks available for allocation.
    free_list: Vec<FreeBlock>,
    /// Minimum allocation alignment.
    alignment: u64,
    /// Pool index (for debugging).
    pool_index: usize,
}

impl AsMemoryPool {
    /// Create a new memory pool with the given capacity.
    pub fn new(
        device: &wgpu::Device,
        capacity: u64,
        alignment: u64,
        pool_index: usize,
    ) -> Result<Self, AsMemoryError> {
        let buffer = device.create_buffer(&wgpu::BufferDescriptor {
            label: Some(&format!("AS Memory Pool {}", pool_index)),
            size: capacity,
            usage: wgpu::BufferUsages::STORAGE
                | wgpu::BufferUsages::COPY_SRC
                | wgpu::BufferUsages::COPY_DST,
            mapped_at_creation: false,
        });

        Ok(Self {
            buffer,
            capacity,
            allocated: 0,
            allocations: Vec::new(),
            free_list: vec![FreeBlock::new(0, capacity)],
            alignment,
            pool_index,
        })
    }

    /// Get the backing buffer.
    #[inline]
    pub fn buffer(&self) -> &wgpu::Buffer {
        &self.buffer
    }

    /// Get the total capacity.
    #[inline]
    pub const fn capacity(&self) -> u64 {
        self.capacity
    }

    /// Get the currently allocated bytes.
    #[inline]
    pub const fn allocated(&self) -> u64 {
        self.allocated
    }

    /// Get the free space.
    #[inline]
    pub const fn free_space(&self) -> u64 {
        self.capacity - self.allocated
    }

    /// Get the number of allocations.
    #[inline]
    pub fn allocation_count(&self) -> usize {
        self.allocations.len()
    }

    /// Get the number of free blocks.
    #[inline]
    pub fn free_block_count(&self) -> usize {
        self.free_list.len()
    }

    /// Calculate fragmentation ratio.
    ///
    /// Fragmentation is measured as 1 - (largest_free_block / total_free).
    /// A value of 0.0 means no fragmentation (one contiguous free block).
    /// A value approaching 1.0 means highly fragmented.
    pub fn fragmentation_ratio(&self) -> f32 {
        let total_free = self.free_space();
        if total_free == 0 {
            return 0.0;
        }

        let largest_free = self
            .free_list
            .iter()
            .map(|b| b.size)
            .max()
            .unwrap_or(0);

        if largest_free == 0 {
            return 1.0;
        }

        1.0 - (largest_free as f32 / total_free as f32)
    }

    /// Try to allocate memory from this pool.
    ///
    /// Uses first-fit strategy for allocation.
    pub fn try_allocate(&mut self, size: u64, as_type: AsType, id: u64) -> Option<AsAllocation> {
        // Find a free block that can fit the allocation
        let block_index = self
            .free_list
            .iter()
            .position(|block| block.can_fit(size, self.alignment))?;

        let block = self.free_list[block_index];
        let aligned_offset = block.aligned_offset(self.alignment);
        let padding = aligned_offset - block.offset;

        // Create the allocation
        let allocation = AsAllocation::new(aligned_offset, size, as_type, id);

        // Update the free block or remove it
        let remaining_size = block.size - size - padding;
        if remaining_size >= self.alignment {
            // Split the block
            self.free_list[block_index] = FreeBlock::new(aligned_offset + size, remaining_size);

            // If there was padding at the start, add a free block for it
            if padding > 0 {
                self.free_list.push(FreeBlock::new(block.offset, padding));
            }
        } else {
            // Remove the block entirely (remaining space too small)
            self.free_list.swap_remove(block_index);
        }

        // Track allocation
        self.allocated += size;
        self.allocations.push(allocation.clone());

        Some(allocation)
    }

    /// Free an allocation by ID.
    pub fn free(&mut self, allocation_id: u64) -> Option<AsAllocation> {
        let alloc_index = self
            .allocations
            .iter()
            .position(|a| a.id == allocation_id)?;

        let allocation = self.allocations.swap_remove(alloc_index);
        self.allocated -= allocation.size;

        // Add back to free list
        let new_block = FreeBlock::new(allocation.offset, allocation.size);
        self.free_list.push(new_block);

        // Coalesce adjacent free blocks
        self.coalesce_free_blocks();

        Some(allocation)
    }

    /// Coalesce adjacent free blocks to reduce fragmentation.
    fn coalesce_free_blocks(&mut self) {
        if self.free_list.len() <= 1 {
            return;
        }

        // Sort by offset
        self.free_list.sort_by_key(|b| b.offset);

        // Merge adjacent blocks
        let mut merged = Vec::with_capacity(self.free_list.len());
        let mut current = self.free_list[0];

        for block in self.free_list.iter().skip(1) {
            if current.end() == block.offset {
                // Adjacent blocks - merge them
                current = FreeBlock::new(current.offset, current.size + block.size);
            } else {
                merged.push(current);
                current = *block;
            }
        }
        merged.push(current);

        self.free_list = merged;
    }

    /// Check if an allocation with the given ID exists in this pool.
    pub fn contains(&self, allocation_id: u64) -> bool {
        self.allocations.iter().any(|a| a.id == allocation_id)
    }

    /// Get an allocation by ID.
    pub fn get_allocation(&self, allocation_id: u64) -> Option<&AsAllocation> {
        self.allocations.iter().find(|a| a.id == allocation_id)
    }

    /// Get all allocations.
    pub fn allocations(&self) -> &[AsAllocation] {
        &self.allocations
    }

    /// Get all free blocks.
    pub fn free_blocks(&self) -> &[FreeBlock] {
        &self.free_list
    }

    /// Check if the pool can fit an allocation of the given size.
    pub fn can_fit(&self, size: u64) -> bool {
        self.free_list
            .iter()
            .any(|block| block.can_fit(size, self.alignment))
    }

    /// Get the largest contiguous free block size.
    pub fn largest_free_block(&self) -> u64 {
        self.free_list.iter().map(|b| b.size).max().unwrap_or(0)
    }
}

impl std::fmt::Debug for AsMemoryPool {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("AsMemoryPool")
            .field("pool_index", &self.pool_index)
            .field("capacity", &self.capacity)
            .field("allocated", &self.allocated)
            .field("allocation_count", &self.allocations.len())
            .field("free_block_count", &self.free_list.len())
            .field("fragmentation", &self.fragmentation_ratio())
            .finish()
    }
}

// ---------------------------------------------------------------------------
// AsMemoryManager
// ---------------------------------------------------------------------------

/// Manages memory for acceleration structures (BLAS/TLAS).
///
/// Provides pool-based allocation with automatic growth, defragmentation support,
/// and memory statistics tracking.
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::{AsMemoryManager, AsMemoryConfig, AsType};
///
/// let config = AsMemoryConfig::new()
///     .with_initial_pool_size(32 * 1024 * 1024)  // 32 MB
///     .with_max_pool_size(128 * 1024 * 1024);    // 128 MB max
///
/// let mut manager = AsMemoryManager::new(&device, config)?;
///
/// // Allocate memory for a BLAS
/// let allocation = manager.allocate(&device, 1024 * 1024, AsType::Blas)?;
/// println!("Allocated BLAS at offset {}", allocation.offset);
///
/// // Check memory status
/// let stats = manager.stats();
/// println!("Memory utilization: {:.1}%", stats.utilization());
///
/// // Free when done
/// manager.free(allocation.id);
/// ```
pub struct AsMemoryManager {
    /// Memory pools.
    pools: Vec<AsMemoryPool>,
    /// Next allocation ID.
    next_id: u64,
    /// Configuration.
    config: AsMemoryConfig,
    /// Cached statistics.
    stats: AsMemoryStats,
}

impl AsMemoryManager {
    /// Create a new AS memory manager with the given configuration.
    pub fn new(device: &wgpu::Device, config: AsMemoryConfig) -> Result<Self, AsMemoryError> {
        config.validate()?;

        // Create initial pool
        let initial_pool = AsMemoryPool::new(device, config.initial_pool_size, config.alignment, 0)?;

        let mut manager = Self {
            pools: vec![initial_pool],
            next_id: 0,
            config,
            stats: AsMemoryStats::new(),
        };

        manager.update_stats();
        Ok(manager)
    }

    /// Create a new AS memory manager with default configuration.
    pub fn with_defaults(device: &wgpu::Device) -> Result<Self, AsMemoryError> {
        Self::new(device, AsMemoryConfig::default())
    }

    /// Allocate memory for an acceleration structure.
    ///
    /// # Arguments
    ///
    /// * `device` - The wgpu device (needed if pool needs to grow)
    /// * `size` - Size in bytes to allocate
    /// * `as_type` - Type of AS (BLAS or TLAS)
    ///
    /// # Returns
    ///
    /// An `AsAllocation` on success.
    ///
    /// # Errors
    ///
    /// Returns error if:
    /// - Allocation size exceeds max pool size
    /// - Unable to allocate from any pool and cannot grow
    pub fn allocate(
        &mut self,
        device: &wgpu::Device,
        size: u64,
        as_type: AsType,
    ) -> Result<AsAllocation, AsMemoryError> {
        // Align the size
        let aligned_size = self.align_size(size);

        // Check if allocation is too large
        if aligned_size > self.config.max_pool_size {
            return Err(AsMemoryError::AllocationTooLarge {
                requested: aligned_size,
                max_pool_size: self.config.max_pool_size,
            });
        }

        // Generate allocation ID
        let id = self.next_id;
        self.next_id += 1;

        // Try to allocate from existing pools
        for pool in &mut self.pools {
            if let Some(allocation) = pool.try_allocate(aligned_size, as_type, id) {
                self.update_stats();
                return Ok(allocation);
            }
        }

        // No pool has space - try to create a new pool
        let new_pool_size = self.calculate_new_pool_size(aligned_size);
        let pool_index = self.pools.len();

        let mut new_pool =
            AsMemoryPool::new(device, new_pool_size, self.config.alignment, pool_index)?;

        let allocation = new_pool
            .try_allocate(aligned_size, as_type, id)
            .ok_or_else(|| AsMemoryError::OutOfMemory {
                requested: aligned_size,
                available: new_pool.free_space(),
            })?;

        self.pools.push(new_pool);
        self.update_stats();

        Ok(allocation)
    }

    /// Free an allocation by ID.
    ///
    /// # Arguments
    ///
    /// * `allocation_id` - The ID of the allocation to free
    pub fn free(&mut self, allocation_id: u64) {
        for pool in &mut self.pools {
            if pool.free(allocation_id).is_some() {
                self.update_stats();
                return;
            }
        }
    }

    /// Check if defragmentation is needed based on the configured threshold.
    pub fn needs_defragmentation(&self) -> bool {
        self.stats.fragmentation_ratio >= self.config.defrag_threshold
    }

    /// Perform defragmentation on all pools.
    ///
    /// This compacts allocations to reduce fragmentation. In a real implementation,
    /// this would use GPU copy operations to move data. For now, this is a CPU-side
    /// compaction that reorganizes the allocation metadata.
    ///
    /// # Note
    ///
    /// In practice, defragmenting AS memory requires rebuilding the acceleration
    /// structures since they contain internal pointers. This method prepares the
    /// compacted layout but actual data movement would require AS rebuild.
    pub fn defragment(
        &mut self,
        _device: &wgpu::Device,
        _encoder: &mut wgpu::CommandEncoder,
    ) {
        for pool in &mut self.pools {
            Self::defragment_pool_inner(pool);
        }
        self.update_stats();
    }

    /// Defragment a single pool (internal helper).
    fn defragment_pool_inner(pool: &mut AsMemoryPool) {
        if pool.allocations.is_empty() {
            // Reset to single free block
            pool.free_list.clear();
            pool.free_list.push(FreeBlock::new(0, pool.capacity));
            return;
        }

        // Sort allocations by offset
        pool.allocations.sort_by_key(|a| a.offset);

        // Compact allocations to the start of the pool
        let mut current_offset = 0u64;
        for allocation in &mut pool.allocations {
            let aligned_offset = (current_offset + pool.alignment - 1) & !(pool.alignment - 1);
            allocation.offset = aligned_offset;
            current_offset = aligned_offset + allocation.size;
        }

        // Rebuild free list with single contiguous block
        pool.free_list.clear();
        let remaining = pool.capacity - current_offset;
        if remaining > 0 {
            pool.free_list.push(FreeBlock::new(current_offset, remaining));
        }
    }

    /// Get current memory statistics.
    pub fn stats(&self) -> AsMemoryStats {
        self.stats.clone()
    }

    /// Resize a specific pool.
    ///
    /// Note: In a real implementation, this would require copying data to a new buffer.
    /// This simplified version only allows growing a pool that has no allocations.
    pub fn resize_pool(
        &mut self,
        device: &wgpu::Device,
        pool_index: usize,
        new_capacity: u64,
    ) -> Result<(), AsMemoryError> {
        if pool_index >= self.pools.len() {
            return Err(AsMemoryError::InvalidPoolIndex(pool_index));
        }

        let pool = &self.pools[pool_index];

        // For simplicity, only allow resize of empty pools
        if !pool.allocations.is_empty() {
            return Err(AsMemoryError::PoolResizeFailed(
                "cannot resize pool with active allocations".to_string(),
            ));
        }

        if new_capacity > self.config.max_pool_size {
            return Err(AsMemoryError::PoolResizeFailed(format!(
                "new capacity {} exceeds max pool size {}",
                new_capacity, self.config.max_pool_size
            )));
        }

        // Create new pool
        let new_pool = AsMemoryPool::new(device, new_capacity, self.config.alignment, pool_index)?;
        self.pools[pool_index] = new_pool;

        self.update_stats();
        Ok(())
    }

    /// Get the number of pools.
    #[inline]
    pub fn pool_count(&self) -> usize {
        self.pools.len()
    }

    /// Get a reference to a pool by index.
    pub fn pool(&self, index: usize) -> Option<&AsMemoryPool> {
        self.pools.get(index)
    }

    /// Get the configuration.
    #[inline]
    pub fn config(&self) -> &AsMemoryConfig {
        &self.config
    }

    /// Get an allocation by ID.
    pub fn get_allocation(&self, allocation_id: u64) -> Option<&AsAllocation> {
        for pool in &self.pools {
            if let Some(allocation) = pool.get_allocation(allocation_id) {
                return Some(allocation);
            }
        }
        None
    }

    /// Get the pool index containing an allocation.
    pub fn pool_for_allocation(&self, allocation_id: u64) -> Option<usize> {
        self.pools
            .iter()
            .position(|pool| pool.contains(allocation_id))
    }

    /// Align a size to the configured alignment.
    #[inline]
    fn align_size(&self, size: u64) -> u64 {
        (size + self.config.alignment - 1) & !(self.config.alignment - 1)
    }

    /// Calculate the size for a new pool.
    fn calculate_new_pool_size(&self, min_size: u64) -> u64 {
        // Start with initial pool size or grow from last pool
        let base_size = if self.pools.is_empty() {
            self.config.initial_pool_size
        } else {
            let last_pool_size = self.pools.last().map(|p| p.capacity).unwrap_or(0);
            (last_pool_size as f32 * self.config.grow_factor) as u64
        };

        // Ensure it can fit the requested allocation
        let size = base_size.max(min_size);

        // Cap at max pool size
        size.min(self.config.max_pool_size)
    }

    /// Update cached statistics.
    fn update_stats(&mut self) {
        let mut stats = AsMemoryStats::new();

        for pool in &self.pools {
            stats.total_capacity += pool.capacity;
            stats.total_allocated += pool.allocated;
            stats.allocation_count += pool.allocation_count();

            for alloc in pool.allocations() {
                match alloc.as_type {
                    AsType::Blas => stats.blas_count += 1,
                    AsType::Tlas => stats.tlas_count += 1,
                }
            }
        }

        stats.total_free = stats.total_capacity - stats.total_allocated;
        stats.pool_count = self.pools.len();

        // Calculate overall fragmentation as weighted average
        if stats.total_free > 0 {
            let mut weighted_frag = 0.0f32;
            for pool in &self.pools {
                let pool_free = pool.free_space();
                if pool_free > 0 {
                    weighted_frag +=
                        pool.fragmentation_ratio() * (pool_free as f32 / stats.total_free as f32);
                }
            }
            stats.fragmentation_ratio = weighted_frag;
        }

        self.stats = stats;
    }

    /// Trim empty pools to reduce memory usage.
    ///
    /// Removes pools that have no allocations, keeping at least one pool.
    pub fn trim_empty_pools(&mut self) {
        if self.pools.len() <= 1 {
            return;
        }

        // Keep first pool and any pool with allocations
        self.pools.retain(|pool| pool.allocation_count() > 0 || pool.pool_index == 0);

        // Renumber pools
        for (i, pool) in self.pools.iter_mut().enumerate() {
            pool.pool_index = i;
        }

        self.update_stats();
    }

    /// Get total capacity across all pools.
    pub fn total_capacity(&self) -> u64 {
        self.stats.total_capacity
    }

    /// Get total allocated memory across all pools.
    pub fn total_allocated(&self) -> u64 {
        self.stats.total_allocated
    }

    /// Get total free memory across all pools.
    pub fn total_free(&self) -> u64 {
        self.stats.total_free
    }
}

impl std::fmt::Debug for AsMemoryManager {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("AsMemoryManager")
            .field("pool_count", &self.pools.len())
            .field("next_id", &self.next_id)
            .field("config", &self.config)
            .field("stats", &self.stats)
            .finish()
    }
}

// === End T-WGPU-P5.5.1: AS Memory Manager ===

// === T-WGPU-P5.5.2: AS Memory Budget ===

// ---------------------------------------------------------------------------
// Budget Constants
// ---------------------------------------------------------------------------

/// Default soft limit ratio (warn at 80% usage).
pub const DEFAULT_SOFT_LIMIT_RATIO: f32 = 0.8;

/// Default maximum warnings to retain in history.
pub const DEFAULT_MAX_WARNINGS: usize = 100;

// ---------------------------------------------------------------------------
// BudgetEnforcement
// ---------------------------------------------------------------------------

/// How budget limits are enforced.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
pub enum BudgetEnforcement {
    /// No enforcement, tracking only.
    #[default]
    None,
    /// Log warnings but allow allocations.
    Warn,
    /// Deny new allocations when over budget.
    Soft,
    /// Deny new allocations and trigger eviction/compaction.
    Hard,
}

impl BudgetEnforcement {
    /// Returns a human-readable name for this enforcement mode.
    pub const fn name(&self) -> &'static str {
        match self {
            BudgetEnforcement::None => "None",
            BudgetEnforcement::Warn => "Warn",
            BudgetEnforcement::Soft => "Soft",
            BudgetEnforcement::Hard => "Hard",
        }
    }

    /// Check if this mode enforces limits (denies allocations).
    pub const fn enforces_limits(&self) -> bool {
        matches!(self, BudgetEnforcement::Soft | BudgetEnforcement::Hard)
    }

    /// Check if this mode triggers auto-eviction.
    pub const fn triggers_eviction(&self) -> bool {
        matches!(self, BudgetEnforcement::Hard)
    }
}

impl std::fmt::Display for BudgetEnforcement {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.name())
    }
}

// ---------------------------------------------------------------------------
// BudgetWarningType
// ---------------------------------------------------------------------------

/// Type of budget warning.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum BudgetWarningType {
    /// Usage crossed the soft_limit_ratio threshold.
    ApproachingLimit,
    /// Usage is at or very near the limit.
    AtLimit,
    /// Allocation would exceed the budget.
    OverBudget,
}

impl BudgetWarningType {
    /// Returns a human-readable name for this warning type.
    pub const fn name(&self) -> &'static str {
        match self {
            BudgetWarningType::ApproachingLimit => "ApproachingLimit",
            BudgetWarningType::AtLimit => "AtLimit",
            BudgetWarningType::OverBudget => "OverBudget",
        }
    }

    /// Returns severity level (higher = more severe).
    pub const fn severity(&self) -> u8 {
        match self {
            BudgetWarningType::ApproachingLimit => 1,
            BudgetWarningType::AtLimit => 2,
            BudgetWarningType::OverBudget => 3,
        }
    }
}

impl std::fmt::Display for BudgetWarningType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.name())
    }
}

// ---------------------------------------------------------------------------
// BudgetWarning
// ---------------------------------------------------------------------------

/// A warning generated when budget thresholds are crossed.
#[derive(Debug, Clone)]
pub struct BudgetWarning {
    /// Type of warning.
    pub warning_type: BudgetWarningType,
    /// Which AS type triggered the warning (None for total budget).
    pub as_type: Option<AsType>,
    /// Current usage when warning was generated.
    pub current_usage: u64,
    /// The limit that was approached/exceeded.
    pub limit: u64,
    /// Frame number when warning was generated.
    pub timestamp_frame: u64,
}

impl BudgetWarning {
    /// Create a new budget warning.
    pub const fn new(
        warning_type: BudgetWarningType,
        as_type: Option<AsType>,
        current_usage: u64,
        limit: u64,
        timestamp_frame: u64,
    ) -> Self {
        Self {
            warning_type,
            as_type,
            current_usage,
            limit,
            timestamp_frame,
        }
    }

    /// Calculate usage ratio (current / limit).
    pub fn usage_ratio(&self) -> f32 {
        if self.limit == 0 {
            0.0
        } else {
            self.current_usage as f32 / self.limit as f32
        }
    }

    /// Get a human-readable description of this warning.
    pub fn description(&self) -> String {
        let type_str = match self.as_type {
            Some(AsType::Blas) => "BLAS",
            Some(AsType::Tlas) => "TLAS",
            None => "Total",
        };

        match self.warning_type {
            BudgetWarningType::ApproachingLimit => {
                format!(
                    "{} memory approaching limit: {} / {} ({:.1}%)",
                    type_str,
                    self.current_usage,
                    self.limit,
                    self.usage_ratio() * 100.0
                )
            }
            BudgetWarningType::AtLimit => {
                format!(
                    "{} memory at limit: {} / {} ({:.1}%)",
                    type_str,
                    self.current_usage,
                    self.limit,
                    self.usage_ratio() * 100.0
                )
            }
            BudgetWarningType::OverBudget => {
                format!(
                    "{} memory over budget: {} exceeds limit {}",
                    type_str, self.current_usage, self.limit
                )
            }
        }
    }
}

impl std::fmt::Display for BudgetWarning {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "[Frame {}] {}", self.timestamp_frame, self.description())
    }
}

// ---------------------------------------------------------------------------
// AsBudget
// ---------------------------------------------------------------------------

/// Budget configuration for AS memory.
#[derive(Debug, Clone, Copy)]
pub struct AsBudget {
    /// Maximum BLAS memory in bytes (0 = unlimited).
    pub blas_limit: u64,
    /// Maximum TLAS memory in bytes (0 = unlimited).
    pub tlas_limit: u64,
    /// Total AS memory limit in bytes (0 = unlimited).
    pub total_limit: u64,
    /// Ratio at which to warn about approaching limit (default 0.8 = 80%).
    pub soft_limit_ratio: f32,
    /// How to enforce budget limits.
    pub enforcement: BudgetEnforcement,
}

impl AsBudget {
    /// Create a new budget with default settings (unlimited).
    pub const fn new() -> Self {
        Self {
            blas_limit: 0,
            tlas_limit: 0,
            total_limit: 0,
            soft_limit_ratio: DEFAULT_SOFT_LIMIT_RATIO,
            enforcement: BudgetEnforcement::None,
        }
    }

    /// Create a budget with all limits set.
    pub const fn with_limits(blas_limit: u64, tlas_limit: u64, total_limit: u64) -> Self {
        Self {
            blas_limit,
            tlas_limit,
            total_limit,
            soft_limit_ratio: DEFAULT_SOFT_LIMIT_RATIO,
            enforcement: BudgetEnforcement::Warn,
        }
    }

    /// Set the BLAS memory limit.
    pub const fn with_blas_limit(mut self, limit: u64) -> Self {
        self.blas_limit = limit;
        self
    }

    /// Set the TLAS memory limit.
    pub const fn with_tlas_limit(mut self, limit: u64) -> Self {
        self.tlas_limit = limit;
        self
    }

    /// Set the total memory limit.
    pub const fn with_total_limit(mut self, limit: u64) -> Self {
        self.total_limit = limit;
        self
    }

    /// Set the soft limit ratio.
    pub const fn with_soft_limit_ratio(mut self, ratio: f32) -> Self {
        self.soft_limit_ratio = ratio;
        self
    }

    /// Set the enforcement mode.
    pub const fn with_enforcement(mut self, enforcement: BudgetEnforcement) -> Self {
        self.enforcement = enforcement;
        self
    }

    /// Check if any limits are set.
    pub const fn has_limits(&self) -> bool {
        self.blas_limit > 0 || self.tlas_limit > 0 || self.total_limit > 0
    }

    /// Check if BLAS has a limit.
    pub const fn has_blas_limit(&self) -> bool {
        self.blas_limit > 0
    }

    /// Check if TLAS has a limit.
    pub const fn has_tlas_limit(&self) -> bool {
        self.tlas_limit > 0
    }

    /// Check if total has a limit.
    pub const fn has_total_limit(&self) -> bool {
        self.total_limit > 0
    }

    /// Get the limit for a specific AS type.
    pub const fn limit_for(&self, as_type: AsType) -> u64 {
        match as_type {
            AsType::Blas => self.blas_limit,
            AsType::Tlas => self.tlas_limit,
        }
    }

    /// Validate the budget configuration.
    pub fn validate(&self) -> Result<(), AsMemoryError> {
        if !(0.0..=1.0).contains(&self.soft_limit_ratio) {
            return Err(AsMemoryError::InvalidConfig(
                "soft_limit_ratio must be in [0.0, 1.0]".to_string(),
            ));
        }
        Ok(())
    }
}

impl Default for AsBudget {
    fn default() -> Self {
        Self::new()
    }
}

impl std::fmt::Display for AsBudget {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "AsBudget {{ BLAS: {}, TLAS: {}, Total: {}, Soft: {:.0}%, Enforcement: {} }}",
            if self.blas_limit == 0 {
                "unlimited".to_string()
            } else {
                format!("{} MB", self.blas_limit / (1024 * 1024))
            },
            if self.tlas_limit == 0 {
                "unlimited".to_string()
            } else {
                format!("{} MB", self.tlas_limit / (1024 * 1024))
            },
            if self.total_limit == 0 {
                "unlimited".to_string()
            } else {
                format!("{} MB", self.total_limit / (1024 * 1024))
            },
            self.soft_limit_ratio * 100.0,
            self.enforcement
        )
    }
}

// ---------------------------------------------------------------------------
// BudgetUsage
// ---------------------------------------------------------------------------

/// Current budget usage statistics.
#[derive(Debug, Clone, Default)]
pub struct BudgetUsage {
    /// Current BLAS memory usage in bytes.
    pub blas_used: u64,
    /// Current TLAS memory usage in bytes.
    pub tlas_used: u64,
    /// Total memory usage in bytes.
    pub total_used: u64,
    /// Peak BLAS memory usage in bytes.
    pub blas_peak: u64,
    /// Peak TLAS memory usage in bytes.
    pub tlas_peak: u64,
    /// Peak total memory usage in bytes.
    pub total_peak: u64,
    /// Remaining BLAS budget (u64::MAX if unlimited).
    pub blas_remaining: u64,
    /// Remaining TLAS budget (u64::MAX if unlimited).
    pub tlas_remaining: u64,
    /// Remaining total budget (u64::MAX if unlimited).
    pub total_remaining: u64,
}

impl BudgetUsage {
    /// Create new empty usage statistics.
    pub const fn new() -> Self {
        Self {
            blas_used: 0,
            tlas_used: 0,
            total_used: 0,
            blas_peak: 0,
            tlas_peak: 0,
            total_peak: 0,
            blas_remaining: u64::MAX,
            tlas_remaining: u64::MAX,
            total_remaining: u64::MAX,
        }
    }

    /// Get usage for a specific AS type.
    pub const fn used_for(&self, as_type: AsType) -> u64 {
        match as_type {
            AsType::Blas => self.blas_used,
            AsType::Tlas => self.tlas_used,
        }
    }

    /// Get peak usage for a specific AS type.
    pub const fn peak_for(&self, as_type: AsType) -> u64 {
        match as_type {
            AsType::Blas => self.blas_peak,
            AsType::Tlas => self.tlas_peak,
        }
    }

    /// Get remaining budget for a specific AS type.
    pub const fn remaining_for(&self, as_type: AsType) -> u64 {
        match as_type {
            AsType::Blas => self.blas_remaining,
            AsType::Tlas => self.tlas_remaining,
        }
    }

    /// Calculate usage ratio for BLAS.
    pub fn blas_ratio(&self, limit: u64) -> f32 {
        if limit == 0 {
            0.0
        } else {
            self.blas_used as f32 / limit as f32
        }
    }

    /// Calculate usage ratio for TLAS.
    pub fn tlas_ratio(&self, limit: u64) -> f32 {
        if limit == 0 {
            0.0
        } else {
            self.tlas_used as f32 / limit as f32
        }
    }

    /// Calculate total usage ratio.
    pub fn total_ratio(&self, limit: u64) -> f32 {
        if limit == 0 {
            0.0
        } else {
            self.total_used as f32 / limit as f32
        }
    }
}

impl std::fmt::Display for BudgetUsage {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "BudgetUsage {{ BLAS: {} (peak: {}), TLAS: {} (peak: {}), Total: {} (peak: {}) }}",
            self.blas_used / 1024,
            self.blas_peak / 1024,
            self.tlas_used / 1024,
            self.tlas_peak / 1024,
            self.total_used / 1024,
            self.total_peak / 1024
        )
    }
}

// ---------------------------------------------------------------------------
// BudgetCheckResult
// ---------------------------------------------------------------------------

/// Result of checking if an allocation is allowed within budget.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum BudgetCheckResult {
    /// Allocation is allowed without warnings.
    Allowed,
    /// Allocation is allowed but with a warning.
    Warned { reason: String },
    /// Allocation is denied.
    Denied { reason: String },
}

impl BudgetCheckResult {
    /// Check if the allocation is allowed (including with warning).
    pub const fn is_allowed(&self) -> bool {
        matches!(self, BudgetCheckResult::Allowed | BudgetCheckResult::Warned { .. })
    }

    /// Check if the allocation was denied.
    pub const fn is_denied(&self) -> bool {
        matches!(self, BudgetCheckResult::Denied { .. })
    }

    /// Check if there was a warning.
    pub const fn has_warning(&self) -> bool {
        matches!(self, BudgetCheckResult::Warned { .. })
    }

    /// Get the reason if warned or denied.
    pub fn reason(&self) -> Option<&str> {
        match self {
            BudgetCheckResult::Allowed => None,
            BudgetCheckResult::Warned { reason } => Some(reason),
            BudgetCheckResult::Denied { reason } => Some(reason),
        }
    }
}

impl std::fmt::Display for BudgetCheckResult {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            BudgetCheckResult::Allowed => write!(f, "Allowed"),
            BudgetCheckResult::Warned { reason } => write!(f, "Warned: {}", reason),
            BudgetCheckResult::Denied { reason } => write!(f, "Denied: {}", reason),
        }
    }
}

// ---------------------------------------------------------------------------
// AsBudgetManager
// ---------------------------------------------------------------------------

/// Manages budget tracking and enforcement for AS memory.
///
/// Tracks usage per AS type (BLAS/TLAS), maintains peak usage statistics,
/// generates warnings when approaching limits, and optionally enforces
/// budget limits.
///
/// # Example
///
/// ```ignore
/// use renderer_backend::blas::{AsBudgetManager, AsBudget, BudgetEnforcement, AsType};
///
/// let budget = AsBudget::new()
///     .with_blas_limit(64 * 1024 * 1024)  // 64 MB BLAS limit
///     .with_tlas_limit(16 * 1024 * 1024)  // 16 MB TLAS limit
///     .with_enforcement(BudgetEnforcement::Soft);
///
/// let mut manager = AsBudgetManager::new(budget);
///
/// // Check if allocation is allowed
/// match manager.can_allocate(1024 * 1024, AsType::Blas) {
///     BudgetCheckResult::Allowed => println!("OK to allocate"),
///     BudgetCheckResult::Warned { reason } => println!("Warning: {}", reason),
///     BudgetCheckResult::Denied { reason } => println!("Denied: {}", reason),
/// }
///
/// // Record the allocation
/// manager.record_allocation(1024 * 1024, AsType::Blas, 0);
///
/// // Check usage
/// let usage = manager.usage();
/// println!("BLAS used: {} bytes", usage.blas_used);
/// ```
#[derive(Debug)]
pub struct AsBudgetManager {
    /// Budget configuration.
    budget: AsBudget,
    /// Current usage statistics.
    usage: BudgetUsage,
    /// Warning history (ring buffer).
    warnings: Vec<BudgetWarning>,
    /// Maximum number of warnings to retain.
    max_warnings: usize,
    /// Whether soft limit warnings have been emitted this session (to avoid spam).
    soft_limit_warned_blas: bool,
    soft_limit_warned_tlas: bool,
    soft_limit_warned_total: bool,
}

impl AsBudgetManager {
    /// Create a new budget manager with the given budget configuration.
    pub fn new(budget: AsBudget) -> Self {
        let mut manager = Self {
            budget,
            usage: BudgetUsage::new(),
            warnings: Vec::new(),
            max_warnings: DEFAULT_MAX_WARNINGS,
            soft_limit_warned_blas: false,
            soft_limit_warned_tlas: false,
            soft_limit_warned_total: false,
        };
        manager.update_remaining();
        manager
    }

    /// Create a new budget manager with custom warning capacity.
    pub fn with_max_warnings(budget: AsBudget, max_warnings: usize) -> Self {
        let mut manager = Self {
            budget,
            usage: BudgetUsage::new(),
            warnings: Vec::new(),
            max_warnings,
            soft_limit_warned_blas: false,
            soft_limit_warned_tlas: false,
            soft_limit_warned_total: false,
        };
        manager.update_remaining();
        manager
    }

    /// Get the budget configuration.
    pub const fn budget(&self) -> &AsBudget {
        &self.budget
    }

    /// Update the budget configuration.
    pub fn set_budget(&mut self, budget: AsBudget) {
        self.budget = budget;
        // Reset soft limit warnings when budget changes
        self.soft_limit_warned_blas = false;
        self.soft_limit_warned_tlas = false;
        self.soft_limit_warned_total = false;
        // Recalculate remaining
        self.update_remaining();
    }

    /// Check if an allocation of the given size is allowed within budget.
    ///
    /// Returns `BudgetCheckResult` indicating whether the allocation is
    /// allowed, warned, or denied.
    pub fn can_allocate(&self, size: u64, as_type: AsType) -> BudgetCheckResult {
        // Check type-specific limit
        let type_limit = self.budget.limit_for(as_type);
        let type_used = self.usage.used_for(as_type);

        if type_limit > 0 {
            let new_usage = type_used.saturating_add(size);

            if new_usage > type_limit {
                if self.budget.enforcement.enforces_limits() {
                    return BudgetCheckResult::Denied {
                        reason: format!(
                            "{} allocation of {} bytes would exceed limit ({} + {} > {})",
                            as_type, size, type_used, size, type_limit
                        ),
                    };
                } else if !matches!(self.budget.enforcement, BudgetEnforcement::None) {
                    return BudgetCheckResult::Warned {
                        reason: format!(
                            "{} allocation of {} bytes exceeds limit ({} + {} > {})",
                            as_type, size, type_used, size, type_limit
                        ),
                    };
                }
            }

            // Check soft limit
            let ratio = new_usage as f32 / type_limit as f32;
            if ratio >= self.budget.soft_limit_ratio {
                if !matches!(self.budget.enforcement, BudgetEnforcement::None) {
                    return BudgetCheckResult::Warned {
                        reason: format!(
                            "{} approaching limit: {:.1}% ({} / {} bytes)",
                            as_type,
                            ratio * 100.0,
                            new_usage,
                            type_limit
                        ),
                    };
                }
            }
        }

        // Check total limit
        if self.budget.total_limit > 0 {
            let new_total = self.usage.total_used.saturating_add(size);

            if new_total > self.budget.total_limit {
                if self.budget.enforcement.enforces_limits() {
                    return BudgetCheckResult::Denied {
                        reason: format!(
                            "Total allocation of {} bytes would exceed limit ({} + {} > {})",
                            size, self.usage.total_used, size, self.budget.total_limit
                        ),
                    };
                } else if !matches!(self.budget.enforcement, BudgetEnforcement::None) {
                    return BudgetCheckResult::Warned {
                        reason: format!(
                            "Total allocation of {} bytes exceeds limit ({} + {} > {})",
                            size, self.usage.total_used, size, self.budget.total_limit
                        ),
                    };
                }
            }

            // Check soft limit
            let ratio = new_total as f32 / self.budget.total_limit as f32;
            if ratio >= self.budget.soft_limit_ratio {
                if !matches!(self.budget.enforcement, BudgetEnforcement::None) {
                    return BudgetCheckResult::Warned {
                        reason: format!(
                            "Total approaching limit: {:.1}% ({} / {} bytes)",
                            ratio * 100.0,
                            new_total,
                            self.budget.total_limit
                        ),
                    };
                }
            }
        }

        BudgetCheckResult::Allowed
    }

    /// Record an allocation.
    ///
    /// Updates usage statistics and peak tracking.
    pub fn record_allocation(&mut self, size: u64, as_type: AsType, frame: u64) {
        // Update usage
        match as_type {
            AsType::Blas => {
                self.usage.blas_used = self.usage.blas_used.saturating_add(size);
                if self.usage.blas_used > self.usage.blas_peak {
                    self.usage.blas_peak = self.usage.blas_used;
                }
            }
            AsType::Tlas => {
                self.usage.tlas_used = self.usage.tlas_used.saturating_add(size);
                if self.usage.tlas_used > self.usage.tlas_peak {
                    self.usage.tlas_peak = self.usage.tlas_used;
                }
            }
        }

        self.usage.total_used = self.usage.blas_used.saturating_add(self.usage.tlas_used);
        if self.usage.total_used > self.usage.total_peak {
            self.usage.total_peak = self.usage.total_used;
        }

        // Update remaining
        self.update_remaining();

        // Generate warnings
        self.generate_warnings(frame);
    }

    /// Record a deallocation.
    ///
    /// Updates usage statistics (peak is not affected).
    pub fn record_free(&mut self, size: u64, as_type: AsType) {
        match as_type {
            AsType::Blas => {
                self.usage.blas_used = self.usage.blas_used.saturating_sub(size);
                // Reset soft limit warning if we go below threshold
                if self.budget.blas_limit > 0 {
                    let ratio = self.usage.blas_used as f32 / self.budget.blas_limit as f32;
                    if ratio < self.budget.soft_limit_ratio * 0.9 {
                        self.soft_limit_warned_blas = false;
                    }
                }
            }
            AsType::Tlas => {
                self.usage.tlas_used = self.usage.tlas_used.saturating_sub(size);
                if self.budget.tlas_limit > 0 {
                    let ratio = self.usage.tlas_used as f32 / self.budget.tlas_limit as f32;
                    if ratio < self.budget.soft_limit_ratio * 0.9 {
                        self.soft_limit_warned_tlas = false;
                    }
                }
            }
        }

        self.usage.total_used = self.usage.blas_used.saturating_add(self.usage.tlas_used);
        if self.budget.total_limit > 0 {
            let ratio = self.usage.total_used as f32 / self.budget.total_limit as f32;
            if ratio < self.budget.soft_limit_ratio * 0.9 {
                self.soft_limit_warned_total = false;
            }
        }

        self.update_remaining();
    }

    /// Get current usage statistics.
    pub const fn usage(&self) -> &BudgetUsage {
        &self.usage
    }

    /// Check for warnings and return any new ones.
    ///
    /// This is useful for polling for warnings after batch operations.
    pub fn check_warnings(&mut self, frame: u64) -> Vec<BudgetWarning> {
        let before_count = self.warnings.len();
        self.generate_warnings(frame);
        self.warnings[before_count..].to_vec()
    }

    /// Get all warnings in the history.
    pub fn warnings(&self) -> &[BudgetWarning] {
        &self.warnings
    }

    /// Clear the warning history.
    pub fn clear_warnings(&mut self) {
        self.warnings.clear();
    }

    /// Reset peak usage tracking.
    pub fn reset_peak_usage(&mut self) {
        self.usage.blas_peak = self.usage.blas_used;
        self.usage.tlas_peak = self.usage.tlas_used;
        self.usage.total_peak = self.usage.total_used;
    }

    /// Reset all usage tracking (for testing or re-initialization).
    pub fn reset_usage(&mut self) {
        self.usage = BudgetUsage::new();
        self.update_remaining();
        self.soft_limit_warned_blas = false;
        self.soft_limit_warned_tlas = false;
        self.soft_limit_warned_total = false;
    }

    /// Get warning count.
    pub fn warning_count(&self) -> usize {
        self.warnings.len()
    }

    /// Check if currently over any limit.
    pub fn is_over_budget(&self) -> bool {
        if self.budget.blas_limit > 0 && self.usage.blas_used > self.budget.blas_limit {
            return true;
        }
        if self.budget.tlas_limit > 0 && self.usage.tlas_used > self.budget.tlas_limit {
            return true;
        }
        if self.budget.total_limit > 0 && self.usage.total_used > self.budget.total_limit {
            return true;
        }
        false
    }

    /// Check if approaching soft limit for any category.
    pub fn is_approaching_limit(&self) -> bool {
        if self.budget.blas_limit > 0 {
            let ratio = self.usage.blas_used as f32 / self.budget.blas_limit as f32;
            if ratio >= self.budget.soft_limit_ratio {
                return true;
            }
        }
        if self.budget.tlas_limit > 0 {
            let ratio = self.usage.tlas_used as f32 / self.budget.tlas_limit as f32;
            if ratio >= self.budget.soft_limit_ratio {
                return true;
            }
        }
        if self.budget.total_limit > 0 {
            let ratio = self.usage.total_used as f32 / self.budget.total_limit as f32;
            if ratio >= self.budget.soft_limit_ratio {
                return true;
            }
        }
        false
    }

    /// Update remaining budget calculations.
    fn update_remaining(&mut self) {
        self.usage.blas_remaining = if self.budget.blas_limit == 0 {
            u64::MAX
        } else {
            self.budget.blas_limit.saturating_sub(self.usage.blas_used)
        };

        self.usage.tlas_remaining = if self.budget.tlas_limit == 0 {
            u64::MAX
        } else {
            self.budget.tlas_limit.saturating_sub(self.usage.tlas_used)
        };

        self.usage.total_remaining = if self.budget.total_limit == 0 {
            u64::MAX
        } else {
            self.budget
                .total_limit
                .saturating_sub(self.usage.total_used)
        };
    }

    /// Generate warnings based on current usage.
    fn generate_warnings(&mut self, frame: u64) {
        // Check BLAS
        if self.budget.blas_limit > 0 {
            let ratio = self.usage.blas_used as f32 / self.budget.blas_limit as f32;

            if self.usage.blas_used > self.budget.blas_limit {
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::OverBudget,
                    Some(AsType::Blas),
                    self.usage.blas_used,
                    self.budget.blas_limit,
                    frame,
                ));
            } else if ratio >= 0.99 {
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::AtLimit,
                    Some(AsType::Blas),
                    self.usage.blas_used,
                    self.budget.blas_limit,
                    frame,
                ));
            } else if ratio >= self.budget.soft_limit_ratio && !self.soft_limit_warned_blas {
                self.soft_limit_warned_blas = true;
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::ApproachingLimit,
                    Some(AsType::Blas),
                    self.usage.blas_used,
                    self.budget.blas_limit,
                    frame,
                ));
            }
        }

        // Check TLAS
        if self.budget.tlas_limit > 0 {
            let ratio = self.usage.tlas_used as f32 / self.budget.tlas_limit as f32;

            if self.usage.tlas_used > self.budget.tlas_limit {
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::OverBudget,
                    Some(AsType::Tlas),
                    self.usage.tlas_used,
                    self.budget.tlas_limit,
                    frame,
                ));
            } else if ratio >= 0.99 {
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::AtLimit,
                    Some(AsType::Tlas),
                    self.usage.tlas_used,
                    self.budget.tlas_limit,
                    frame,
                ));
            } else if ratio >= self.budget.soft_limit_ratio && !self.soft_limit_warned_tlas {
                self.soft_limit_warned_tlas = true;
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::ApproachingLimit,
                    Some(AsType::Tlas),
                    self.usage.tlas_used,
                    self.budget.tlas_limit,
                    frame,
                ));
            }
        }

        // Check Total
        if self.budget.total_limit > 0 {
            let ratio = self.usage.total_used as f32 / self.budget.total_limit as f32;

            if self.usage.total_used > self.budget.total_limit {
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::OverBudget,
                    None,
                    self.usage.total_used,
                    self.budget.total_limit,
                    frame,
                ));
            } else if ratio >= 0.99 {
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::AtLimit,
                    None,
                    self.usage.total_used,
                    self.budget.total_limit,
                    frame,
                ));
            } else if ratio >= self.budget.soft_limit_ratio && !self.soft_limit_warned_total {
                self.soft_limit_warned_total = true;
                self.add_warning(BudgetWarning::new(
                    BudgetWarningType::ApproachingLimit,
                    None,
                    self.usage.total_used,
                    self.budget.total_limit,
                    frame,
                ));
            }
        }
    }

    /// Add a warning to the history, maintaining ring buffer.
    fn add_warning(&mut self, warning: BudgetWarning) {
        if self.warnings.len() >= self.max_warnings {
            self.warnings.remove(0);
        }
        self.warnings.push(warning);
    }
}

impl Clone for AsBudgetManager {
    fn clone(&self) -> Self {
        Self {
            budget: self.budget,
            usage: self.usage.clone(),
            warnings: self.warnings.clone(),
            max_warnings: self.max_warnings,
            soft_limit_warned_blas: self.soft_limit_warned_blas,
            soft_limit_warned_tlas: self.soft_limit_warned_tlas,
            soft_limit_warned_total: self.soft_limit_warned_total,
        }
    }
}

impl std::fmt::Display for AsBudgetManager {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "AsBudgetManager {{ budget: {}, usage: {}, warnings: {} }}",
            self.budget,
            self.usage,
            self.warnings.len()
        )
    }
}

// === End T-WGPU-P5.5.2: AS Memory Budget ===

// === T-WGPU-P5.6.1: Ray Query Fundamentals ===
//
// Ray query infrastructure for wgpu 25.x ray tracing. This provides:
// - Feature detection for ray query support
// - TLAS binding for compute/fragment shaders
// - Ray description types for shader communication
// - WGSL code generation helpers

// ---------------------------------------------------------------------------
// Ray Query Feature Detection
// ---------------------------------------------------------------------------

/// Ray query and ray tracing feature availability.
///
/// Detects whether the device supports ray query operations (inline ray tracing
/// in compute/fragment shaders) and/or ray tracing pipelines.
///
/// # Example
///
/// ```ignore
/// let features = RayQueryFeatures::from_adapter(&adapter);
/// if features.is_ray_query_supported() {
///     // Can use ray queries in compute shaders
/// }
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct RayQueryFeatures {
    /// Ray query support (inline ray tracing in compute/fragment shaders).
    pub ray_query: bool,
    /// Ray tracing pipeline support (dedicated ray tracing pipelines).
    pub ray_tracing_pipeline: bool,
}

impl RayQueryFeatures {
    /// Create features from adapter capabilities.
    ///
    /// Checks the adapter's feature set to determine ray tracing support.
    /// In wgpu 25.x, this requires checking for experimental ray tracing features.
    #[cfg(feature = "wgpu")]
    pub fn from_adapter(adapter: &wgpu::Adapter) -> Self {
        let features = adapter.features();
        Self {
            // wgpu 25.x uses experimental features for ray tracing
            ray_query: features.contains(wgpu::Features::EXPERIMENTAL_RAY_QUERY),
            ray_tracing_pipeline: features.contains(wgpu::Features::EXPERIMENTAL_RAY_TRACING_ACCELERATION_STRUCTURE),
        }
    }

    /// Create features assuming full support (for testing/mock purposes).
    pub fn full_support() -> Self {
        Self {
            ray_query: true,
            ray_tracing_pipeline: true,
        }
    }

    /// Create features assuming no support.
    pub fn no_support() -> Self {
        Self::default()
    }

    /// Check if ray query (inline ray tracing) is supported.
    ///
    /// Ray query allows tracing rays directly in compute or fragment shaders
    /// without needing a dedicated ray tracing pipeline.
    pub fn is_ray_query_supported(&self) -> bool {
        self.ray_query
    }

    /// Check if ray tracing pipelines are supported.
    ///
    /// Ray tracing pipelines provide dedicated shader stages (ray generation,
    /// closest hit, any hit, miss) for full ray tracing workflows.
    pub fn is_ray_tracing_pipeline_supported(&self) -> bool {
        self.ray_tracing_pipeline
    }

    /// Check if any ray tracing capability is available.
    pub fn has_any_ray_tracing(&self) -> bool {
        self.ray_query || self.ray_tracing_pipeline
    }
}

impl std::fmt::Display for RayQueryFeatures {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "RayQueryFeatures {{ ray_query: {}, ray_tracing_pipeline: {} }}",
            self.ray_query, self.ray_tracing_pipeline
        )
    }
}

// ---------------------------------------------------------------------------
// TLAS Binding Configuration
// ---------------------------------------------------------------------------

/// Descriptor for binding a TLAS to a shader.
///
/// Configures how the top-level acceleration structure is bound to
/// compute or fragment shaders for ray query operations.
///
/// # Example
///
/// ```ignore
/// let binding_desc = TlasBindingDescriptor {
///     binding: 0,
///     visibility: wgpu::ShaderStages::COMPUTE,
/// };
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TlasBindingDescriptor {
    /// The binding index in the bind group.
    pub binding: u32,
    /// Which shader stages can access the TLAS.
    pub visibility: TlasShaderVisibility,
}

impl TlasBindingDescriptor {
    /// Create a new TLAS binding descriptor.
    pub fn new(binding: u32, visibility: TlasShaderVisibility) -> Self {
        Self { binding, visibility }
    }

    /// Create a descriptor for compute shader access only.
    pub fn compute(binding: u32) -> Self {
        Self {
            binding,
            visibility: TlasShaderVisibility::COMPUTE,
        }
    }

    /// Create a descriptor for fragment shader access only.
    pub fn fragment(binding: u32) -> Self {
        Self {
            binding,
            visibility: TlasShaderVisibility::FRAGMENT,
        }
    }

    /// Create a descriptor for both compute and fragment shader access.
    pub fn compute_and_fragment(binding: u32) -> Self {
        Self {
            binding,
            visibility: TlasShaderVisibility::COMPUTE | TlasShaderVisibility::FRAGMENT,
        }
    }
}

impl Default for TlasBindingDescriptor {
    fn default() -> Self {
        Self {
            binding: 0,
            visibility: TlasShaderVisibility::COMPUTE,
        }
    }
}

/// Shader visibility flags for TLAS binding.
///
/// Mirrors wgpu::ShaderStages but limited to stages that support ray queries.
bitflags! {
    #[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
    pub struct TlasShaderVisibility: u32 {
        /// Compute shader visibility.
        const COMPUTE = 1 << 0;
        /// Fragment shader visibility.
        const FRAGMENT = 1 << 1;
    }
}

impl TlasShaderVisibility {
    /// Convert to wgpu::ShaderStages (when wgpu feature is enabled).
    #[cfg(feature = "wgpu")]
    pub fn to_wgpu_stages(self) -> wgpu::ShaderStages {
        let mut stages = wgpu::ShaderStages::empty();
        if self.contains(TlasShaderVisibility::COMPUTE) {
            stages |= wgpu::ShaderStages::COMPUTE;
        }
        if self.contains(TlasShaderVisibility::FRAGMENT) {
            stages |= wgpu::ShaderStages::FRAGMENT;
        }
        stages
    }
}

// ---------------------------------------------------------------------------
// TLAS Bind Group Layout
// ---------------------------------------------------------------------------

/// Layout for binding TLAS to shaders.
///
/// Encapsulates the bind group layout entry for acceleration structure binding.
/// Use this to create bind group layouts that include TLAS access.
///
/// # Example
///
/// ```ignore
/// let desc = TlasBindingDescriptor::compute(0);
/// let layout = TlasBindGroupLayout::new(&device, &desc);
///
/// // Use layout.layout() when creating pipeline layouts
/// ```
#[derive(Debug)]
pub struct TlasBindGroupLayout {
    /// The binding index for the TLAS.
    binding: u32,
    /// Shader visibility for this binding.
    visibility: TlasShaderVisibility,
    /// Cached bind group layout entry (for wgpu integration).
    #[cfg(feature = "wgpu")]
    layout: Option<wgpu::BindGroupLayout>,
}

impl TlasBindGroupLayout {
    /// Create a new TLAS bind group layout.
    pub fn new(desc: &TlasBindingDescriptor) -> Self {
        Self {
            binding: desc.binding,
            visibility: desc.visibility,
            #[cfg(feature = "wgpu")]
            layout: None,
        }
    }

    /// Create with a wgpu device (creates actual bind group layout).
    #[cfg(feature = "wgpu")]
    pub fn with_device(device: &wgpu::Device, desc: &TlasBindingDescriptor) -> Self {
        let layout = device.create_bind_group_layout(&wgpu::BindGroupLayoutDescriptor {
            label: Some("TLAS Bind Group Layout"),
            entries: &[wgpu::BindGroupLayoutEntry {
                binding: desc.binding,
                visibility: desc.visibility.to_wgpu_stages(),
                ty: wgpu::BindingType::AccelerationStructure,
                count: None,
            }],
        });

        Self {
            binding: desc.binding,
            visibility: desc.visibility,
            layout: Some(layout),
        }
    }

    /// Get the binding index.
    pub fn binding(&self) -> u32 {
        self.binding
    }

    /// Get the shader visibility.
    pub fn visibility(&self) -> TlasShaderVisibility {
        self.visibility
    }

    /// Get the underlying wgpu bind group layout.
    #[cfg(feature = "wgpu")]
    pub fn layout(&self) -> Option<&wgpu::BindGroupLayout> {
        self.layout.as_ref()
    }

    /// Create a bind group layout entry for this TLAS binding.
    ///
    /// Use this when creating a combined bind group layout with other resources.
    #[cfg(feature = "wgpu")]
    pub fn as_layout_entry(&self) -> wgpu::BindGroupLayoutEntry {
        wgpu::BindGroupLayoutEntry {
            binding: self.binding,
            visibility: self.visibility.to_wgpu_stages(),
            ty: wgpu::BindingType::AccelerationStructure,
            count: None,
        }
    }
}

// ---------------------------------------------------------------------------
// Ray Description
// ---------------------------------------------------------------------------

/// Ray description for shader communication.
///
/// This struct is designed to be uploaded to GPU buffers and used in shaders
/// for ray tracing operations. It matches the expected layout for WGSL ray
/// initialization.
///
/// # Memory Layout
///
/// - Size: 32 bytes
/// - Alignment: 4 bytes
/// - Layout: `[origin.x, origin.y, origin.z, t_min, direction.x, direction.y, direction.z, t_max]`
///
/// # Example
///
/// ```ignore
/// let ray = RayDesc {
///     origin: [0.0, 0.0, 0.0],
///     t_min: 0.001,
///     direction: [0.0, 0.0, 1.0],
///     t_max: 1000.0,
/// };
///
/// // Upload to GPU buffer for ray tracing
/// queue.write_buffer(&ray_buffer, 0, bytemuck::bytes_of(&ray));
/// ```
#[repr(C)]
#[derive(Clone, Copy, Debug, PartialEq)]
pub struct RayDesc {
    /// Ray origin point in world space.
    pub origin: [f32; 3],
    /// Minimum ray parameter (t_min). Intersections closer than this are ignored.
    pub t_min: f32,
    /// Ray direction (should be normalized for correct distance calculations).
    pub direction: [f32; 3],
    /// Maximum ray parameter (t_max). Intersections farther than this are ignored.
    pub t_max: f32,
}

// Manual Pod/Zeroable implementation to avoid bytemuck dependency at struct level
unsafe impl bytemuck::Pod for RayDesc {}
unsafe impl bytemuck::Zeroable for RayDesc {}

impl RayDesc {
    /// Create a new ray description.
    pub fn new(origin: [f32; 3], direction: [f32; 3], t_min: f32, t_max: f32) -> Self {
        Self {
            origin,
            t_min,
            direction,
            t_max,
        }
    }

    /// Create a ray from origin to target point.
    ///
    /// The direction is normalized and t_max is set to the distance to the target.
    pub fn from_points(origin: [f32; 3], target: [f32; 3], t_min: f32) -> Self {
        let dx = target[0] - origin[0];
        let dy = target[1] - origin[1];
        let dz = target[2] - origin[2];
        let distance = (dx * dx + dy * dy + dz * dz).sqrt();

        let direction = if distance > 0.0 {
            [dx / distance, dy / distance, dz / distance]
        } else {
            [0.0, 0.0, 1.0] // Default forward direction
        };

        Self {
            origin,
            t_min,
            direction,
            t_max: distance,
        }
    }

    /// Create a primary ray for camera ray casting.
    ///
    /// Uses typical defaults for primary rays: t_min near zero, t_max very large.
    pub fn primary(origin: [f32; 3], direction: [f32; 3]) -> Self {
        Self {
            origin,
            t_min: 0.001,
            direction,
            t_max: f32::MAX,
        }
    }

    /// Create a shadow ray toward a light source.
    ///
    /// Shadow rays typically use a small t_min to avoid self-intersection
    /// and t_max set to the light distance (minus epsilon).
    pub fn shadow(origin: [f32; 3], light_position: [f32; 3]) -> Self {
        let mut ray = Self::from_points(origin, light_position, 0.001);
        // Slightly reduce t_max to avoid hitting the light source geometry
        ray.t_max *= 0.999;
        ray
    }

    /// Get the point along the ray at parameter t.
    pub fn point_at(&self, t: f32) -> [f32; 3] {
        [
            self.origin[0] + self.direction[0] * t,
            self.origin[1] + self.direction[1] * t,
            self.origin[2] + self.direction[2] * t,
        ]
    }

    /// Check if a parameter t is within the valid range [t_min, t_max].
    pub fn is_valid_t(&self, t: f32) -> bool {
        t >= self.t_min && t <= self.t_max
    }
}

impl Default for RayDesc {
    fn default() -> Self {
        Self {
            origin: [0.0, 0.0, 0.0],
            t_min: 0.001,
            direction: [0.0, 0.0, 1.0],
            t_max: 1000.0,
        }
    }
}

// ---------------------------------------------------------------------------
// Ray Query Types
// ---------------------------------------------------------------------------

/// Type of ray query to perform.
///
/// Determines the traversal behavior and what kind of intersection
/// information is returned.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
pub enum RayQueryType {
    /// Find the closest intersection along the ray.
    ///
    /// Traverses all geometry and returns the hit with the smallest t value.
    /// Use for primary rays, reflection rays, and any case where you need
    /// accurate hit information.
    #[default]
    Nearest,

    /// Stop at the first intersection found.
    ///
    /// More efficient than Nearest when you only need to know if something
    /// is hit, not what specifically. Ideal for shadow rays and occlusion
    /// queries.
    Any,
}

impl RayQueryType {
    /// Check if this query type should terminate on first hit.
    pub fn terminates_on_first_hit(&self) -> bool {
        matches!(self, RayQueryType::Any)
    }

    /// Get the recommended ray flags for this query type.
    pub fn recommended_flags(&self) -> RayFlags {
        match self {
            RayQueryType::Nearest => RayFlags::NONE,
            RayQueryType::Any => RayFlags::TERMINATE_ON_FIRST_HIT,
        }
    }
}

impl std::fmt::Display for RayQueryType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            RayQueryType::Nearest => write!(f, "Nearest"),
            RayQueryType::Any => write!(f, "Any"),
        }
    }
}

// ---------------------------------------------------------------------------
// Ray Flags
// ---------------------------------------------------------------------------

bitflags! {
    /// Flags controlling ray traversal behavior.
    ///
    /// These flags map to the ray flags used in WGSL rayQueryInitialize.
    #[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
    pub struct RayFlags: u32 {
        /// No special behavior.
        const NONE = 0;

        /// Force all geometry to be treated as opaque.
        ///
        /// Ignores the opacity flags on geometry, treating everything as if
        /// it blocks rays. Useful for shadow rays where you don't care about
        /// transparency.
        const FORCE_OPAQUE = 1 << 0;

        /// Force all geometry to be treated as non-opaque.
        ///
        /// All intersections will invoke the any-hit shader (if present).
        const FORCE_NON_OPAQUE = 1 << 1;

        /// Terminate traversal on the first hit found.
        ///
        /// More efficient for shadow/occlusion queries where you only need
        /// to know if anything is hit, not what the closest hit is.
        const TERMINATE_ON_FIRST_HIT = 1 << 2;

        /// Skip closest hit shader invocation.
        ///
        /// Only useful with ray tracing pipelines, not ray queries.
        const SKIP_CLOSEST_HIT_SHADER = 1 << 3;

        /// Cull back-facing triangles.
        ///
        /// Back faces (clockwise winding) will be ignored.
        /// Matches SPIR-V CullBackFacingTrianglesKHR (0x0010).
        const CULL_BACK_FACING = 1 << 4;

        /// Cull front-facing triangles.
        ///
        /// Front faces (counter-clockwise winding) will be ignored.
        /// Matches SPIR-V CullFrontFacingTrianglesKHR (0x0020).
        const CULL_FRONT_FACING = 1 << 5;

        /// Cull opaque geometry.
        const CULL_OPAQUE = 1 << 6;

        /// Cull non-opaque geometry.
        const CULL_NON_OPAQUE = 1 << 7;

        /// Skip triangle intersection (only test AABBs).
        ///
        /// Useful when you only have procedural geometry.
        const SKIP_TRIANGLES = 1 << 8;

        /// Skip AABB intersection (only test triangles).
        ///
        /// Useful when you only have triangle geometry.
        const SKIP_AABBS = 1 << 9;
    }
}

impl RayFlags {
    /// Create flags for shadow ray tracing.
    ///
    /// Optimized for determining occlusion without needing exact hit info.
    pub fn shadow() -> Self {
        Self::TERMINATE_ON_FIRST_HIT | Self::FORCE_OPAQUE
    }

    /// Create flags for primary ray tracing.
    ///
    /// Default flags for finding the closest intersection.
    pub fn primary() -> Self {
        Self::NONE
    }

    /// Create flags for back-face culling (typical for closed meshes).
    pub fn with_backface_culling() -> Self {
        Self::CULL_BACK_FACING
    }

    /// Get the WGSL flag value.
    pub fn to_wgsl_value(&self) -> u32 {
        self.bits()
    }
}

// ---------------------------------------------------------------------------
// Trace Configuration
// ---------------------------------------------------------------------------

/// Configuration for ray tracing operations.
///
/// Combines query type, culling mask, and ray flags into a single
/// configuration object.
///
/// # Example
///
/// ```ignore
/// // Primary ray configuration
/// let primary_config = TraceConfig::default();
///
/// // Shadow ray configuration
/// let shadow_config = TraceConfig::shadow();
///
/// // Custom configuration
/// let custom_config = TraceConfig::new()
///     .with_query_type(RayQueryType::Nearest)
///     .with_cull_mask(0xFF)
///     .with_flags(RayFlags::CULL_BACK_FACING);
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TraceConfig {
    /// Type of ray query (Nearest or Any).
    pub query_type: RayQueryType,
    /// Instance cull mask (8-bit mask ANDed with instance mask).
    pub cull_mask: u32,
    /// Ray traversal flags.
    pub flags: RayFlags,
}

impl TraceConfig {
    /// Create a new trace configuration with defaults.
    pub fn new() -> Self {
        Self::default()
    }

    /// Create a configuration for shadow rays.
    ///
    /// Uses Any query type and terminate-on-first-hit for efficiency.
    pub fn shadow() -> Self {
        Self {
            query_type: RayQueryType::Any,
            cull_mask: 0xFF,
            flags: RayFlags::shadow(),
        }
    }

    /// Create a configuration for primary rays.
    ///
    /// Uses Nearest query type with no special flags.
    pub fn primary() -> Self {
        Self {
            query_type: RayQueryType::Nearest,
            cull_mask: 0xFF,
            flags: RayFlags::primary(),
        }
    }

    /// Set the query type.
    pub fn with_query_type(mut self, query_type: RayQueryType) -> Self {
        self.query_type = query_type;
        self
    }

    /// Set the cull mask.
    ///
    /// The cull mask is ANDed with the instance mask during traversal.
    /// Instances with `(instance_mask & cull_mask) == 0` are skipped.
    pub fn with_cull_mask(mut self, cull_mask: u32) -> Self {
        self.cull_mask = cull_mask;
        self
    }

    /// Set the ray flags.
    pub fn with_flags(mut self, flags: RayFlags) -> Self {
        self.flags = flags;
        self
    }

    /// Add additional flags (OR operation).
    pub fn add_flags(mut self, flags: RayFlags) -> Self {
        self.flags |= flags;
        self
    }

    /// Enable back-face culling.
    pub fn with_backface_culling(self) -> Self {
        self.add_flags(RayFlags::CULL_BACK_FACING)
    }

    /// Enable front-face culling.
    pub fn with_frontface_culling(self) -> Self {
        self.add_flags(RayFlags::CULL_FRONT_FACING)
    }

    /// Skip triangle geometry (only test AABBs).
    pub fn skip_triangles(self) -> Self {
        self.add_flags(RayFlags::SKIP_TRIANGLES)
    }

    /// Skip AABB geometry (only test triangles).
    pub fn skip_aabbs(self) -> Self {
        self.add_flags(RayFlags::SKIP_AABBS)
    }
}

impl Default for TraceConfig {
    fn default() -> Self {
        Self {
            query_type: RayQueryType::Nearest,
            cull_mask: 0xFF, // All instances visible by default
            flags: RayFlags::NONE,
        }
    }
}

// ---------------------------------------------------------------------------
// WGSL Code Generation
// ---------------------------------------------------------------------------

/// Generate WGSL code for a TLAS binding declaration.
///
/// # Example
///
/// ```ignore
/// let wgsl = generate_tlas_binding_wgsl(0, 0);
/// // Produces: "@group(0) @binding(0) var tlas: acceleration_structure;"
/// ```
pub fn generate_tlas_binding_wgsl(group: u32, binding: u32) -> String {
    format!(
        "@group({}) @binding({}) var tlas: acceleration_structure;",
        group, binding
    )
}

/// Generate WGSL code for ray query variable declaration.
///
/// Creates a ray query variable in the appropriate scope.
pub fn generate_ray_query_decl_wgsl() -> String {
    "var<private> rq: ray_query;".to_string()
}

/// Generate WGSL code for a basic ray trace operation.
///
/// # Arguments
///
/// * `config` - Trace configuration
///
/// # Returns
///
/// WGSL code that performs ray initialization and traversal.
pub fn generate_ray_query_wgsl(config: &TraceConfig) -> String {
    let flags = config.flags.to_wgsl_value();
    let cull_mask = config.cull_mask;

    format!(
        r#"// Initialize ray query
rayQueryInitialize(&rq, tlas, {}u, {}u, ray);

// Traverse acceleration structure
while (rayQueryProceed(&rq)) {{
    // Process candidate intersections if needed
}}

// Get committed intersection
let hit_type = rayQueryGetCommittedIntersectionType(&rq);"#,
        flags, cull_mask
    )
}

/// Generate complete WGSL code for a ray query helper function.
///
/// Creates a reusable function for tracing rays.
///
/// # Arguments
///
/// * `function_name` - Name of the generated function
/// * `config` - Trace configuration
///
/// # Returns
///
/// Complete WGSL function code.
pub fn generate_ray_query_function_wgsl(function_name: &str, config: &TraceConfig) -> String {
    let flags = config.flags.to_wgsl_value();
    let cull_mask = config.cull_mask;

    format!(
        r#"// Ray trace helper function
fn {function_name}(ray_origin: vec3<f32>, ray_direction: vec3<f32>, t_min: f32, t_max: f32) -> bool {{
    var rq: ray_query;

    let ray = RayDesc(ray_origin, t_min, ray_direction, t_max);

    rayQueryInitialize(&rq, tlas, {flags}u, {cull_mask}u, ray);

    while (rayQueryProceed(&rq)) {{
        // Accept all intersections for opaque geometry
    }}

    return rayQueryGetCommittedIntersectionType(&rq) != RAY_QUERY_COMMITTED_INTERSECTION_NONE;
}}"#,
        function_name = function_name,
        flags = flags,
        cull_mask = cull_mask
    )
}

/// Generate WGSL struct definition for RayDesc.
///
/// Creates a struct matching the CPU-side RayDesc for uniform/storage buffers.
pub fn generate_ray_desc_struct_wgsl() -> String {
    r#"struct RayDesc {
    origin: vec3<f32>,
    t_min: f32,
    direction: vec3<f32>,
    t_max: f32,
}"#
    .to_string()
}

/// Generate WGSL code for extracting hit information from a ray query.
pub fn generate_hit_info_wgsl() -> String {
    r#"// Extract hit information from committed intersection
let hit_kind = rayQueryGetCommittedIntersectionType(&rq);
let hit_t = rayQueryGetCommittedIntersectionT(&rq);
let hit_instance_id = rayQueryGetCommittedIntersectionInstanceId(&rq);
let hit_primitive_index = rayQueryGetCommittedIntersectionPrimitiveIndex(&rq);
let hit_barycentrics = rayQueryGetCommittedIntersectionBarycentrics(&rq);
let hit_front_face = rayQueryGetCommittedIntersectionFrontFace(&rq);"#
        .to_string()
}

// ---------------------------------------------------------------------------
// Ray Query Declaration Helpers
// ---------------------------------------------------------------------------

/// Ray query variable declaration configuration.
///
/// Used to generate WGSL ray query variable declarations with the
/// appropriate storage class.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct RayQueryDecl {
    /// The query type (affects usage patterns, not declaration).
    pub query_type: RayQueryType,
}

impl RayQueryDecl {
    /// Create a new ray query declaration.
    pub fn new(query_type: RayQueryType) -> Self {
        Self { query_type }
    }

    /// Create a declaration for nearest-hit queries.
    pub fn nearest() -> Self {
        Self::new(RayQueryType::Nearest)
    }

    /// Create a declaration for any-hit queries.
    pub fn any() -> Self {
        Self::new(RayQueryType::Any)
    }

    /// Generate WGSL declaration code.
    pub fn to_wgsl(&self) -> String {
        generate_ray_query_decl_wgsl()
    }
}

// === End T-WGPU-P5.6.1: Ray Query Fundamentals ===

// === T-WGPU-P5.6.2: Ray Query WGSL API ===
//
// Complete ray query WGSL API patterns for wgpu 25.x ray tracing. This provides:
// - Ray query function enumeration for WGSL code generation
// - Intersection type enums for committed and candidate intersections
// - HitInfo structure for extracting intersection data
// - RayQueryWgslGenerator for complete shader code generation

// ---------------------------------------------------------------------------
// WGSL Ray Query Constants
// ---------------------------------------------------------------------------

/// WGSL constant for committed intersection type: none.
pub const WGSL_RAY_QUERY_COMMITTED_NONE: &str = "RAY_QUERY_COMMITTED_INTERSECTION_TYPE_NONE";

/// WGSL constant for committed intersection type: triangle.
pub const WGSL_RAY_QUERY_COMMITTED_TRIANGLE: &str = "RAY_QUERY_COMMITTED_INTERSECTION_TYPE_TRIANGLE";

/// WGSL constant for committed intersection type: AABB/procedural (generated).
pub const WGSL_RAY_QUERY_COMMITTED_AABB: &str = "RAY_QUERY_COMMITTED_INTERSECTION_TYPE_GENERATED";

/// WGSL constant for candidate intersection type: triangle.
pub const WGSL_RAY_QUERY_CANDIDATE_TRIANGLE: &str = "RAY_QUERY_CANDIDATE_INTERSECTION_TYPE_TRIANGLE";

/// WGSL constant for candidate intersection type: AABB.
pub const WGSL_RAY_QUERY_CANDIDATE_AABB: &str = "RAY_QUERY_CANDIDATE_INTERSECTION_TYPE_AABB";

// ---------------------------------------------------------------------------
// Ray Query Function Enumeration
// ---------------------------------------------------------------------------

/// WGSL ray query functions available in wgpu 25.x.
///
/// This enumeration covers all ray query intrinsic functions:
/// - Initialization and traversal control
/// - Candidate intersection accessors (during traversal)
/// - Committed intersection accessors (after traversal)
///
/// # Example
///
/// ```ignore
/// let func = RayQueryFunction::Initialize;
/// println!("WGSL name: {}", func.wgsl_name());
/// println!("Return type: {}", func.return_type());
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum RayQueryFunction {
    // --- Traversal Control ---
    /// Initialize ray query with TLAS, flags, cull mask, and ray.
    Initialize,
    /// Proceed to next intersection candidate. Returns false when done.
    Proceed,
    /// Terminate traversal early.
    Terminate,
    /// Confirm candidate intersection (for procedural/any-hit).
    ConfirmIntersection,

    // --- Candidate Intersection Accessors ---
    /// Get candidate intersection type (triangle or AABB).
    GetCandidateIntersectionType,
    /// Get candidate intersection T parameter.
    GetCandidateIntersectionT,
    /// Get candidate intersection instance ID.
    GetCandidateIntersectionInstanceId,
    /// Get candidate intersection primitive index.
    GetCandidateIntersectionPrimitiveIndex,
    /// Get candidate intersection barycentrics.
    GetCandidateIntersectionBarycentrics,
    /// Get candidate intersection object-to-world transform.
    GetCandidateIntersectionObjectToWorld,

    // --- Committed Intersection Accessors ---
    /// Get committed intersection type (none, triangle, or generated).
    GetCommittedIntersectionType,
    /// Get committed intersection T parameter.
    GetCommittedIntersectionT,
    /// Get committed intersection instance ID.
    GetCommittedIntersectionInstanceId,
    /// Get committed intersection primitive index.
    GetCommittedIntersectionPrimitiveIndex,
    /// Get committed intersection barycentrics.
    GetCommittedIntersectionBarycentrics,
    /// Get committed intersection front face flag.
    GetCommittedIntersectionFrontFace,
    /// Get committed intersection object-to-world transform.
    GetCommittedIntersectionObjectToWorld,
    /// Get committed intersection world-to-object transform.
    GetCommittedIntersectionWorldToObject,
}

impl RayQueryFunction {
    /// Get the WGSL function name.
    pub fn wgsl_name(&self) -> &'static str {
        match self {
            Self::Initialize => "rayQueryInitialize",
            Self::Proceed => "rayQueryProceed",
            Self::Terminate => "rayQueryTerminate",
            Self::ConfirmIntersection => "rayQueryConfirmIntersection",
            Self::GetCandidateIntersectionType => "rayQueryGetCandidateIntersectionType",
            Self::GetCandidateIntersectionT => "rayQueryGetCandidateIntersectionT",
            Self::GetCandidateIntersectionInstanceId => "rayQueryGetCandidateIntersectionInstanceId",
            Self::GetCandidateIntersectionPrimitiveIndex => "rayQueryGetCandidateIntersectionPrimitiveIndex",
            Self::GetCandidateIntersectionBarycentrics => "rayQueryGetCandidateIntersectionBarycentrics",
            Self::GetCandidateIntersectionObjectToWorld => "rayQueryGetCandidateIntersectionObjectToWorld",
            Self::GetCommittedIntersectionType => "rayQueryGetCommittedIntersectionType",
            Self::GetCommittedIntersectionT => "rayQueryGetCommittedIntersectionT",
            Self::GetCommittedIntersectionInstanceId => "rayQueryGetCommittedIntersectionInstanceId",
            Self::GetCommittedIntersectionPrimitiveIndex => "rayQueryGetCommittedIntersectionPrimitiveIndex",
            Self::GetCommittedIntersectionBarycentrics => "rayQueryGetCommittedIntersectionBarycentrics",
            Self::GetCommittedIntersectionFrontFace => "rayQueryGetCommittedIntersectionFrontFace",
            Self::GetCommittedIntersectionObjectToWorld => "rayQueryGetCommittedIntersectionObjectToWorld",
            Self::GetCommittedIntersectionWorldToObject => "rayQueryGetCommittedIntersectionWorldToObject",
        }
    }

    /// Get the WGSL return type for this function.
    ///
    /// Returns "void" for functions with no return value.
    pub fn return_type(&self) -> &'static str {
        match self {
            Self::Initialize => "void",
            Self::Proceed => "bool",
            Self::Terminate => "void",
            Self::ConfirmIntersection => "void",
            Self::GetCandidateIntersectionType => "u32",
            Self::GetCandidateIntersectionT => "f32",
            Self::GetCandidateIntersectionInstanceId => "u32",
            Self::GetCandidateIntersectionPrimitiveIndex => "u32",
            Self::GetCandidateIntersectionBarycentrics => "vec2<f32>",
            Self::GetCandidateIntersectionObjectToWorld => "mat4x3<f32>",
            Self::GetCommittedIntersectionType => "u32",
            Self::GetCommittedIntersectionT => "f32",
            Self::GetCommittedIntersectionInstanceId => "u32",
            Self::GetCommittedIntersectionPrimitiveIndex => "u32",
            Self::GetCommittedIntersectionBarycentrics => "vec2<f32>",
            Self::GetCommittedIntersectionFrontFace => "bool",
            Self::GetCommittedIntersectionObjectToWorld => "mat4x3<f32>",
            Self::GetCommittedIntersectionWorldToObject => "mat4x3<f32>",
        }
    }

    /// Check if this function is a traversal control function.
    pub fn is_traversal_control(&self) -> bool {
        matches!(
            self,
            Self::Initialize | Self::Proceed | Self::Terminate | Self::ConfirmIntersection
        )
    }

    /// Check if this function accesses candidate intersection data.
    pub fn is_candidate_accessor(&self) -> bool {
        matches!(
            self,
            Self::GetCandidateIntersectionType
                | Self::GetCandidateIntersectionT
                | Self::GetCandidateIntersectionInstanceId
                | Self::GetCandidateIntersectionPrimitiveIndex
                | Self::GetCandidateIntersectionBarycentrics
                | Self::GetCandidateIntersectionObjectToWorld
        )
    }

    /// Check if this function accesses committed intersection data.
    pub fn is_committed_accessor(&self) -> bool {
        matches!(
            self,
            Self::GetCommittedIntersectionType
                | Self::GetCommittedIntersectionT
                | Self::GetCommittedIntersectionInstanceId
                | Self::GetCommittedIntersectionPrimitiveIndex
                | Self::GetCommittedIntersectionBarycentrics
                | Self::GetCommittedIntersectionFrontFace
                | Self::GetCommittedIntersectionObjectToWorld
                | Self::GetCommittedIntersectionWorldToObject
        )
    }

    /// Get all ray query functions.
    pub fn all() -> &'static [RayQueryFunction] {
        &[
            Self::Initialize,
            Self::Proceed,
            Self::Terminate,
            Self::ConfirmIntersection,
            Self::GetCandidateIntersectionType,
            Self::GetCandidateIntersectionT,
            Self::GetCandidateIntersectionInstanceId,
            Self::GetCandidateIntersectionPrimitiveIndex,
            Self::GetCandidateIntersectionBarycentrics,
            Self::GetCandidateIntersectionObjectToWorld,
            Self::GetCommittedIntersectionType,
            Self::GetCommittedIntersectionT,
            Self::GetCommittedIntersectionInstanceId,
            Self::GetCommittedIntersectionPrimitiveIndex,
            Self::GetCommittedIntersectionBarycentrics,
            Self::GetCommittedIntersectionFrontFace,
            Self::GetCommittedIntersectionObjectToWorld,
            Self::GetCommittedIntersectionWorldToObject,
        ]
    }
}

impl std::fmt::Display for RayQueryFunction {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.wgsl_name())
    }
}

// ---------------------------------------------------------------------------
// Intersection Types
// ---------------------------------------------------------------------------

/// Committed intersection type returned by ray query.
///
/// After traversal completes, this indicates what type of intersection
/// was found (if any).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
pub enum IntersectionType {
    /// No intersection found.
    #[default]
    None,
    /// Triangle geometry intersection.
    Triangle,
    /// AABB/procedural geometry intersection (generated by any-hit).
    Aabb,
}

impl IntersectionType {
    /// Get the WGSL constant name for this intersection type.
    pub fn wgsl_constant(&self) -> &'static str {
        match self {
            Self::None => WGSL_RAY_QUERY_COMMITTED_NONE,
            Self::Triangle => WGSL_RAY_QUERY_COMMITTED_TRIANGLE,
            Self::Aabb => WGSL_RAY_QUERY_COMMITTED_AABB,
        }
    }

    /// Check if this represents a valid hit (not None).
    pub fn is_hit(&self) -> bool {
        !matches!(self, Self::None)
    }

    /// Check if this is a triangle intersection.
    pub fn is_triangle(&self) -> bool {
        matches!(self, Self::Triangle)
    }

    /// Check if this is an AABB/procedural intersection.
    pub fn is_aabb(&self) -> bool {
        matches!(self, Self::Aabb)
    }
}

impl std::fmt::Display for IntersectionType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::None => write!(f, "None"),
            Self::Triangle => write!(f, "Triangle"),
            Self::Aabb => write!(f, "AABB"),
        }
    }
}

/// Candidate intersection type during ray query traversal.
///
/// During traversal (inside the `rayQueryProceed` loop), this indicates
/// what type of candidate intersection is being processed.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum CandidateIntersectionType {
    /// Triangle geometry candidate.
    Triangle,
    /// AABB/procedural geometry candidate.
    Aabb,
}

impl CandidateIntersectionType {
    /// Get the WGSL constant name for this candidate type.
    pub fn wgsl_constant(&self) -> &'static str {
        match self {
            Self::Triangle => WGSL_RAY_QUERY_CANDIDATE_TRIANGLE,
            Self::Aabb => WGSL_RAY_QUERY_CANDIDATE_AABB,
        }
    }

    /// Check if this is a triangle candidate.
    pub fn is_triangle(&self) -> bool {
        matches!(self, Self::Triangle)
    }

    /// Check if this is an AABB candidate.
    pub fn is_aabb(&self) -> bool {
        matches!(self, Self::Aabb)
    }
}

impl std::fmt::Display for CandidateIntersectionType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Triangle => write!(f, "Triangle"),
            Self::Aabb => write!(f, "AABB"),
        }
    }
}

// ---------------------------------------------------------------------------
// Hit Information
// ---------------------------------------------------------------------------

/// Extracted hit data from ray query committed intersection.
///
/// This structure holds the essential intersection data extracted from
/// a successful ray query. It matches the data accessible via the
/// `rayQueryGetCommittedIntersection*` WGSL functions.
///
/// # Memory Layout
///
/// - Size: 20 bytes (5 * 4 bytes, with bool as u32 for alignment)
/// - Alignment: 4 bytes
///
/// # Example
///
/// ```ignore
/// let hit = HitInfo {
///     t: 5.0,
///     instance_id: 0,
///     primitive_id: 42,
///     front_face: true,
///     barycentrics: [0.3, 0.3],
/// };
///
/// // Compute hit position
/// let hit_position = ray.point_at(hit.t);
///
/// // Compute interpolation weights (for vertex attributes)
/// let w0 = 1.0 - hit.barycentrics[0] - hit.barycentrics[1];
/// let w1 = hit.barycentrics[0];
/// let w2 = hit.barycentrics[1];
/// ```
#[repr(C)]
#[derive(Clone, Copy, Debug, PartialEq)]
pub struct HitInfo {
    /// Distance along ray to intersection point.
    pub t: f32,
    /// Instance ID of the hit geometry.
    pub instance_id: u32,
    /// Primitive (triangle) index within the instance.
    pub primitive_id: u32,
    /// Whether the front face was hit.
    pub front_face: bool,
    /// Barycentric coordinates of hit point within triangle.
    /// `[u, v]` where `w = 1 - u - v`.
    pub barycentrics: [f32; 2],
}

impl HitInfo {
    /// Create a new hit info with the given values.
    pub fn new(
        t: f32,
        instance_id: u32,
        primitive_id: u32,
        front_face: bool,
        barycentrics: [f32; 2],
    ) -> Self {
        Self {
            t,
            instance_id,
            primitive_id,
            front_face,
            barycentrics,
        }
    }

    /// Create a "no hit" marker with invalid values.
    pub fn no_hit() -> Self {
        Self {
            t: f32::MAX,
            instance_id: u32::MAX,
            primitive_id: u32::MAX,
            front_face: false,
            barycentrics: [0.0, 0.0],
        }
    }

    /// Check if this represents a valid hit.
    pub fn is_hit(&self) -> bool {
        self.t < f32::MAX && self.instance_id != u32::MAX
    }

    /// Get barycentric weight for vertex 0.
    pub fn w0(&self) -> f32 {
        1.0 - self.barycentrics[0] - self.barycentrics[1]
    }

    /// Get barycentric weight for vertex 1 (same as barycentrics[0]).
    pub fn w1(&self) -> f32 {
        self.barycentrics[0]
    }

    /// Get barycentric weight for vertex 2 (same as barycentrics[1]).
    pub fn w2(&self) -> f32 {
        self.barycentrics[1]
    }

    /// Interpolate vertex attribute using barycentric coordinates.
    ///
    /// Given attribute values at triangle vertices (v0, v1, v2),
    /// returns the interpolated value at the hit point.
    pub fn interpolate(&self, v0: f32, v1: f32, v2: f32) -> f32 {
        self.w0() * v0 + self.w1() * v1 + self.w2() * v2
    }

    /// Interpolate 3D vector attribute using barycentric coordinates.
    pub fn interpolate_vec3(&self, v0: [f32; 3], v1: [f32; 3], v2: [f32; 3]) -> [f32; 3] {
        let w0 = self.w0();
        let w1 = self.w1();
        let w2 = self.w2();
        [
            w0 * v0[0] + w1 * v1[0] + w2 * v2[0],
            w0 * v0[1] + w1 * v1[1] + w2 * v2[1],
            w0 * v0[2] + w1 * v1[2] + w2 * v2[2],
        ]
    }
}

impl Default for HitInfo {
    fn default() -> Self {
        Self::no_hit()
    }
}

// ---------------------------------------------------------------------------
// Ray Query WGSL Generator
// ---------------------------------------------------------------------------

/// WGSL code generator for ray query operations.
///
/// Generates complete WGSL code snippets and shader functions for
/// various ray tracing patterns including shadow queries, nearest hit,
/// and any-hit processing.
///
/// # Example
///
/// ```ignore
/// let generator = RayQueryWgslGenerator::new(TraceConfig::shadow(), 0, 0);
///
/// // Generate shadow query function
/// let shadow_code = generator.generate_shadow_query();
///
/// // Generate complete shadow shader
/// let shader = generator.generate_complete_shadow_shader();
/// ```
#[derive(Debug, Clone)]
pub struct RayQueryWgslGenerator {
    /// Trace configuration (flags, cull mask, query type).
    config: TraceConfig,
    /// TLAS binding index.
    tlas_binding: u32,
    /// TLAS bind group index.
    tlas_group: u32,
}

impl RayQueryWgslGenerator {
    /// Create a new WGSL generator.
    ///
    /// # Arguments
    ///
    /// * `config` - Trace configuration for ray flags and behavior
    /// * `tlas_binding` - Binding index for the TLAS
    /// * `tlas_group` - Bind group index for the TLAS
    pub fn new(config: TraceConfig, tlas_binding: u32, tlas_group: u32) -> Self {
        Self {
            config,
            tlas_binding,
            tlas_group,
        }
    }

    /// Create a generator for shadow ray queries.
    pub fn shadow(tlas_binding: u32, tlas_group: u32) -> Self {
        Self::new(TraceConfig::shadow(), tlas_binding, tlas_group)
    }

    /// Create a generator for primary (nearest hit) queries.
    pub fn primary(tlas_binding: u32, tlas_group: u32) -> Self {
        Self::new(TraceConfig::primary(), tlas_binding, tlas_group)
    }

    /// Get the trace configuration.
    pub fn config(&self) -> &TraceConfig {
        &self.config
    }

    /// Get the TLAS binding index.
    pub fn tlas_binding(&self) -> u32 {
        self.tlas_binding
    }

    /// Get the TLAS bind group index.
    pub fn tlas_group(&self) -> u32 {
        self.tlas_group
    }

    // -------------------------------------------------------------------------
    // Individual Function Generators
    // -------------------------------------------------------------------------

    /// Generate WGSL code for ray query initialization.
    ///
    /// Produces a `rayQueryInitialize` call with the configured flags and cull mask.
    pub fn generate_initialize(&self) -> String {
        format!(
            "rayQueryInitialize(&rq, tlas, {}u, {}u, ray);",
            self.config.flags.to_wgsl_value(),
            self.config.cull_mask
        )
    }

    /// Generate WGSL code for the traversal loop.
    ///
    /// # Arguments
    ///
    /// * `body` - Code to execute inside the loop for candidate processing
    ///
    /// # Returns
    ///
    /// Complete while loop with `rayQueryProceed` and the provided body.
    pub fn generate_traverse_loop(&self, body: &str) -> String {
        if body.is_empty() {
            "while (rayQueryProceed(&rq)) {}".to_string()
        } else {
            format!(
                "while (rayQueryProceed(&rq)) {{\n    {}\n}}",
                body.replace('\n', "\n    ")
            )
        }
    }

    /// Generate WGSL code to extract committed hit information.
    ///
    /// Returns code that extracts all committed intersection data into local variables.
    pub fn generate_get_committed_hit(&self) -> String {
        r#"let hit_type = rayQueryGetCommittedIntersectionType(&rq);
let hit_t = rayQueryGetCommittedIntersectionT(&rq);
let hit_instance_id = rayQueryGetCommittedIntersectionInstanceId(&rq);
let hit_primitive_id = rayQueryGetCommittedIntersectionPrimitiveIndex(&rq);
let hit_barycentrics = rayQueryGetCommittedIntersectionBarycentrics(&rq);
let hit_front_face = rayQueryGetCommittedIntersectionFrontFace(&rq);
let hit_object_to_world = rayQueryGetCommittedIntersectionObjectToWorld(&rq);
let hit_world_to_object = rayQueryGetCommittedIntersectionWorldToObject(&rq);"#
            .to_string()
    }

    /// Generate WGSL code to extract candidate hit information.
    ///
    /// Returns code that extracts candidate intersection data into local variables.
    pub fn generate_get_candidate_hit(&self) -> String {
        r#"let candidate_type = rayQueryGetCandidateIntersectionType(&rq);
let candidate_t = rayQueryGetCandidateIntersectionT(&rq);
let candidate_instance_id = rayQueryGetCandidateIntersectionInstanceId(&rq);
let candidate_primitive_id = rayQueryGetCandidateIntersectionPrimitiveIndex(&rq);
let candidate_barycentrics = rayQueryGetCandidateIntersectionBarycentrics(&rq);
let candidate_object_to_world = rayQueryGetCandidateIntersectionObjectToWorld(&rq);"#
            .to_string()
    }

    // -------------------------------------------------------------------------
    // Complete Pattern Generators
    // -------------------------------------------------------------------------

    /// Generate WGSL code for a shadow ray query.
    ///
    /// Shadow queries only need to know if any intersection exists,
    /// not the details of the closest hit.
    pub fn generate_shadow_query(&self) -> String {
        let flags = RayFlags::shadow().to_wgsl_value();
        format!(
            r#"// Shadow ray query
var rq: ray_query;
rayQueryInitialize(&rq, tlas, {}u, {}u, ray);
while (rayQueryProceed(&rq)) {{}}
let in_shadow = rayQueryGetCommittedIntersectionType(&rq) != {};"#,
            flags, self.config.cull_mask, WGSL_RAY_QUERY_COMMITTED_NONE
        )
    }

    /// Generate WGSL code for a nearest hit ray query.
    ///
    /// Nearest hit queries find the closest intersection and extract
    /// complete hit information.
    pub fn generate_nearest_hit_query(&self) -> String {
        format!(
            r#"// Nearest hit ray query
var rq: ray_query;
{}
{}

// Check if we hit something
let hit_type = rayQueryGetCommittedIntersectionType(&rq);
if (hit_type == {}) {{
    // Extract hit information
    let hit_t = rayQueryGetCommittedIntersectionT(&rq);
    let hit_instance_id = rayQueryGetCommittedIntersectionInstanceId(&rq);
    let hit_primitive_id = rayQueryGetCommittedIntersectionPrimitiveIndex(&rq);
    let hit_barycentrics = rayQueryGetCommittedIntersectionBarycentrics(&rq);
    let hit_front_face = rayQueryGetCommittedIntersectionFrontFace(&rq);
}}"#,
            self.generate_initialize(),
            self.generate_traverse_loop(""),
            WGSL_RAY_QUERY_COMMITTED_TRIANGLE
        )
    }

    /// Generate WGSL code for an any-hit ray query with custom processing.
    ///
    /// Any-hit queries allow custom processing of each candidate intersection,
    /// useful for alpha testing, procedural geometry, or collecting all hits.
    ///
    /// # Arguments
    ///
    /// * `any_hit_body` - Code to execute for each candidate intersection
    pub fn generate_any_hit_query(&self, any_hit_body: &str) -> String {
        let body = format!(
            r#"let candidate_type = rayQueryGetCandidateIntersectionType(&rq);
if (candidate_type == {}) {{
    // AABB/procedural geometry - evaluate and potentially confirm
    {}
    rayQueryConfirmIntersection(&rq);
}} else {{
    // Triangle geometry - process and potentially reject
    {}
}}"#,
            WGSL_RAY_QUERY_CANDIDATE_AABB,
            any_hit_body,
            any_hit_body
        );

        format!(
            r#"// Any-hit ray query with custom processing
var rq: ray_query;
{}
{}

// Get final committed hit
let hit_type = rayQueryGetCommittedIntersectionType(&rq);"#,
            self.generate_initialize(),
            self.generate_traverse_loop(&body)
        )
    }

    // -------------------------------------------------------------------------
    // Full Shader Helpers
    // -------------------------------------------------------------------------

    /// Generate a complete shadow ray compute shader.
    ///
    /// Produces a full WGSL compute shader that can trace shadow rays
    /// from a buffer of ray origins/directions and output shadow factors.
    pub fn generate_complete_shadow_shader(&self) -> String {
        let flags = RayFlags::shadow().to_wgsl_value();
        format!(
            r#"// WGSL Shadow Ray Compute Shader
// Generated by RayQueryWgslGenerator

// Acceleration structure binding
@group({group}) @binding({binding}) var tlas: acceleration_structure;

// Input: ray data
struct RayData {{
    origin: vec3<f32>,
    t_min: f32,
    direction: vec3<f32>,
    t_max: f32,
}}

@group(0) @binding(1) var<storage, read> rays: array<RayData>;

// Output: shadow factors (0.0 = shadowed, 1.0 = lit)
@group(0) @binding(2) var<storage, read_write> shadow_factors: array<f32>;

@compute @workgroup_size(64)
fn main(@builtin(global_invocation_id) global_id: vec3<u32>) {{
    let ray_idx = global_id.x;
    if (ray_idx >= arrayLength(&rays)) {{
        return;
    }}

    let ray_data = rays[ray_idx];

    // Construct ray descriptor
    var ray: RayDesc;
    ray.origin = ray_data.origin;
    ray.t_min = ray_data.t_min;
    ray.direction = ray_data.direction;
    ray.t_max = ray_data.t_max;

    // Trace shadow ray
    var rq: ray_query;
    rayQueryInitialize(&rq, tlas, {flags}u, {cull_mask}u, ray);
    while (rayQueryProceed(&rq)) {{}}

    // Output shadow factor
    let hit = rayQueryGetCommittedIntersectionType(&rq) != {none};
    shadow_factors[ray_idx] = select(1.0, 0.0, hit);
}}

// RayDesc struct for WGSL
struct RayDesc {{
    origin: vec3<f32>,
    t_min: f32,
    direction: vec3<f32>,
    t_max: f32,
}}"#,
            group = self.tlas_group,
            binding = self.tlas_binding,
            flags = flags,
            cull_mask = self.config.cull_mask,
            none = WGSL_RAY_QUERY_COMMITTED_NONE
        )
    }

    /// Generate a complete primary ray compute shader.
    ///
    /// Produces a full WGSL compute shader that traces primary rays
    /// and outputs hit information.
    pub fn generate_complete_primary_shader(&self) -> String {
        format!(
            r#"// WGSL Primary Ray Compute Shader
// Generated by RayQueryWgslGenerator

// Acceleration structure binding
@group({group}) @binding({binding}) var tlas: acceleration_structure;

// Input: ray data
struct RayData {{
    origin: vec3<f32>,
    t_min: f32,
    direction: vec3<f32>,
    t_max: f32,
}}

@group(0) @binding(1) var<storage, read> rays: array<RayData>;

// Output: hit information
struct HitOutput {{
    t: f32,
    instance_id: u32,
    primitive_id: u32,
    front_face: u32,
    bary_u: f32,
    bary_v: f32,
    _padding: vec2<f32>,
}}

@group(0) @binding(2) var<storage, read_write> hits: array<HitOutput>;

@compute @workgroup_size(64)
fn main(@builtin(global_invocation_id) global_id: vec3<u32>) {{
    let ray_idx = global_id.x;
    if (ray_idx >= arrayLength(&rays)) {{
        return;
    }}

    let ray_data = rays[ray_idx];

    // Construct ray descriptor
    var ray: RayDesc;
    ray.origin = ray_data.origin;
    ray.t_min = ray_data.t_min;
    ray.direction = ray_data.direction;
    ray.t_max = ray_data.t_max;

    // Trace primary ray
    var rq: ray_query;
    {init}
    {traverse}

    // Extract hit information
    var hit: HitOutput;
    let hit_type = rayQueryGetCommittedIntersectionType(&rq);
    if (hit_type == {triangle}) {{
        hit.t = rayQueryGetCommittedIntersectionT(&rq);
        hit.instance_id = rayQueryGetCommittedIntersectionInstanceId(&rq);
        hit.primitive_id = rayQueryGetCommittedIntersectionPrimitiveIndex(&rq);
        hit.front_face = select(0u, 1u, rayQueryGetCommittedIntersectionFrontFace(&rq));
        let bary = rayQueryGetCommittedIntersectionBarycentrics(&rq);
        hit.bary_u = bary.x;
        hit.bary_v = bary.y;
    }} else {{
        // No hit - mark with invalid values
        hit.t = 3.402823e+38; // f32::MAX
        hit.instance_id = 0xFFFFFFFFu;
        hit.primitive_id = 0xFFFFFFFFu;
        hit.front_face = 0u;
        hit.bary_u = 0.0;
        hit.bary_v = 0.0;
    }}
    hit._padding = vec2<f32>(0.0, 0.0);

    hits[ray_idx] = hit;
}}

// RayDesc struct for WGSL
struct RayDesc {{
    origin: vec3<f32>,
    t_min: f32,
    direction: vec3<f32>,
    t_max: f32,
}}"#,
            group = self.tlas_group,
            binding = self.tlas_binding,
            init = self.generate_initialize(),
            traverse = self.generate_traverse_loop(""),
            triangle = WGSL_RAY_QUERY_COMMITTED_TRIANGLE
        )
    }

    /// Generate WGSL bindings for the TLAS.
    pub fn generate_bindings(&self) -> String {
        generate_tlas_binding_wgsl(self.tlas_group, self.tlas_binding)
    }
}

impl Default for RayQueryWgslGenerator {
    fn default() -> Self {
        Self::new(TraceConfig::default(), 0, 0)
    }
}

// === End T-WGPU-P5.6.2: Ray Query WGSL API ===

// === T-WGPU-P5.6.3: Ray Flags Documentation and Usage Patterns ===

// ---------------------------------------------------------------------------
// Ray Flag Usage Documentation
// ---------------------------------------------------------------------------

/// Documentation for a ray flag's intended use case.
///
/// Provides detailed information about when and why to use specific ray flags,
/// including performance implications.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RayFlagUsage {
    /// The flag this usage documents.
    pub flag: RayFlags,
    /// Short description of the primary use case.
    pub use_case: &'static str,
    /// Detailed explanation of the flag's behavior.
    pub description: &'static str,
    /// Optional performance notes and recommendations.
    pub performance_note: Option<&'static str>,
}

impl RayFlagUsage {
    /// Get documentation for all ray flags.
    ///
    /// Returns a slice containing usage information for every flag in `RayFlags`.
    pub fn all_usages() -> &'static [RayFlagUsage] {
        &[
            RayFlagUsage {
                flag: RayFlags::NONE,
                use_case: "Default ray traversal",
                description: "No special behavior. The ray will traverse the acceleration \
                    structure normally, testing all geometry and reporting the closest hit.",
                performance_note: None,
            },
            RayFlagUsage {
                flag: RayFlags::FORCE_OPAQUE,
                use_case: "Shadow rays, ambient occlusion",
                description: "Forces all geometry to be treated as opaque, ignoring the \
                    opacity flags on individual geometry instances. Any-hit shaders will \
                    not be invoked. This is useful for shadow rays where you only care \
                    about whether something blocks light, not about transparency.",
                performance_note: Some(
                    "Significant performance improvement for shadow rays as it skips \
                    any-hit shader invocations and alpha testing."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::FORCE_NON_OPAQUE,
                use_case: "Transparency testing, stained glass",
                description: "Forces all geometry to be treated as non-opaque. All \
                    intersections will invoke the any-hit shader (if present in a ray \
                    tracing pipeline). Useful when you need to process every intersection \
                    for transparency accumulation.",
                performance_note: Some(
                    "Slower than opaque traversal due to any-hit shader invocations. \
                    Use sparingly and only when transparency handling is required."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::TERMINATE_ON_FIRST_HIT,
                use_case: "Shadow queries, visibility tests",
                description: "Terminates traversal immediately upon finding any hit. \
                    The first intersection found (which may not be the closest) is \
                    returned. Ideal for boolean occlusion queries.",
                performance_note: Some(
                    "Major performance win for shadow/occlusion queries. Can be 2-10x \
                    faster than finding the closest hit depending on scene complexity."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::SKIP_CLOSEST_HIT_SHADER,
                use_case: "Ray tracing pipeline optimization",
                description: "Skips the closest-hit shader invocation. Only meaningful \
                    in full ray tracing pipelines (not ray queries). Useful when you \
                    only need hit information for traversal decisions, not shading.",
                performance_note: Some(
                    "Only affects ray tracing pipelines. Has no effect on ray queries."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::CULL_FRONT_FACING,
                use_case: "Inside-out rendering, refraction",
                description: "Culls front-facing triangles (counter-clockwise winding). \
                    Only back-facing triangles will be tested. Useful for rendering \
                    the inside of objects or for certain refraction effects.",
                performance_note: Some(
                    "Reduces intersection tests by ~50% for closed meshes, but may \
                    cause visual artifacts if meshes are not watertight."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::CULL_BACK_FACING,
                use_case: "Standard rendering, closed meshes",
                description: "Culls back-facing triangles (clockwise winding). Only \
                    front-facing triangles will be tested. This is the standard \
                    culling mode for rendering the outside of closed meshes.",
                performance_note: Some(
                    "Reduces intersection tests by ~50% for closed meshes. Recommended \
                    for primary rays on watertight geometry."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::CULL_OPAQUE,
                use_case: "Transparent-only passes",
                description: "Skips all opaque geometry during traversal. Only non-opaque \
                    (transparent) geometry will be tested. Useful for separate \
                    transparent rendering passes.",
                performance_note: Some(
                    "Performance depends on the ratio of opaque to transparent geometry. \
                    Most beneficial when transparent geometry is sparse."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::CULL_NON_OPAQUE,
                use_case: "Opaque-only passes",
                description: "Skips all non-opaque (transparent) geometry during traversal. \
                    Only opaque geometry will be tested. Useful for depth pre-passes \
                    or when transparency is handled separately.",
                performance_note: Some(
                    "Can significantly speed up primary ray passes by skipping expensive \
                    transparency calculations."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::SKIP_TRIANGLES,
                use_case: "Procedural geometry only",
                description: "Skips all triangle geometry, only testing AABB (procedural) \
                    geometry. Useful when you have a scene with mixed geometry types \
                    and only want to test procedural volumes.",
                performance_note: Some(
                    "Avoid using with SKIP_AABBS as no geometry will be tested. \
                    Useful for SDF or volumetric-only ray marching."
                ),
            },
            RayFlagUsage {
                flag: RayFlags::SKIP_AABBS,
                use_case: "Triangle geometry only",
                description: "Skips all AABB (procedural) geometry, only testing triangles. \
                    Useful when you have mixed geometry and want to focus on mesh \
                    intersections without procedural overhead.",
                performance_note: Some(
                    "Default choice for pure triangle mesh scenes. Avoids unnecessary \
                    AABB intersection tests."
                ),
            },
        ]
    }

    /// Find usage documentation for a specific flag.
    pub fn for_flag(flag: RayFlags) -> Option<&'static RayFlagUsage> {
        Self::all_usages().iter().find(|u| u.flag == flag)
    }

    /// Get usage documentation for flags contained in a combined flag value.
    pub fn for_combined_flags(flags: RayFlags) -> Vec<&'static RayFlagUsage> {
        Self::all_usages()
            .iter()
            .filter(|u| u.flag != RayFlags::NONE && flags.contains(u.flag))
            .collect()
    }
}

// ---------------------------------------------------------------------------
// Ray Flag Presets
// ---------------------------------------------------------------------------

/// Predefined ray flag combinations for common rendering scenarios.
///
/// These presets provide optimized flag configurations for typical ray tracing
/// use cases, making it easy to select the right flags without understanding
/// every individual flag.
///
/// # Example
///
/// ```ignore
/// use crate::blas::{RayFlagPreset, RayFlags};
///
/// // Get flags for shadow rays
/// let shadow_flags = RayFlagPreset::Shadow.flags();
///
/// // Get description of the preset
/// let desc = RayFlagPreset::Shadow.description();
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum RayFlagPreset {
    /// Shadow ray preset: FORCE_OPAQUE | TERMINATE_ON_FIRST_HIT
    ///
    /// Optimized for determining whether a point is in shadow. Doesn't need
    /// the closest hit, just whether anything blocks the light.
    Shadow,

    /// Primary ray preset: NONE or CULL_BACK_FACING
    ///
    /// Standard ray for finding visible surfaces. Uses default flags or
    /// back-face culling for closed meshes.
    PrimaryRay,

    /// Reflection ray preset: CULL_BACK_FACING
    ///
    /// Optimized for mirror reflections. Assumes reflecting off front-facing
    /// surfaces into the scene.
    Reflection,

    /// Refraction ray preset: NONE
    ///
    /// No culling - needs to hit both entry and exit points of transparent
    /// objects to properly calculate refraction.
    Refraction,

    /// Ambient occlusion preset: FORCE_OPAQUE | TERMINATE_ON_FIRST_HIT
    ///
    /// Similar to shadow rays - only needs to know if anything occludes,
    /// not the exact geometry.
    AmbientOcclusion,

    /// Visibility query preset: FORCE_OPAQUE | TERMINATE_ON_FIRST_HIT | CULL_BACK_FACING
    ///
    /// Fast visibility check for closed meshes. Combines early termination
    /// with back-face culling for maximum performance.
    Visibility,

    /// Procedural-only preset: SKIP_TRIANGLES
    ///
    /// Only test AABB/procedural geometry. Useful for SDF ray marching or
    /// volumetric effects.
    ProceduralOnly,

    /// Triangles-only preset: SKIP_AABBS
    ///
    /// Only test triangle geometry. Standard choice for pure mesh scenes.
    TrianglesOnly,
}

impl RayFlagPreset {
    /// Get the ray flags for this preset.
    pub fn flags(&self) -> RayFlags {
        match self {
            RayFlagPreset::Shadow => {
                RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT
            }
            RayFlagPreset::PrimaryRay => RayFlags::NONE,
            RayFlagPreset::Reflection => RayFlags::CULL_BACK_FACING,
            RayFlagPreset::Refraction => RayFlags::NONE,
            RayFlagPreset::AmbientOcclusion => {
                RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT
            }
            RayFlagPreset::Visibility => {
                RayFlags::FORCE_OPAQUE
                    | RayFlags::TERMINATE_ON_FIRST_HIT
                    | RayFlags::CULL_BACK_FACING
            }
            RayFlagPreset::ProceduralOnly => RayFlags::SKIP_TRIANGLES,
            RayFlagPreset::TrianglesOnly => RayFlags::SKIP_AABBS,
        }
    }

    /// Get a human-readable description of this preset.
    pub fn description(&self) -> &'static str {
        match self {
            RayFlagPreset::Shadow => {
                "Optimized for shadow rays. Uses FORCE_OPAQUE to skip transparency \
                and TERMINATE_ON_FIRST_HIT for early exit. Best for hard shadows."
            }
            RayFlagPreset::PrimaryRay => {
                "Default flags for primary/camera rays. Finds the closest \
                intersection with full geometry testing."
            }
            RayFlagPreset::Reflection => {
                "Optimized for reflection rays. Uses back-face culling since \
                reflections typically hit front-facing surfaces."
            }
            RayFlagPreset::Refraction => {
                "No culling for refraction rays. Needs both entry and exit points \
                of transparent objects for correct refraction calculation."
            }
            RayFlagPreset::AmbientOcclusion => {
                "Optimized for AO rays. Uses early termination since AO only \
                needs to know if anything occludes, not what."
            }
            RayFlagPreset::Visibility => {
                "Maximum performance visibility check. Combines opaque forcing, \
                early termination, and back-face culling."
            }
            RayFlagPreset::ProceduralOnly => {
                "Only tests procedural/AABB geometry. Use for SDF ray marching \
                or volumetric effects without triangle overhead."
            }
            RayFlagPreset::TrianglesOnly => {
                "Only tests triangle geometry. Standard choice for mesh-only \
                scenes without procedural geometry."
            }
        }
    }

    /// Get all available presets.
    pub fn all() -> &'static [RayFlagPreset] {
        &[
            RayFlagPreset::Shadow,
            RayFlagPreset::PrimaryRay,
            RayFlagPreset::Reflection,
            RayFlagPreset::Refraction,
            RayFlagPreset::AmbientOcclusion,
            RayFlagPreset::Visibility,
            RayFlagPreset::ProceduralOnly,
            RayFlagPreset::TrianglesOnly,
        ]
    }

    /// Find a preset that matches the given flags, if any.
    pub fn from_flags(flags: RayFlags) -> Option<RayFlagPreset> {
        Self::all().iter().copied().find(|p| p.flags() == flags)
    }
}

// ---------------------------------------------------------------------------
// Ray Flag Validation
// ---------------------------------------------------------------------------

/// Errors that can occur when validating ray flag combinations.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RayFlagError {
    /// CULL_FRONT_FACING and CULL_BACK_FACING cannot be used together.
    ///
    /// Both flags together would cull all triangles, resulting in no hits.
    ConflictingCullFlags,

    /// FORCE_OPAQUE and FORCE_NON_OPAQUE cannot be used together.
    ///
    /// These flags are mutually exclusive - geometry cannot be both
    /// opaque and non-opaque simultaneously.
    ConflictingOpaqueFlags,

    /// SKIP_TRIANGLES and SKIP_AABBS cannot be used together.
    ///
    /// Both flags together would skip all geometry, resulting in no hits.
    ConflictingSkipFlags,

    /// Warning: flags contain redundant combinations.
    ///
    /// The flags work but contain unnecessary or contradictory elements.
    /// For example, TERMINATE_ON_FIRST_HIT makes CULL_BACK_FACING less
    /// meaningful for shadow queries.
    RedundantFlags {
        /// Description of which flags are redundant.
        reason: &'static str,
    },
}

impl std::fmt::Display for RayFlagError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            RayFlagError::ConflictingCullFlags => {
                write!(
                    f,
                    "CULL_FRONT_FACING and CULL_BACK_FACING cannot be used together"
                )
            }
            RayFlagError::ConflictingOpaqueFlags => {
                write!(
                    f,
                    "FORCE_OPAQUE and FORCE_NON_OPAQUE cannot be used together"
                )
            }
            RayFlagError::ConflictingSkipFlags => {
                write!(
                    f,
                    "SKIP_TRIANGLES and SKIP_AABBS cannot be used together"
                )
            }
            RayFlagError::RedundantFlags { reason } => {
                write!(f, "Redundant flags: {}", reason)
            }
        }
    }
}

impl std::error::Error for RayFlagError {}

/// Validator for ray flag combinations.
///
/// Checks for conflicting or redundant flag combinations and provides
/// suggestions for corrections.
pub struct RayFlagValidator;

impl RayFlagValidator {
    /// Validate a ray flag combination.
    ///
    /// Returns `Ok(())` if the flags are valid, or an error describing
    /// the conflict.
    ///
    /// # Example
    ///
    /// ```ignore
    /// use crate::blas::{RayFlags, RayFlagValidator};
    ///
    /// // Valid combination
    /// let valid = RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT;
    /// assert!(RayFlagValidator::validate(valid).is_ok());
    ///
    /// // Invalid combination
    /// let invalid = RayFlags::CULL_FRONT_FACING | RayFlags::CULL_BACK_FACING;
    /// assert!(RayFlagValidator::validate(invalid).is_err());
    /// ```
    pub fn validate(flags: RayFlags) -> Result<(), RayFlagError> {
        // Check for conflicting cull flags
        if flags.contains(RayFlags::CULL_FRONT_FACING)
            && flags.contains(RayFlags::CULL_BACK_FACING)
        {
            return Err(RayFlagError::ConflictingCullFlags);
        }

        // Check for conflicting opaque flags
        if flags.contains(RayFlags::FORCE_OPAQUE)
            && flags.contains(RayFlags::FORCE_NON_OPAQUE)
        {
            return Err(RayFlagError::ConflictingOpaqueFlags);
        }

        // Check for conflicting skip flags
        if flags.contains(RayFlags::SKIP_TRIANGLES)
            && flags.contains(RayFlags::SKIP_AABBS)
        {
            return Err(RayFlagError::ConflictingSkipFlags);
        }

        Ok(())
    }

    /// Check if flags contain any conflicting combinations.
    pub fn has_conflicting_flags(flags: RayFlags) -> bool {
        Self::validate(flags).is_err()
    }

    /// Check for redundant flag combinations.
    ///
    /// Returns a list of warnings for flags that work but may be suboptimal.
    pub fn check_redundant(flags: RayFlags) -> Vec<RayFlagError> {
        let mut warnings = Vec::new();

        // FORCE_OPAQUE makes CULL_OPAQUE/CULL_NON_OPAQUE less meaningful
        if flags.contains(RayFlags::FORCE_OPAQUE) {
            if flags.contains(RayFlags::CULL_OPAQUE) {
                warnings.push(RayFlagError::RedundantFlags {
                    reason: "FORCE_OPAQUE with CULL_OPAQUE would cull all geometry",
                });
            }
            if flags.contains(RayFlags::CULL_NON_OPAQUE) {
                warnings.push(RayFlagError::RedundantFlags {
                    reason: "CULL_NON_OPAQUE is redundant when FORCE_OPAQUE is set",
                });
            }
        }

        // FORCE_NON_OPAQUE makes CULL_OPAQUE/CULL_NON_OPAQUE less meaningful
        if flags.contains(RayFlags::FORCE_NON_OPAQUE) {
            if flags.contains(RayFlags::CULL_NON_OPAQUE) {
                warnings.push(RayFlagError::RedundantFlags {
                    reason: "FORCE_NON_OPAQUE with CULL_NON_OPAQUE would cull all geometry",
                });
            }
            if flags.contains(RayFlags::CULL_OPAQUE) {
                warnings.push(RayFlagError::RedundantFlags {
                    reason: "CULL_OPAQUE is redundant when FORCE_NON_OPAQUE is set",
                });
            }
        }

        warnings
    }

    /// Suggest a corrected flag combination.
    ///
    /// If the flags have conflicts, this returns a corrected version.
    /// The correction strategy is:
    /// - For cull conflicts: remove CULL_FRONT_FACING (back-face culling is more common)
    /// - For opaque conflicts: keep FORCE_OPAQUE (more common for performance)
    /// - For skip conflicts: remove SKIP_AABBS (triangle-only is more common)
    pub fn suggest_correction(flags: RayFlags) -> RayFlags {
        let mut corrected = flags;

        // Fix cull conflicts by removing front-face culling
        if flags.contains(RayFlags::CULL_FRONT_FACING)
            && flags.contains(RayFlags::CULL_BACK_FACING)
        {
            corrected.remove(RayFlags::CULL_FRONT_FACING);
        }

        // Fix opaque conflicts by keeping FORCE_OPAQUE
        if flags.contains(RayFlags::FORCE_OPAQUE)
            && flags.contains(RayFlags::FORCE_NON_OPAQUE)
        {
            corrected.remove(RayFlags::FORCE_NON_OPAQUE);
        }

        // Fix skip conflicts by removing SKIP_AABBS
        if flags.contains(RayFlags::SKIP_TRIANGLES)
            && flags.contains(RayFlags::SKIP_AABBS)
        {
            corrected.remove(RayFlags::SKIP_AABBS);
        }

        corrected
    }

    /// Get a detailed report of flag analysis.
    pub fn analyze(flags: RayFlags) -> RayFlagAnalysis {
        RayFlagAnalysis {
            flags,
            is_valid: Self::validate(flags).is_ok(),
            errors: Self::validate(flags).err().into_iter().collect(),
            warnings: Self::check_redundant(flags),
            suggested: if Self::has_conflicting_flags(flags) {
                Some(Self::suggest_correction(flags))
            } else {
                None
            },
            matching_preset: RayFlagPreset::from_flags(flags),
        }
    }
}

/// Detailed analysis of ray flag combination.
#[derive(Debug, Clone)]
pub struct RayFlagAnalysis {
    /// The analyzed flags.
    pub flags: RayFlags,
    /// Whether the flags are valid (no conflicts).
    pub is_valid: bool,
    /// List of errors (conflicts) found.
    pub errors: Vec<RayFlagError>,
    /// List of warnings (redundancies) found.
    pub warnings: Vec<RayFlagError>,
    /// Suggested correction if flags are invalid.
    pub suggested: Option<RayFlags>,
    /// Matching preset if flags correspond to a known preset.
    pub matching_preset: Option<RayFlagPreset>,
}

// ---------------------------------------------------------------------------
// Ray Flag Builder
// ---------------------------------------------------------------------------

/// Fluent builder for constructing ray flag combinations.
///
/// Provides a safe, readable way to build ray flag combinations with
/// optional validation.
///
/// # Example
///
/// ```ignore
/// use crate::blas::{RayFlagBuilder, RayFlagPreset};
///
/// // Build from scratch
/// let flags = RayFlagBuilder::new()
///     .force_opaque()
///     .terminate_on_first_hit()
///     .cull_back_facing()
///     .build()
///     .unwrap();
///
/// // Build from preset
/// let flags = RayFlagBuilder::from_preset(RayFlagPreset::Shadow)
///     .cull_back_facing()
///     .build()
///     .unwrap();
/// ```
#[derive(Debug, Clone)]
pub struct RayFlagBuilder {
    flags: RayFlags,
}

impl RayFlagBuilder {
    /// Create a new builder with no flags set.
    pub fn new() -> Self {
        Self {
            flags: RayFlags::NONE,
        }
    }

    /// Create a builder starting from a preset.
    pub fn from_preset(preset: RayFlagPreset) -> Self {
        Self {
            flags: preset.flags(),
        }
    }

    /// Create a builder from existing flags.
    pub fn from_flags(flags: RayFlags) -> Self {
        Self { flags }
    }

    /// Add FORCE_OPAQUE flag.
    pub fn force_opaque(mut self) -> Self {
        self.flags |= RayFlags::FORCE_OPAQUE;
        self
    }

    /// Add FORCE_NON_OPAQUE flag.
    pub fn force_non_opaque(mut self) -> Self {
        self.flags |= RayFlags::FORCE_NON_OPAQUE;
        self
    }

    /// Add TERMINATE_ON_FIRST_HIT flag.
    pub fn terminate_on_first_hit(mut self) -> Self {
        self.flags |= RayFlags::TERMINATE_ON_FIRST_HIT;
        self
    }

    /// Add SKIP_CLOSEST_HIT_SHADER flag.
    pub fn skip_closest_hit_shader(mut self) -> Self {
        self.flags |= RayFlags::SKIP_CLOSEST_HIT_SHADER;
        self
    }

    /// Add CULL_BACK_FACING flag.
    pub fn cull_back_facing(mut self) -> Self {
        self.flags |= RayFlags::CULL_BACK_FACING;
        self
    }

    /// Add CULL_FRONT_FACING flag.
    pub fn cull_front_facing(mut self) -> Self {
        self.flags |= RayFlags::CULL_FRONT_FACING;
        self
    }

    /// Add CULL_OPAQUE flag.
    pub fn cull_opaque(mut self) -> Self {
        self.flags |= RayFlags::CULL_OPAQUE;
        self
    }

    /// Add CULL_NON_OPAQUE flag.
    pub fn cull_non_opaque(mut self) -> Self {
        self.flags |= RayFlags::CULL_NON_OPAQUE;
        self
    }

    /// Add SKIP_TRIANGLES flag.
    pub fn skip_triangles(mut self) -> Self {
        self.flags |= RayFlags::SKIP_TRIANGLES;
        self
    }

    /// Add SKIP_AABBS flag.
    pub fn skip_aabbs(mut self) -> Self {
        self.flags |= RayFlags::SKIP_AABBS;
        self
    }

    /// Remove a specific flag.
    pub fn without(mut self, flag: RayFlags) -> Self {
        self.flags.remove(flag);
        self
    }

    /// Clear all flags.
    pub fn clear(mut self) -> Self {
        self.flags = RayFlags::NONE;
        self
    }

    /// Build the flags with validation.
    ///
    /// Returns an error if the flag combination is invalid.
    pub fn build(self) -> Result<RayFlags, RayFlagError> {
        RayFlagValidator::validate(self.flags)?;
        Ok(self.flags)
    }

    /// Build the flags without validation.
    ///
    /// Use this when you know the flags are valid or want to intentionally
    /// create an invalid combination for testing.
    pub fn build_unchecked(self) -> RayFlags {
        self.flags
    }

    /// Get the current flags without consuming the builder.
    pub fn current(&self) -> RayFlags {
        self.flags
    }

    /// Check if the current flags are valid.
    pub fn is_valid(&self) -> bool {
        RayFlagValidator::validate(self.flags).is_ok()
    }
}

impl Default for RayFlagBuilder {
    fn default() -> Self {
        Self::new()
    }
}

// ---------------------------------------------------------------------------
// WGSL Code Generation for Ray Flags
// ---------------------------------------------------------------------------

/// Generate WGSL constant definitions for all ray flags.
///
/// Creates a block of WGSL code defining constants that match the Rust
/// `RayFlags` values. These can be used directly in WGSL shaders.
///
/// # Example Output
///
/// ```wgsl
/// // Ray flags for rayQueryInitialize
/// const RAY_FLAG_NONE: u32 = 0x00u;
/// const RAY_FLAG_FORCE_OPAQUE: u32 = 0x01u;
/// const RAY_FLAG_FORCE_NON_OPAQUE: u32 = 0x02u;
/// // ... etc
/// ```
pub fn generate_ray_flags_wgsl_constants() -> String {
    let mut output = String::new();
    output.push_str("// Ray flags for rayQueryInitialize (wgpu 25.x)\n");
    output.push_str("// These constants match the Vulkan/DXR ray flag values\n\n");

    let flags = [
        ("RAY_FLAG_NONE", RayFlags::NONE),
        ("RAY_FLAG_FORCE_OPAQUE", RayFlags::FORCE_OPAQUE),
        ("RAY_FLAG_FORCE_NON_OPAQUE", RayFlags::FORCE_NON_OPAQUE),
        ("RAY_FLAG_TERMINATE_ON_FIRST_HIT", RayFlags::TERMINATE_ON_FIRST_HIT),
        ("RAY_FLAG_SKIP_CLOSEST_HIT_SHADER", RayFlags::SKIP_CLOSEST_HIT_SHADER),
        ("RAY_FLAG_CULL_FRONT_FACING", RayFlags::CULL_FRONT_FACING),
        ("RAY_FLAG_CULL_BACK_FACING", RayFlags::CULL_BACK_FACING),
        ("RAY_FLAG_CULL_OPAQUE", RayFlags::CULL_OPAQUE),
        ("RAY_FLAG_CULL_NON_OPAQUE", RayFlags::CULL_NON_OPAQUE),
        ("RAY_FLAG_SKIP_TRIANGLES", RayFlags::SKIP_TRIANGLES),
        ("RAY_FLAG_SKIP_AABBS", RayFlags::SKIP_AABBS),
    ];

    for (name, flag) in flags {
        output.push_str(&format!(
            "const {}: u32 = 0x{:02x}u;\n",
            name,
            flag.bits()
        ));
    }

    output.push_str("\n// Common flag combinations\n");
    output.push_str(&format!(
        "const RAY_FLAG_SHADOW: u32 = 0x{:02x}u; // FORCE_OPAQUE | TERMINATE_ON_FIRST_HIT\n",
        RayFlagPreset::Shadow.flags().bits()
    ));
    output.push_str(&format!(
        "const RAY_FLAG_VISIBILITY: u32 = 0x{:02x}u; // FORCE_OPAQUE | TERMINATE_ON_FIRST_HIT | CULL_BACK_FACING\n",
        RayFlagPreset::Visibility.flags().bits()
    ));

    output
}

/// Generate a WGSL comment describing a ray flag combination.
///
/// Useful for annotating generated shader code with human-readable
/// descriptions of the flags being used.
///
/// # Example
///
/// ```ignore
/// let flags = RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT;
/// let comment = generate_ray_flags_comment(flags);
/// // Returns: "// Ray flags: FORCE_OPAQUE | TERMINATE_ON_FIRST_HIT (shadow preset)"
/// ```
pub fn generate_ray_flags_comment(flags: RayFlags) -> String {
    if flags == RayFlags::NONE {
        return "// Ray flags: NONE (default traversal)".to_string();
    }

    let mut flag_names = Vec::new();

    if flags.contains(RayFlags::FORCE_OPAQUE) {
        flag_names.push("FORCE_OPAQUE");
    }
    if flags.contains(RayFlags::FORCE_NON_OPAQUE) {
        flag_names.push("FORCE_NON_OPAQUE");
    }
    if flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT) {
        flag_names.push("TERMINATE_ON_FIRST_HIT");
    }
    if flags.contains(RayFlags::SKIP_CLOSEST_HIT_SHADER) {
        flag_names.push("SKIP_CLOSEST_HIT_SHADER");
    }
    if flags.contains(RayFlags::CULL_FRONT_FACING) {
        flag_names.push("CULL_FRONT_FACING");
    }
    if flags.contains(RayFlags::CULL_BACK_FACING) {
        flag_names.push("CULL_BACK_FACING");
    }
    if flags.contains(RayFlags::CULL_OPAQUE) {
        flag_names.push("CULL_OPAQUE");
    }
    if flags.contains(RayFlags::CULL_NON_OPAQUE) {
        flag_names.push("CULL_NON_OPAQUE");
    }
    if flags.contains(RayFlags::SKIP_TRIANGLES) {
        flag_names.push("SKIP_TRIANGLES");
    }
    if flags.contains(RayFlags::SKIP_AABBS) {
        flag_names.push("SKIP_AABBS");
    }

    let flag_str = flag_names.join(" | ");

    // Check if this matches a preset
    if let Some(preset) = RayFlagPreset::from_flags(flags) {
        let preset_name = match preset {
            RayFlagPreset::Shadow => "shadow preset",
            RayFlagPreset::PrimaryRay => "primary ray preset",
            RayFlagPreset::Reflection => "reflection preset",
            RayFlagPreset::Refraction => "refraction preset",
            RayFlagPreset::AmbientOcclusion => "ambient occlusion preset",
            RayFlagPreset::Visibility => "visibility preset",
            RayFlagPreset::ProceduralOnly => "procedural-only preset",
            RayFlagPreset::TrianglesOnly => "triangles-only preset",
        };
        format!("// Ray flags: {} ({})", flag_str, preset_name)
    } else {
        format!("// Ray flags: {}", flag_str)
    }
}

/// Generate WGSL code for a rayQueryInitialize call with specific flags.
///
/// Creates the WGSL function call with properly formatted flag value
/// and an explanatory comment.
pub fn generate_ray_query_init_wgsl(
    query_var: &str,
    accel_struct: &str,
    flags: RayFlags,
    cull_mask: u32,
    origin: &str,
    t_min: &str,
    direction: &str,
    t_max: &str,
) -> String {
    let comment = generate_ray_flags_comment(flags);
    format!(
        "{}\nrayQueryInitialize(\n    &{},\n    {},\n    0x{:02x}u,\n    0x{:02x}u,\n    {},\n    {},\n    {},\n    {}\n);",
        comment,
        query_var,
        accel_struct,
        flags.bits(),
        cull_mask,
        origin,
        t_min,
        direction,
        t_max
    )
}

