    // -------------------------------------------------------------------------
    // Test: Config flags affect build
    // -------------------------------------------------------------------------

    #[test]
    fn test_config_flags_affect_build() {
        let (vertices, indices) = make_triangle();

        // Static config
        let static_blas = BlasBuilder::new()
            .config(BlasConfig::for_static_geometry())
            .vertices_indices(&vertices, &indices)
            .build()
            .expect("Failed to build static BLAS");

        // Animated config
        let animated_blas = BlasBuilder::new()
            .config(BlasConfig::for_animated_geometry())
            .vertices_indices(&vertices, &indices)
            .build()
            .expect("Failed to build animated BLAS");

        // Static BLAS should allow compaction but not update
        assert!(static_blas.supports_compaction());
        assert!(!static_blas.supports_update());

        // Animated BLAS should allow update but not compaction
        assert!(!animated_blas.supports_compaction());
        assert!(animated_blas.supports_update());

        // Animated BLAS should use more memory (scratch buffer)
        assert!(
            animated_blas.memory_size > static_blas.memory_size,
            "Animated BLAS should use more memory due to scratch buffer"
        );
    }

