    #[test]
    fn test_bounding_box_expand_point() {
        let mut bbox = BoundingBox::empty();
        bbox.expand_point(&[1.0, 2.0, 3.0]);

        assert!(bbox.is_valid());
        assert_eq!(bbox.min, [1.0, 2.0, 3.0]);
        assert_eq!(bbox.max, [1.0, 2.0, 3.0]);

        bbox.expand_point(&[-1.0, -2.0, -3.0]);
        assert_eq!(bbox.min, [-1.0, -2.0, -3.0]);
        assert_eq!(bbox.max, [1.0, 2.0, 3.0]);
    }

    #[test]
    fn test_bounding_box_expand_box() {
        let mut bbox1 = BoundingBox::new([0.0, 0.0, 0.0], [1.0, 1.0, 1.0]);
        let bbox2 = BoundingBox::new([2.0, 2.0, 2.0], [3.0, 3.0, 3.0]);

        bbox1.expand_box(&bbox2);

        assert_eq!(bbox1.min, [0.0, 0.0, 0.0]);
        assert_eq!(bbox1.max, [3.0, 3.0, 3.0]);
    }

