    // -------------------------------------------------------------------------
    // Test: BlasTriangleGeometry validation logic (T-WGPU-P5.1.1)
    // -------------------------------------------------------------------------
    //
    // NOTE: These tests validate the geometry configuration logic.
    // Integration tests with real wgpu::Buffer instances should be in
    // blackbox tests that have access to a wgpu device.

    /// Helper struct for testing validation logic without real wgpu::Buffer
    /// This mirrors BlasTriangleGeometry parameters for validation testing.
    struct ValidationParams {
        vertex_count: u32,
        vertex_stride: u64,
        vertex_format: VertexFormat,
        has_index_buffer: bool,
        index_count: Option<u32>,
        index_format: Option<wgpu::IndexFormat>,
        has_transform_buffer: bool,
        transform_offset: u64,
    }

    impl ValidationParams {
        /// Validate using the same logic as BlasTriangleGeometry::validate
        fn validate(&self) -> Result<(), BlasTriangleGeometryError> {
            // Vertex count must be > 0
            if self.vertex_count == 0 {
                return Err(BlasTriangleGeometryError::ZeroVertexCount);
            }

            // Stride must be >= format size
            let min_stride = self.vertex_format.size_bytes();
            let effective_stride = if self.vertex_stride == 0 {
                min_stride
            } else {
                self.vertex_stride
            };
            if effective_stride < min_stride {
                return Err(BlasTriangleGeometryError::InvalidVertexStride {
                    stride: effective_stride,
                    minimum: min_stride,
                });
            }

            // Index buffer/count/format consistency
            match (self.has_index_buffer, self.index_count, self.index_format) {
                (true, None, _) => {
                    return Err(BlasTriangleGeometryError::IndexBufferWithoutCount);
                }
                (false, Some(_), _) => {
                    return Err(BlasTriangleGeometryError::IndexCountWithoutBuffer);
                }
                (false, _, Some(_)) => {
                    return Err(BlasTriangleGeometryError::IndexFormatWithoutBuffer);
                }
                _ => {}
            }

            // Transform offset alignment (16 bytes per spec)
            if self.has_transform_buffer && self.transform_offset % 16 != 0 {
                return Err(BlasTriangleGeometryError::UnalignedTransformOffset {
                    offset: self.transform_offset,
                });
            }

            Ok(())
        }

        /// Calculate triangle count using same logic as BlasTriangleGeometry
        fn triangle_count(&self) -> u32 {
            if let Some(index_count) = self.index_count {
                index_count / 3
            } else {
                self.vertex_count / 3
            }
        }
    }

    #[test]
    fn test_validation_zero_vertex_count() {
        let params = ValidationParams {
            vertex_count: 0,
            vertex_stride: 12,
            vertex_format: VertexFormat::Float32x3,
            has_index_buffer: false,
            index_count: None,
            index_format: None,
            has_transform_buffer: false,
            transform_offset: 0,
        };
        assert!(matches!(params.validate(), Err(BlasTriangleGeometryError::ZeroVertexCount)));
    }

    #[test]
    fn test_validation_invalid_stride() {
        let params = ValidationParams {
            vertex_count: 100,
            vertex_stride: 8, // Invalid: less than Float32x3 (12 bytes)
            vertex_format: VertexFormat::Float32x3,
            has_index_buffer: false,
            index_count: None,
            index_format: None,
            has_transform_buffer: false,
            transform_offset: 0,
        };
        assert!(matches!(
            params.validate(),
            Err(BlasTriangleGeometryError::InvalidVertexStride { stride: 8, minimum: 12 })
        ));
    }

