    // =========================================================================
    // BlasAABBGeometry Validation Tests (T-WGPU-P5.1.2)
    // =========================================================================

    /// Helper struct for testing AABB geometry validation logic without real wgpu::Buffer
    struct AABBValidationParams {
        aabb_count: u32,
        aabb_stride: u64,
        flags: BlasGeometryFlags,
    }

    impl AABBValidationParams {
        fn validate(&self) -> Result<(), BlasAABBGeometryError> {
            // AABB count must be > 0
            if self.aabb_count == 0 {
                return Err(BlasAABBGeometryError::ZeroAABBCount);
            }

            // Stride must be >= MIN_STRIDE (24 bytes)
            let effective_stride = if self.aabb_stride == 0 {
                AABB::SIZE_BYTES
            } else {
                self.aabb_stride
            };
            if effective_stride < AABB::SIZE_BYTES {
                return Err(BlasAABBGeometryError::InvalidStride {
                    stride: effective_stride,
                    minimum: AABB::SIZE_BYTES,
                });
            }

            Ok(())
        }

        fn effective_stride(&self) -> u64 {
            if self.aabb_stride == 0 {
                AABB::SIZE_BYTES
            } else {
                self.aabb_stride
            }
        }

        fn required_buffer_size(&self) -> u64 {
            self.aabb_count as u64 * self.effective_stride()
        }

        fn validate_with_buffer_size(&self, buffer_size: u64) -> Result<(), BlasAABBGeometryError> {
            self.validate()?;
            let required = self.required_buffer_size();
            if buffer_size < required {
                return Err(BlasAABBGeometryError::InsufficientBufferSize {
                    required,
                    available: buffer_size,
                });
            }
            Ok(())
        }

        fn estimated_blas_size(&self) -> usize {
            MIN_BLAS_MEMORY + self.aabb_count as usize * BYTES_PER_AABB
        }

        fn offset_for_aabb(&self, index: u32) -> u64 {
            index as u64 * self.effective_stride()
        }
    }

