    #[test]
    fn test_blas_build_flags_validation_valid() {
        // Valid: only PREFER_FAST_TRACE
        let flags = BlasBuildFlags::PREFER_FAST_TRACE;
        assert_eq!(flags.validate(), BlasBuildFlagsValidation::Valid);
        assert!(flags.is_valid());

        // Valid: only PREFER_FAST_BUILD
        let flags = BlasBuildFlags::PREFER_FAST_BUILD;
        assert_eq!(flags.validate(), BlasBuildFlagsValidation::Valid);
        assert!(flags.is_valid());

        // Valid: PREFER_FAST_BUILD with ALLOW_UPDATE (recommended combo)
        let flags = BlasBuildFlags::PREFER_FAST_BUILD | BlasBuildFlags::ALLOW_UPDATE;
        assert_eq!(flags.validate(), BlasBuildFlagsValidation::Valid);
        assert!(flags.is_valid());

        // Valid: default_static
        let flags = BlasBuildFlags::default_static();
        assert_eq!(flags.validate(), BlasBuildFlagsValidation::Valid);
        assert!(flags.is_valid());

        // Valid: default_dynamic
        let flags = BlasBuildFlags::default_dynamic();
        assert_eq!(flags.validate(), BlasBuildFlagsValidation::Valid);
        assert!(flags.is_valid());
    }

    #[test]
    fn test_blas_build_flags_validation_mutual_exclusivity() {
        // Invalid: both PREFER_FAST_TRACE and PREFER_FAST_BUILD
        let flags = BlasBuildFlags::PREFER_FAST_TRACE | BlasBuildFlags::PREFER_FAST_BUILD;
        assert_eq!(
            flags.validate(),
            BlasBuildFlagsValidation::MutuallyExclusivePreference
        );
        assert!(!flags.is_valid());
    }

    #[test]
    fn test_blas_build_flags_validation_update_warning() {
        // Warning: ALLOW_UPDATE without PREFER_FAST_BUILD
        let flags = BlasBuildFlags::ALLOW_UPDATE;
        assert_eq!(
            flags.validate(),
            BlasBuildFlagsValidation::UpdateWithoutFastBuild
        );
        // Note: This is a warning, not an error, so is_valid() still returns true
        assert!(flags.is_valid());

        // Warning: ALLOW_UPDATE with PREFER_FAST_TRACE (suboptimal)
        let flags = BlasBuildFlags::PREFER_FAST_TRACE | BlasBuildFlags::ALLOW_UPDATE;
        assert_eq!(
            flags.validate(),
            BlasBuildFlagsValidation::UpdateWithoutFastBuild
        );
        assert!(flags.is_valid());
    }

