    // -------------------------------------------------------------------------
    // Test: Build size querying logic
    // -------------------------------------------------------------------------

    #[test]
    fn test_query_build_sizes_scaling() {
        // Verify that build sizes scale appropriately with geometry

        // Small geometry
        let small_base = 1000u64;
        let scratch_multiplier = 1.5;
        let small_scratch = (small_base as f64 * scratch_multiplier) as u64;

        // Large geometry
        let large_base = 1000000u64;
        let large_scratch = (large_base as f64 * scratch_multiplier) as u64;

        // Scratch should scale linearly with base size
        assert!(large_scratch > small_scratch);
        let ratio = large_scratch as f64 / small_scratch as f64;
        assert!((ratio - (large_base as f64 / small_base as f64)).abs() < 0.01);
    }

    #[test]
    fn test_query_build_sizes_alignment() {
        // Build sizes should be aligned to 256 bytes
        let base_size = 1000u64;

        // Align function: (size + 255) & !255
        let aligned = (base_size + 255) & !255;
        assert_eq!(aligned % 256, 0);

        let base_1234 = 1234u64;
        let aligned_1234 = (base_1234 + 255) & !255;
        assert_eq!(aligned_1234, 1280); // Next multiple of 256
    }

    #[test]
    fn test_query_build_sizes_fast_trace_vs_fast_build() {
        // PREFER_FAST_TRACE should use more scratch
        let fast_trace_multiplier = 2.0;
        let fast_build_multiplier = 1.5;

        let base = 1000u64;
        let trace_scratch = (base as f64 * fast_trace_multiplier) as u64;
        let build_scratch = (base as f64 * fast_build_multiplier) as u64;

        assert!(trace_scratch > build_scratch);
    }

