    #[test]
    fn test_compaction_query_manager_get_candidates() {
        let mut manager = CompactionQueryManager::new();

        // Add results with varying savings
        manager.completed.push((1, CompactionQueryResult::new(1000, 600, 0, 1)));  // 40% savings
        manager.completed.push((2, CompactionQueryResult::new(1000, 950, 0, 1)));  // 5% savings
        manager.completed.push((3, CompactionQueryResult::new(1000, 800, 0, 1)));  // 20% savings

        let candidates = manager.get_compaction_candidates(0.10);

        // Should include 40% and 20%, not 5%
        assert_eq!(candidates.len(), 2);
        assert!(candidates.iter().any(|(id, _)| *id == 1));
        assert!(candidates.iter().any(|(id, _)| *id == 3));
    }

