    #[test]
    fn test_compaction_query_typical_sizes() {
        // Verify typical compaction ratios make sense
        let original = 1_000_000u64;

        // Best case: 50% savings
        let best_compacted = 500_000u64;
        let best_ratio = best_compacted as f32 / original as f32;
        assert!((best_ratio - 0.5).abs() < 0.001);

        // Typical case: 35% savings
        let typical_compacted = 650_000u64;
        let typical_ratio = typical_compacted as f32 / original as f32;
        assert!((typical_ratio - 0.65).abs() < 0.001);

        // Worst case: 20% savings
        let worst_compacted = 800_000u64;
        let worst_ratio = worst_compacted as f32 / original as f32;
        assert!((worst_ratio - 0.8).abs() < 0.001);
    }

    // -------------------------------------------------------------------------
    // Test: Memory savings calculation accuracy
    // -------------------------------------------------------------------------

    #[test]
    fn test_compaction_memory_savings_accuracy() {
        // Test with realistic BLAS sizes
        let sizes: [(u64, u64); 5] = [
            (65536, 42598),      // Small BLAS
            (262144, 170393),    // Medium BLAS
            (1048576, 681574),   // Large BLAS
            (10485760, 6815744), // Very large BLAS
            (104857600, 68157440), // Huge BLAS
        ];

        for (original, compacted) in &sizes {
            let result = CompactionQueryResult::new(*original, *compacted, 0, 1);

            // Verify bytes saved is correct
            assert_eq!(result.bytes_saved(), original - compacted);

            // Verify percentage is reasonable (30-40% typical)
            let savings = result.savings_percent();
            assert!(savings > 0.30 && savings < 0.40,
                "Unexpected savings {:.1}% for {} -> {} bytes",
                savings * 100.0, original, compacted);
        }
    }

