    #[test]
    fn test_compaction_workflow_tracking() {
        let mut stats = CompactionStats::new();

        // Simulate compacting multiple BLAS over several frames
        let compactions = [
            (65536u64, 42598u64),      // Small BLAS
            (262144, 170393),           // Medium BLAS
            (1048576, 681574),          // Large BLAS
        ];

        for (original, compacted) in &compactions {
            let bytes_saved = original - compacted;
            stats.record_compaction(*original, bytes_saved);
        }

        assert_eq!(stats.compaction_count, 3);

        // Total original: 65536 + 262144 + 1048576 = 1376256
        assert_eq!(stats.total_original_size, 1376256);

        // Total saved: 22938 + 91751 + 367002 = 481691
        assert_eq!(stats.total_bytes_saved, 481691);

        // Verify savings percentage is reasonable (30-40%)
        let avg_savings = stats.average_savings_percent();
        assert!(avg_savings > 0.30 && avg_savings < 0.40,
            "Average savings {:.1}% outside expected range", avg_savings * 100.0);
    }

    #[test]
    fn test_compaction_stats_large_scale() {
        let mut stats = CompactionStats::new();

        // Simulate compacting many BLAS (e.g., entire scene)
        for i in 0..1000 {
            let original = (1 + i) * 1024; // 1KB to 1MB
            let savings_ratio = 0.30 + (i as f32 / 1000.0) * 0.10; // 30-40% savings
            let bytes_saved = (original as f32 * savings_ratio) as u64;
            stats.record_compaction(original, bytes_saved);
        }

        assert_eq!(stats.compaction_count, 1000);
        assert!(stats.total_bytes_saved > 0);
        assert!(stats.average_savings_percent() > 0.30);
    }

