    #[test]
    fn test_compaction_policy_profiles() {
        // Aggressive profile
        let aggressive = CompactionPolicy::aggressive();
        assert!(aggressive.savings_threshold < 0.10);
        assert!(aggressive.min_blas_size < 16 * 1024);
        assert!(aggressive.max_pending_compactions > 8);

        // Conservative profile
        let conservative = CompactionPolicy::conservative();
        assert!(conservative.savings_threshold > 0.10);
        assert!(conservative.min_blas_size > 16 * 1024);
        assert!(conservative.max_pending_compactions < 8);

        // Memory constrained profile
        let constrained = CompactionPolicy::memory_constrained();
        assert!(constrained.savings_threshold < 0.05);
        assert!(constrained.min_blas_size < 4 * 1024);
    }

    #[test]
    fn test_compaction_policy_should_compact() {
        let policy = CompactionPolicy::balanced();

        // Create a query result with 15% savings (above default 10% threshold)
        let good_result = CompactionQueryResult::new(
            100_000, // original
            85_000,  // compacted (15% savings)
            0, 1,
        );

        // Create a query result with 5% savings (below threshold)
        let bad_result = CompactionQueryResult::new(
            100_000,
            95_000, // only 5% savings
            0, 1,
        );

        // Normal memory pressure
        assert!(policy.should_compact(&good_result, 100_000, 0.5));
        assert!(!policy.should_compact(&bad_result, 100_000, 0.5));

        // High memory pressure - lower threshold
        assert!(policy.should_compact(&bad_result, 100_000, 0.95));
    }

    #[test]
    fn test_compaction_policy_skip_small_blas() {
        let policy = CompactionPolicy::balanced();

        let result = CompactionQueryResult::new(
            10_000, // 10 KB - below default 16 KB threshold
            6_500,  // 35% savings (very good)
            0, 1,
        );

        // Even with good savings, should skip because BLAS is too small
        assert!(!policy.should_compact(&result, 10_000, 0.5));

        // Aggressive policy has lower size threshold
        let aggressive = CompactionPolicy::aggressive();
        assert!(aggressive.should_compact(&result, 10_000, 0.5));
    }

    #[test]
    fn test_compaction_policy_evaluate_decision() {
        let policy = CompactionPolicy::balanced();

        let result = CompactionQueryResult::new(
            100_000,
            85_000, // 15% savings
            0, 1,
        );

        // Normal case - should compact
        let decision = policy.evaluate_compaction(&result, 100_000, false, 0.5, 0);
        assert!(decision.should_compact);
        assert_eq!(decision.reason, CompactionDecisionReason::SavingsExceedThreshold);

        // Skip updateable
        let decision = policy.evaluate_compaction(&result, 100_000, true, 0.5, 0);
        assert!(!decision.should_compact);
        assert_eq!(decision.reason, CompactionDecisionReason::UpdateableSkipped);

        // Pending limit reached
        let decision = policy.evaluate_compaction(&result, 100_000, false, 0.5, 100);
        assert!(!decision.should_compact);
        assert_eq!(decision.reason, CompactionDecisionReason::PendingLimitReached);

        // BLAS too small
        let decision = policy.evaluate_compaction(&result, 1_000, false, 0.5, 0);
        assert!(!decision.should_compact);
        assert_eq!(decision.reason, CompactionDecisionReason::BlasTooSmall);
    }

    #[test]
    fn test_compaction_policy_memory_pressure() {
        let policy = CompactionPolicy::balanced();

        // 8% savings - below normal 10% threshold
        let result = CompactionQueryResult::new(
            100_000,
            92_000,
            0, 1,
        );

        // Low pressure - should not compact
        assert!(!policy.should_compact(&result, 100_000, 0.5));

        // High pressure (above 80%) - threshold drops to 5%
        assert!(policy.should_compact(&result, 100_000, 0.90));

        // Check effective threshold
        assert_eq!(policy.effective_threshold(0.5), 0.10);
        assert_eq!(policy.effective_threshold(0.90), 0.05);
    }

