    #[test]
    fn test_async_compaction_poll_result_checks() {
        assert!(AsyncCompactionPollResult::Pending.is_pending());
        assert!(!AsyncCompactionPollResult::Pending.is_complete());

        let result = CompactionQueryResult::new(100_000, 85_000, 0, 1);
        assert!(!AsyncCompactionPollResult::ReadyToCompact(result).is_pending());
        assert!(!AsyncCompactionPollResult::ReadyToCompact(result).is_complete());

        assert!(!AsyncCompactionPollResult::Complete(15_000).is_pending());
        assert!(AsyncCompactionPollResult::Complete(15_000).is_complete());

        assert!(AsyncCompactionPollResult::Skipped(CompactionDecisionReason::BlasTooSmall).is_complete());
        assert!(AsyncCompactionPollResult::Failed("error".to_string()).is_complete());
    }

