    #[test]
    fn test_blas_update_quality_degradation() {
        // Test: Quality degrades with each update

        let mut tracker = BlasUpdateTracker::new();
        let initial_quality = tracker.quality();

        // Perform 10 updates
        for i in 0..10 {
            let (quality, _) = tracker.record_update(1024);
            // Quality should decrease monotonically
            if i > 0 {
                assert!(quality < initial_quality);
            }
        }

        // After 10 updates, quality should be noticeably degraded
        let final_quality = tracker.quality();
        assert!(final_quality < 0.8); // ~3% per update = ~73% after 10

        // Should still be "good" (above 0.7 threshold)
        // Actually after 10 updates at 3%: (0.97)^10 ≈ 0.737
        // Let's verify it's reasonable
        let expected = (1.0 - DEFAULT_QUALITY_DEGRADATION_RATE).powi(10);
        assert!((final_quality - expected).abs() < 0.001);
    }

