        // Test: Multiple sequential updates tracking

        let mut tracker = BlasUpdateTracker::new();

        // Simulate 20 frame animation loop
        let mut qualities = Vec::new();
        for i in 0..20 {
            let (quality, _warned) = tracker.record_update(512);
            qualities.push(quality);

            // Quality should monotonically decrease
            if i > 0 {
                assert!(qualities[i] <= qualities[i - 1]);
            }
        }

        // Verify final state
        assert_eq!(tracker.update_count(), 20);

        // Expected quality: (0.97)^20 ≈ 0.543
