    #[test]
    fn test_blas_geometry_type_degradation_rates() {
        // Test: Each geometry type has correct degradation rate

        assert_eq!(BlasGeometryType::Static.default_degradation_rate(), 0.0);
        assert_eq!(BlasGeometryType::SlowlyAnimated.default_degradation_rate(), 0.02);
        assert_eq!(BlasGeometryType::FastAnimated.default_degradation_rate(), 0.05);
        assert_eq!(BlasGeometryType::HighlyDynamic.default_degradation_rate(), 0.10);

        // Test estimated rebuild intervals
        assert_eq!(BlasGeometryType::Static.estimated_rebuild_interval(), u32::MAX);
        assert_eq!(BlasGeometryType::SlowlyAnimated.estimated_rebuild_interval(), 34);
        assert_eq!(BlasGeometryType::FastAnimated.estimated_rebuild_interval(), 14);
        assert_eq!(BlasGeometryType::HighlyDynamic.estimated_rebuild_interval(), 7);

        // Test as_str
        assert_eq!(BlasGeometryType::Static.as_str(), "Static");
        assert_eq!(BlasGeometryType::SlowlyAnimated.as_str(), "SlowlyAnimated");
        assert_eq!(BlasGeometryType::FastAnimated.as_str(), "FastAnimated");
        assert_eq!(BlasGeometryType::HighlyDynamic.as_str(), "HighlyDynamic");

        // Test from_degradation_rate
        assert_eq!(BlasGeometryType::from_degradation_rate(0.0), BlasGeometryType::Static);
        assert_eq!(BlasGeometryType::from_degradation_rate(0.02), BlasGeometryType::SlowlyAnimated);
        assert_eq!(BlasGeometryType::from_degradation_rate(0.05), BlasGeometryType::FastAnimated);
        assert_eq!(BlasGeometryType::from_degradation_rate(0.15), BlasGeometryType::HighlyDynamic);
    }

    #[test]
    fn test_blas_quality_frames_to_rebuild() {
        // Test: Frames-to-rebuild calculation

        // Fresh quality should have many frames
        let metrics_fresh = BlasQualityMetrics::new(
            1.0,
            0,
            std::time::Duration::ZERO,
            0.05,
            BlasGeometryType::FastAnimated,
        );
        // At 5% degradation: (0.95)^n < 0.5 => n > 13.5
        assert!(metrics_fresh.estimated_frames_to_rebuild >= 13);
        assert!(metrics_fresh.estimated_frames_to_rebuild <= 15);

        // Already below threshold should return 0
        let metrics_low = BlasQualityMetrics::new(
            0.4,
            20,
            std::time::Duration::from_secs(10),
            0.05,
            BlasGeometryType::FastAnimated,
        );
        assert_eq!(metrics_low.estimated_frames_to_rebuild, 0);
        assert!(metrics_low.needs_rebuild());

        // Static geometry (rate = 0) should never need rebuild
        let metrics_static = BlasQualityMetrics::new(
            0.9,
            0,
            std::time::Duration::ZERO,
            0.0,
            BlasGeometryType::Static,
        );
        assert_eq!(metrics_static.estimated_frames_to_rebuild, u32::MAX);
    }

    #[test]
    fn test_blas_quality_tracker_metrics() {
        // Test: BlasQualityTracker produces correct metrics

        let mut tracker = BlasQualityTracker::new(BlasGeometryType::FastAnimated);

        assert_eq!(tracker.geometry_type(), BlasGeometryType::FastAnimated);
        assert!((tracker.degradation_rate() - 0.05).abs() < 0.001);
        assert_eq!(tracker.update_count(), 0);
        assert!((tracker.quality() - 1.0).abs() < 0.001);

        // Record some updates
        for _ in 0..5 {
            tracker.record_update(512);
        }

        assert_eq!(tracker.update_count(), 5);
        assert!(tracker.quality() < 1.0);
        assert_eq!(tracker.total_scratch_used(), 5 * 512);
        assert_eq!(tracker.average_scratch_per_update(), 512);

        // Get metrics
        let metrics = tracker.get_metrics();
        assert_eq!(metrics.update_count, 5);
        assert!((metrics.quality - tracker.quality()).abs() < 0.001);
        assert_eq!(metrics.geometry_type, BlasGeometryType::FastAnimated);
        assert!(metrics.time_since_rebuild.as_nanos() > 0);
    }

    #[test]
    fn test_blas_quality_stats_aggregation() {
        // Test: BlasQualityStats aggregates multiple trackers correctly

        let mut stats = BlasQualityStats::new();

        assert_eq!(stats.total_blas_count, 0);
        assert_eq!(stats.blas_needing_rebuild, 0);

        // Create trackers with different states
        let tracker1 = BlasQualityTracker::new(BlasGeometryType::Static);
        // Quality 1.0

        let mut tracker2 = BlasQualityTracker::new(BlasGeometryType::HighlyDynamic);
        for _ in 0..8 {
            // Should drop below 0.5 at 10% rate: (0.9)^8 = 0.43
            tracker2.record_update(256);
        }

        let mut tracker3 = BlasQualityTracker::new(BlasGeometryType::SlowlyAnimated);
        for _ in 0..5 {
            tracker3.record_update(128);
        }

        // Accumulate
        stats.accumulate(&tracker1);
        stats.accumulate(&tracker2);
        stats.accumulate(&tracker3);

        assert_eq!(stats.total_blas_count, 3);
        assert_eq!(stats.blas_needing_rebuild, 1); // Only tracker2 needs rebuild
        assert!(stats.worst_quality < 0.5); // tracker2's quality
        assert!(stats.average_quality > 0.5); // Average should be higher

        // Test merge
        let mut stats2 = BlasQualityStats::new();
        let tracker4 = BlasQualityTracker::new(BlasGeometryType::Static);
        stats2.accumulate(&tracker4);

        stats.merge(&stats2);
        assert_eq!(stats.total_blas_count, 4);
    }

    #[test]
    fn test_blas_quality_rebuild_resets() {
        // Test: record_rebuild resets tracker state

        let mut tracker = BlasQualityTracker::new(BlasGeometryType::FastAnimated);

        // Degrade quality
        for _ in 0..15 {
            tracker.record_update(1024);
        }

        assert!(tracker.quality() < 0.7);
        assert!(tracker.update_count() > 0);
        assert!(tracker.total_scratch_used() > 0);

        // Record rebuild
        tracker.record_rebuild();

        assert!((tracker.quality() - 1.0).abs() < 0.001);
        assert_eq!(tracker.update_count(), 0);
        assert_eq!(tracker.total_scratch_used(), 0);
        assert!(tracker.is_quality_good());
        assert!(!tracker.needs_rebuild());

        // Test reset alias
        tracker.record_update(512);
        tracker.reset();
        assert!((tracker.quality() - 1.0).abs() < 0.001);
    }

    #[test]
    fn test_blas_quality_different_geometry_types() {
        // Test: Different geometry types degrade at different rates

        let mut static_tracker = BlasQualityTracker::new(BlasGeometryType::Static);
        let mut slow_tracker = BlasQualityTracker::new(BlasGeometryType::SlowlyAnimated);
        let mut fast_tracker = BlasQualityTracker::new(BlasGeometryType::FastAnimated);
        let mut dynamic_tracker = BlasQualityTracker::new(BlasGeometryType::HighlyDynamic);

        // Apply 10 updates to each
        for _ in 0..10 {
            static_tracker.record_update(256);
            slow_tracker.record_update(256);
            fast_tracker.record_update(256);
            dynamic_tracker.record_update(256);
        }

        // Static should not degrade (rate = 0)
        assert!((static_tracker.quality() - 1.0).abs() < 0.001);

        // Slowly animated: (0.98)^10 ≈ 0.817
        assert!(slow_tracker.quality() > 0.8);
        assert!(slow_tracker.quality() < 0.85);

        // Fast animated: (0.95)^10 ≈ 0.599
        assert!(fast_tracker.quality() > 0.55);
        assert!(fast_tracker.quality() < 0.65);

        // Highly dynamic: (0.90)^10 ≈ 0.349
        assert!(dynamic_tracker.quality() < 0.4);
        assert!(dynamic_tracker.needs_rebuild());

        // Verify ordering: static > slow > fast > dynamic
        assert!(static_tracker.quality() > slow_tracker.quality());
        assert!(slow_tracker.quality() > fast_tracker.quality());
        assert!(fast_tracker.quality() > dynamic_tracker.quality());
    }

    #[test]
    fn test_blas_quality_metrics_serialization() {
        // Test: BlasQualityMetrics produces correct string representations

        let metrics = BlasQualityMetrics::new(
            0.75,
            10,
            std::time::Duration::from_secs(5),
            0.03,
            BlasGeometryType::SlowlyAnimated,
        );

        // Test quality_percent
        assert_eq!(metrics.quality_percent(), "75.0%");

        // Test status based on quality levels
        assert_eq!(metrics.status(), "Good"); // 0.75 >= 0.7

        let degraded_metrics = BlasQualityMetrics::new(
            0.6,
            15,
            std::time::Duration::from_secs(8),
            0.03,
            BlasGeometryType::SlowlyAnimated,
        );
        assert_eq!(degraded_metrics.status(), "Degraded"); // 0.5 <= 0.6 < 0.7

        let rebuild_metrics = BlasQualityMetrics::new(
            0.4,
            25,
            std::time::Duration::from_secs(12),
            0.03,
            BlasGeometryType::SlowlyAnimated,
        );
        assert_eq!(rebuild_metrics.status(), "Rebuild Needed"); // 0.4 < 0.5

        // Test BlasQualityStats summary and Display
        let mut stats = BlasQualityStats::new();
        let tracker = BlasQualityTracker::new(BlasGeometryType::Static);
        stats.accumulate(&tracker);

        let summary = stats.summary();
        assert!(summary.contains("BLAS Quality"));
        assert!(summary.contains("0/1")); // 0 needing rebuild out of 1

        // Test Display trait
        let display_str = format!("{}", stats);
        assert_eq!(display_str, summary);

        // Test geometry type Display
        let geo_str = format!("{}", BlasGeometryType::FastAnimated);
        assert_eq!(geo_str, "FastAnimated");
    }

