    #[test]
    fn test_dynamic_policy_evaluate_update() {
        // Test: Policy returns Update for healthy tracker

        let policy = DynamicBlasPolicy::default();
        let mut tracker = BlasQualityTracker::new(BlasGeometryType::SlowlyAnimated);

        // Fresh tracker should evaluate to Update
        let decision = policy.evaluate(&tracker);
        assert!(decision.is_update());
        assert_eq!(format!("{}", decision), "Update");

        // After a few updates, still should be Update (quality > 0.7)
        for _ in 0..5 {
            tracker.record_update(1024);
        }
        // (0.98)^5 ≈ 0.904, well above threshold
        let decision = policy.evaluate(&tracker);
        assert!(decision.is_update());
        assert!(!policy.should_rebuild(&tracker));
    }

    #[test]
    fn test_dynamic_policy_evaluate_rebuild() {
        // Test: Policy returns Rebuild when quality is below force threshold

        let policy = DynamicBlasPolicy::default();
        let mut tracker = BlasQualityTracker::new(BlasGeometryType::HighlyDynamic);

        // Degrade quality below force_rebuild_threshold (0.5)
        // (0.90)^7 ≈ 0.478, which is < 0.5
        for _ in 0..7 {
            tracker.record_update(512);
        }

        let decision = policy.evaluate(&tracker);
        assert!(decision.is_rebuild());
        assert!(policy.should_rebuild(&tracker));

        // Check reason
        let reason = decision.rebuild_reason().unwrap();
        assert!(reason.contains("below force threshold"));
    }

    #[test]
    fn test_dynamic_policy_max_frames_trigger() {
        // Test: Policy triggers rebuild when max_refit_frames is exceeded

        let policy = DynamicBlasPolicy::new()
            .with_max_refit_frames(10)
            .for_geometry_type(BlasGeometryType::Static); // Static = 0% degradation

        let mut tracker = BlasQualityTracker::new(BlasGeometryType::Static);

        // Quality won't degrade (static), but frame count will trigger rebuild
        for _ in 0..10 {
            tracker.record_update(256);
        }

        // Quality is still 1.0, but we've hit max frames
        assert!((tracker.quality() - 1.0).abs() < 0.001);
        assert!(policy.should_rebuild(&tracker));

        let decision = policy.evaluate(&tracker);
        // Note: Static geometry returns Skip, not Rebuild
        // The evaluate method short-circuits for static geometry
        assert!(decision.is_skip());

        // Test with non-static geometry
        let policy_fast = DynamicBlasPolicy::new()
            .with_max_refit_frames(5)
            .with_quality_threshold(0.3) // Very low threshold
            .for_geometry_type(BlasGeometryType::SlowlyAnimated);

        let mut tracker_fast = BlasQualityTracker::new(BlasGeometryType::SlowlyAnimated);
        for _ in 0..6 {
            tracker_fast.record_update(256);
        }

        // Should trigger rebuild due to frame count
        let decision = policy_fast.evaluate(&tracker_fast);
        assert!(decision.is_rebuild());
        let reason = decision.rebuild_reason().unwrap();
        assert!(reason.contains("Exceeded max refit frames"));
    }

    #[test]
    fn test_dynamic_policy_quality_trigger() {
        // Test: Quality threshold triggers rebuild when prefer_update=false

        let policy = DynamicBlasPolicy::new()
            .with_quality_threshold(0.8)
            .with_prefer_update(false)
            .for_geometry_type(BlasGeometryType::FastAnimated);

        let mut tracker = BlasQualityTracker::new(BlasGeometryType::FastAnimated);

        // Degrade to below 0.8 but above 0.5
        // (0.95)^5 ≈ 0.774
        for _ in 0..5 {
            tracker.record_update(512);
        }

        // Quality is ~0.77, below threshold 0.8, prefer_update=false
        assert!(tracker.quality() < 0.8);
        assert!(tracker.quality() > 0.5);

        let decision = policy.evaluate(&tracker);
        assert!(decision.is_rebuild());
        let reason = decision.rebuild_reason().unwrap();
        assert!(reason.contains("prefer_update=false"));

        // With prefer_update=true, same quality should NOT trigger rebuild
        let policy_prefer = DynamicBlasPolicy::new()
            .with_quality_threshold(0.8)
            .with_prefer_update(true)
            .for_geometry_type(BlasGeometryType::FastAnimated);

        let decision_prefer = policy_prefer.evaluate(&tracker);
        assert!(decision_prefer.is_update());
    }

