    #[test]
    fn test_policy_decision_methods() {
        // Test: PolicyDecision helper methods

        let update = PolicyDecision::Update;
        assert!(update.is_update());
        assert!(!update.is_rebuild());
        assert!(!update.is_skip());
        assert_eq!(update.rebuild_reason(), None);

        let rebuild = PolicyDecision::rebuild("Quality too low");
        assert!(!rebuild.is_update());
        assert!(rebuild.is_rebuild());
        assert!(!rebuild.is_skip());
        assert_eq!(rebuild.rebuild_reason(), Some("Quality too low"));

        let skip = PolicyDecision::Skip;
        assert!(!skip.is_update());
        assert!(!skip.is_rebuild());
        assert!(skip.is_skip());
        assert_eq!(skip.rebuild_reason(), None);

        // Test Display
        assert_eq!(format!("{}", update), "Update");
        assert_eq!(format!("{}", skip), "Skip");
        let rebuild_display = format!("{}", rebuild);
        assert!(rebuild_display.contains("Rebuild:"));
        assert!(rebuild_display.contains("Quality too low"));
    }

