    #[test]
    fn test_tlas_instance_builder() {
        // Test: TlasInstanceBuilder creates instances with correct values

        let blas_id = BlasId(42);
        let transform = Transform3x4::from_translation(10.0, 20.0, 30.0);
        let custom_index = 12345u32;
        let mask = 0xAB;
        let sbt_offset = 789u32;
        let flags = TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE
            | TlasInstanceFlags::FORCE_OPAQUE;
        let blas_address = 0x1234_5678_9ABC_DEF0u64;

        let instance = TlasInstanceBuilder::new(blas_id)
            .transform(transform)
            .custom_index(custom_index)
            .mask(mask)
            .sbt_offset(sbt_offset)
            .flags(flags)
            .build(blas_address);

        // Verify all fields
        assert_eq!(instance.transform.data, transform.data);
        assert_eq!(instance.custom_index(), custom_index);
        assert_eq!(instance.mask(), mask);
        assert_eq!(instance.sbt_offset(), sbt_offset);
        assert_eq!(instance.flags(), flags);
        assert_eq!(instance.blas_address, blas_address);

        // Test builder convenience methods
        let double_sided = TlasInstanceBuilder::new(BlasId(1))
            .double_sided()
            .build(0);
        assert!(double_sided.flags().contains(TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE));

        let forced_opaque = TlasInstanceBuilder::new(BlasId(2))
            .force_opaque()
            .build(0);
        assert!(forced_opaque.flags().contains(TlasInstanceFlags::FORCE_OPAQUE));

        let forced_non_opaque = TlasInstanceBuilder::new(BlasId(3))
            .force_non_opaque()
            .build(0);
        assert!(forced_non_opaque.flags().contains(TlasInstanceFlags::FORCE_NO_OPAQUE));
        assert!(!forced_non_opaque.flags().contains(TlasInstanceFlags::FORCE_OPAQUE));

        // Test build_deferred
        let deferred = TlasInstanceBuilder::new(BlasId(4))
            .custom_index(999)
            .build_deferred();
        assert_eq!(deferred.blas_address, 0);
        assert_eq!(deferred.custom_index(), 999);
    }

    #[test]
    fn test_transform3x4_identity() {
        // Test: Identity transform is correct

        let identity = Transform3x4::identity();

        // Check diagonal is 1, rest is 0
        assert_eq!(identity.data[0], [1.0, 0.0, 0.0, 0.0]);
        assert_eq!(identity.data[1], [0.0, 1.0, 0.0, 0.0]);
        assert_eq!(identity.data[2], [0.0, 0.0, 1.0, 0.0]);

        // Identity should not change points
        let point = [5.0, 10.0, 15.0];
        let transformed = identity.transform_point(point);
        assert_eq!(transformed, point);

        // Identity should not change vectors
        let vector = [1.0, 2.0, 3.0];
        let transformed_vec = identity.transform_vector(vector);
        assert_eq!(transformed_vec, vector);

        // Default should be identity
        let default = Transform3x4::default();
        assert_eq!(default.data, identity.data);
    }

    #[test]
    fn test_transform3x4_translation() {
        // Test: Translation transform moves points correctly

        let translation = Transform3x4::from_translation(10.0, 20.0, 30.0);

        // Check matrix structure
        assert_eq!(translation.data[0], [1.0, 0.0, 0.0, 10.0]);
        assert_eq!(translation.data[1], [0.0, 1.0, 0.0, 20.0]);
        assert_eq!(translation.data[2], [0.0, 0.0, 1.0, 30.0]);

        // Translation accessor
        assert_eq!(translation.translation(), [10.0, 20.0, 30.0]);

        // Points should be translated
        let point = [0.0, 0.0, 0.0];
        let transformed = translation.transform_point(point);
        assert_eq!(transformed, [10.0, 20.0, 30.0]);

        let point2 = [5.0, 5.0, 5.0];
        let transformed2 = translation.transform_point(point2);
        assert_eq!(transformed2, [15.0, 25.0, 35.0]);

        // Vectors should NOT be translated
        let vector = [1.0, 0.0, 0.0];
        let transformed_vec = translation.transform_vector(vector);
        assert_eq!(transformed_vec, vector);

        // Test set_translation
        let mut mutable = Transform3x4::identity();
        mutable.set_translation(100.0, 200.0, 300.0);
        assert_eq!(mutable.translation(), [100.0, 200.0, 300.0]);
    }

    #[test]
    fn test_transform3x4_scale() {
        // Test: Scale transform scales points correctly

        let scale = Transform3x4::from_scale(2.0, 3.0, 4.0);

        // Check matrix structure
        assert_eq!(scale.data[0], [2.0, 0.0, 0.0, 0.0]);
        assert_eq!(scale.data[1], [0.0, 3.0, 0.0, 0.0]);
        assert_eq!(scale.data[2], [0.0, 0.0, 4.0, 0.0]);

        // Points should be scaled
        let point = [1.0, 1.0, 1.0];
        let transformed = scale.transform_point(point);
        assert_eq!(transformed, [2.0, 3.0, 4.0]);

        // Vectors should also be scaled
        let vector = [1.0, 1.0, 1.0];
        let transformed_vec = scale.transform_vector(vector);
        assert_eq!(transformed_vec, [2.0, 3.0, 4.0]);

        // Uniform scale
        let uniform = Transform3x4::from_scale(5.0, 5.0, 5.0);
        let point2 = [2.0, 3.0, 4.0];
        let transformed2 = uniform.transform_point(point2);
        assert_eq!(transformed2, [10.0, 15.0, 20.0]);
    }

    #[test]
    fn test_transform3x4_rotation() {
        // Test: Rotation transforms rotate correctly

        use std::f32::consts::{FRAC_PI_2, PI};

        // Test Y-axis rotation (90 degrees)
        let rot_y = Transform3x4::from_rotation_y(FRAC_PI_2);
        let point = [1.0, 0.0, 0.0]; // Point on +X axis
        let rotated = rot_y.transform_point(point);
        // 90 degree Y rotation: +X becomes +Z
        assert!((rotated[0] - 0.0).abs() < 1e-6);
        assert!((rotated[1] - 0.0).abs() < 1e-6);
        assert!((rotated[2] - (-1.0)).abs() < 1e-6);

        // Test X-axis rotation (90 degrees)
        let rot_x = Transform3x4::from_rotation_x(FRAC_PI_2);
        let point = [0.0, 1.0, 0.0]; // Point on +Y axis
        let rotated = rot_x.transform_point(point);
        // 90 degree X rotation: +Y becomes +Z
        assert!((rotated[0] - 0.0).abs() < 1e-6);
        assert!((rotated[1] - 0.0).abs() < 1e-6);
        assert!((rotated[2] - 1.0).abs() < 1e-6);

        // Test Z-axis rotation (90 degrees)
        let rot_z = Transform3x4::from_rotation_z(FRAC_PI_2);
        let point = [1.0, 0.0, 0.0]; // Point on +X axis
        let rotated = rot_z.transform_point(point);
        // 90 degree Z rotation: +X becomes +Y
        assert!((rotated[0] - 0.0).abs() < 1e-6);
        assert!((rotated[1] - 1.0).abs() < 1e-6);
        assert!((rotated[2] - 0.0).abs() < 1e-6);

        // Test 180 degree rotation
        let rot_180 = Transform3x4::from_rotation_y(PI);
        let point = [1.0, 0.0, 0.0];
        let rotated = rot_180.transform_point(point);
        // 180 degree Y rotation: +X becomes -X
        assert!((rotated[0] - (-1.0)).abs() < 1e-6);
        assert!((rotated[1] - 0.0).abs() < 1e-6);
        assert!((rotated[2] - 0.0).abs() < 1e-6);
    }

    #[test]
    fn test_tlas_instance_flags() {
        // Test: TlasInstanceFlags bitwise operations and methods

        let empty = TlasInstanceFlags::empty();
        assert!(!empty.contains(TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE));
        assert!(!empty.contains(TlasInstanceFlags::FORCE_OPAQUE));

        // Single flag
        let cull_disable = TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE;
        assert!(cull_disable.contains(TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE));
        assert!(!cull_disable.contains(TlasInstanceFlags::TRIANGLE_FLIP_FACING));

        // Combined flags
        let combined = TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE
            | TlasInstanceFlags::FORCE_OPAQUE;
        assert!(combined.contains(TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE));
        assert!(combined.contains(TlasInstanceFlags::FORCE_OPAQUE));
        assert!(!combined.contains(TlasInstanceFlags::FORCE_NO_OPAQUE));

        // Conflict detection
        let conflict = TlasInstanceFlags::FORCE_OPAQUE | TlasInstanceFlags::FORCE_NO_OPAQUE;
        assert!(conflict.has_conflict());
        assert!(!combined.has_conflict());
        assert!(!empty.has_conflict());

        // Conflict resolution (FORCE_NO_OPAQUE wins)
        let resolved = conflict.resolve_conflicts();
        assert!(!resolved.has_conflict());
        assert!(resolved.contains(TlasInstanceFlags::FORCE_NO_OPAQUE));
        assert!(!resolved.contains(TlasInstanceFlags::FORCE_OPAQUE));

        // Flag values match Vulkan/DXR spec
        assert_eq!(TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE.bits(), 0x01);
        assert_eq!(TlasInstanceFlags::TRIANGLE_FLIP_FACING.bits(), 0x02);
        assert_eq!(TlasInstanceFlags::FORCE_OPAQUE.bits(), 0x04);
        assert_eq!(TlasInstanceFlags::FORCE_NO_OPAQUE.bits(), 0x08);
    }

    #[test]
    fn test_tlas_instance_packed_format() {
        // Test: Instance packing/unpacking is correct (GPU memory layout)

        let instance = TlasInstance::from_components(
            Transform3x4::identity(),
            0x00ABCDEF,  // 24-bit custom index
            0x12,        // 8-bit mask
            0x00123456,  // 24-bit SBT offset
            TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE | TlasInstanceFlags::FORCE_OPAQUE,
            0xDEADBEEF_CAFEBABE,
        );

        // Verify unpacking
        assert_eq!(instance.custom_index(), 0x00ABCDEF);
        assert_eq!(instance.mask(), 0x12);
        assert_eq!(instance.sbt_offset(), 0x00123456);
        assert_eq!(
            instance.flags(),
            TlasInstanceFlags::TRIANGLE_FACING_CULL_DISABLE | TlasInstanceFlags::FORCE_OPAQUE
        );
        assert_eq!(instance.blas_address, 0xDEADBEEF_CAFEBABE);

        // Test setters
        let mut mutable = TlasInstance::new();

        mutable.set_custom_index(0x00FEDCBA);
        assert_eq!(mutable.custom_index(), 0x00FEDCBA);

        mutable.set_mask(0x34);
        assert_eq!(mutable.mask(), 0x34);

        mutable.set_sbt_offset(0x00654321);
        assert_eq!(mutable.sbt_offset(), 0x00654321);

        mutable.set_flags(TlasInstanceFlags::TRIANGLE_FLIP_FACING);
        assert_eq!(mutable.flags(), TlasInstanceFlags::TRIANGLE_FLIP_FACING);

        // Verify packed format preserves other fields
        mutable.set_custom_index(0x00111111);
        assert_eq!(mutable.mask(), 0x34); // Mask unchanged
        mutable.set_mask(0x56);
        assert_eq!(mutable.custom_index(), 0x00111111); // Custom index unchanged

        // Test maximum values
        let max_instance = TlasInstance::from_components(
            Transform3x4::identity(),
            TLAS_INSTANCE_CUSTOM_INDEX_MAX,
            0xFF,
            TLAS_INSTANCE_SBT_OFFSET_MAX,
            TlasInstanceFlags::all(),
            u64::MAX,
        );

        assert_eq!(max_instance.custom_index(), TLAS_INSTANCE_CUSTOM_INDEX_MAX);
        assert_eq!(max_instance.mask(), 0xFF);
        assert_eq!(max_instance.sbt_offset(), TLAS_INSTANCE_SBT_OFFSET_MAX);
        assert_eq!(max_instance.blas_address, u64::MAX);

        // Test as_bytes produces correct size
        let bytes = instance.as_bytes();
        assert_eq!(bytes.len(), TLAS_INSTANCE_SIZE);
        assert_eq!(bytes.len(), 64);

        // Test visibility check
        assert!(instance.is_visible_to(0x12)); // Exact match
        assert!(instance.is_visible_to(0xFF)); // All bits set
        assert!(instance.is_visible_to(0x10)); // Partial overlap
        assert!(!instance.is_visible_to(0x00)); // No overlap
        assert!(!instance.is_visible_to(0xED)); // No overlap (0x12 & 0xED = 0)
    }

    #[test]
    fn test_transform3x4_matrix4x4_conversion() {
        // Test: Conversion from 4x4 matrices

        // Row-major 4x4 (typical layout)
        let mat4_row: [f32; 16] = [
            1.0, 0.0, 0.0, 10.0,  // Row 0
            0.0, 1.0, 0.0, 20.0,  // Row 1
            0.0, 0.0, 1.0, 30.0,  // Row 2
            0.0, 0.0, 0.0, 1.0,   // Row 3 (ignored)
        ];

        let from_row = Transform3x4::from_matrix4x4(&mat4_row);
        assert_eq!(from_row.translation(), [10.0, 20.0, 30.0]);

        // Column-major 4x4 (OpenGL/glam layout)
        let mat4_col: [f32; 16] = [
            1.0, 0.0, 0.0, 0.0,  // Column 0
            0.0, 1.0, 0.0, 0.0,  // Column 1
            0.0, 0.0, 1.0, 0.0,  // Column 2
            10.0, 20.0, 30.0, 1.0, // Column 3 (translation)
        ];

        let from_col = Transform3x4::from_matrix4x4_column_major(&mat4_col);
        assert_eq!(from_col.translation(), [10.0, 20.0, 30.0]);

        // Both conversions should produce the same result
        assert_eq!(from_row.data, from_col.data);
    }

    #[test]
    fn test_transform3x4_multiply() {
        // Test: Transform multiplication

        let translate = Transform3x4::from_translation(10.0, 0.0, 0.0);
        let scale = Transform3x4::from_scale(2.0, 2.0, 2.0);

        // Scale then translate: point (1,0,0) -> scale to (2,0,0) -> translate to (12,0,0)
        let combined = translate.multiply(&scale);
        let point = [1.0, 0.0, 0.0];
        let result = combined.transform_point(point);
        assert!((result[0] - 12.0).abs() < 1e-6);
        assert!((result[1] - 0.0).abs() < 1e-6);
        assert!((result[2] - 0.0).abs() < 1e-6);

        // as_flat returns correct array
        let flat = Transform3x4::identity().as_flat();
        assert_eq!(flat.len(), 12);
        assert_eq!(flat[0], 1.0);
        assert_eq!(flat[5], 1.0);
        assert_eq!(flat[10], 1.0);
    }

    #[test]
    fn test_visibility_mask_constants() {
        // Test: Visibility mask constants are correctly defined

        assert_eq!(visibility_masks::ALL, 0xFF);
        assert_eq!(visibility_masks::NONE, 0x00);
        assert_eq!(visibility_masks::MAIN_VIEW, 0x01);
        assert_eq!(visibility_masks::SHADOW, 0x02);
        assert_eq!(visibility_masks::REFLECTION, 0x04);
        assert_eq!(visibility_masks::REFRACTION, 0x08);
        assert_eq!(visibility_masks::AMBIENT_OCCLUSION, 0x10);
        assert_eq!(visibility_masks::GLOBAL_ILLUMINATION, 0x20);
        assert_eq!(visibility_masks::USER_1, 0x40);
        assert_eq!(visibility_masks::USER_2, 0x80);

        // Verify no overlaps in base masks
        let base_masks = [
            visibility_masks::MAIN_VIEW,
            visibility_masks::SHADOW,
            visibility_masks::REFLECTION,
            visibility_masks::REFRACTION,
            visibility_masks::AMBIENT_OCCLUSION,
            visibility_masks::GLOBAL_ILLUMINATION,
            visibility_masks::USER_1,
            visibility_masks::USER_2,
        ];

        for i in 0..base_masks.len() {
            for j in (i + 1)..base_masks.len() {
                assert_eq!(
                    base_masks[i] & base_masks[j],
                    0,
                    "Masks {} and {} overlap",
                    i,
                    j
                );
            }
        }

        // Verify composite masks
        assert_eq!(
            visibility_masks::DEFAULT_OPAQUE,
            visibility_masks::MAIN_VIEW
                | visibility_masks::SHADOW
                | visibility_masks::REFLECTION
                | visibility_masks::GLOBAL_ILLUMINATION
        );

        assert_eq!(
            visibility_masks::DEFAULT_TRANSPARENT,
            visibility_masks::MAIN_VIEW
                | visibility_masks::REFLECTION
                | visibility_masks::REFRACTION
        );
    }

