    #[test]
    fn test_tlas_build_sizes_estimation() {
        // Test: Build sizes estimation produces reasonable values
        let sizes_small = TlasBuildSizes::estimate(10, TlasBuildFlags::default());
        let sizes_large = TlasBuildSizes::estimate(10000, TlasBuildFlags::default());

        // Small TLAS should be smaller
        assert!(sizes_small.acceleration_structure_size < sizes_large.acceleration_structure_size);
        assert!(sizes_small.build_scratch_size < sizes_large.build_scratch_size);

        // Sizes should be non-zero for non-empty TLAS
        assert!(sizes_small.acceleration_structure_size > 0);
        assert!(sizes_small.build_scratch_size > 0);

        // Update scratch only set when ALLOW_UPDATE is enabled
        let sizes_update = TlasBuildSizes::estimate(100, TlasBuildFlags::ALLOW_UPDATE);
        assert!(sizes_update.update_scratch_size > 0);

        let sizes_no_update = TlasBuildSizes::estimate(100, TlasBuildFlags::default());
        assert_eq!(sizes_no_update.update_scratch_size, 0);

        // Sizes should be aligned
        const ALIGNMENT: u64 = 256;
        assert_eq!(sizes_small.acceleration_structure_size % ALIGNMENT, 0);
        assert_eq!(sizes_small.build_scratch_size % ALIGNMENT, 0);
    }

