    #[test]
    fn test_tlas_scratch_allocation() {
        // Test: Scratch buffer size calculation for TLAS

        let sizes_10 = TlasBuildSizes::estimate(10, TlasBuildFlags::PREFER_FAST_BUILD);
        let sizes_100 = TlasBuildSizes::estimate(100, TlasBuildFlags::PREFER_FAST_BUILD);
        let sizes_1000 = TlasBuildSizes::estimate(1000, TlasBuildFlags::PREFER_FAST_BUILD);

        // More instances = more scratch
        assert!(sizes_10.build_scratch_size < sizes_100.build_scratch_size);
        assert!(sizes_100.build_scratch_size < sizes_1000.build_scratch_size);

        // Fast trace needs more scratch than fast build
        let sizes_fast_trace = TlasBuildSizes::estimate(100, TlasBuildFlags::PREFER_FAST_TRACE);
        let sizes_fast_build = TlasBuildSizes::estimate(100, TlasBuildFlags::PREFER_FAST_BUILD);
        assert!(sizes_fast_trace.build_scratch_size > sizes_fast_build.build_scratch_size);
    }

