    #[test]
    fn test_bitset_operations() {
        // Test: BitSet basic operations (set, clear, test, count)

        let mut bits = BitSet::new(256);

        // Initially empty
        assert_eq!(bits.count_set(), 0);
        assert!(bits.none_set());
        assert!(!bits.any_set());

        // Set some bits
        bits.set(0);
        bits.set(63);
        bits.set(64);
        bits.set(127);
        bits.set(255);

        assert_eq!(bits.count_set(), 5);
        assert!(bits.any_set());
        assert!(!bits.none_set());

        // Test individual bits
        assert!(bits.test(0));
        assert!(bits.test(63));
        assert!(bits.test(64));
        assert!(bits.test(127));
        assert!(bits.test(255));
        assert!(!bits.test(1));
        assert!(!bits.test(100));

        // Clear a bit
        bits.clear(64);
        assert!(!bits.test(64));
        assert_eq!(bits.count_set(), 4);

        // Iterate set bits
        let set_indices: Vec<usize> = bits.iter_set().collect();
        assert_eq!(set_indices, vec![0, 63, 127, 255]);

        // Clear all
        bits.clear_all();
        assert_eq!(bits.count_set(), 0);
        assert!(bits.none_set());

        // Set all
        bits.set_all();
        assert_eq!(bits.count_set(), 256);
        assert!(bits.test(0));
        assert!(bits.test(255));
    }

    #[test]
    fn test_bitset_edge_cases() {
        // Test: BitSet with non-64-aligned capacity

        let mut bits = BitSet::new(100);
        assert_eq!(bits.capacity(), 100);

        // Set and clear at boundaries
        bits.set(0);
        bits.set(99);
        assert_eq!(bits.count_set(), 2);

        // Set all should only set 100 bits
        bits.set_all();
        assert_eq!(bits.count_set(), 100);

        // Verify last bit is set but beyond is not accessible
        assert!(bits.test(99));

        // Empty bitset
        let mut empty = BitSet::new(0);
        assert_eq!(empty.capacity(), 0);
        assert_eq!(empty.count_set(), 0);

        // Single bit
        let mut single = BitSet::new(1);
        single.set(0);
        assert!(single.test(0));
        assert_eq!(single.count_set(), 1);
    }

