    #[test]
    fn test_tlas_frame_timing() {
        // Test: Frame timing integration (last_rebuild_frame tracking)

        let mut last_rebuild_frame: u64 = 0;
        let mut frame_number: u64 = 0;

        // Simulate frames without full rebuild
        for _ in 0..10 {
            frame_number += 1;
            // No full rebuild - last_rebuild_frame stays at 0
        }
        assert_eq!(last_rebuild_frame, 0);

        // Frame 11: Full rebuild
        frame_number += 1;
        let did_full_rebuild = true;
        if did_full_rebuild {
            last_rebuild_frame = frame_number;
        }
        assert_eq!(last_rebuild_frame, 11);

        // More frames without rebuild
        for _ in 0..5 {
            frame_number += 1;
        }
        assert_eq!(frame_number, 16);
        assert_eq!(last_rebuild_frame, 11); // Still 11

        // Frame 17: Another full rebuild
        frame_number += 1;
        last_rebuild_frame = frame_number;
        assert_eq!(last_rebuild_frame, 17);
    }

