    #[test]
    fn test_culler_with_transforms() {
        let config = CullingConfig::new()
            .with_frustum_culling(true)
            .with_occlusion_culling(false)
            .with_lod(false)
            .with_min_screen_percentage(0.0);

        let mut culler = TlasInstanceCuller::new(config, 5);

        // Set bounds in local space (at origin with radius 1)
        culler.set_instance_bounds(0, BoundingSphere::new([0.0, 0.0, 0.0], 1.0));
        culler.set_instance_bounds(1, BoundingSphere::new([0.0, 0.0, 0.0], 1.0));
        culler.set_active_count(2);

        // Transforms that move instances
        let transforms = [
            Transform3x4::from_translation(0.0, 0.0, 50.0),   // Inside frustum
            Transform3x4::from_translation(0.0, 0.0, -50.0),  // Behind frustum
        ];

        let frustum = Frustum {
            planes: [
                [-1.0, 0.0, 0.0, 100.0],
                [1.0, 0.0, 0.0, 100.0],
                [0.0, -1.0, 0.0, 100.0],
                [0.0, 1.0, 0.0, 100.0],
                [0.0, 0.0, 1.0, 0.0],     // Near at z=0
                [0.0, 0.0, -1.0, 1000.0],
            ],
        };

        let result = culler.cull_with_transforms(
            &transforms,
            &frustum,
            [0.0, 0.0, 0.0],
            std::f32::consts::FRAC_PI_4,
            1.0,
        );

        assert_eq!(result.stats.total_instances, 2);
        assert_eq!(result.stats.visible_count, 1);
        assert!(result.visible_indices.contains(&0));
        assert!(!result.visible_indices.contains(&1));
    }

    #[test]
    fn test_bounding_sphere_screen_percentage() {
        let sphere = BoundingSphere::new([0.0, 0.0, 10.0], 1.0);
        let view_pos = [0.0, 0.0, 0.0];
        let fov_y = std::f32::consts::FRAC_PI_2; // 90 degree FOV
        let aspect = 1.0;

        let pct = sphere.screen_percentage(view_pos, fov_y, aspect);
        assert!(pct > 0.0);
        assert!(pct < 1.0);

        // Closer sphere should have larger screen percentage
        let closer = BoundingSphere::new([0.0, 0.0, 5.0], 1.0);
        let closer_pct = closer.screen_percentage(view_pos, fov_y, aspect);
        assert!(closer_pct > pct);

        // Larger sphere should have larger screen percentage
        let larger = BoundingSphere::new([0.0, 0.0, 10.0], 2.0);
        let larger_pct = larger.screen_percentage(view_pos, fov_y, aspect);
        assert!(larger_pct > pct);

        // Inside the sphere should return 1.0
        let inside = BoundingSphere::new([0.0, 0.0, 0.0], 10.0);
        let inside_pct = inside.screen_percentage(view_pos, fov_y, aspect);
        assert!((inside_pct - 1.0).abs() < 1e-6);
    }

    #[test]
    fn test_culler_reset() {
        let config = CullingConfig::default();
        let mut culler = TlasInstanceCuller::new(config, 10);

        // Add some data
        culler.set_instance_bounds(0, BoundingSphere::new([1.0, 2.0, 3.0], 5.0));
        culler.set_lod_distances(0, [10.0, 20.0, 30.0, 40.0]);
        culler.set_visibility(0, false);
        culler.set_active_count(5);

        // Reset
        culler.reset();

        assert_eq!(culler.active_count(), 0);
        assert!(culler.was_visible(0)); // Should be visible again after reset
        let bounds = culler.get_instance_bounds(0).unwrap();
        assert_eq!(bounds.center, [0.0, 0.0, 0.0]);
        assert_eq!(bounds.radius, 1.0);
    }

