    #[test]
    fn test_as_memory_pool_growth() {
        // Test config for pool growth
        let config = AsMemoryConfig::new()
            .with_initial_pool_size(1024)
            .with_max_pool_size(4096)
            .with_grow_factor(2.0);

        assert!(config.validate().is_ok());

        // Verify grow factor calculation
        let initial = config.initial_pool_size as f32;
        let grown = initial * config.grow_factor;
        assert_eq!(grown, 2048.0);

        // Second growth
        let second_growth = grown * config.grow_factor;
        assert_eq!(second_growth, 4096.0);

        // Third growth would exceed max, should be capped
        let third_growth = (second_growth * config.grow_factor).min(config.max_pool_size as f32);
        assert_eq!(third_growth, 4096.0);
    }

