    #[test]
    fn test_as_memory_alignment() {
        // Test alignment with FreeBlock
        let unaligned_block = FreeBlock::new(100, 1000);
        let aligned_offset = unaligned_block.aligned_offset(256);
        assert_eq!(aligned_offset, 256);
        assert_eq!(aligned_offset % 256, 0);

        // Test that aligned block stays aligned
        let aligned_block = FreeBlock::new(512, 1024);
        let offset = aligned_block.aligned_offset(256);
        assert_eq!(offset, 512);

        // Test can_fit with alignment consideration
        let block = FreeBlock::new(100, 300);
        // Aligned offset would be 256, need 300 - (256-100) = 300 - 156 = 144 remaining
        // So it cannot fit 200 bytes
        assert!(!block.can_fit(200, 256));

        // A larger block should fit
        let large_block = FreeBlock::new(100, 500);
        // Aligned offset 256, remaining = 500 - 156 = 344, can fit 200
        assert!(large_block.can_fit(200, 256));

        // Test default alignment constant
        assert_eq!(AS_MEMORY_ALIGNMENT, 256);
        assert!(AS_MEMORY_ALIGNMENT.is_power_of_two());
    }

    #[test]
    fn test_as_memory_out_of_memory() {
        // Test AsMemoryError
        let oom_error = AsMemoryError::OutOfMemory {
            requested: 1024,
            available: 512,
        };
        let display = format!("{}", oom_error);
        assert!(display.contains("1024"));
        assert!(display.contains("512"));

        let not_found = AsMemoryError::AllocationNotFound(42);
        assert!(format!("{}", not_found).contains("42"));

        let invalid_pool = AsMemoryError::InvalidPoolIndex(5);
        assert!(format!("{}", invalid_pool).contains("5"));

        let resize_failed = AsMemoryError::PoolResizeFailed("test error".to_string());
        assert!(format!("{}", resize_failed).contains("test error"));

        let invalid_config = AsMemoryError::InvalidConfig("bad config".to_string());
        assert!(format!("{}", invalid_config).contains("bad config"));

        let too_large = AsMemoryError::AllocationTooLarge {
            requested: 1000,
            max_pool_size: 500,
        };
        assert!(format!("{}", too_large).contains("1000"));
        assert!(format!("{}", too_large).contains("500"));

        let buffer_failed = AsMemoryError::BufferCreationFailed("GPU error".to_string());
        assert!(format!("{}", buffer_failed).contains("GPU error"));
    }

    #[test]
    fn test_as_memory_config_validation() {
        // Valid default config
        let config = AsMemoryConfig::default();
        assert!(config.validate().is_ok());

        // Test each validation error
        let zero_initial = AsMemoryConfig::new().with_initial_pool_size(0);
        assert!(matches!(
            zero_initial.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));

        let max_less_than_initial = AsMemoryConfig::new()
            .with_initial_pool_size(1000)
            .with_max_pool_size(500);
        assert!(matches!(
            max_less_than_initial.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));

        let bad_grow_factor = AsMemoryConfig::new().with_grow_factor(1.0);
        assert!(matches!(
            bad_grow_factor.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));

        let negative_threshold = AsMemoryConfig::new().with_defrag_threshold(-0.1);
        assert!(matches!(
            negative_threshold.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));

        let over_threshold = AsMemoryConfig::new().with_defrag_threshold(1.5);
        assert!(matches!(
            over_threshold.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));

        let zero_alignment = AsMemoryConfig::new().with_alignment(0);
        assert!(matches!(
            zero_alignment.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));

        let non_power_of_two = AsMemoryConfig::new().with_alignment(100);
        assert!(matches!(
            non_power_of_two.validate(),
            Err(AsMemoryError::InvalidConfig(_))
        ));
    }

