    #[test]
    fn test_ray_query_features_detection() {
        // Test default (no support)
        let no_support = RayQueryFeatures::no_support();
        assert!(!no_support.is_ray_query_supported());
        assert!(!no_support.is_ray_tracing_pipeline_supported());
        assert!(!no_support.has_any_ray_tracing());

        // Test full support
        let full = RayQueryFeatures::full_support();
        assert!(full.is_ray_query_supported());
        assert!(full.is_ray_tracing_pipeline_supported());
        assert!(full.has_any_ray_tracing());

        // Test partial support (ray query only)
        let ray_query_only = RayQueryFeatures {
            ray_query: true,
            ray_tracing_pipeline: false,
        };
        assert!(ray_query_only.is_ray_query_supported());
        assert!(!ray_query_only.is_ray_tracing_pipeline_supported());
        assert!(ray_query_only.has_any_ray_tracing());

        // Test display
        let display = format!("{}", full);
        assert!(display.contains("ray_query: true"));
        assert!(display.contains("ray_tracing_pipeline: true"));
    }

