    #[test]
    fn test_trace_config_builder() {
        // Test default
        let default_config = TraceConfig::default();
        assert_eq!(default_config.query_type, RayQueryType::Nearest);
        assert_eq!(default_config.cull_mask, 0xFF);
        assert_eq!(default_config.flags, RayFlags::NONE);

        // Test new() is same as default
        assert_eq!(TraceConfig::new(), TraceConfig::default());

        // Test shadow() preset
        let shadow_config = TraceConfig::shadow();
        assert_eq!(shadow_config.query_type, RayQueryType::Any);
        assert_eq!(shadow_config.cull_mask, 0xFF);
        assert!(shadow_config.flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(shadow_config.flags.contains(RayFlags::FORCE_OPAQUE));

        // Test primary() preset
        let primary_config = TraceConfig::primary();
        assert_eq!(primary_config.query_type, RayQueryType::Nearest);
        assert_eq!(primary_config.flags, RayFlags::NONE);

        // Test builder pattern
        let custom = TraceConfig::new()
            .with_query_type(RayQueryType::Any)
            .with_cull_mask(0x0F)
            .with_flags(RayFlags::CULL_BACK_FACING)
            .add_flags(RayFlags::FORCE_OPAQUE);

        assert_eq!(custom.query_type, RayQueryType::Any);
        assert_eq!(custom.cull_mask, 0x0F);
        assert!(custom.flags.contains(RayFlags::CULL_BACK_FACING));
        assert!(custom.flags.contains(RayFlags::FORCE_OPAQUE));

        // Test convenience methods
        let with_culling = TraceConfig::new().with_backface_culling();
        assert!(with_culling.flags.contains(RayFlags::CULL_BACK_FACING));

        let with_front_culling = TraceConfig::new().with_frontface_culling();
        assert!(with_front_culling.flags.contains(RayFlags::CULL_FRONT_FACING));

        let skip_tri = TraceConfig::new().skip_triangles();
        assert!(skip_tri.flags.contains(RayFlags::SKIP_TRIANGLES));

        let skip_aabb = TraceConfig::new().skip_aabbs();
        assert!(skip_aabb.flags.contains(RayFlags::SKIP_AABBS));
    }

    #[test]
    fn test_ray_flags_combinations() {
        // Test NONE
        let none = RayFlags::NONE;
        assert_eq!(none.bits(), 0);
        assert!(!none.contains(RayFlags::FORCE_OPAQUE));

        // Test single flags
        let opaque = RayFlags::FORCE_OPAQUE;
        assert!(opaque.contains(RayFlags::FORCE_OPAQUE));
        assert!(!opaque.contains(RayFlags::TERMINATE_ON_FIRST_HIT));

        // Test combining flags
        let combined = RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT;
        assert!(combined.contains(RayFlags::FORCE_OPAQUE));
        assert!(combined.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(!combined.contains(RayFlags::CULL_BACK_FACING));

        // Test shadow() preset
        let shadow = RayFlags::shadow();
        assert!(shadow.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(shadow.contains(RayFlags::FORCE_OPAQUE));

        // Test primary() preset
        let primary = RayFlags::primary();
        assert_eq!(primary, RayFlags::NONE);

        // Test with_backface_culling()
        let backface = RayFlags::with_backface_culling();
        assert!(backface.contains(RayFlags::CULL_BACK_FACING));

        // Test to_wgsl_value
        assert_eq!(RayFlags::NONE.to_wgsl_value(), 0);
        assert_eq!(RayFlags::FORCE_OPAQUE.to_wgsl_value(), 1);
        assert_eq!(RayFlags::TERMINATE_ON_FIRST_HIT.to_wgsl_value(), 4);

        // Test all individual flags have unique bits
        let all_flags = [
            RayFlags::FORCE_OPAQUE,
            RayFlags::FORCE_NON_OPAQUE,
            RayFlags::TERMINATE_ON_FIRST_HIT,
            RayFlags::SKIP_CLOSEST_HIT_SHADER,
            RayFlags::CULL_FRONT_FACING,
            RayFlags::CULL_BACK_FACING,
            RayFlags::CULL_OPAQUE,
            RayFlags::CULL_NON_OPAQUE,
            RayFlags::SKIP_TRIANGLES,
            RayFlags::SKIP_AABBS,
        ];

        for (i, flag1) in all_flags.iter().enumerate() {
            for (j, flag2) in all_flags.iter().enumerate() {
                if i != j {
                    // Different flags should not overlap
                    assert!((*flag1 & *flag2).is_empty(),
                        "Flags {:?} and {:?} overlap", flag1, flag2);
                }
            }
        }
    }

