    #[test]
    fn test_tlas_shader_visibility() {
        // Test individual flags
        let compute = TlasShaderVisibility::COMPUTE;
        let fragment = TlasShaderVisibility::FRAGMENT;

        assert!(compute.contains(TlasShaderVisibility::COMPUTE));
        assert!(!compute.contains(TlasShaderVisibility::FRAGMENT));

        assert!(!fragment.contains(TlasShaderVisibility::COMPUTE));
        assert!(fragment.contains(TlasShaderVisibility::FRAGMENT));

        // Test combining
        let both = TlasShaderVisibility::COMPUTE | TlasShaderVisibility::FRAGMENT;
        assert!(both.contains(TlasShaderVisibility::COMPUTE));
        assert!(both.contains(TlasShaderVisibility::FRAGMENT));

        // Test bits
        assert_eq!(TlasShaderVisibility::COMPUTE.bits(), 1);
        assert_eq!(TlasShaderVisibility::FRAGMENT.bits(), 2);
        assert_eq!(both.bits(), 3);
    }

    #[test]
    fn test_ray_desc_shadow() {
        let origin = [1.0, 2.0, 3.0];
        let light_pos = [4.0, 6.0, 3.0];

        let shadow_ray = RayDesc::shadow(origin, light_pos);

        // Origin should match
        assert_eq!(shadow_ray.origin, origin);

        // Direction should be normalized toward light
        // Direction = (3, 4, 0) / 5 = (0.6, 0.8, 0)
        assert!((shadow_ray.direction[0] - 0.6).abs() < 1e-6);
        assert!((shadow_ray.direction[1] - 0.8).abs() < 1e-6);
        assert!((shadow_ray.direction[2] - 0.0).abs() < 1e-6);

        // t_min should be small
        assert_eq!(shadow_ray.t_min, 0.001);

        // t_max should be slightly less than distance to light
        // Distance = 5, so t_max should be ~4.995
        assert!(shadow_ray.t_max < 5.0);
        assert!(shadow_ray.t_max > 4.9);
    }

