    #[test]
    fn test_hit_info_layout() {
        // Test construction
        let hit = HitInfo::new(5.0, 1, 42, true, [0.3, 0.3]);
        assert_eq!(hit.t, 5.0);
        assert_eq!(hit.instance_id, 1);
        assert_eq!(hit.primitive_id, 42);
        assert!(hit.front_face);
        assert_eq!(hit.barycentrics, [0.3, 0.3]);

        // Test no_hit marker
        let no_hit = HitInfo::no_hit();
        assert_eq!(no_hit.t, f32::MAX);
        assert_eq!(no_hit.instance_id, u32::MAX);
        assert_eq!(no_hit.primitive_id, u32::MAX);
        assert!(!no_hit.front_face);
        assert!(!no_hit.is_hit());

        // Test is_hit
        assert!(hit.is_hit());

        // Test barycentric weights
        let hit2 = HitInfo::new(1.0, 0, 0, true, [0.25, 0.25]);
        assert!((hit2.w0() - 0.5).abs() < 1e-6);
        assert!((hit2.w1() - 0.25).abs() < 1e-6);
        assert!((hit2.w2() - 0.25).abs() < 1e-6);

        // Test interpolate
        let interpolated = hit2.interpolate(1.0, 2.0, 3.0);
        // w0 * 1 + w1 * 2 + w2 * 3 = 0.5 * 1 + 0.25 * 2 + 0.25 * 3 = 0.5 + 0.5 + 0.75 = 1.75
        assert!((interpolated - 1.75).abs() < 1e-6);

        // Test interpolate_vec3
        let v0 = [1.0, 0.0, 0.0];
        let v1 = [0.0, 1.0, 0.0];
        let v2 = [0.0, 0.0, 1.0];
        let result = hit2.interpolate_vec3(v0, v1, v2);
        // w0 * v0 + w1 * v1 + w2 * v2 = [0.5, 0.25, 0.25]
        assert!((result[0] - 0.5).abs() < 1e-6);
        assert!((result[1] - 0.25).abs() < 1e-6);
        assert!((result[2] - 0.25).abs() < 1e-6);

        // Test default
        let default_hit = HitInfo::default();
        assert!(!default_hit.is_hit());
    }

