    #[test]
    fn test_ray_flag_usages() {
        let usages = RayFlagUsage::all_usages();

        // Should have documentation for all flags (including NONE)
        assert_eq!(usages.len(), 11);

        // Check that all flags are covered
        let documented_flags: Vec<RayFlags> = usages.iter().map(|u| u.flag).collect();
        assert!(documented_flags.contains(&RayFlags::NONE));
        assert!(documented_flags.contains(&RayFlags::FORCE_OPAQUE));
        assert!(documented_flags.contains(&RayFlags::FORCE_NON_OPAQUE));
        assert!(documented_flags.contains(&RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(documented_flags.contains(&RayFlags::SKIP_CLOSEST_HIT_SHADER));
        assert!(documented_flags.contains(&RayFlags::CULL_FRONT_FACING));
        assert!(documented_flags.contains(&RayFlags::CULL_BACK_FACING));
        assert!(documented_flags.contains(&RayFlags::CULL_OPAQUE));
        assert!(documented_flags.contains(&RayFlags::CULL_NON_OPAQUE));
        assert!(documented_flags.contains(&RayFlags::SKIP_TRIANGLES));
        assert!(documented_flags.contains(&RayFlags::SKIP_AABBS));

        // Check for_flag lookup
        let opaque_usage = RayFlagUsage::for_flag(RayFlags::FORCE_OPAQUE);
        assert!(opaque_usage.is_some());
        let opaque_usage = opaque_usage.unwrap();
        assert_eq!(opaque_usage.flag, RayFlags::FORCE_OPAQUE);
        assert!(!opaque_usage.use_case.is_empty());
        assert!(!opaque_usage.description.is_empty());
        assert!(opaque_usage.performance_note.is_some());

        // Check for_combined_flags
        let combined = RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT;
        let combined_usages = RayFlagUsage::for_combined_flags(combined);
        assert_eq!(combined_usages.len(), 2);
        let flags: Vec<RayFlags> = combined_usages.iter().map(|u| u.flag).collect();
        assert!(flags.contains(&RayFlags::FORCE_OPAQUE));
        assert!(flags.contains(&RayFlags::TERMINATE_ON_FIRST_HIT));
    }

    #[test]
    fn test_ray_flag_presets() {
        // Test Shadow preset
        let shadow = RayFlagPreset::Shadow;
        let shadow_flags = shadow.flags();
        assert!(shadow_flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(shadow_flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(!shadow_flags.contains(RayFlags::CULL_BACK_FACING));
        assert!(!shadow.description().is_empty());

        // Test PrimaryRay preset
        let primary = RayFlagPreset::PrimaryRay;
        assert_eq!(primary.flags(), RayFlags::NONE);

        // Test Reflection preset
        let reflection = RayFlagPreset::Reflection;
        assert!(reflection.flags().contains(RayFlags::CULL_BACK_FACING));

        // Test Refraction preset
        let refraction = RayFlagPreset::Refraction;
        assert_eq!(refraction.flags(), RayFlags::NONE);

        // Test AmbientOcclusion preset
        let ao = RayFlagPreset::AmbientOcclusion;
        assert!(ao.flags().contains(RayFlags::FORCE_OPAQUE));
        assert!(ao.flags().contains(RayFlags::TERMINATE_ON_FIRST_HIT));

        // Test Visibility preset
        let visibility = RayFlagPreset::Visibility;
        assert!(visibility.flags().contains(RayFlags::FORCE_OPAQUE));
        assert!(visibility.flags().contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(visibility.flags().contains(RayFlags::CULL_BACK_FACING));

        // Test ProceduralOnly preset
        let procedural = RayFlagPreset::ProceduralOnly;
        assert!(procedural.flags().contains(RayFlags::SKIP_TRIANGLES));

        // Test TrianglesOnly preset
        let triangles = RayFlagPreset::TrianglesOnly;
        assert!(triangles.flags().contains(RayFlags::SKIP_AABBS));

        // Test all() returns all presets
        let all = RayFlagPreset::all();
        assert_eq!(all.len(), 8);

        // Test from_flags
        let found = RayFlagPreset::from_flags(shadow_flags);
        // Shadow and AO have same flags, so either is valid
        assert!(
            found == Some(RayFlagPreset::Shadow)
                || found == Some(RayFlagPreset::AmbientOcclusion)
        );

        let visibility_flags = RayFlagPreset::Visibility.flags();
        assert_eq!(
            RayFlagPreset::from_flags(visibility_flags),
            Some(RayFlagPreset::Visibility)
        );

        // Unknown combination should return None
        let unknown = RayFlags::CULL_OPAQUE | RayFlags::CULL_NON_OPAQUE;
        assert_eq!(RayFlagPreset::from_flags(unknown), None);
    }

    #[test]
    fn test_ray_flag_validator_conflicts() {
        // Valid combinations
        assert!(RayFlagValidator::validate(RayFlags::NONE).is_ok());
        assert!(RayFlagValidator::validate(RayFlags::FORCE_OPAQUE).is_ok());
        assert!(RayFlagValidator::validate(
            RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT
        )
        .is_ok());
        assert!(RayFlagValidator::validate(RayFlags::CULL_BACK_FACING).is_ok());

        // Conflicting cull flags
        let cull_conflict = RayFlags::CULL_FRONT_FACING | RayFlags::CULL_BACK_FACING;
        assert!(RayFlagValidator::validate(cull_conflict).is_err());
        assert_eq!(
            RayFlagValidator::validate(cull_conflict),
            Err(RayFlagError::ConflictingCullFlags)
        );
        assert!(RayFlagValidator::has_conflicting_flags(cull_conflict));

        // Conflicting opaque flags
        let opaque_conflict = RayFlags::FORCE_OPAQUE | RayFlags::FORCE_NON_OPAQUE;
        assert!(RayFlagValidator::validate(opaque_conflict).is_err());
        assert_eq!(
            RayFlagValidator::validate(opaque_conflict),
            Err(RayFlagError::ConflictingOpaqueFlags)
        );
        assert!(RayFlagValidator::has_conflicting_flags(opaque_conflict));

        // Conflicting skip flags
        let skip_conflict = RayFlags::SKIP_TRIANGLES | RayFlags::SKIP_AABBS;
        assert!(RayFlagValidator::validate(skip_conflict).is_err());
        assert_eq!(
            RayFlagValidator::validate(skip_conflict),
            Err(RayFlagError::ConflictingSkipFlags)
        );
        assert!(RayFlagValidator::has_conflicting_flags(skip_conflict));

        // No conflicts
        assert!(!RayFlagValidator::has_conflicting_flags(RayFlags::NONE));
        assert!(!RayFlagValidator::has_conflicting_flags(
            RayFlagPreset::Shadow.flags()
        ));
    }

    #[test]
    fn test_ray_flag_validator_redundant() {
        // No redundancy for clean flags
        let clean = RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT;
        let warnings = RayFlagValidator::check_redundant(clean);
        assert!(warnings.is_empty());

        // FORCE_OPAQUE with CULL_OPAQUE is problematic
        let opaque_cull = RayFlags::FORCE_OPAQUE | RayFlags::CULL_OPAQUE;
        let warnings = RayFlagValidator::check_redundant(opaque_cull);
        assert!(!warnings.is_empty());
        assert!(matches!(
            warnings[0],
            RayFlagError::RedundantFlags { reason: _ }
        ));

        // FORCE_OPAQUE with CULL_NON_OPAQUE is redundant
        let opaque_cull_non = RayFlags::FORCE_OPAQUE | RayFlags::CULL_NON_OPAQUE;
        let warnings = RayFlagValidator::check_redundant(opaque_cull_non);
        assert!(!warnings.is_empty());

        // FORCE_NON_OPAQUE with CULL_NON_OPAQUE is problematic
        let non_opaque_cull = RayFlags::FORCE_NON_OPAQUE | RayFlags::CULL_NON_OPAQUE;
        let warnings = RayFlagValidator::check_redundant(non_opaque_cull);
        assert!(!warnings.is_empty());
    }

    #[test]
    fn test_ray_flag_validator_suggest_correction() {
        // Cull conflict - removes CULL_FRONT_FACING
        let cull_conflict = RayFlags::CULL_FRONT_FACING | RayFlags::CULL_BACK_FACING;
        let corrected = RayFlagValidator::suggest_correction(cull_conflict);
        assert!(!corrected.contains(RayFlags::CULL_FRONT_FACING));
        assert!(corrected.contains(RayFlags::CULL_BACK_FACING));
        assert!(RayFlagValidator::validate(corrected).is_ok());

        // Opaque conflict - keeps FORCE_OPAQUE
        let opaque_conflict = RayFlags::FORCE_OPAQUE | RayFlags::FORCE_NON_OPAQUE;
        let corrected = RayFlagValidator::suggest_correction(opaque_conflict);
        assert!(corrected.contains(RayFlags::FORCE_OPAQUE));
        assert!(!corrected.contains(RayFlags::FORCE_NON_OPAQUE));
        assert!(RayFlagValidator::validate(corrected).is_ok());

        // Skip conflict - removes SKIP_AABBS
        let skip_conflict = RayFlags::SKIP_TRIANGLES | RayFlags::SKIP_AABBS;
        let corrected = RayFlagValidator::suggest_correction(skip_conflict);
        assert!(corrected.contains(RayFlags::SKIP_TRIANGLES));
        assert!(!corrected.contains(RayFlags::SKIP_AABBS));
        assert!(RayFlagValidator::validate(corrected).is_ok());

        // Valid flags unchanged
        let valid = RayFlags::FORCE_OPAQUE | RayFlags::TERMINATE_ON_FIRST_HIT;
        let corrected = RayFlagValidator::suggest_correction(valid);
        assert_eq!(corrected, valid);
    }

    #[test]
    fn test_ray_flag_validator_analyze() {
        // Valid flags
        let valid = RayFlagPreset::Shadow.flags();
        let analysis = RayFlagValidator::analyze(valid);
        assert!(analysis.is_valid);
        assert!(analysis.errors.is_empty());
        assert!(analysis.warnings.is_empty());
        assert!(analysis.suggested.is_none());
        assert!(analysis.matching_preset.is_some());

        // Invalid flags
        let invalid = RayFlags::CULL_FRONT_FACING | RayFlags::CULL_BACK_FACING;
        let analysis = RayFlagValidator::analyze(invalid);
        assert!(!analysis.is_valid);
        assert!(!analysis.errors.is_empty());
        assert!(analysis.suggested.is_some());
    }

    #[test]
    fn test_ray_flag_builder_fluent() {
        // Build from scratch
        let flags = RayFlagBuilder::new()
            .force_opaque()
            .terminate_on_first_hit()
            .build()
            .unwrap();
        assert!(flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));

        // Chain all methods
        let flags = RayFlagBuilder::new()
            .force_opaque()
            .terminate_on_first_hit()
            .cull_back_facing()
            .build()
            .unwrap();
        assert!(flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(flags.contains(RayFlags::CULL_BACK_FACING));

        // Test all builder methods - create two builders since build() consumes
        let builder_for_validation = RayFlagBuilder::new()
            .force_opaque()
            .force_non_opaque() // Will conflict
            .terminate_on_first_hit()
            .skip_closest_hit_shader()
            .cull_back_facing()
            .cull_front_facing() // Will conflict
            .cull_opaque()
            .cull_non_opaque()
            .skip_triangles()
            .skip_aabbs(); // Will conflict

        // Should fail validation due to conflicts
        assert!(builder_for_validation.build().is_err());

        // But build_unchecked works (create new builder)
        let builder_for_unchecked = RayFlagBuilder::new()
            .force_opaque()
            .force_non_opaque()
            .terminate_on_first_hit()
            .skip_closest_hit_shader()
            .cull_back_facing()
            .cull_front_facing()
            .cull_opaque()
            .cull_non_opaque()
            .skip_triangles()
            .skip_aabbs();

        let unchecked = builder_for_unchecked.build_unchecked();
        assert!(unchecked.contains(RayFlags::FORCE_OPAQUE));
        assert!(unchecked.contains(RayFlags::FORCE_NON_OPAQUE));
    }

    #[test]
    fn test_ray_flag_builder_preset() {
        // Build from preset
        let flags = RayFlagBuilder::from_preset(RayFlagPreset::Shadow)
            .cull_back_facing()
            .build()
            .unwrap();
        assert!(flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(flags.contains(RayFlags::CULL_BACK_FACING));

        // Build from existing flags
        let existing = RayFlags::FORCE_OPAQUE;
        let flags = RayFlagBuilder::from_flags(existing)
            .terminate_on_first_hit()
            .build()
            .unwrap();
        assert!(flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));

        // Test without() method
        let flags = RayFlagBuilder::from_preset(RayFlagPreset::Visibility)
            .without(RayFlags::CULL_BACK_FACING)
            .build()
            .unwrap();
        assert!(flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));
        assert!(!flags.contains(RayFlags::CULL_BACK_FACING));

        // Test clear() method
        let flags = RayFlagBuilder::from_preset(RayFlagPreset::Shadow)
            .clear()
            .force_opaque()
            .build()
            .unwrap();
        assert!(flags.contains(RayFlags::FORCE_OPAQUE));
        assert!(!flags.contains(RayFlags::TERMINATE_ON_FIRST_HIT));

        // Test current() and is_valid()
        let builder = RayFlagBuilder::new()
            .force_opaque()
            .terminate_on_first_hit();
        assert!(builder.is_valid());
        assert!(builder.current().contains(RayFlags::FORCE_OPAQUE));

        let invalid_builder = RayFlagBuilder::new()
            .cull_front_facing()
            .cull_back_facing();
        assert!(!invalid_builder.is_valid());
    }

