        assert!(wgsl.contains("RAY_FLAG_SKIP_CLOSEST_HIT_SHADER: u32 = 0x08u"));
        assert!(wgsl.contains("RAY_FLAG_CULL_BACK_FACING: u32 = 0x10u"));
        assert!(wgsl.contains("RAY_FLAG_CULL_FRONT_FACING: u32 = 0x20u"));
        assert!(wgsl.contains("RAY_FLAG_CULL_OPAQUE: u32 = 0x40u"));
        assert!(wgsl.contains("RAY_FLAG_CULL_NON_OPAQUE: u32 = 0x80u"));
        assert!(wgsl.contains("RAY_FLAG_SKIP_TRIANGLES: u32 = 0x100u"));
