    #[test]
    fn test_ray_flag_error_display() {
        // Test all error variants have proper Display implementation
        let errors = [
            RayFlagError::ConflictingCullFlags,
            RayFlagError::ConflictingOpaqueFlags,
            RayFlagError::ConflictingSkipFlags,
            RayFlagError::RedundantFlags {
                reason: "test reason",
            },
        ];

        for error in errors {
            let display = format!("{}", error);
            assert!(!display.is_empty());
        }

        // Check specific messages
        assert!(format!("{}", RayFlagError::ConflictingCullFlags)
            .contains("CULL_FRONT_FACING"));
        assert!(format!("{}", RayFlagError::ConflictingOpaqueFlags)
            .contains("FORCE_OPAQUE"));
        assert!(format!("{}", RayFlagError::ConflictingSkipFlags)
            .contains("SKIP_TRIANGLES"));
        assert!(format!(
            "{}",
            RayFlagError::RedundantFlags {
                reason: "my reason"
            }
        )
        .contains("my reason"));
    }

