// =============================================================================
// T-WGPU-P5.6.4: Shadow Ray Pattern
// =============================================================================
//
// Shadow ray patterns for wgpu 25.x ray tracing with:
// - Early termination (TERMINATE_ON_FIRST_HIT) for optimized shadow queries
// - Binary visibility result (hit/miss boolean output)
// - Light loop integration for multiple lights per pixel
// - Soft shadows via multi-ray area light sampling
// =============================================================================

// ---------------------------------------------------------------------------
// Shadow Ray Configuration
// ---------------------------------------------------------------------------

/// Configuration for shadow ray tracing operations.
///
/// Controls behavior like max distance, bias offset, alpha testing,
/// and face culling for shadow queries.
///
/// # Example
///
/// ```ignore
/// use crate::blas::ShadowRayConfig;
///
/// // Default configuration
/// let config = ShadowRayConfig::default();
///
/// // Custom configuration for close-range shadows
/// let config = ShadowRayConfig {
///     max_distance: 100.0,
///     bias: 0.01,
///     use_alpha_test: true,
///     cull_back_faces: false,
/// };
/// ```
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct ShadowRayConfig {
    /// Maximum distance for shadow rays. Rays beyond this distance
    /// are considered fully lit (no shadow).
    pub max_distance: f32,

    /// Bias offset to prevent self-shadowing (shadow acne).
    /// Applied along the surface normal before casting the ray.
    pub bias: f32,

    /// Whether to perform alpha testing for transparent shadows.
    /// When true, uses FORCE_NON_OPAQUE to allow any-hit testing.
    /// When false, uses FORCE_OPAQUE for maximum performance.
    pub use_alpha_test: bool,

    /// Whether to cull back-facing triangles during shadow testing.
    /// Typically true for closed meshes to improve performance.
    pub cull_back_faces: bool,
}

impl Default for ShadowRayConfig {
    fn default() -> Self {
        Self {
            max_distance: 1000.0,
            bias: 0.001,
            use_alpha_test: false,
            cull_back_faces: true,
        }
    }
}

impl ShadowRayConfig {
    /// Create a configuration for close-range soft shadows.
    pub fn soft_shadow() -> Self {
        Self {
            max_distance: 500.0,
            bias: 0.0005,
            use_alpha_test: false,
            cull_back_faces: true,
        }
    }

    /// Create a configuration for hard shadows with maximum performance.
    pub fn hard_shadow() -> Self {
        Self {
            max_distance: 1000.0,
            bias: 0.001,
            use_alpha_test: false,
            cull_back_faces: true,
        }
    }

    /// Create a configuration for transparent shadow casting.
    pub fn transparent_shadow() -> Self {
        Self {
            max_distance: 1000.0,
            bias: 0.001,
            use_alpha_test: true,
            cull_back_faces: false,
        }
    }

    /// Get the ray flags appropriate for this configuration.
    pub fn ray_flags(&self) -> RayFlags {
        let mut flags = RayFlags::TERMINATE_ON_FIRST_HIT;

        if self.use_alpha_test {
            flags |= RayFlags::FORCE_NON_OPAQUE;
        } else {
            flags |= RayFlags::FORCE_OPAQUE;
        }

        if self.cull_back_faces {
            flags |= RayFlags::CULL_BACK_FACING;
        }

        flags
    }

    /// Validate the configuration values.
    pub fn validate(&self) -> Result<(), ShadowRayError> {
        if self.max_distance <= 0.0 {
            return Err(ShadowRayError::InvalidMaxDistance(self.max_distance));
        }
        if self.bias < 0.0 {
            return Err(ShadowRayError::InvalidBias(self.bias));
        }
        Ok(())
    }
}

// ---------------------------------------------------------------------------
// Shadow Ray Result
// ---------------------------------------------------------------------------

/// Result of a shadow ray query.
///
/// Contains the visibility factor (0.0 = fully shadowed, 1.0 = fully lit)
/// and optionally the distance to the first occluder hit.
///
/// # Memory Layout
///
/// This struct is Pod/Zeroable for direct GPU buffer usage:
/// - `visibility`: 4 bytes (f32)
/// - `hit_distance`: 4 bytes (f32)
/// - Total: 8 bytes, 4-byte aligned
///
/// # Example
///
/// ```ignore
/// use crate::blas::ShadowRayResult;
///
/// // Create a result indicating full occlusion
/// let occluded = ShadowRayResult::shadowed(5.5);
///
/// // Create a result indicating no occlusion
/// let lit = ShadowRayResult::lit();
///
/// // Check visibility
/// if result.is_fully_lit() {
///     // Apply full lighting
/// } else if result.is_fully_shadowed() {
///     // Skip direct lighting
/// }
/// ```
#[repr(C)]
#[derive(Clone, Copy, Debug, PartialEq)]
pub struct ShadowRayResult {
    /// Visibility factor: 0.0 = fully shadowed, 1.0 = fully lit.
    /// For soft shadows, intermediate values represent partial occlusion.
    pub visibility: f32,

    /// Distance to the first hit (occluder), or `f32::MAX` if no hit.
    /// Useful for contact hardening soft shadows (PCSS).
    pub hit_distance: f32,
}

unsafe impl bytemuck::Pod for ShadowRayResult {}
unsafe impl bytemuck::Zeroable for ShadowRayResult {}

impl Default for ShadowRayResult {
    fn default() -> Self {
        Self::lit()
    }
}

impl ShadowRayResult {
    /// Create a result indicating the point is fully lit (no occlusion).
    pub fn lit() -> Self {
        Self {
            visibility: 1.0,
            hit_distance: f32::MAX,
        }
    }

    /// Create a result indicating the point is fully shadowed.
    pub fn shadowed(hit_distance: f32) -> Self {
        Self {
            visibility: 0.0,
            hit_distance,
        }
    }

    /// Create a result with partial visibility (for soft shadows).
    pub fn partial(visibility: f32, hit_distance: f32) -> Self {
        Self {
            visibility: visibility.clamp(0.0, 1.0),
            hit_distance,
        }
    }

    /// Check if the point is fully lit (visibility == 1.0).
    pub fn is_fully_lit(&self) -> bool {
        self.visibility >= 1.0
    }

    /// Check if the point is fully shadowed (visibility == 0.0).
    pub fn is_fully_shadowed(&self) -> bool {
        self.visibility <= 0.0
    }

    /// Check if the point is partially shadowed.
    pub fn is_partially_shadowed(&self) -> bool {
        self.visibility > 0.0 && self.visibility < 1.0
    }

    /// Combine multiple shadow results (e.g., from multiple samples).
    pub fn combine(results: &[ShadowRayResult]) -> Self {
        if results.is_empty() {
            return Self::lit();
        }

        let total_visibility: f32 = results.iter().map(|r| r.visibility).sum();
        let avg_visibility = total_visibility / results.len() as f32;

        let min_distance = results
            .iter()
            .filter(|r| r.visibility < 1.0)
            .map(|r| r.hit_distance)
            .fold(f32::MAX, f32::min);

        Self {
            visibility: avg_visibility,
            hit_distance: min_distance,
        }
    }
}

// ---------------------------------------------------------------------------
// Shadow Ray Errors
// ---------------------------------------------------------------------------

/// Errors that can occur during shadow ray operations.
#[derive(Debug, Clone, PartialEq)]
pub enum ShadowRayError {
    /// Invalid max distance (must be positive).
    InvalidMaxDistance(f32),

    /// Invalid bias value (must be non-negative).
    InvalidBias(f32),

    /// Invalid sample count (must be at least 1).
    InvalidSampleCount(u32),

    /// Light is behind the surface (dot product <= 0).
    LightBehindSurface,

    /// Invalid light configuration.
    InvalidLightConfig(&'static str),
}

impl std::fmt::Display for ShadowRayError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ShadowRayError::InvalidMaxDistance(d) => {
                write!(f, "Invalid max distance: {} (must be positive)", d)
            }
            ShadowRayError::InvalidBias(b) => {
                write!(f, "Invalid bias: {} (must be non-negative)", b)
            }
            ShadowRayError::InvalidSampleCount(c) => {
                write!(f, "Invalid sample count: {} (must be at least 1)", c)
            }
            ShadowRayError::LightBehindSurface => {
                write!(f, "Light is behind the surface (cannot cast shadow ray)")
            }
            ShadowRayError::InvalidLightConfig(reason) => {
                write!(f, "Invalid light configuration: {}", reason)
            }
        }
    }
}

impl std::error::Error for ShadowRayError {}

// ---------------------------------------------------------------------------
// Light Types
// ---------------------------------------------------------------------------

/// Light source types for shadow ray generation.
///
/// Each light type defines how shadow rays should be cast toward the light
/// source, including position, direction, and shape parameters.
///
/// # Example
///
/// ```ignore
/// use crate::blas::LightType;
///
/// // Point light at position (10, 20, 10) with radius 0.5
/// let point = LightType::Point {
///     position: [10.0, 20.0, 10.0],
///     radius: 0.5,
/// };
///
/// // Directional light (sun) pointing downward
/// let sun = LightType::Directional {
///     direction: [0.0, -1.0, 0.0],
/// };
///
/// // Area light for soft shadows
/// let area = LightType::Area {
///     center: [0.0, 5.0, 0.0],
///     normal: [0.0, -1.0, 0.0],
///     half_extents: [2.0, 2.0],
/// };
/// ```
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum LightType {
    /// Point light source.
    ///
    /// Emits light equally in all directions from a single point.
    /// The radius is used for soft shadow sampling.
    Point {
        /// World-space position of the light.
        position: [f32; 3],
        /// Radius of the light source (for soft shadows). Use 0.0 for hard shadows.
        radius: f32,
    },

    /// Directional light source (infinite distance, like the sun).
    ///
    /// All rays are parallel in the given direction.
    Directional {
        /// Direction vector pointing FROM the light TO the scene.
        /// Should be normalized.
        direction: [f32; 3],
    },

    /// Spot light source.
    ///
    /// Point light with a cone of influence.
    Spot {
        /// World-space position of the light.
        position: [f32; 3],
        /// Direction the spotlight is pointing (normalized).
        direction: [f32; 3],
        /// Inner cone angle in radians (full intensity).
        inner_angle: f32,
        /// Outer cone angle in radians (falloff to zero).
        outer_angle: f32,
    },

    /// Rectangular area light source.
    ///
    /// Produces soft shadows with natural penumbra.
    Area {
        /// Center position of the area light.
        center: [f32; 3],
        /// Normal direction of the light (pointing away from emitting surface).
        normal: [f32; 3],
        /// Half-extents of the rectangular light [width/2, height/2].
        half_extents: [f32; 2],
    },
}

impl LightType {
    /// Get the primary position or a representative point for this light.
    pub fn position(&self) -> [f32; 3] {
        match self {
            LightType::Point { position, .. } => *position,
            LightType::Directional { direction } => {
                // Return a far point in the opposite direction
                let d = *direction;
                [-d[0] * 10000.0, -d[1] * 10000.0, -d[2] * 10000.0]
            }
            LightType::Spot { position, .. } => *position,
            LightType::Area { center, .. } => *center,
        }
    }

    /// Get the direction from a surface point to this light.
    pub fn direction_from(&self, surface_pos: [f32; 3]) -> [f32; 3] {
        match self {
            LightType::Point { position, .. } | LightType::Spot { position, .. } => {
                let dx = position[0] - surface_pos[0];
                let dy = position[1] - surface_pos[1];
                let dz = position[2] - surface_pos[2];
                let len = (dx * dx + dy * dy + dz * dz).sqrt();
                if len > 0.0 {
                    [dx / len, dy / len, dz / len]
                } else {
                    [0.0, 1.0, 0.0]
                }
            }
            LightType::Directional { direction } => {
                // Negate because direction points FROM light TO scene
                [-direction[0], -direction[1], -direction[2]]
            }
            LightType::Area { center, .. } => {
                let dx = center[0] - surface_pos[0];
                let dy = center[1] - surface_pos[1];
                let dz = center[2] - surface_pos[2];
                let len = (dx * dx + dy * dy + dz * dz).sqrt();
                if len > 0.0 {
                    [dx / len, dy / len, dz / len]
                } else {
                    [0.0, 1.0, 0.0]
                }
            }
        }
    }

    /// Get the distance from a surface point to this light.
    /// Returns `f32::MAX` for directional lights.
    pub fn distance_from(&self, surface_pos: [f32; 3]) -> f32 {
        match self {
            LightType::Point { position, .. }
            | LightType::Spot { position, .. }
            | LightType::Area { center: position, .. } => {
                let dx = position[0] - surface_pos[0];
                let dy = position[1] - surface_pos[1];
                let dz = position[2] - surface_pos[2];
                (dx * dx + dy * dy + dz * dz).sqrt()
            }
            LightType::Directional { .. } => f32::MAX,
        }
    }

    /// Check if this light type produces soft shadows.
    pub fn is_area_light(&self) -> bool {
        match self {
            LightType::Point { radius, .. } => *radius > 0.0,
            LightType::Directional { .. } => false,
            LightType::Spot { .. } => false,
            LightType::Area { .. } => true,
        }
    }

    /// Validate the light parameters.
    pub fn validate(&self) -> Result<(), ShadowRayError> {
        match self {
            LightType::Point { radius, .. } => {
                if *radius < 0.0 {
                    return Err(ShadowRayError::InvalidLightConfig(
                        "Point light radius must be non-negative",
                    ));
                }
            }
            LightType::Directional { direction } => {
                let len_sq =
                    direction[0] * direction[0] + direction[1] * direction[1] + direction[2] * direction[2];
                if len_sq < 0.001 {
                    return Err(ShadowRayError::InvalidLightConfig(
                        "Directional light direction must not be zero",
                    ));
                }
            }
            LightType::Spot {
                inner_angle,
                outer_angle,
                ..
            } => {
                if *inner_angle < 0.0 || *outer_angle < 0.0 {
                    return Err(ShadowRayError::InvalidLightConfig(
                        "Spot light angles must be non-negative",
                    ));
                }
                if *inner_angle > *outer_angle {
                    return Err(ShadowRayError::InvalidLightConfig(
                        "Spot light inner angle must be <= outer angle",
                    ));
                }
            }
            LightType::Area { half_extents, .. } => {
                if half_extents[0] <= 0.0 || half_extents[1] <= 0.0 {
                    return Err(ShadowRayError::InvalidLightConfig(
                        "Area light half extents must be positive",
                    ));
                }
            }
        }
        Ok(())
    }
}

// ---------------------------------------------------------------------------
// Shadow Ray Generator
// ---------------------------------------------------------------------------

/// Generator for shadow rays from surface points to light sources.
///
/// Provides methods to create properly configured `RayDesc` instances
/// for shadow testing, with appropriate bias and distance settings.
///
/// # Example
///
/// ```ignore
/// use crate::blas::{ShadowRayGenerator, ShadowRayConfig, LightType};
///
/// let config = ShadowRayConfig::default();
/// let surface_pos = [0.0, 0.0, 0.0];
/// let light_pos = [10.0, 20.0, 10.0];
///
/// // Generate ray for point light
/// let ray = ShadowRayGenerator::point_light(surface_pos, light_pos, &config);
///
/// // Generate ray for directional light
/// let light_dir = [0.0, -1.0, 0.0]; // Pointing down (from sun)
/// let ray = ShadowRayGenerator::directional_light(surface_pos, light_dir, &config);
/// ```
pub struct ShadowRayGenerator;

impl ShadowRayGenerator {
    /// Generate a shadow ray from a surface point to a point light.
    ///
    /// The ray is configured with:
    /// - Origin: surface position + bias in light direction
    /// - Direction: normalized vector toward light
    /// - t_min: config.bias
    /// - t_max: min(distance_to_light - epsilon, config.max_distance)
    pub fn point_light(
        surface_pos: [f32; 3],
        light_pos: [f32; 3],
        config: &ShadowRayConfig,
    ) -> RayDesc {
        let dx = light_pos[0] - surface_pos[0];
        let dy = light_pos[1] - surface_pos[1];
        let dz = light_pos[2] - surface_pos[2];
        let distance = (dx * dx + dy * dy + dz * dz).sqrt();

        let direction = if distance > 0.0 {
            [dx / distance, dy / distance, dz / distance]
        } else {
            [0.0, 1.0, 0.0] // Default up if at same position
        };

        // Apply bias in the direction of the light
        let origin = [
            surface_pos[0] + direction[0] * config.bias,
            surface_pos[1] + direction[1] * config.bias,
            surface_pos[2] + direction[2] * config.bias,
        ];

        // Cap t_max at light distance (minus small epsilon) and max_distance
        let t_max = (distance - config.bias * 2.0)
            .min(config.max_distance)
            .max(0.0);

        RayDesc {
            origin,
            t_min: config.bias,
            direction,
            t_max,
        }
    }

    /// Generate a shadow ray for a directional light (e.g., sun).
    ///
    /// The ray is configured with:
    /// - Origin: surface position
    /// - Direction: negated light direction (toward light)
    /// - t_min: config.bias
    /// - t_max: config.max_distance (directional lights have infinite distance)
    pub fn directional_light(
        surface_pos: [f32; 3],
        light_dir: [f32; 3],
        config: &ShadowRayConfig,
    ) -> RayDesc {
        // Normalize and negate (light_dir points FROM light, we need TO light)
        let len = (light_dir[0] * light_dir[0]
            + light_dir[1] * light_dir[1]
            + light_dir[2] * light_dir[2])
        .sqrt();

        let direction = if len > 0.0 {
            [-light_dir[0] / len, -light_dir[1] / len, -light_dir[2] / len]
        } else {
            [0.0, 1.0, 0.0]
        };

        // Apply bias in the direction of the light
        let origin = [
            surface_pos[0] + direction[0] * config.bias,
            surface_pos[1] + direction[1] * config.bias,
            surface_pos[2] + direction[2] * config.bias,
        ];

        RayDesc {
            origin,
            t_min: config.bias,
            direction,
            t_max: config.max_distance,
        }
    }

    /// Generate a shadow ray for a spot light.
    ///
    /// Returns `None` if the surface point is outside the light's cone.
    pub fn spot_light(
        surface_pos: [f32; 3],
        light: &LightType,
        config: &ShadowRayConfig,
    ) -> Option<RayDesc> {
        match light {
            LightType::Spot {
                position,
                direction: spot_dir,
                outer_angle,
                ..
            } => {
                // Calculate direction from surface to light
                let to_light = [
                    position[0] - surface_pos[0],
                    position[1] - surface_pos[1],
                    position[2] - surface_pos[2],
                ];
                let distance = (to_light[0] * to_light[0]
                    + to_light[1] * to_light[1]
                    + to_light[2] * to_light[2])
                .sqrt();

                if distance < 0.001 {
                    return None;
                }

                let to_light_norm = [
                    to_light[0] / distance,
                    to_light[1] / distance,
                    to_light[2] / distance,
                ];

                // Check if surface is within spot cone
                // Dot product of -to_light and spot_dir gives cos(angle)
                let cos_angle = -(to_light_norm[0] * spot_dir[0]
                    + to_light_norm[1] * spot_dir[1]
                    + to_light_norm[2] * spot_dir[2]);

                let cos_outer = outer_angle.cos();

                if cos_angle < cos_outer {
                    return None; // Outside spot cone
                }

                // Apply bias
                let origin = [
                    surface_pos[0] + to_light_norm[0] * config.bias,
                    surface_pos[1] + to_light_norm[1] * config.bias,
                    surface_pos[2] + to_light_norm[2] * config.bias,
                ];

                let t_max = (distance - config.bias * 2.0)
                    .min(config.max_distance)
                    .max(0.0);

                Some(RayDesc {
                    origin,
                    t_min: config.bias,
                    direction: to_light_norm,
                    t_max,
                })
            }
            _ => None,
        }
    }

    /// Generate a shadow ray for any light type.
    pub fn for_light(
        surface_pos: [f32; 3],
        light: &LightType,
        config: &ShadowRayConfig,
    ) -> Option<RayDesc> {
        match light {
            LightType::Point { position, .. } => {
                Some(Self::point_light(surface_pos, *position, config))
            }
            LightType::Directional { direction } => {
                Some(Self::directional_light(surface_pos, *direction, config))
            }
            LightType::Spot { .. } => Self::spot_light(surface_pos, light, config),
            LightType::Area { center, .. } => {
                Some(Self::point_light(surface_pos, *center, config))
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Soft Shadow Sampling
// ---------------------------------------------------------------------------

/// Sampling patterns for soft shadow multi-ray queries.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
pub enum SamplingPattern {
    /// Uniform random sampling.
    /// Fast but can produce noise.
    #[default]
    Uniform,

    /// Stratified sampling (jittered grid).
    /// Better coverage than uniform with similar cost.
    Stratified,

    /// Poisson disk sampling.
    /// Best quality but more expensive to generate.
    PoissonDisk,

    /// Halton sequence (quasi-random).
    /// Low-discrepancy sequence for good coverage.
    Halton,
}

impl SamplingPattern {
    /// Get a human-readable name for this pattern.
    pub fn name(&self) -> &'static str {
        match self {
            SamplingPattern::Uniform => "Uniform",
            SamplingPattern::Stratified => "Stratified",
            SamplingPattern::PoissonDisk => "Poisson Disk",
            SamplingPattern::Halton => "Halton",
        }
    }

    /// Get all available sampling patterns.
    pub fn all() -> &'static [SamplingPattern] {
        &[
            SamplingPattern::Uniform,
            SamplingPattern::Stratified,
            SamplingPattern::PoissonDisk,
            SamplingPattern::Halton,
        ]
    }
}

/// Sampler for generating soft shadow rays.
///
/// Generates multiple sample points for area lights and spherical lights
/// to create realistic soft shadows with proper penumbra.
///
/// # Example
///
/// ```ignore
/// use crate::blas::{SoftShadowSampler, SamplingPattern, LightType};
///
/// let sampler = SoftShadowSampler::new(16); // 16 samples per pixel
///
/// // Generate samples for area light soft shadows
/// let samples = sampler.generate_samples(pixel_seed);
///
/// // Sample points on an area light
/// let area_light = LightType::Area {
///     center: [0.0, 5.0, 0.0],
///     normal: [0.0, -1.0, 0.0],
///     half_extents: [2.0, 2.0],
/// };
///
/// for i in 0..sampler.sample_count {
///     let light_point = sampler.sample_area_light(&area_light, i, pixel_seed);
///     // Cast shadow ray to light_point
/// }
/// ```
#[derive(Debug, Clone, PartialEq)]
pub struct SoftShadowSampler {
    /// Number of shadow rays to cast per pixel/light.
    pub sample_count: u32,

    /// Jitter radius for adding noise to sample positions.
    /// Helps break up banding artifacts.
    pub jitter_radius: f32,

    /// Sampling pattern to use for generating samples.
    pub sampling_pattern: SamplingPattern,
}

impl Default for SoftShadowSampler {
    fn default() -> Self {
        Self {
            sample_count: 16,
            jitter_radius: 0.0,
            sampling_pattern: SamplingPattern::Stratified,
        }
    }
}

impl SoftShadowSampler {
    /// Create a new sampler with the specified sample count.
    pub fn new(sample_count: u32) -> Self {
        Self {
            sample_count: sample_count.max(1),
            jitter_radius: 0.0,
            sampling_pattern: SamplingPattern::Stratified,
        }
    }

    /// Create a sampler with a specific pattern.
    pub fn with_pattern(sample_count: u32, pattern: SamplingPattern) -> Self {
        Self {
            sample_count: sample_count.max(1),
            jitter_radius: 0.0,
            sampling_pattern: pattern,
        }
    }

    /// Set the jitter radius for sample positions.
    pub fn with_jitter(mut self, radius: f32) -> Self {
        self.jitter_radius = radius.max(0.0);
        self
    }

    /// Generate 2D sample positions in [-1, 1] range.
    ///
    /// The `seed` parameter should be unique per pixel for temporal variation.
    pub fn generate_samples(&self, seed: u32) -> Vec<[f32; 2]> {
        let mut samples = Vec::with_capacity(self.sample_count as usize);

        match self.sampling_pattern {
            SamplingPattern::Uniform => {
                for i in 0..self.sample_count {
                    let s = Self::hash_to_float(seed, i, 0);
                    let t = Self::hash_to_float(seed, i, 1);
                    samples.push([s * 2.0 - 1.0, t * 2.0 - 1.0]);
                }
            }
            SamplingPattern::Stratified => {
                let grid_size = (self.sample_count as f32).sqrt().ceil() as u32;
                let cell_size = 2.0 / grid_size as f32;

                for i in 0..self.sample_count {
                    let cell_x = i % grid_size;
                    let cell_y = i / grid_size;

                    let jitter_x = Self::hash_to_float(seed, i, 0);
                    let jitter_y = Self::hash_to_float(seed, i, 1);

                    let x = -1.0 + (cell_x as f32 + jitter_x) * cell_size;
                    let y = -1.0 + (cell_y as f32 + jitter_y) * cell_size;

                    samples.push([x.clamp(-1.0, 1.0), y.clamp(-1.0, 1.0)]);
                }
            }
            SamplingPattern::PoissonDisk => {
                // Simplified Poisson disk using rejection sampling
                // For production, use a proper algorithm like Bridson's
                let min_dist = 2.0 / (self.sample_count as f32).sqrt();

                samples.push([0.0, 0.0]); // Start at center

                let mut attempts = 0;
                while samples.len() < self.sample_count as usize && attempts < self.sample_count * 30
                {
                    let x = Self::hash_to_float(seed, attempts, 0) * 2.0 - 1.0;
                    let y = Self::hash_to_float(seed, attempts, 1) * 2.0 - 1.0;

                    let valid = samples
                        .iter()
                        .all(|s| (s[0] - x).powi(2) + (s[1] - y).powi(2) >= min_dist * min_dist);

                    if valid {
                        samples.push([x, y]);
                    }
                    attempts += 1;
                }

                // Fill remaining with uniform if needed
                while samples.len() < self.sample_count as usize {
                    let i = samples.len() as u32;
                    let x = Self::hash_to_float(seed, i + 1000, 0) * 2.0 - 1.0;
                    let y = Self::hash_to_float(seed, i + 1000, 1) * 2.0 - 1.0;
                    samples.push([x, y]);
                }
            }
            SamplingPattern::Halton => {
                for i in 0..self.sample_count {
                    let x = Self::halton(i + 1, 2) * 2.0 - 1.0;
                    let y = Self::halton(i + 1, 3) * 2.0 - 1.0;
                    samples.push([x, y]);
                }
            }
        }

        // Apply jitter if requested
        if self.jitter_radius > 0.0 {
            for (i, sample) in samples.iter_mut().enumerate() {
                let jx = Self::hash_to_float(seed, i as u32, 2) * 2.0 - 1.0;
                let jy = Self::hash_to_float(seed, i as u32, 3) * 2.0 - 1.0;
                sample[0] = (sample[0] + jx * self.jitter_radius).clamp(-1.0, 1.0);
                sample[1] = (sample[1] + jy * self.jitter_radius).clamp(-1.0, 1.0);
            }
        }

        samples
    }

    /// Sample a point on an area light surface.
    ///
    /// Returns a world-space position on the light for the given sample index.
    pub fn sample_area_light(&self, light: &LightType, sample_idx: u32, seed: u32) -> [f32; 3] {
        match light {
            LightType::Area {
                center,
                normal,
                half_extents,
            } => {
                // Generate 2D sample point
                let s = Self::hash_to_float(seed, sample_idx, 0) * 2.0 - 1.0;
                let t = Self::hash_to_float(seed, sample_idx, 1) * 2.0 - 1.0;

                // Build tangent frame from normal
                let (tangent, bitangent) = Self::build_tangent_frame(*normal);

                // Compute point on light surface
                [
                    center[0] + tangent[0] * s * half_extents[0] + bitangent[0] * t * half_extents[1],
                    center[1] + tangent[1] * s * half_extents[0] + bitangent[1] * t * half_extents[1],
                    center[2] + tangent[2] * s * half_extents[0] + bitangent[2] * t * half_extents[1],
                ]
            }
            LightType::Point { position, radius } => {
                if *radius <= 0.0 {
                    return *position;
                }

                // Sample point on sphere surface
                let u = Self::hash_to_float(seed, sample_idx, 0);
                let v = Self::hash_to_float(seed, sample_idx, 1);

                let theta = 2.0 * std::f32::consts::PI * u;
                let phi = (1.0 - 2.0 * v).acos();

                let sin_phi = phi.sin();
                [
                    position[0] + radius * sin_phi * theta.cos(),
                    position[1] + radius * phi.cos(),
                    position[2] + radius * sin_phi * theta.sin(),
                ]
            }
            LightType::Directional { direction } => {
                // For directional lights, return a far point
                // with slight angular variation for soft sun shadows
                let angular_size = 0.00465; // ~0.5 degrees (sun angular diameter)

                let u = Self::hash_to_float(seed, sample_idx, 0) * 2.0 - 1.0;
                let v = Self::hash_to_float(seed, sample_idx, 1) * 2.0 - 1.0;

                let (tangent, bitangent) = Self::build_tangent_frame(*direction);

                let perturbed_dir = [
                    -direction[0] + tangent[0] * u * angular_size + bitangent[0] * v * angular_size,
                    -direction[1] + tangent[1] * u * angular_size + bitangent[1] * v * angular_size,
                    -direction[2] + tangent[2] * u * angular_size + bitangent[2] * v * angular_size,
                ];

                // Return far point in perturbed direction
                [
                    perturbed_dir[0] * 10000.0,
                    perturbed_dir[1] * 10000.0,
                    perturbed_dir[2] * 10000.0,
                ]
            }
            LightType::Spot { position, .. } => {
                // Spot lights typically don't have area, return position
                *position
            }
        }
    }

    /// Hash function for generating pseudo-random floats [0, 1].
    fn hash_to_float(seed: u32, index: u32, channel: u32) -> f32 {
        // Simple hash combining seed, index, and channel
        let mut h = seed.wrapping_mul(0x9E3779B9);
        h = h.wrapping_add(index.wrapping_mul(0x85EBCA6B));
        h = h.wrapping_add(channel.wrapping_mul(0xC2B2AE35));
        h ^= h >> 16;
        h = h.wrapping_mul(0x85EBCA6B);
        h ^= h >> 13;
        h = h.wrapping_mul(0xC2B2AE35);
        h ^= h >> 16;

        (h as f32) / (u32::MAX as f32)
    }

    /// Halton sequence for quasi-random sampling.
    fn halton(index: u32, base: u32) -> f32 {
        let mut result = 0.0f32;
        let mut f = 1.0 / base as f32;
        let mut i = index;

        while i > 0 {
            result += f * (i % base) as f32;
            i /= base;
            f /= base as f32;
        }

        result
    }

    /// Build an orthonormal tangent frame from a normal vector.
    fn build_tangent_frame(normal: [f32; 3]) -> ([f32; 3], [f32; 3]) {
        // Choose a vector not parallel to normal
        let up = if normal[1].abs() < 0.999 {
            [0.0, 1.0, 0.0]
        } else {
            [1.0, 0.0, 0.0]
        };

        // Cross product: tangent = normal x up
        let tangent = [
            normal[1] * up[2] - normal[2] * up[1],
            normal[2] * up[0] - normal[0] * up[2],
            normal[0] * up[1] - normal[1] * up[0],
        ];

        // Normalize tangent
        let len = (tangent[0] * tangent[0] + tangent[1] * tangent[1] + tangent[2] * tangent[2]).sqrt();
        let tangent = if len > 0.0 {
            [tangent[0] / len, tangent[1] / len, tangent[2] / len]
        } else {
            [1.0, 0.0, 0.0]
        };

        // Cross product: bitangent = tangent x normal
        let bitangent = [
            tangent[1] * normal[2] - tangent[2] * normal[1],
            tangent[2] * normal[0] - tangent[0] * normal[2],
            tangent[0] * normal[1] - tangent[1] * normal[0],
        ];

        (tangent, bitangent)
    }
}

// ---------------------------------------------------------------------------
// Shadow WGSL Generator
// ---------------------------------------------------------------------------

/// Generator for WGSL shadow ray tracing code.
///
/// Produces optimized WGSL functions for shadow testing including:
/// - Single shadow ray test
/// - Light loop for multiple lights
/// - Soft shadow accumulation
/// - Percentage Closer Filtering (PCF)
///
/// # Example
///
/// ```ignore
/// use crate::blas::{ShadowWgslGenerator, ShadowRayConfig};
///
/// let generator = ShadowWgslGenerator::new(ShadowRayConfig::default());
///
/// // Generate shadow test function
/// let shadow_fn = generator.generate_shadow_test_function();
///
/// // Generate light loop for 4 lights
/// let light_loop = generator.generate_light_loop(4);
/// ```
pub struct ShadowWgslGenerator {
    config: ShadowRayConfig,
}

impl ShadowWgslGenerator {
    /// Create a new generator with the given configuration.
    pub fn new(config: ShadowRayConfig) -> Self {
        Self { config }
    }

    /// Generate the basic shadow ray test function.
    ///
    /// This function casts a single ray and returns visibility (0.0 or 1.0).
    pub fn generate_shadow_test_function(&self) -> String {
        let flags = self.config.ray_flags().bits();

        format!(
            r#"/// Trace a shadow ray and return visibility (0.0 = shadowed, 1.0 = lit).
///
/// Uses TERMINATE_ON_FIRST_HIT for early termination.
fn trace_shadow_ray(origin: vec3<f32>, direction: vec3<f32>, max_dist: f32) -> f32 {{
    var rq: ray_query;
    rayQueryInitialize(
        &rq,
        tlas,
        0x{:02x}u,  // Ray flags: TERMINATE_ON_FIRST_HIT | {}
        0xffu,      // Cull mask: test all geometry
        origin,
        {:.6},      // t_min (bias)
        direction,
        max_dist    // t_max
    );

    // Traverse the acceleration structure
    rayQueryProceed(&rq);

    // Check hit type
    let hit_type = rayQueryGetCommittedIntersectionType(&rq);

    // RAY_QUERY_COMMITTED_INTERSECTION_TYPE_NONE = 0 means no hit (fully lit)
    return select(0.0, 1.0, hit_type == 0u);
}}
"#,
            flags,
            if self.config.use_alpha_test {
                "FORCE_NON_OPAQUE"
            } else {
                "FORCE_OPAQUE"
            },
            self.config.bias,
        )
    }

    /// Generate a light loop for processing multiple lights.
    ///
    /// Produces a function that iterates over a light array and accumulates shadow.
    pub fn generate_light_loop(&self, light_count: u32) -> String {
        format!(
            r#"/// Light data structure.
struct Light {{
    position: vec3<f32>,
    light_type: u32,  // 0=point, 1=directional, 2=spot, 3=area
    direction: vec3<f32>,
    intensity: f32,
    color: vec3<f32>,
    radius: f32,
}}

/// Uniform buffer containing all lights.
@group(1) @binding(0)
var<uniform> lights: array<Light, {light_count}>;

/// Calculate shadow for a single light.
fn shadow_for_light(surface_pos: vec3<f32>, light_idx: u32) -> f32 {{
    let light = lights[light_idx];

    var to_light: vec3<f32>;
    var max_dist: f32;

    switch (light.light_type) {{
        case 0u: {{ // Point light
            to_light = light.position - surface_pos;
            max_dist = length(to_light);
            to_light = normalize(to_light);
        }}
        case 1u: {{ // Directional light
            to_light = -light.direction;
            max_dist = {max_dist:.1};
        }}
        case 2u: {{ // Spot light
            to_light = light.position - surface_pos;
            max_dist = length(to_light);
            to_light = normalize(to_light);

            // Check spot cone
            let cos_angle = dot(-to_light, light.direction);
            if (cos_angle < light.radius) {{ // radius = cos(outer_angle)
                return 1.0; // Outside cone, fully lit
            }}
        }}
        case 3u: {{ // Area light (sample center)
            to_light = light.position - surface_pos;
            max_dist = length(to_light);
            to_light = normalize(to_light);
        }}
        default: {{
            return 1.0;
        }}
    }}

    return trace_shadow_ray(surface_pos, to_light, max_dist);
}}

/// Accumulate shadow visibility from all lights.
fn calculate_total_shadow(surface_pos: vec3<f32>) -> f32 {{
    var total_vis = 0.0;
    for (var i = 0u; i < {light_count}u; i++) {{
        total_vis += shadow_for_light(surface_pos, i);
    }}
    return total_vis / f32({light_count}u);
}}
"#,
            light_count = light_count,
            max_dist = self.config.max_distance,
        )
    }

    /// Generate soft shadow function with multiple samples.
    ///
    /// Uses stratified sampling for better quality soft shadows.
    pub fn generate_soft_shadow_function(&self, sample_count: u32) -> String {
        let grid_size = (sample_count as f32).sqrt().ceil() as u32;

        format!(
            r#"/// Soft shadow configuration.
const SOFT_SHADOW_SAMPLES: u32 = {sample_count}u;
const SOFT_SHADOW_GRID: u32 = {grid_size}u;

/// Sample an area light position for soft shadows.
fn sample_area_light(
    light_center: vec3<f32>,
    light_normal: vec3<f32>,
    half_extents: vec2<f32>,
    sample_idx: u32,
    seed: u32
) -> vec3<f32> {{
    // Build tangent frame
    let up = select(vec3<f32>(1.0, 0.0, 0.0), vec3<f32>(0.0, 1.0, 0.0), abs(light_normal.y) < 0.999);
    let tangent = normalize(cross(light_normal, up));
    let bitangent = cross(tangent, light_normal);

    // Stratified sample position
    let cell_x = sample_idx % SOFT_SHADOW_GRID;
    let cell_y = sample_idx / SOFT_SHADOW_GRID;
    let cell_size = 2.0 / f32(SOFT_SHADOW_GRID);

    // Hash for jitter
    let h = hash_pcg(seed + sample_idx);
    let jitter_x = f32(h & 0xffffu) / 65535.0;
    let jitter_y = f32((h >> 16u) & 0xffffu) / 65535.0;

    let s = -1.0 + (f32(cell_x) + jitter_x) * cell_size;
    let t = -1.0 + (f32(cell_y) + jitter_y) * cell_size;

    return light_center
        + tangent * s * half_extents.x
        + bitangent * t * half_extents.y;
}}

/// PCG hash function for random numbers.
fn hash_pcg(input: u32) -> u32 {{
    var state = input * 747796405u + 2891336453u;
    let word = ((state >> ((state >> 28u) + 4u)) ^ state) * 277803737u;
    return (word >> 22u) ^ word;
}}

/// Calculate soft shadow for an area light.
fn soft_shadow_area_light(
    surface_pos: vec3<f32>,
    light_center: vec3<f32>,
    light_normal: vec3<f32>,
    half_extents: vec2<f32>,
    pixel_seed: u32
) -> f32 {{
    var visibility = 0.0;

    for (var i = 0u; i < SOFT_SHADOW_SAMPLES; i++) {{
        let light_pos = sample_area_light(
            light_center,
            light_normal,
            half_extents,
            i,
            pixel_seed
        );

        let to_light = light_pos - surface_pos;
        let dist = length(to_light);
        let dir = to_light / dist;

        visibility += trace_shadow_ray(surface_pos, dir, dist);
    }}

    return visibility / f32(SOFT_SHADOW_SAMPLES);
}}
"#,
            sample_count = sample_count,
            grid_size = grid_size,
        )
    }

    /// Generate Percentage Closer Filtering (PCF) function.
    ///
    /// PCF is useful for smoothing shadow edges without multi-sampling.
    pub fn generate_pcf_function(&self) -> String {
        format!(
            r#"/// Percentage Closer Filtering for shadow edge smoothing.
///
/// Uses a 3x3 kernel to sample shadow at nearby positions.
const PCF_KERNEL_SIZE: i32 = 1;  // -1 to 1 = 3x3 kernel
const PCF_FILTER_RADIUS: f32 = 0.001;  // World-space filter radius

/// Calculate PCF shadow with edge smoothing.
fn shadow_pcf(
    surface_pos: vec3<f32>,
    surface_normal: vec3<f32>,
    to_light: vec3<f32>,
    max_dist: f32
) -> f32 {{
    // Build tangent frame from normal
    let up = select(vec3<f32>(1.0, 0.0, 0.0), vec3<f32>(0.0, 1.0, 0.0), abs(surface_normal.y) < 0.999);
    let tangent = normalize(cross(surface_normal, up));
    let bitangent = cross(tangent, surface_normal);

    var visibility = 0.0;
    var sample_count = 0.0;

    for (var x = -PCF_KERNEL_SIZE; x <= PCF_KERNEL_SIZE; x++) {{
        for (var y = -PCF_KERNEL_SIZE; y <= PCF_KERNEL_SIZE; y++) {{
            let offset = tangent * f32(x) * PCF_FILTER_RADIUS
                       + bitangent * f32(y) * PCF_FILTER_RADIUS;

            let sample_pos = surface_pos + offset;
            visibility += trace_shadow_ray(sample_pos, to_light, max_dist);
            sample_count += 1.0;
        }}
    }}

    return visibility / sample_count;
}}

/// Calculate shadow with Contact Hardening Soft Shadows (PCSS).
///
/// Penumbra size varies based on blocker distance.
fn shadow_pcss(
    surface_pos: vec3<f32>,
    surface_normal: vec3<f32>,
    light_pos: vec3<f32>,
    light_radius: f32
) -> f32 {{
    let to_light = light_pos - surface_pos;
    let light_dist = length(to_light);
    let light_dir = to_light / light_dist;

    // First pass: find average blocker distance
    var rq: ray_query;
    rayQueryInitialize(
        &rq,
        tlas,
        0x05u,  // TERMINATE_ON_FIRST_HIT | FORCE_OPAQUE
        0xffu,
        surface_pos,
        {bias:.6},
        light_dir,
        light_dist
    );
    rayQueryProceed(&rq);

    let hit_type = rayQueryGetCommittedIntersectionType(&rq);
    if (hit_type == 0u) {{
        return 1.0;  // No blocker, fully lit
    }}

    // Get blocker distance
    let blocker_dist = rayQueryGetCommittedIntersectionT(&rq);

    // Calculate penumbra size based on blocker distance
    let penumbra_ratio = (light_dist - blocker_dist) / blocker_dist;
    let penumbra_size = penumbra_ratio * light_radius;

    // Second pass: PCF with variable kernel size
    let filter_radius = min(penumbra_size * 0.5, 0.1);

    // Use standard PCF with calculated filter radius
    // (Simplified - production would use proper PCSS sampling)
    return shadow_pcf(surface_pos, surface_normal, light_dir, light_dist);
}}
"#,
            bias = self.config.bias,
        )
    }

    /// Generate a complete shadow module with all functions.
    pub fn generate_complete_module(&self, light_count: u32, sample_count: u32) -> String {
        let mut code = String::new();

        code.push_str("// =================================================\n");
        code.push_str("// Shadow Ray Tracing Module (Auto-generated)\n");
        code.push_str("// =================================================\n\n");

        code.push_str("// --- Basic Shadow Test ---\n");
        code.push_str(&self.generate_shadow_test_function());
        code.push_str("\n");

        code.push_str("// --- Light Loop ---\n");
        code.push_str(&self.generate_light_loop(light_count));
        code.push_str("\n");

        code.push_str("// --- Soft Shadow Sampling ---\n");
        code.push_str(&self.generate_soft_shadow_function(sample_count));
        code.push_str("\n");

        code.push_str("// --- PCF and PCSS ---\n");
        code.push_str(&self.generate_pcf_function());

        code
    }
}

