// RecursiveTracer - Secondary ray dispatch for closest-hit
// ---------------------------------------------------------------------------

/// Generator for recursive ray tracing WGSL code.
///
/// Provides code generation for spawning secondary rays (reflection,
/// refraction, shadow rays) from closest-hit shaders.
pub struct RecursiveTracer {
    max_depth: u32,
}

impl Default for RecursiveTracer {
    fn default() -> Self {
        Self { max_depth: 4 }
    }
}

impl RecursiveTracer {
    /// Create with custom max depth.
    pub fn new(max_depth: u32) -> Self {
        Self { max_depth }
    }

    /// Get max depth.
    pub fn max_depth(&self) -> u32 {
        self.max_depth
    }

    /// Generate WGSL for depth checking.
    pub fn generate_depth_check(&self) -> String {
        format!(
            r#"// Check if recursion depth allows spawning secondary rays
const MAX_RECURSION_DEPTH: u32 = {max_depth}u;

fn can_spawn_secondary_ray(current_depth: u32) -> bool {{
    return current_depth < MAX_RECURSION_DEPTH;
}}"#,
            max_depth = self.max_depth
        )
    }

    /// Generate WGSL for reflection ray setup.
    pub fn generate_reflection_ray() -> String {
        r#"// Calculate reflection ray direction
fn compute_reflection_ray(
    incident: vec3<f32>,
    normal: vec3<f32>
) -> vec3<f32> {
    return reflect(incident, normal);
}

// Spawn reflection ray with roughness-based cone
fn compute_glossy_reflection(
    incident: vec3<f32>,
    normal: vec3<f32>,
    roughness: f32,
    random_vec: vec2<f32>
) -> vec3<f32> {
    let perfect_reflect = reflect(incident, normal);

    // Generate random direction in hemisphere
    let cone_angle = roughness * roughness * 3.14159 * 0.5;
    let phi = random_vec.x * 2.0 * 3.14159;
    let cos_theta = cos(random_vec.y * cone_angle);
    let sin_theta = sin(random_vec.y * cone_angle);

    // Build tangent space around reflection
    let up = select(vec3<f32>(1.0, 0.0, 0.0), vec3<f32>(0.0, 1.0, 0.0),
                    abs(perfect_reflect.y) < 0.999);
    let tangent = normalize(cross(up, perfect_reflect));
    let bitangent = cross(perfect_reflect, tangent);

    // Apply cone jitter
    let local_dir = vec3<f32>(
        sin_theta * cos(phi),
        sin_theta * sin(phi),
        cos_theta
    );

    return normalize(
        tangent * local_dir.x +
        bitangent * local_dir.y +
        perfect_reflect * local_dir.z
    );
}"#.to_string()
    }

    /// Generate WGSL for refraction ray setup.
    pub fn generate_refraction_ray() -> String {
        r#"// Calculate refraction ray using Snell's law
fn compute_refraction_ray(
    incident: vec3<f32>,
    normal: vec3<f32>,
    ior_ratio: f32  // n1/n2
) -> vec3<f32> {
    let cos_i = -dot(incident, normal);
    let sin2_t = ior_ratio * ior_ratio * (1.0 - cos_i * cos_i);

    // Total internal reflection check
    if (sin2_t > 1.0) {
        return reflect(incident, normal);
    }

    let cos_t = sqrt(1.0 - sin2_t);
    return ior_ratio * incident + (ior_ratio * cos_i - cos_t) * normal;
}

// Fresnel-Schlick approximation
fn fresnel_schlick(cos_theta: f32, f0: f32) -> f32 {
    return f0 + (1.0 - f0) * pow(1.0 - cos_theta, 5.0);
}

// Full Fresnel with IOR
fn fresnel_dielectric(cos_i: f32, ior: f32) -> f32 {
    let f0 = pow((1.0 - ior) / (1.0 + ior), 2.0);
    return fresnel_schlick(abs(cos_i), f0);
}"#.to_string()
    }

    /// Generate WGSL for shadow ray.
    pub fn generate_shadow_ray() -> String {
        r#"// Shadow ray parameters
struct ShadowRayParams {
    origin: vec3<f32>,
    direction: vec3<f32>,
    max_distance: f32,
}

// Setup shadow ray toward light
fn setup_shadow_ray(
    hit_position: vec3<f32>,
    normal: vec3<f32>,
    light_position: vec3<f32>
) -> ShadowRayParams {
    var params: ShadowRayParams;

    // Offset origin slightly along normal to avoid self-intersection
    params.origin = hit_position + normal * 0.001;

    let to_light = light_position - params.origin;
    params.max_distance = length(to_light);
    params.direction = to_light / params.max_distance;

    return params;
}

// Check if point is in shadow (returns visibility 0-1)
// This is a placeholder - actual implementation uses ray_query
fn trace_shadow_ray(params: ShadowRayParams) -> f32 {
    // In actual usage, spawn ray_query and check for any hit
    // Return 0.0 if occluded, 1.0 if visible
    return 1.0;
}"#.to_string()
    }

    /// Generate WGSL for recursive trace dispatch.
    pub fn generate_recursive_trace(&self) -> String {
        format!(
            r#"// Recursive ray trace dispatch
// Note: wgpu uses inline ray_query, so "recursion" is actually iterative

struct SecondaryRayResult {{
    color: vec3<f32>,
    hit: bool,
    depth: f32,
}}

// Trace secondary ray for reflection/refraction
// In wgpu inline RT model, this creates a new ray_query
fn trace_secondary_ray(
    tlas: acceleration_structure,
    origin: vec3<f32>,
    direction: vec3<f32>,
    t_min: f32,
    t_max: f32,
    current_depth: u32
) -> SecondaryRayResult {{
    var result: SecondaryRayResult;
    result.color = vec3<f32>(0.0);
    result.hit = false;
    result.depth = t_max;

    // Check recursion depth
    if (current_depth >= {max_depth}u) {{
        return result;  // Recursion limit reached
    }}

    // Create new ray query for secondary ray
    var rq: ray_query;
    rayQueryInitialize(
        &rq,
        tlas,
        RayDesc(0u, 0xFFu, t_min, t_max, origin, direction)
    );

    // Traverse - actual shading would call closest_hit logic
    while (rayQueryProceed(&rq)) {{
        // Process candidates (any-hit logic if needed)
        if (rayQueryGetCandidateIntersectionType(&rq) == CANDIDATE_TRIANGLE) {{
            rayQueryConfirmIntersection(&rq);
        }}
    }}

    // Check for committed hit
    if (rayQueryGetCommittedIntersectionType(&rq) == COMMITTED_TRIANGLE_INTERSECTION) {{
        result.hit = true;
        result.depth = rayQueryGetCommittedIntersectionT(&rq);
        // Actual shading would compute color here
        // For now, return placeholder
        result.color = vec3<f32>(0.5);
    }}

    return result;
}}"#,
            max_depth = self.max_depth
        )
    }

    /// Generate complete recursive tracing WGSL.
    pub fn generate_complete(&self) -> String {
        let mut wgsl = String::with_capacity(4096);
        wgsl.push_str("// Recursive Ray Tracing Utilities\n\n");
        wgsl.push_str(&self.generate_depth_check());
        wgsl.push_str("\n\n");
        wgsl.push_str(&Self::generate_reflection_ray());
        wgsl.push_str("\n\n");
        wgsl.push_str(&Self::generate_refraction_ray());
        wgsl.push_str("\n\n");
        wgsl.push_str(&Self::generate_shadow_ray());
        wgsl.push_str("\n\n");
        wgsl.push_str(&self.generate_recursive_trace());
        wgsl
    }
}

// ---------------------------------------------------------------------------
// PayloadWriter - Hit payload output generation
// ---------------------------------------------------------------------------

/// Generator for payload writing WGSL code.
///
/// Provides code generation for writing closest-hit results
/// to the ray payload structure.
pub struct PayloadWriter {
    custom_fields: Vec<CustomPayloadField>,
}

impl Default for PayloadWriter {
    fn default() -> Self {
        Self {
            custom_fields: Vec::new(),
        }
    }
}

impl PayloadWriter {
    /// Create a new payload writer.
    pub fn new() -> Self {
        Self::default()
    }

    /// Add a custom field.
    pub fn add_field(mut self, field: CustomPayloadField) -> Self {
        self.custom_fields.push(field);
        self
    }

    /// Add multiple custom fields.
    pub fn with_fields(mut self, fields: Vec<CustomPayloadField>) -> Self {
        self.custom_fields.extend(fields);
        self
    }

    /// Get custom fields.
    pub fn custom_fields(&self) -> &[CustomPayloadField] {
        &self.custom_fields
    }

    /// Generate WGSL for basic payload write.
    pub fn generate_payload_write() -> String {
        r#"// Write shading result to payload
fn write_hit_payload(
    payload: ptr<function, HitPayload>,
    color: vec4<f32>,
    depth: f32,
    normal: vec3<f32>,
    hit_kind: u32
) {
    (*payload).color = color;
    (*payload).depth = depth;
    (*payload).normal = normal;
    (*payload).hit_kind = hit_kind;
}

// Write color only
fn write_payload_color(
    payload: ptr<function, HitPayload>,
    color: vec4<f32>
) {
    (*payload).color = color;
}

// Write hit info only
fn write_payload_hit_info(
    payload: ptr<function, HitPayload>,
    depth: f32,
    normal: vec3<f32>,
    hit_kind: u32
) {
    (*payload).depth = depth;
    (*payload).normal = normal;
    (*payload).hit_kind = hit_kind;
}"#.to_string()
    }

    /// Generate custom payload struct if custom fields are present.
    pub fn generate_custom_struct(&self) -> Option<String> {
        if self.custom_fields.is_empty() {
            return None;
        }

        let mut wgsl = String::from("struct CustomHitPayload {\n");
        wgsl.push_str("    // Standard fields\n");
        wgsl.push_str("    color: vec4<f32>,\n");
        wgsl.push_str("    depth: f32,\n");
        wgsl.push_str("    normal: vec3<f32>,\n");
        wgsl.push_str("    hit_kind: u32,\n");
        wgsl.push_str("    // Custom fields\n");

        for field in &self.custom_fields {
            wgsl.push_str(&field.generate_wgsl_field());
            wgsl.push_str("\n");
        }

        wgsl.push_str("}");
        Some(wgsl)
    }

    /// Generate complete payload writing utilities.
    pub fn generate_complete(&self) -> String {
        let mut wgsl = String::with_capacity(2048);
        wgsl.push_str("// Payload Writing Utilities\n\n");
        wgsl.push_str(&HitPayload::generate_wgsl_struct());
        wgsl.push_str("\n\n");

        if let Some(custom) = self.generate_custom_struct() {
            wgsl.push_str(&custom);
            wgsl.push_str("\n\n");
        }

        wgsl.push_str(&Self::generate_payload_write());
        wgsl.push_str("\n\n");
        wgsl.push_str(&HitPayload::generate_wgsl_miss());
        wgsl
    }
}

// ---------------------------------------------------------------------------
// ClosestHitWgslGenerator - Complete closest-hit shader generator
// ---------------------------------------------------------------------------

/// Generator for complete closest-hit shader WGSL code.
///
/// Produces shader code for PBR shading, material lookup,
/// recursive tracing, and payload output at ray hit points.
pub struct ClosestHitWgslGenerator {
    desc: ClosestHitShaderDesc,
    recursive_tracer: RecursiveTracer,
    payload_writer: PayloadWriter,
}

impl ClosestHitWgslGenerator {
    /// Create a new generator with the given descriptor.
    pub fn new(desc: ClosestHitShaderDesc) -> Self {
        let max_recursion = desc.max_recursion;
        Self {
            desc,
            recursive_tracer: RecursiveTracer::new(max_recursion),
            payload_writer: PayloadWriter::new(),
        }
    }

    /// Create with custom payload writer.
    pub fn with_payload_writer(mut self, writer: PayloadWriter) -> Self {
        self.payload_writer = writer;
        self
    }

    /// Get the descriptor.
    pub fn desc(&self) -> &ClosestHitShaderDesc {
        &self.desc
    }

    /// Generate hit attributes struct for closest-hit.
    fn generate_hit_attributes() -> String {
        r#"// Hit attributes from committed intersection
struct ClosestHitAttributes {
    barycentrics: vec2<f32>,  // Triangle barycentrics (u, v)
    instance_id: u32,          // Instance index in TLAS
    primitive_id: u32,         // Triangle index in geometry
    geometry_index: u32,       // Geometry index in instance
    t: f32,                    // Hit distance
    hit_kind: u32,             // Front/back face indicator
    object_ray_origin: vec3<f32>,
    object_ray_direction: vec3<f32>,
    world_ray_origin: vec3<f32>,
    world_ray_direction: vec3<f32>,
}

// Extract hit attributes from committed ray_query intersection
fn extract_closest_hit_attributes(rq: ptr<function, ray_query>) -> ClosestHitAttributes {
    var attrs: ClosestHitAttributes;

    attrs.barycentrics = rayQueryGetCommittedIntersectionBarycentrics(rq);
    attrs.instance_id = rayQueryGetCommittedIntersectionInstanceId(rq);
    attrs.primitive_id = rayQueryGetCommittedIntersectionPrimitiveIndex(rq);
    attrs.geometry_index = rayQueryGetCommittedIntersectionGeometryIndex(rq);
    attrs.t = rayQueryGetCommittedIntersectionT(rq);
    attrs.hit_kind = rayQueryGetCommittedIntersectionFrontFace(rq);
    attrs.object_ray_origin = rayQueryGetCommittedIntersectionObjectRayOrigin(rq);
    attrs.object_ray_direction = rayQueryGetCommittedIntersectionObjectRayDirection(rq);
    attrs.world_ray_origin = rayQueryGetWorldRayOrigin(rq);
    attrs.world_ray_direction = rayQueryGetWorldRayDirection(rq);

    return attrs;
}"#.to_string()
    }

    /// Generate geometry helpers (normal computation, UV interpolation).
    fn generate_geometry_helpers() -> String {
        r#"// Compute hit position in world space
fn compute_hit_position(
    ray_origin: vec3<f32>,
    ray_direction: vec3<f32>,
    t: f32
) -> vec3<f32> {
    return ray_origin + ray_direction * t;
}

// Interpolate vertex attribute using barycentrics
fn interpolate_vec3(
    barycentrics: vec2<f32>,
    v0: vec3<f32>,
    v1: vec3<f32>,
    v2: vec3<f32>
) -> vec3<f32> {
    let w = 1.0 - barycentrics.x - barycentrics.y;
    return v0 * w + v1 * barycentrics.x + v2 * barycentrics.y;
}

fn interpolate_vec2(
    barycentrics: vec2<f32>,
    v0: vec2<f32>,
    v1: vec2<f32>,
    v2: vec2<f32>
) -> vec2<f32> {
    let w = 1.0 - barycentrics.x - barycentrics.y;
    return v0 * w + v1 * barycentrics.x + v2 * barycentrics.y;
}

// Compute face normal from triangle vertices
fn compute_face_normal(
    v0: vec3<f32>,
    v1: vec3<f32>,
    v2: vec3<f32>
) -> vec3<f32> {
    let edge1 = v1 - v0;
    let edge2 = v2 - v0;
    return normalize(cross(edge1, edge2));
}

// Transform normal from object to world space
fn transform_normal(
    normal: vec3<f32>,
    inverse_transpose: mat4x4<f32>
) -> vec3<f32> {
    return normalize((inverse_transpose * vec4<f32>(normal, 0.0)).xyz);
}"#.to_string()
    }

    /// Generate PBR shading functions.
    fn generate_pbr_shading() -> String {
        r#"// PBR Shading Functions

// Lambertian diffuse
fn pbr_diffuse(albedo: vec3<f32>) -> vec3<f32> {
    return albedo / 3.14159;
}

// GGX/Trowbridge-Reitz normal distribution
fn ggx_distribution(n_dot_h: f32, roughness: f32) -> f32 {
    let a = roughness * roughness;
    let a2 = a * a;
    let n_dot_h2 = n_dot_h * n_dot_h;
    let denom = n_dot_h2 * (a2 - 1.0) + 1.0;
    return a2 / (3.14159 * denom * denom);
}

// Smith's geometry function (Schlick-GGX)
fn geometry_schlick_ggx(n_dot_v: f32, roughness: f32) -> f32 {
    let r = roughness + 1.0;
    let k = (r * r) / 8.0;
    return n_dot_v / (n_dot_v * (1.0 - k) + k);
}

fn geometry_smith(n_dot_v: f32, n_dot_l: f32, roughness: f32) -> f32 {
    let ggx1 = geometry_schlick_ggx(n_dot_v, roughness);
    let ggx2 = geometry_schlick_ggx(n_dot_l, roughness);
    return ggx1 * ggx2;
}

// Fresnel-Schlick
fn fresnel_schlick_vec3(cos_theta: f32, f0: vec3<f32>) -> vec3<f32> {
    return f0 + (vec3<f32>(1.0) - f0) * pow(1.0 - cos_theta, 5.0);
}

// Complete PBR BRDF evaluation
fn evaluate_pbr(
    albedo: vec3<f32>,
    metallic: f32,
    roughness: f32,
    normal: vec3<f32>,
    view_dir: vec3<f32>,
    light_dir: vec3<f32>,
    light_color: vec3<f32>
) -> vec3<f32> {
    let half_vec = normalize(view_dir + light_dir);

    let n_dot_v = max(dot(normal, view_dir), 0.001);
    let n_dot_l = max(dot(normal, light_dir), 0.0);
    let n_dot_h = max(dot(normal, half_vec), 0.0);
    let v_dot_h = max(dot(view_dir, half_vec), 0.0);

    // Fresnel reflectance at normal incidence
    let f0 = mix(vec3<f32>(0.04), albedo, metallic);

    // Cook-Torrance specular BRDF
    let d = ggx_distribution(n_dot_h, roughness);
    let g = geometry_smith(n_dot_v, n_dot_l, roughness);
    let f = fresnel_schlick_vec3(v_dot_h, f0);

    let specular = (d * g * f) / max(4.0 * n_dot_v * n_dot_l, 0.001);

    // Diffuse (energy conservation)
    let k_d = (vec3<f32>(1.0) - f) * (1.0 - metallic);
    let diffuse = k_d * pbr_diffuse(albedo);

    return (diffuse + specular) * light_color * n_dot_l;
}"#.to_string()
    }

    /// Generate the main closest-hit function.
    fn generate_closest_hit_main(&self) -> String {
        format!(
            r#"// Main closest-hit shading function
// Called after ray traversal commits an intersection

fn {entry_point}(
    attrs: ClosestHitAttributes,
    payload: ptr<function, HitPayload>,
    recursion_depth: u32
) {{
    // Fetch material for this instance
    let material = fetch_material(attrs.instance_id);

    // Compute hit position
    let hit_pos = compute_hit_position(
        attrs.world_ray_origin,
        attrs.world_ray_direction,
        attrs.t
    );

    // Get surface normal (placeholder - actual impl would fetch from vertex data)
    // For now, use a default up normal
    var normal = vec3<f32>(0.0, 1.0, 0.0);

    // Transform normal to world space
    let normal_transform = get_normal_transform(attrs.instance_id);
    normal = transform_normal(normal, normal_transform);

    // Flip normal for back-face hits
    let view_dir = -normalize(attrs.world_ray_direction);
    if (dot(normal, view_dir) < 0.0) {{
        normal = -normal;
    }}

    // Basic lighting setup (placeholder - would come from scene)
    let light_dir = normalize(vec3<f32>(1.0, 1.0, 1.0));
    let light_color = vec3<f32>(1.0, 1.0, 1.0);

    // Evaluate PBR shading
    var color = evaluate_pbr(
        material.albedo.rgb,
        material.metallic,
        material.roughness,
        normal,
        view_dir,
        light_dir,
        light_color
    );

    // Add emissive
    color += material.emissive;

    // Recursive reflection (if depth allows and material is reflective)
    if (recursion_depth < {max_recursion}u && material.metallic > 0.1) {{
        let reflect_dir = reflect(attrs.world_ray_direction, normal);
        // Note: actual recursive trace would call trace_secondary_ray here
        // For inline RT, this would create a new ray_query
        let reflect_contribution = material.metallic * 0.5;
        // Placeholder: attenuate color for recursion visualization
        color = color * (1.0 - reflect_contribution * 0.5);
    }}

    // Write payload
    write_hit_payload(
        payload,
        vec4<f32>(color, 1.0),
        attrs.t,
        normal,
        select(0u, 1u, attrs.hit_kind != 0u)  // 0 = back, 1 = front
    );
}}"#,
            entry_point = self.desc.entry_point,
            max_recursion = self.desc.max_recursion
        )
    }

    /// Generate integration snippet for ray_query usage.
    fn generate_ray_query_integration(&self) -> String {
        format!(
            r#"// Integration with ray_query traversal
// Call this after rayQueryProceed returns false with a committed hit

fn process_closest_hit(
    rq: ptr<function, ray_query>,
    payload: ptr<function, HitPayload>,
    recursion_depth: u32
) {{
    // Check for committed triangle hit
    let hit_type = rayQueryGetCommittedIntersectionType(rq);

    if (hit_type == COMMITTED_TRIANGLE_INTERSECTION) {{
        // Extract hit attributes
        let attrs = extract_closest_hit_attributes(rq);

        // Run closest-hit shading
        {entry_point}(attrs, payload, recursion_depth);
    }} else if (hit_type == COMMITTED_NOTHING) {{
        // Ray missed - write miss payload
        *payload = init_miss_payload();
    }}
}}"#,
            entry_point = self.desc.entry_point
        )
    }

    /// Generate complete closest-hit shader.
    pub fn generate_complete_shader(&self) -> String {
        let mut shader = String::with_capacity(16384);

        // Header comment
        shader.push_str(&format!(
            "// T-WGPU-P5.7.5: Closest-Hit Shader Stage\n\
             // Entry point: {}\n\
             // Max recursion: {}\n\
             // Payload size: {} bytes\n\n",
            self.desc.entry_point,
            self.desc.max_recursion,
            self.desc.payload_size
        ));

        // Constants
        shader.push_str("// Intersection type constants\n");
        shader.push_str("const COMMITTED_NOTHING: u32 = 0u;\n");
        shader.push_str("const COMMITTED_TRIANGLE_INTERSECTION: u32 = 1u;\n");
        shader.push_str("const COMMITTED_PROCEDURAL_INTERSECTION: u32 = 2u;\n");
        shader.push_str("const CANDIDATE_TRIANGLE: u32 = 1u;\n\n");

        // Payload struct
        shader.push_str(&self.payload_writer.generate_complete());
        shader.push_str("\n\n");

        // Hit attributes
        shader.push_str(&Self::generate_hit_attributes());
        shader.push_str("\n\n");

        // Material lookup
        shader.push_str(&MaterialLookup::generate_complete());
        shader.push_str("\n\n");

        // Geometry helpers
        shader.push_str(&Self::generate_geometry_helpers());
        shader.push_str("\n\n");

        // PBR shading
        shader.push_str(&Self::generate_pbr_shading());
        shader.push_str("\n\n");

        // Recursive tracing (if enabled)
        if self.desc.supports_recursion() {
            shader.push_str(&self.recursive_tracer.generate_complete());
            shader.push_str("\n\n");
        }

        // Main closest-hit function
        shader.push_str(&self.generate_closest_hit_main());
        shader.push_str("\n\n");

        // Ray query integration
        shader.push_str(&self.generate_ray_query_integration());
        shader.push_str("\n");

        shader
    }
}

// ---------------------------------------------------------------------------
// ClosestHitShaderBuilder - Builder pattern for closest-hit shaders
// ---------------------------------------------------------------------------

/// Builder for constructing closest-hit shaders with validation.
pub struct ClosestHitShaderBuilder {
    label: String,
    entry_point: String,
    max_recursion: u32,
    payload_size: u32,
    custom_fields: Vec<CustomPayloadField>,
}

impl Default for ClosestHitShaderBuilder {
    fn default() -> Self {
        Self {
            label: String::new(),
            entry_point: "closest_hit_main".to_string(),
            max_recursion: 4,
            payload_size: HitPayload::size_bytes() as u32,
            custom_fields: Vec::new(),
        }
    }
}

impl ClosestHitShaderBuilder {
    /// Create a new builder.
    pub fn new() -> Self {
        Self::default()
    }

    /// Set the label.
    pub fn label(mut self, label: impl Into<String>) -> Self {
        self.label = label.into();
        self
    }

    /// Set the entry point.
    pub fn entry_point(mut self, entry: impl Into<String>) -> Self {
        self.entry_point = entry.into();
        self
    }

    /// Set max recursion depth.
    pub fn max_recursion(mut self, depth: u32) -> Self {
        self.max_recursion = depth;
        self
    }

    /// Set payload size.
    pub fn payload_size(mut self, size: u32) -> Self {
        self.payload_size = size;
        self
    }

    /// Disable recursion.
    pub fn no_recursion(mut self) -> Self {
        self.max_recursion = 0;
        self
    }

    /// Add a custom payload field.
    pub fn add_custom_field(mut self, name: impl Into<String>, field_type: PayloadFieldType) -> Self {
        self.custom_fields.push(CustomPayloadField::new(name, field_type));
        self
    }

    /// Build the closest-hit shader descriptor.
    pub fn build(self) -> Result<ClosestHitShaderDesc, ClosestHitError> {
        let desc = ClosestHitShaderDesc {
            label: self.label,
            entry_point: self.entry_point,
            max_recursion: self.max_recursion,
            payload_size: self.payload_size,
        };
        desc.validate()?;
        Ok(desc)
    }

    /// Build and generate the complete shader.
    pub fn build_shader(self) -> Result<String, ClosestHitError> {
        let custom_fields = self.custom_fields.clone();
        let desc = self.build()?;
        let payload_writer = PayloadWriter::new().with_fields(custom_fields);
        let generator = ClosestHitWgslGenerator::new(desc).with_payload_writer(payload_writer);
        Ok(generator.generate_complete_shader())
    }
}

// === End T-WGPU-P5.7.5: Closest-Hit Shader Stage ===

// T-WGPU-P5.7.6: Miss Shader Stage
// Miss shader for environment sampling in wgpu ray tracing.
// Handles cubemap, equirectangular, procedural sky, and solid color backgrounds.

// ---------------------------------------------------------------------------
// MissShaderError - Error types for miss shader
// ---------------------------------------------------------------------------

/// Errors that can occur during miss shader setup.
#[derive(Debug, Clone, PartialEq)]
pub enum MissShaderError {
    /// Invalid entry point name.
    InvalidEntryPoint,
    /// Invalid miss index (must be contiguous from 0).
    InvalidMissIndex(u32, String),
    /// Duplicate miss index.
    DuplicateMissIndex(u32),
    /// Missing default miss shader (index 0).
    MissingDefaultMissShader,
    /// Non-contiguous miss indices.
    NonContiguousIndices(Vec<u32>),
    /// Invalid environment texture.
    InvalidEnvironmentTexture(String),
    /// Invalid sky parameters.
    InvalidSkyParameters(String),
}

impl std::fmt::Display for MissShaderError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            MissShaderError::InvalidEntryPoint => {
                write!(f, "Invalid entry point name")
            }
            MissShaderError::InvalidMissIndex(idx, reason) => {
                write!(f, "Invalid miss index {}: {}", idx, reason)
            }
            MissShaderError::DuplicateMissIndex(idx) => {
                write!(f, "Duplicate miss index: {}", idx)
            }
            MissShaderError::MissingDefaultMissShader => {
                write!(f, "Missing default miss shader at index 0")
            }
            MissShaderError::NonContiguousIndices(indices) => {
                write!(f, "Miss indices must be contiguous: {:?}", indices)
            }
            MissShaderError::InvalidEnvironmentTexture(reason) => {
                write!(f, "Invalid environment texture: {}", reason)
            }
            MissShaderError::InvalidSkyParameters(reason) => {
                write!(f, "Invalid sky parameters: {}", reason)
            }
        }
    }
}

impl std::error::Error for MissShaderError {}

// ---------------------------------------------------------------------------
// EnvironmentSource - Source for environment color
// ---------------------------------------------------------------------------

/// Source type for environment color in miss shader.
///
/// Defines how the background color is computed when a ray misses all geometry.
#[derive(Debug, Clone, PartialEq)]
pub enum EnvironmentSource {
    /// 6-face cubemap texture.
    Cubemap,
    /// 2D equirectangular panorama texture.
    Equirectangular,
    /// Procedural atmospheric sky.
    ProceduralSky,
    /// Constant solid color.
    SolidColor([f32; 4]),
}

impl Default for EnvironmentSource {
    fn default() -> Self {
        EnvironmentSource::ProceduralSky
    }
}

impl EnvironmentSource {
    /// Check if this source requires a texture.
    pub fn requires_texture(&self) -> bool {
        matches!(self, EnvironmentSource::Cubemap | EnvironmentSource::Equirectangular)
    }

    /// Check if this source is procedural.
    pub fn is_procedural(&self) -> bool {
        matches!(self, EnvironmentSource::ProceduralSky | EnvironmentSource::SolidColor(_))
    }

    /// Get the variant name for WGSL comments.
    pub fn variant_name(&self) -> &'static str {
        match self {
            EnvironmentSource::Cubemap => "Cubemap",
            EnvironmentSource::Equirectangular => "Equirectangular",
            EnvironmentSource::ProceduralSky => "ProceduralSky",
            EnvironmentSource::SolidColor(_) => "SolidColor",
        }
    }
}

// ---------------------------------------------------------------------------
// MissShaderDesc - Miss shader descriptor
// ---------------------------------------------------------------------------

/// Descriptor for miss shader configuration.
///
/// Defines the shader entry point, miss index in the SBT, and environment source.
#[derive(Debug, Clone, PartialEq)]
pub struct MissShaderDesc {
    /// Optional label for debugging.
    pub label: String,
    /// Shader entry point name (conceptual @miss attribute).
    pub entry_point: String,
    /// Miss index in the Shader Binding Table.
    pub miss_index: u32,
    /// Environment color source.
    pub env_source: EnvironmentSource,
}

impl Default for MissShaderDesc {
    fn default() -> Self {
        Self {
            label: String::new(),
            entry_point: "miss_main".to_string(),
            miss_index: 0,
            env_source: EnvironmentSource::default(),
        }
    }
}

impl MissShaderDesc {
    /// Create a new default miss shader descriptor.
    pub fn new() -> Self {
        Self::default()
    }

    /// Create with specific miss index.
    pub fn with_index(miss_index: u32) -> Self {
        Self {
            miss_index,
            ..Default::default()
        }
    }

    /// Create with environment source.
    pub fn with_env_source(env_source: EnvironmentSource) -> Self {
        Self {
            env_source,
            ..Default::default()
        }
    }

    /// Set the label.
    pub fn label(mut self, label: impl Into<String>) -> Self {
        self.label = label.into();
        self
    }

    /// Set the entry point name.
    pub fn entry_point(mut self, entry: impl Into<String>) -> Self {
        self.entry_point = entry.into();
        self
    }

    /// Set miss index.
    pub fn miss_index(mut self, index: u32) -> Self {
        self.miss_index = index;
        self
    }

    /// Set environment source.
    pub fn env_source(mut self, source: EnvironmentSource) -> Self {
        self.env_source = source;
        self
    }

    /// Validate the descriptor.
    pub fn validate(&self) -> Result<(), MissShaderError> {
        if self.entry_point.is_empty() {
            return Err(MissShaderError::InvalidEntryPoint);
        }
        Ok(())
    }

    /// Check if this uses a texture-based environment.
    pub fn uses_texture(&self) -> bool {
        self.env_source.requires_texture()
    }
}

// ---------------------------------------------------------------------------
// EnvironmentSampler - Environment texture sampling utilities
// ---------------------------------------------------------------------------

/// Generator for environment sampling WGSL code.
///
/// Provides code generation for cubemap and equirectangular texture sampling.
pub struct EnvironmentSampler {
    /// LOD bias for texture sampling.
    lod_bias: f32,
    /// Enable glossy reflection LOD.
    glossy_lod: bool,
}

impl Default for EnvironmentSampler {
    fn default() -> Self {
        Self {
            lod_bias: 0.0,
            glossy_lod: true,
        }
    }
}

impl EnvironmentSampler {
    /// Create a new environment sampler.
    pub fn new() -> Self {
        Self::default()
    }

    /// Set LOD bias.
    pub fn lod_bias(mut self, bias: f32) -> Self {
        self.lod_bias = bias;
        self
    }

    /// Enable or disable glossy LOD.
    pub fn glossy_lod(mut self, enabled: bool) -> Self {
        self.glossy_lod = enabled;
        self
    }

    /// Generate WGSL for cubemap sampling.
    pub fn generate_cubemap_sample() -> String {
        r#"// Sample environment from cubemap texture
// direction: normalized ray direction in world space
// lod: mip level for glossy reflections (0 = sharp, higher = blurry)
fn sample_cubemap_environment(
    direction: vec3<f32>,
    lod: f32
) -> vec3<f32> {
    // Cubemap uses direction directly as lookup vector
    return textureSampleLevel(env_cubemap, env_sampler, direction, lod).rgb;
}

// Cubemap texture and sampler bindings (defined externally)
// @group(0) @binding(N) var env_cubemap: texture_cube<f32>;
// @group(0) @binding(M) var env_sampler: sampler;"#.to_string()
    }

    /// Generate WGSL for equirectangular sampling.
    pub fn generate_equirect_sample() -> String {
        r#"// Convert 3D direction to equirectangular UV coordinates
// Uses standard mapping: phi = atan2(z, x), theta = asin(y)
fn direction_to_equirect(dir: vec3<f32>) -> vec2<f32> {
    let PI = 3.14159265359;

    // Compute spherical coordinates
    let phi = atan2(dir.z, dir.x);  // Azimuthal angle [-PI, PI]
    let theta = asin(clamp(dir.y, -1.0, 1.0));  // Polar angle [-PI/2, PI/2]

    // Map to UV coordinates [0, 1]
    let u = phi / (2.0 * PI) + 0.5;
    let v = theta / PI + 0.5;

    return vec2<f32>(u, v);
}

// Sample environment from equirectangular (panorama) texture
fn sample_equirect_environment(
    direction: vec3<f32>,
    lod: f32
) -> vec3<f32> {
    let uv = direction_to_equirect(direction);
    return textureSampleLevel(env_equirect, env_sampler, uv, lod).rgb;
}

// Equirectangular texture bindings (defined externally)
// @group(0) @binding(N) var env_equirect: texture_2d<f32>;
// @group(0) @binding(M) var env_sampler: sampler;"#.to_string()
    }

    /// Generate WGSL for LOD calculation based on roughness.
    pub fn generate_glossy_lod() -> String {
        r#"// Calculate LOD for glossy reflections based on roughness
// roughness: 0 = mirror, 1 = diffuse
// max_lod: maximum mip level of the environment map
fn compute_glossy_lod(roughness: f32, max_lod: f32) -> f32 {
    // Simple linear mapping - can be replaced with more accurate model
    return roughness * max_lod;
}

// Alternative: perceptually linear roughness mapping
fn compute_glossy_lod_perceptual(roughness: f32, max_lod: f32) -> f32 {
    // Roughness^2 gives more perceptually linear results
    let alpha = roughness * roughness;
    return alpha * max_lod;
}"#.to_string()
    }

    /// Generate complete environment sampling code.
    pub fn generate_complete(&self) -> String {
        let mut wgsl = String::with_capacity(2048);
        wgsl.push_str("// Environment Sampling Utilities\n\n");
        wgsl.push_str(&Self::generate_equirect_sample());
        wgsl.push_str("\n\n");
        wgsl.push_str(&Self::generate_cubemap_sample());
        if self.glossy_lod {
            wgsl.push_str("\n\n");
            wgsl.push_str(&Self::generate_glossy_lod());
        }
        wgsl
    }
}

// ---------------------------------------------------------------------------
// ProceduralSky - Procedural atmospheric sky generation
// ---------------------------------------------------------------------------

/// Configuration for procedural sky rendering.
///
/// Provides simplified atmospheric scattering for sky color computation.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct ProceduralSky {
    /// Sun direction (normalized).
    pub sun_direction: [f32; 3],
    /// Horizon color (RGB).
    pub horizon_color: [f32; 3],
    /// Zenith color (RGB).
    pub zenith_color: [f32; 3],
    /// Sun color/intensity (RGB).
    pub sun_color: [f32; 3],
    /// Sun angular radius (in radians).
    pub sun_radius: f32,
    /// Rayleigh scattering coefficient.
    pub rayleigh_coefficient: f32,
    /// Mie scattering coefficient.
    pub mie_coefficient: f32,
    /// Mie scattering direction (g parameter, -1 to 1).
    pub mie_direction: f32,
}

impl Default for ProceduralSky {
    fn default() -> Self {
        Self {
            // Default: sun at 45 degrees elevation
            sun_direction: [0.0, 0.707, 0.707],
            horizon_color: [0.7, 0.8, 0.9],
            zenith_color: [0.2, 0.4, 0.8],
            sun_color: [1.0, 0.95, 0.85],
            sun_radius: 0.00873, // ~0.5 degrees
            rayleigh_coefficient: 1.0,
            mie_coefficient: 0.005,
            mie_direction: 0.8, // Forward scattering
        }
    }
}

impl ProceduralSky {
    /// Create a new procedural sky with default settings.
    pub fn new() -> Self {
        Self::default()
    }

    /// Create with sun direction.
    pub fn with_sun_direction(sun_direction: [f32; 3]) -> Self {
        Self {
            sun_direction,
            ..Default::default()
        }
    }

    /// Set sun direction.
    pub fn sun_direction(mut self, dir: [f32; 3]) -> Self {
        self.sun_direction = dir;
        self
    }

    /// Set horizon color.
    pub fn horizon_color(mut self, color: [f32; 3]) -> Self {
        self.horizon_color = color;
        self
    }

    /// Set zenith color.
    pub fn zenith_color(mut self, color: [f32; 3]) -> Self {
        self.zenith_color = color;
        self
    }

    /// Set sun color.
    pub fn sun_color(mut self, color: [f32; 3]) -> Self {
        self.sun_color = color;
        self
    }

    /// Set sun radius.
    pub fn sun_radius(mut self, radius: f32) -> Self {
        self.sun_radius = radius;
        self
    }

    /// Set Rayleigh coefficient.
    pub fn rayleigh(mut self, coeff: f32) -> Self {
        self.rayleigh_coefficient = coeff;
        self
    }

    /// Set Mie coefficient.
    pub fn mie(mut self, coeff: f32) -> Self {
        self.mie_coefficient = coeff;
        self
    }

    /// Set Mie direction (g parameter).
    pub fn mie_direction(mut self, g: f32) -> Self {
        self.mie_direction = g.clamp(-1.0, 1.0);
        self
    }

    /// Validate sky parameters.
    pub fn validate(&self) -> Result<(), MissShaderError> {
        // Check sun direction is normalized (approximately)
        let len_sq = self.sun_direction[0] * self.sun_direction[0]
            + self.sun_direction[1] * self.sun_direction[1]
            + self.sun_direction[2] * self.sun_direction[2];
        if (len_sq - 1.0).abs() > 0.01 {
            return Err(MissShaderError::InvalidSkyParameters(
                "Sun direction must be normalized".to_string(),
            ));
        }
        if self.sun_radius <= 0.0 {
            return Err(MissShaderError::InvalidSkyParameters(
                "Sun radius must be positive".to_string(),
            ));
        }
        Ok(())
    }

    /// Generate WGSL for procedural sky color computation.
    pub fn generate_sky_color(&self) -> String {
        format!(
            r#"// Procedural Sky Color Computation
// Simplified atmospheric scattering model

// Sky parameters (can be made uniform for runtime adjustment)
const SKY_SUN_DIRECTION: vec3<f32> = vec3<f32>({sun_x}, {sun_y}, {sun_z});
const SKY_HORIZON_COLOR: vec3<f32> = vec3<f32>({hz_r}, {hz_g}, {hz_b});
const SKY_ZENITH_COLOR: vec3<f32> = vec3<f32>({zn_r}, {zn_g}, {zn_b});
const SKY_SUN_COLOR: vec3<f32> = vec3<f32>({sc_r}, {sc_g}, {sc_b});
const SKY_SUN_RADIUS: f32 = {sun_radius};
const SKY_RAYLEIGH: f32 = {rayleigh};
const SKY_MIE: f32 = {mie};
const SKY_MIE_G: f32 = {mie_g};

// Rayleigh phase function
fn rayleigh_phase(cos_theta: f32) -> f32 {{
    return (3.0 / (16.0 * 3.14159)) * (1.0 + cos_theta * cos_theta);
}}

// Henyey-Greenstein phase function for Mie scattering
fn mie_phase(cos_theta: f32, g: f32) -> f32 {{
    let g2 = g * g;
    let denom = 1.0 + g2 - 2.0 * g * cos_theta;
    return (1.0 - g2) / (4.0 * 3.14159 * pow(denom, 1.5));
}}

// Compute procedural sky color for a given view direction
fn compute_sky_color(
    ray_dir: vec3<f32>,
    sun_direction: vec3<f32>
) -> vec3<f32> {{
    // Height-based gradient (y component)
    let altitude = ray_dir.y;
    let gradient = clamp(altitude, 0.0, 1.0);

    // Base sky color: horizon to zenith gradient
    var sky_color = mix(SKY_HORIZON_COLOR, SKY_ZENITH_COLOR, pow(gradient, 0.5));

    // Sun angle
    let cos_sun_angle = dot(ray_dir, sun_direction);

    // Rayleigh scattering (blue sky)
    let rayleigh = rayleigh_phase(cos_sun_angle) * SKY_RAYLEIGH;

    // Mie scattering (sun glow)
    let mie = mie_phase(cos_sun_angle, SKY_MIE_G) * SKY_MIE;

    // Apply scattering
    sky_color = sky_color + SKY_SUN_COLOR * (rayleigh * vec3<f32>(0.3, 0.5, 1.0) + mie);

    // Sun disk
    let sun_disk = smoothstep(cos(SKY_SUN_RADIUS * 1.5), cos(SKY_SUN_RADIUS * 0.5), cos_sun_angle);
    sky_color = mix(sky_color, SKY_SUN_COLOR * 10.0, sun_disk);

    // Below horizon: darken
    if (altitude < 0.0) {{
        let below_factor = clamp(-altitude * 5.0, 0.0, 1.0);
        sky_color = mix(sky_color, SKY_HORIZON_COLOR * 0.1, below_factor);
    }}

    return sky_color;
}}

// Simplified sky color (faster, less accurate)
fn compute_sky_color_simple(ray_dir: vec3<f32>) -> vec3<f32> {{
    let t = clamp(ray_dir.y * 0.5 + 0.5, 0.0, 1.0);
    return mix(SKY_HORIZON_COLOR, SKY_ZENITH_COLOR, t);
}}"#,
            sun_x = self.sun_direction[0],
            sun_y = self.sun_direction[1],
            sun_z = self.sun_direction[2],
            hz_r = self.horizon_color[0],
            hz_g = self.horizon_color[1],
            hz_b = self.horizon_color[2],
            zn_r = self.zenith_color[0],
            zn_g = self.zenith_color[1],
            zn_b = self.zenith_color[2],
            sc_r = self.sun_color[0],
            sc_g = self.sun_color[1],
            sc_b = self.sun_color[2],
            sun_radius = self.sun_radius,
            rayleigh = self.rayleigh_coefficient,
            mie = self.mie_coefficient,
            mie_g = self.mie_direction
        )
    }
}

// ---------------------------------------------------------------------------
// MissShaderTable - Collection of miss shaders
// ---------------------------------------------------------------------------

/// Table of miss shaders indexed by miss index.
///
/// Manages multiple miss shaders for different ray types
/// (e.g., primary rays vs shadow rays).
#[derive(Debug, Clone, Default)]
pub struct MissShaderTable {
    /// Miss shaders indexed by miss_index.
    shaders: Vec<Option<MissShaderDesc>>,
}

impl MissShaderTable {
    /// Create a new empty miss shader table.
    pub fn new() -> Self {
        Self::default()
    }

    /// Create with a default miss shader at index 0.
    pub fn with_default(desc: MissShaderDesc) -> Self {
        let mut table = Self::new();
        let _ = table.add(desc.miss_index(0));
        table
    }

    /// Add a miss shader to the table.
    pub fn add(&mut self, desc: MissShaderDesc) -> Result<(), MissShaderError> {
        let index = desc.miss_index as usize;

        // Ensure vector is large enough
        if self.shaders.len() <= index {
            self.shaders.resize(index + 1, None);
        }

        // Check for duplicate
        if self.shaders[index].is_some() {
            return Err(MissShaderError::DuplicateMissIndex(desc.miss_index));
        }

        self.shaders[index] = Some(desc);
        Ok(())
    }

    /// Remove a miss shader by index.
    pub fn remove(&mut self, miss_index: u32) -> Option<MissShaderDesc> {
        let index = miss_index as usize;
        if index < self.shaders.len() {
            self.shaders[index].take()
        } else {
            None
        }
    }

    /// Get a miss shader by index.
    pub fn get(&self, miss_index: u32) -> Option<&MissShaderDesc> {
        self.shaders.get(miss_index as usize).and_then(|opt| opt.as_ref())
    }

    /// Get the default miss shader (index 0).
    pub fn default_shader(&self) -> Option<&MissShaderDesc> {
        self.get(0)
    }

    /// Get number of miss shaders.
    pub fn len(&self) -> usize {
        self.shaders.iter().filter(|s| s.is_some()).count()
    }

    /// Check if table is empty.
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }

    /// Get all miss indices in use.
    pub fn indices(&self) -> Vec<u32> {
        self.shaders
            .iter()
            .enumerate()
            .filter_map(|(i, s)| s.as_ref().map(|_| i as u32))
            .collect()
    }

    /// Validate that indices are contiguous from 0.
    pub fn validate(&self) -> Result<(), MissShaderError> {
        if self.is_empty() {
            return Ok(());
        }

        // Check for index 0 (default miss shader)
        if self.shaders.is_empty() || self.shaders[0].is_none() {
            return Err(MissShaderError::MissingDefaultMissShader);
        }

        // Check for contiguous indices
        let indices = self.indices();
        for (expected, &actual) in indices.iter().enumerate() {
            if expected as u32 != actual {
                return Err(MissShaderError::NonContiguousIndices(indices));
            }
        }

        // Validate each shader
        for shader in self.shaders.iter().flatten() {
            shader.validate()?;
        }

        Ok(())
    }

    /// Iterate over all miss shaders.
    pub fn iter(&self) -> impl Iterator<Item = &MissShaderDesc> {
        self.shaders.iter().filter_map(|s| s.as_ref())
    }
}

// ---------------------------------------------------------------------------
// MissWgslGenerator - Complete miss shader generator
// ---------------------------------------------------------------------------

/// Generator for complete miss shader WGSL code.
///
/// Produces shader code for environment sampling, procedural sky,
/// or solid color background when rays miss all geometry.
pub struct MissWgslGenerator {
    desc: MissShaderDesc,
    env_sampler: EnvironmentSampler,
    procedural_sky: ProceduralSky,
}

impl MissWgslGenerator {
    /// Create a new generator with the given descriptor.
    pub fn new(desc: MissShaderDesc) -> Self {
        Self {
            desc,
            env_sampler: EnvironmentSampler::new(),
            procedural_sky: ProceduralSky::new(),
        }
    }

    /// Create with custom environment sampler.
    pub fn with_env_sampler(mut self, sampler: EnvironmentSampler) -> Self {
        self.env_sampler = sampler;
        self
    }

    /// Create with custom procedural sky.
    pub fn with_procedural_sky(mut self, sky: ProceduralSky) -> Self {
        self.procedural_sky = sky;
        self
    }

    /// Get the descriptor.
    pub fn desc(&self) -> &MissShaderDesc {
        &self.desc
    }

    /// Generate miss payload struct.
    fn generate_miss_payload() -> String {
        r#"// Miss payload - written when ray hits nothing
struct MissPayload {
    color: vec4<f32>,  // Environment/background color
    depth: f32,        // -1.0 indicates miss (no hit)
    flags: u32,        // Miss flags (e.g., miss shader index)
}

// Initialize miss payload with environment color
fn init_miss_payload_with_color(color: vec3<f32>) -> MissPayload {
    var payload: MissPayload;
    payload.color = vec4<f32>(color, 1.0);
    payload.depth = -1.0;  // Negative depth indicates miss
    payload.flags = 0u;
    return payload;
}"#.to_string()
    }

    /// Generate environment sampling code based on source type.
    fn generate_environment_sample(&self) -> String {
        match &self.desc.env_source {
            EnvironmentSource::Cubemap => {
                EnvironmentSampler::generate_cubemap_sample()
            }
            EnvironmentSource::Equirectangular => {
                EnvironmentSampler::generate_equirect_sample()
            }
            EnvironmentSource::ProceduralSky => {
                self.procedural_sky.generate_sky_color()
            }
            EnvironmentSource::SolidColor(color) => {
                format!(
                    r#"// Solid color background
const MISS_SOLID_COLOR: vec4<f32> = vec4<f32>({}, {}, {}, {});

fn get_solid_color() -> vec3<f32> {{
    return MISS_SOLID_COLOR.rgb;
}}"#,
                    color[0], color[1], color[2], color[3]
                )
            }
        }
    }

    /// Generate the main miss shader function.
    fn generate_miss_main(&self) -> String {
        let sample_call = match &self.desc.env_source {
            EnvironmentSource::Cubemap => {
                "sample_cubemap_environment(ray_dir, 0.0)"
            }
            EnvironmentSource::Equirectangular => {
                "sample_equirect_environment(ray_dir, 0.0)"
            }
            EnvironmentSource::ProceduralSky => {
                "compute_sky_color(ray_dir, SKY_SUN_DIRECTION)"
            }
            EnvironmentSource::SolidColor(_) => {
                "get_solid_color()"
            }
        };

        format!(
            r#"// Main miss shader function
// Called when ray misses all geometry (ray_query committed type == NONE)
//
// @miss attribute (conceptual - wgpu uses inline ray_query)
fn {entry_point}(
    ray_dir: vec3<f32>,
    payload: ptr<function, HitPayload>
) {{
    // Sample environment color based on ray direction
    let color = {sample_call};

    // Write to payload
    (*payload).color = vec4<f32>(color, 1.0);
    (*payload).depth = -1.0;  // Negative depth indicates miss (no hit)
    (*payload).normal = -ray_dir;  // Normal points back at viewer
    (*payload).hit_kind = 0xFFFFFFFFu;  // Max value indicates miss
}}"#,
            entry_point = self.desc.entry_point,
            sample_call = sample_call
        )
    }

    /// Generate ray_query integration snippet.
    fn generate_ray_query_integration(&self) -> String {
        format!(
            r#"// Integration with ray_query traversal
// Call this after rayQueryProceed returns false with no committed hit

fn process_miss(
    rq: ptr<function, ray_query>,
    payload: ptr<function, HitPayload>
) {{
    // Check for no committed hit
    let hit_type = rayQueryGetCommittedIntersectionType(rq);

    if (hit_type == COMMITTED_NOTHING) {{
        // Ray missed all geometry - execute miss shader
        let ray_dir = normalize(rayQueryGetWorldRayDirection(rq));
        {entry_point}(ray_dir, payload);
    }}
}}"#,
            entry_point = self.desc.entry_point
        )
    }

    /// Generate complete miss shader.
    pub fn generate_complete_shader(&self) -> String {
        let mut shader = String::with_capacity(8192);

        // Header comment
        shader.push_str(&format!(
            "// T-WGPU-P5.7.6: Miss Shader Stage\n\
             // Entry point: {}\n\
             // Miss index: {}\n\
             // Environment source: {}\n\n",
            self.desc.entry_point,
            self.desc.miss_index,
            self.desc.env_source.variant_name()
        ));

        // Constants
        shader.push_str("const PI: f32 = 3.14159265359;\n\n");

        // Miss payload struct
        shader.push_str(&Self::generate_miss_payload());
        shader.push_str("\n\n");

        // HitPayload struct (reuse from closest-hit)
        shader.push_str(&HitPayload::generate_wgsl_struct());
        shader.push_str("\n\n");

        // Environment sampling code
        shader.push_str(&self.generate_environment_sample());
        shader.push_str("\n\n");

        // Main miss shader function
        shader.push_str(&self.generate_miss_main());
        shader.push_str("\n\n");

        // Ray query integration
        shader.push_str(&self.generate_ray_query_integration());

        shader
    }
}

// ---------------------------------------------------------------------------
// MissShaderDescBuilder - Builder for miss shader descriptors
// ---------------------------------------------------------------------------

/// Builder for creating miss shader descriptors.
pub struct MissShaderDescBuilder {
    label: Option<String>,
    entry_point: String,
    miss_index: u32,
    env_source: EnvironmentSource,
}

impl Default for MissShaderDescBuilder {
    fn default() -> Self {
        Self {
            label: None,
            entry_point: "miss_main".to_string(),
            miss_index: 0,
            env_source: EnvironmentSource::default(),
        }
    }
}

impl MissShaderDescBuilder {
    /// Create a new builder with defaults.
    pub fn new() -> Self {
        Self::default()
    }

    /// Set label.
    pub fn label(mut self, label: impl Into<String>) -> Self {
        self.label = Some(label.into());
        self
    }

    /// Set entry point.
    pub fn entry_point(mut self, entry: impl Into<String>) -> Self {
        self.entry_point = entry.into();
        self
    }

    /// Set miss index.
    pub fn miss_index(mut self, index: u32) -> Self {
        self.miss_index = index;
        self
    }

    /// Set environment source to cubemap.
    pub fn cubemap(mut self) -> Self {
        self.env_source = EnvironmentSource::Cubemap;
        self
    }

    /// Set environment source to equirectangular.
    pub fn equirectangular(mut self) -> Self {
        self.env_source = EnvironmentSource::Equirectangular;
        self
    }

    /// Set environment source to procedural sky.
    pub fn procedural_sky(mut self) -> Self {
        self.env_source = EnvironmentSource::ProceduralSky;
        self
    }

    /// Set environment source to solid color.
    pub fn solid_color(mut self, color: [f32; 4]) -> Self {
        self.env_source = EnvironmentSource::SolidColor(color);
        self
    }

    /// Set custom environment source.
    pub fn env_source(mut self, source: EnvironmentSource) -> Self {
        self.env_source = source;
        self
    }

    /// Build the descriptor.
    pub fn build(self) -> Result<MissShaderDesc, MissShaderError> {
        let desc = MissShaderDesc {
            label: self.label.unwrap_or_default(),
            entry_point: self.entry_point,
            miss_index: self.miss_index,
            env_source: self.env_source,
        };
        desc.validate()?;
        Ok(desc)
    }

    /// Build and generate the complete shader.
    pub fn build_shader(self) -> Result<String, MissShaderError> {
        let desc = self.build()?;
        let generator = MissWgslGenerator::new(desc);
        Ok(generator.generate_complete_shader())
    }

    /// Build with custom procedural sky settings.
    pub fn build_shader_with_sky(self, sky: ProceduralSky) -> Result<String, MissShaderError> {
        let desc = self.build()?;
        let generator = MissWgslGenerator::new(desc).with_procedural_sky(sky);
        Ok(generator.generate_complete_shader())
    }
}

// === End T-WGPU-P5.7.6: Miss Shader Stage ===

// T-WGPU-P5.7.7: Callable Shader Stage
// Callable shader for utility functions in wgpu ray tracing.
// Note: wgpu doesn't have native callable shaders. Callable shaders are modeled
// as utility functions. Execute callable = function call in compute shader.
// Callable data passed via function parameters.

// ---------------------------------------------------------------------------
// CallableShaderError - Error types for callable shader
// ---------------------------------------------------------------------------

/// Errors that can occur during callable shader setup.
#[derive(Debug, Clone, PartialEq)]
pub enum CallableShaderError {
    /// Invalid entry point name.
    InvalidEntryPoint,
    /// Invalid callable index (must be contiguous from 0).
    InvalidCallableIndex(u32, String),
    /// Duplicate callable index.
    DuplicateCallableIndex(u32),
    /// Missing default callable shader (index 0).
    MissingDefaultCallableShader,
    /// Non-contiguous callable indices.
    NonContiguousIndices(Vec<u32>),
    /// Invalid callable data configuration.
    InvalidCallableData(String),
    /// Invalid callable type.
    InvalidCallableType(String),
}

impl std::fmt::Display for CallableShaderError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            CallableShaderError::InvalidEntryPoint => {
                write!(f, "Invalid entry point name")
            }
            CallableShaderError::InvalidCallableIndex(idx, reason) => {
                write!(f, "Invalid callable index {}: {}", idx, reason)
            }
            CallableShaderError::DuplicateCallableIndex(idx) => {
                write!(f, "Duplicate callable index: {}", idx)
            }
            CallableShaderError::MissingDefaultCallableShader => {
                write!(f, "Missing default callable shader at index 0")
            }
            CallableShaderError::NonContiguousIndices(indices) => {
                write!(f, "Callable indices must be contiguous: {:?}", indices)
            }
            CallableShaderError::InvalidCallableData(reason) => {
                write!(f, "Invalid callable data: {}", reason)
            }
            CallableShaderError::InvalidCallableType(reason) => {
                write!(f, "Invalid callable type: {}", reason)
            }
        }
    }
}

impl std::error::Error for CallableShaderError {}

// ---------------------------------------------------------------------------
// CallableType - Type of callable shader operation
// ---------------------------------------------------------------------------

/// Type of callable shader operation.
///
/// Defines the category of utility function the callable shader performs.
#[derive(Debug, Clone, PartialEq)]
pub enum CallableType {
    /// Evaluate BRDF at a surface point.
    BrdfEvaluate,
    /// Indirect texture lookup (procedural texturing).
    TextureSample,
    /// Light sampling for importance sampling.
    LightSample,
    /// User-defined custom callable type.
    Custom(String),
}

impl Default for CallableType {
    fn default() -> Self {
        CallableType::BrdfEvaluate
    }
}

impl CallableType {
    /// Check if this is a BRDF-related callable.
    pub fn is_brdf(&self) -> bool {
        matches!(self, CallableType::BrdfEvaluate)
    }

    /// Check if this is a sampling-related callable.
    pub fn is_sampling(&self) -> bool {
        matches!(self, CallableType::TextureSample | CallableType::LightSample)
    }

    /// Check if this is a custom callable.
    pub fn is_custom(&self) -> bool {
        matches!(self, CallableType::Custom(_))
    }

    /// Get the variant name for WGSL comments.
    pub fn variant_name(&self) -> &str {
        match self {
            CallableType::BrdfEvaluate => "BrdfEvaluate",
            CallableType::TextureSample => "TextureSample",
            CallableType::LightSample => "LightSample",
            CallableType::Custom(name) => name.as_str(),
        }
    }

    /// Get the function name prefix for WGSL.
    pub fn function_prefix(&self) -> &str {
        match self {
            CallableType::BrdfEvaluate => "callable_brdf",
            CallableType::TextureSample => "callable_texture",
            CallableType::LightSample => "callable_light",
            CallableType::Custom(name) => name.as_str(),
        }
    }
}

// ---------------------------------------------------------------------------
// CallableData - Input/output payload for callable shaders
// ---------------------------------------------------------------------------

/// Input/output data for callable shader invocation.
///
/// This struct is Pod/Zeroable for direct GPU buffer usage.
/// It contains the input parameters and output results for BRDF evaluation.
#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct CallableData {
    /// View direction (normalized).
    pub view_dir: [f32; 3],
    /// Padding for alignment.
    pub _pad0: f32,
    /// Light direction (normalized).
    pub light_dir: [f32; 3],
    /// Padding for alignment.
    pub _pad1: f32,
    /// Surface normal (normalized).
    pub normal: [f32; 3],
    /// Surface roughness (0.0 = smooth, 1.0 = rough).
    pub roughness: f32,
    /// Surface metallic factor (0.0 = dielectric, 1.0 = metallic).
    pub metallic: f32,
    /// Padding for alignment.
    pub _pad2: [f32; 3],
    /// Output: BRDF evaluation result (RGB).
    pub result: [f32; 3],
    /// Output: Probability density function value.
    pub pdf: f32,
}

impl Default for CallableData {
    fn default() -> Self {
        Self {
            view_dir: [0.0, 0.0, 1.0],
            _pad0: 0.0,
            light_dir: [0.0, 0.707, 0.707],
            _pad1: 0.0,
            normal: [0.0, 1.0, 0.0],
            roughness: 0.5,
            metallic: 0.0,
            _pad2: [0.0; 3],
            result: [0.0; 3],
            pdf: 0.0,
        }
    }
}

// Manual Pod/Zeroable implementation for GPU usage
unsafe impl bytemuck::Pod for CallableData {}
unsafe impl bytemuck::Zeroable for CallableData {}

impl CallableData {
    /// Create a new callable data with default values.
    pub fn new() -> Self {
        Self::default()
    }

    /// Create callable data for BRDF evaluation.
    pub fn for_brdf(view_dir: [f32; 3], light_dir: [f32; 3], normal: [f32; 3]) -> Self {
        Self {
            view_dir,
            light_dir,
            normal,
            ..Default::default()
        }
    }

    /// Set the view direction.
    pub fn view_dir(mut self, dir: [f32; 3]) -> Self {
        self.view_dir = dir;
        self
    }

    /// Set the light direction.
    pub fn light_dir(mut self, dir: [f32; 3]) -> Self {
        self.light_dir = dir;
        self
    }

    /// Set the surface normal.
    pub fn normal(mut self, n: [f32; 3]) -> Self {
        self.normal = n;
        self
    }

    /// Set the roughness.
    pub fn roughness(mut self, r: f32) -> Self {
        self.roughness = r.clamp(0.0, 1.0);
        self
    }

    /// Set the metallic factor.
    pub fn metallic(mut self, m: f32) -> Self {
        self.metallic = m.clamp(0.0, 1.0);
        self
    }

    /// Get the size in bytes (for GPU buffer allocation).
    pub fn size_bytes() -> usize {
        std::mem::size_of::<Self>()
    }

    /// Validate the callable data.
    pub fn validate(&self) -> Result<(), CallableShaderError> {
        // Check view_dir is not zero
        let view_len = (self.view_dir[0].powi(2) + self.view_dir[1].powi(2) + self.view_dir[2].powi(2)).sqrt();
        if view_len < 0.001 {
            return Err(CallableShaderError::InvalidCallableData(
                "view_dir must be non-zero".to_string(),
            ));
        }

        // Check light_dir is not zero
        let light_len = (self.light_dir[0].powi(2) + self.light_dir[1].powi(2) + self.light_dir[2].powi(2)).sqrt();
        if light_len < 0.001 {
            return Err(CallableShaderError::InvalidCallableData(
                "light_dir must be non-zero".to_string(),
            ));
        }

        // Check normal is not zero
        let normal_len = (self.normal[0].powi(2) + self.normal[1].powi(2) + self.normal[2].powi(2)).sqrt();
        if normal_len < 0.001 {
            return Err(CallableShaderError::InvalidCallableData(
                "normal must be non-zero".to_string(),
            ));
        }

        // Check roughness range
        if self.roughness < 0.0 || self.roughness > 1.0 {
            return Err(CallableShaderError::InvalidCallableData(
                format!("roughness must be in [0, 1], got {}", self.roughness),
            ));
        }

        // Check metallic range
        if self.metallic < 0.0 || self.metallic > 1.0 {
            return Err(CallableShaderError::InvalidCallableData(
                format!("metallic must be in [0, 1], got {}", self.metallic),
            ));
        }

        Ok(())
    }

    /// Generate WGSL struct definition.
    pub fn generate_wgsl_struct() -> String {
        r#"// T-WGPU-P5.7.7: Callable Shader Stage
// Callable data structure for BRDF evaluation
struct CallableData {
    view_dir: vec3<f32>,
    _pad0: f32,
    light_dir: vec3<f32>,
    _pad1: f32,
    normal: vec3<f32>,
    roughness: f32,
    metallic: f32,
    _pad2: vec3<f32>,
    result: vec3<f32>,
    pdf: f32,
}"#.to_string()
    }
}

