// =============================================================================
// T-WGPU-P5.9.5: SINGLE BOUNCE GI
// =============================================================================
//
// Single bounce global illumination for wgpu 25.x.
// Traces diffuse rays from hit points into a hemisphere around the normal.
// Each ray gathers indirect light from the environment and other surfaces.
// Results are accumulated and denoised.

// ---------------------------------------------------------------------------
// GI Error
// ---------------------------------------------------------------------------

/// Errors that can occur during single bounce GI operations.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum GiError {
    /// Sample count is invalid (must be 1-64).
    InvalidSampleCount(u32),
    /// Ray distance is invalid (must be > 0).
    InvalidRayDistance(String),
    /// TLAS is not bound to the pipeline.
    TlasNotBound,
    /// Shader generation failed.
    ShaderGenerationFailed(String),
}

impl std::fmt::Display for GiError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            GiError::InvalidSampleCount(count) => {
                write!(f, "Invalid sample count: {} (must be 1-64)", count)
            }
            GiError::InvalidRayDistance(dist_str) => {
                write!(f, "Invalid ray distance: {} (must be > 0)", dist_str)
            }
            GiError::TlasNotBound => {
                write!(f, "TLAS not bound to pipeline")
            }
            GiError::ShaderGenerationFailed(msg) => {
                write!(f, "Shader generation failed: {}", msg)
            }
        }
    }
}

impl std::error::Error for GiError {}

// ---------------------------------------------------------------------------
// Diffuse Ray Config
// ---------------------------------------------------------------------------

/// Configuration for diffuse ray casting in single bounce GI.
///
/// Controls the number of rays per pixel, maximum ray distance,
/// bias for self-intersection prevention, and sampling strategy.
#[derive(Debug, Clone, PartialEq)]
pub struct DiffuseRayConfig {
    /// Number of rays per pixel (1-64).
    pub sample_count: u32,
    /// Maximum ray distance.
    pub max_distance: f32,
    /// Bias to prevent self-intersection.
    pub bias: f32,
    /// Whether to use cosine-weighted hemisphere sampling.
    pub cos_weighted: bool,
}

impl Default for DiffuseRayConfig {
    fn default() -> Self {
        Self {
            sample_count: 8,
            max_distance: 100.0,
            bias: 0.001,
            cos_weighted: true,
        }
    }
}

impl DiffuseRayConfig {
    /// Create a new diffuse ray config with the given sample count.
    pub fn new(sample_count: u32) -> Self {
        Self {
            sample_count,
            ..Default::default()
        }
    }

    /// Create a low quality config (1 sample).
    pub fn low_quality() -> Self {
        Self {
            sample_count: 1,
            max_distance: 50.0,
            bias: 0.001,
            cos_weighted: true,
        }
    }

    /// Create a high quality config (32 samples).
    pub fn high_quality() -> Self {
        Self {
            sample_count: 32,
            max_distance: 200.0,
            bias: 0.0005,
            cos_weighted: true,
        }
    }

    /// Create an ultra quality config (64 samples).
    pub fn ultra_quality() -> Self {
        Self {
            sample_count: 64,
            max_distance: 500.0,
            bias: 0.0001,
            cos_weighted: true,
        }
    }

    /// Validate the configuration.
    pub fn validate(&self) -> Result<(), GiError> {
        // Sample count must be 1-64
        if self.sample_count < 1 || self.sample_count > 64 {
            return Err(GiError::InvalidSampleCount(self.sample_count));
        }

        // Max distance must be positive
        if self.max_distance <= 0.0 {
            return Err(GiError::InvalidRayDistance(format!("{}", self.max_distance)));
        }

        Ok(())
    }
}

// ---------------------------------------------------------------------------
// GI Hemisphere Sampler
// ---------------------------------------------------------------------------

/// GI-specific hemisphere sampler for diffuse ray generation.
///
/// Generates sample directions distributed over a hemisphere.
/// Supports both uniform and cosine-weighted sampling.
/// Note: This is separate from the AO HemisphereSampler to allow
/// GI-specific optimizations and configurations.
#[derive(Debug, Clone)]
pub struct GiHemisphereSampler {
    /// Number of samples to generate.
    pub sample_count: u32,
    /// Whether to use cosine-weighted sampling.
    pub cos_weighted: bool,
}

impl Default for GiHemisphereSampler {
    fn default() -> Self {
        Self {
            sample_count: 8,
            cos_weighted: true,
        }
    }
}

impl GiHemisphereSampler {
    /// Create a new GI hemisphere sampler.
    pub fn new(sample_count: u32, cos_weighted: bool) -> Self {
        Self {
            sample_count,
            cos_weighted,
        }
    }

    /// Create a uniform GI hemisphere sampler.
    pub fn uniform(sample_count: u32) -> Self {
        Self {
            sample_count,
            cos_weighted: false,
        }
    }

    /// Create a cosine-weighted GI hemisphere sampler.
    pub fn cosine_weighted(sample_count: u32) -> Self {
        Self {
            sample_count,
            cos_weighted: true,
        }
    }

    /// Generate sample directions for a given normal.
    ///
    /// Returns a vector of directions in world space, each pointing
    /// into the hemisphere defined by the normal.
    pub fn generate_samples(&self, normal: [f32; 3]) -> Vec<[f32; 3]> {
        let mut samples = Vec::with_capacity(self.sample_count as usize);

        // Build orthonormal basis from normal
        let (tangent, bitangent) = Self::build_basis(normal);

        for i in 0..self.sample_count {
            // Generate quasi-random point using Hammersley sequence
            let xi = Self::hammersley(i, self.sample_count);

            let local_dir = if self.cos_weighted {
                Self::cosine_weighted_sample_local(xi)
            } else {
                Self::uniform_sample_local(xi)
            };

            // Transform to world space
            let world_dir = Self::transform_to_world(local_dir, normal, tangent, bitangent);
            samples.push(world_dir);
        }

        samples
    }

    /// Build an orthonormal basis from a normal vector.
    fn build_basis(normal: [f32; 3]) -> ([f32; 3], [f32; 3]) {
        // Use Hughes-Moller method for numerical stability
        let sign = if normal[2] >= 0.0 { 1.0 } else { -1.0 };
        let a = -1.0 / (sign + normal[2]);
        let b = normal[0] * normal[1] * a;

        let tangent = [
            1.0 + sign * normal[0] * normal[0] * a,
            sign * b,
            -sign * normal[0],
        ];

        let bitangent = [b, sign + normal[1] * normal[1] * a, -normal[1]];

        (tangent, bitangent)
    }

    /// Generate a Hammersley sequence point.
    fn hammersley(i: u32, n: u32) -> [f32; 2] {
        // Van der Corput radical inverse base 2
        let mut bits = i;
        bits = (bits << 16) | (bits >> 16);
        bits = ((bits & 0x55555555) << 1) | ((bits & 0xAAAAAAAA) >> 1);
        bits = ((bits & 0x33333333) << 2) | ((bits & 0xCCCCCCCC) >> 2);
        bits = ((bits & 0x0F0F0F0F) << 4) | ((bits & 0xF0F0F0F0) >> 4);
        bits = ((bits & 0x00FF00FF) << 8) | ((bits & 0xFF00FF00) >> 8);

        let radical_inverse = bits as f32 * 2.3283064365386963e-10; // 1/2^32

        [(i as f32 + 0.5) / n as f32, radical_inverse]
    }

    /// Generate a cosine-weighted sample in local space.
    fn cosine_weighted_sample_local(xi: [f32; 2]) -> [f32; 3] {
        let r = xi[0].sqrt();
        let theta = 2.0 * std::f32::consts::PI * xi[1];
        let x = r * theta.cos();
        let y = r * theta.sin();
        let z = (1.0 - xi[0]).sqrt();
        [x, y, z]
    }

    /// Generate a uniform sample in local space.
    fn uniform_sample_local(xi: [f32; 2]) -> [f32; 3] {
        let cos_theta = 1.0 - xi[0];
        let sin_theta = (1.0 - cos_theta * cos_theta).sqrt();
        let phi = 2.0 * std::f32::consts::PI * xi[1];
        let x = sin_theta * phi.cos();
        let y = sin_theta * phi.sin();
        let z = cos_theta;
        [x, y, z]
    }

    /// Transform a local direction to world space.
    fn transform_to_world(
        local: [f32; 3],
        normal: [f32; 3],
        tangent: [f32; 3],
        bitangent: [f32; 3],
    ) -> [f32; 3] {
        [
            local[0] * tangent[0] + local[1] * bitangent[0] + local[2] * normal[0],
            local[0] * tangent[1] + local[1] * bitangent[1] + local[2] * normal[1],
            local[0] * tangent[2] + local[1] * bitangent[2] + local[2] * normal[2],
        ]
    }

    /// Generate WGSL code for cosine-weighted sampling.
    pub fn generate_cosine_weighted_sample() -> String {
        r#"// T-WGPU-P5.9.5: Cosine-Weighted Hemisphere Sampling

fn gi_cosine_weighted_sample(normal: vec3<f32>, xi: vec2<f32>) -> vec3<f32> {
    // Generate local hemisphere direction
    let r = sqrt(xi.x);
    let theta = 2.0 * 3.14159265359 * xi.y;
    let x = r * cos(theta);
    let y = r * sin(theta);
    let z = sqrt(1.0 - xi.x);

    // Build orthonormal basis (Hughes-Moller method)
    let sign = select(-1.0, 1.0, normal.z >= 0.0);
    let a = -1.0 / (sign + normal.z);
    let b = normal.x * normal.y * a;
    let tangent = vec3<f32>(
        1.0 + sign * normal.x * normal.x * a,
        sign * b,
        -sign * normal.x
    );
    let bitangent = vec3<f32>(
        b,
        sign + normal.y * normal.y * a,
        -normal.y
    );

    // Transform to world space
    return x * tangent + y * bitangent + z * normal;
}
"#
        .to_string()
    }

    /// Generate WGSL code for uniform hemisphere sampling.
    pub fn generate_uniform_sample() -> String {
        r#"// T-WGPU-P5.9.5: Uniform Hemisphere Sampling

fn gi_uniform_hemisphere_sample(normal: vec3<f32>, xi: vec2<f32>) -> vec3<f32> {
    // Generate local hemisphere direction
    let cos_theta = 1.0 - xi.x;
    let sin_theta = sqrt(1.0 - cos_theta * cos_theta);
    let phi = 2.0 * 3.14159265359 * xi.y;
    let x = sin_theta * cos(phi);
    let y = sin_theta * sin(phi);
    let z = cos_theta;

    // Build orthonormal basis (Hughes-Moller method)
    let sign = select(-1.0, 1.0, normal.z >= 0.0);
    let a = -1.0 / (sign + normal.z);
    let b = normal.x * normal.y * a;
    let tangent = vec3<f32>(
        1.0 + sign * normal.x * normal.x * a,
        sign * b,
        -sign * normal.x
    );
    let bitangent = vec3<f32>(
        b,
        sign + normal.y * normal.y * a,
        -normal.y
    );

    // Transform to world space
    return x * tangent + y * bitangent + z * normal;
}
"#
        .to_string()
    }
}

// ---------------------------------------------------------------------------
// Indirect Light Accumulator
// ---------------------------------------------------------------------------

/// Accumulates indirect lighting from hemisphere samples.
///
/// Handles weighting by cosine factor and normalization.
#[derive(Debug, Clone)]
pub struct IndirectLightAccumulator {
    /// Whether to weight samples by cosine factor.
    pub weight_by_cos: bool,
    /// Whether to normalize the final result.
    pub normalize: bool,
}

impl Default for IndirectLightAccumulator {
    fn default() -> Self {
        Self {
            weight_by_cos: true,
            normalize: true,
        }
    }
}

impl IndirectLightAccumulator {
    /// Create a new accumulator.
    pub fn new(weight_by_cos: bool, normalize: bool) -> Self {
        Self {
            weight_by_cos,
            normalize,
        }
    }

    /// Generate WGSL code for accumulating indirect light.
    pub fn generate_accumulation_code(&self) -> String {
        let mut code = String::new();
        code.push_str("// T-WGPU-P5.9.5: Indirect Light Accumulation\n\n");

        code.push_str("struct IndirectLightResult {\n");
        code.push_str("    radiance: vec3<f32>,\n");
        code.push_str("    weight: f32,\n");
        code.push_str("}\n\n");

        code.push_str("fn accumulate_indirect_light(\n");
        code.push_str("    sample_radiance: vec3<f32>,\n");
        code.push_str("    sample_direction: vec3<f32>,\n");
        code.push_str("    normal: vec3<f32>,\n");
        code.push_str("    accumulated: ptr<function, IndirectLightResult>\n");
        code.push_str(") {\n");

        if self.weight_by_cos {
            code.push_str("    // Weight by cosine of angle between sample direction and normal\n");
            code.push_str("    let cos_theta = max(dot(sample_direction, normal), 0.0);\n");
            code.push_str("    (*accumulated).radiance += sample_radiance * cos_theta;\n");
            code.push_str("    (*accumulated).weight += cos_theta;\n");
        } else {
            code.push_str("    // Unweighted accumulation\n");
            code.push_str("    (*accumulated).radiance += sample_radiance;\n");
            code.push_str("    (*accumulated).weight += 1.0;\n");
        }

        code.push_str("}\n\n");

        code.push_str("fn finalize_indirect_light(accumulated: IndirectLightResult) -> vec3<f32> {\n");
        if self.normalize {
            code.push_str("    // Normalize by accumulated weight\n");
            code.push_str("    if (accumulated.weight > 0.0) {\n");
            code.push_str("        return accumulated.radiance / accumulated.weight;\n");
            code.push_str("    }\n");
            code.push_str("    return vec3<f32>(0.0);\n");
        } else {
            code.push_str("    return accumulated.radiance;\n");
        }
        code.push_str("}\n");

        code
    }
}

// ---------------------------------------------------------------------------
// GI Denoise Hook
// ---------------------------------------------------------------------------

/// Hook for denoising integration in single bounce GI.
///
/// Prepares GI output for external denoising passes (temporal/spatial).
#[derive(Debug, Clone)]
pub struct GiDenoiseHook {
    /// Whether denoising is enabled.
    pub enabled: bool,
    /// Whether to use temporal accumulation.
    pub temporal: bool,
    /// Spatial filter sigma (blur radius).
    pub spatial_sigma: f32,
    /// Color difference threshold for edge preservation.
    pub color_sigma: f32,
}

impl Default for GiDenoiseHook {
    fn default() -> Self {
        Self {
            enabled: true,
            temporal: true,
            spatial_sigma: 3.0,
            color_sigma: 0.1,
        }
    }
}

impl GiDenoiseHook {
    /// Create a new denoise hook.
    pub fn new(enabled: bool) -> Self {
        Self {
            enabled,
            ..Default::default()
        }
    }

    /// Create a disabled denoise hook.
    pub fn disabled() -> Self {
        Self {
            enabled: false,
            temporal: false,
            spatial_sigma: 0.0,
            color_sigma: 0.0,
        }
    }

    /// Create a high quality denoise hook.
    pub fn high_quality() -> Self {
        Self {
            enabled: true,
            temporal: true,
            spatial_sigma: 5.0,
            color_sigma: 0.05,
        }
    }

    /// Generate WGSL code for preparing denoiser input.
    pub fn generate_denoise_prep(&self) -> String {
        let mut code = String::new();
        code.push_str("// T-WGPU-P5.9.5: GI Denoise Preparation\n\n");

        if !self.enabled {
            code.push_str("// Denoising disabled - passthrough\n");
            code.push_str("fn prepare_denoise_output(gi_result: vec3<f32>, normal: vec3<f32>, depth: f32) -> vec4<f32> {\n");
            code.push_str("    return vec4<f32>(gi_result, 1.0);\n");
            code.push_str("}\n");
            return code;
        }

        code.push_str("struct DenoiseInput {\n");
        code.push_str("    radiance: vec3<f32>,\n");
        code.push_str("    variance: f32,\n");
        code.push_str("    normal: vec3<f32>,\n");
        code.push_str("    depth: f32,\n");
        code.push_str("}\n\n");

        code.push_str("fn prepare_denoise_output(\n");
        code.push_str("    gi_result: vec3<f32>,\n");
        code.push_str("    normal: vec3<f32>,\n");
        code.push_str("    depth: f32,\n");
        code.push_str("    variance: f32\n");
        code.push_str(") -> DenoiseInput {\n");
        code.push_str("    return DenoiseInput(\n");
        code.push_str("        gi_result,\n");
        code.push_str("        variance,\n");
        code.push_str("        normal,\n");
        code.push_str("        depth\n");
        code.push_str("    );\n");
        code.push_str("}\n\n");

        if self.temporal {
            code.push_str(&format!(
                "const DENOISE_SPATIAL_SIGMA: f32 = {};\n",
                self.spatial_sigma
            ));
            code.push_str(&format!(
                "const DENOISE_COLOR_SIGMA: f32 = {};\n\n",
                self.color_sigma
            ));

            code.push_str("// Temporal accumulation weight\n");
            code.push_str("fn compute_temporal_weight(\n");
            code.push_str("    current: DenoiseInput,\n");
            code.push_str("    history: DenoiseInput,\n");
            code.push_str("    motion: vec2<f32>\n");
            code.push_str(") -> f32 {\n");
            code.push_str("    // Depth rejection\n");
            code.push_str("    let depth_diff = abs(current.depth - history.depth);\n");
            code.push_str("    let depth_weight = exp(-depth_diff * 10.0);\n");
            code.push_str("    \n");
            code.push_str("    // Normal rejection\n");
            code.push_str("    let normal_diff = 1.0 - max(dot(current.normal, history.normal), 0.0);\n");
            code.push_str("    let normal_weight = exp(-normal_diff * 5.0);\n");
            code.push_str("    \n");
            code.push_str("    // Motion rejection\n");
            code.push_str("    let motion_len = length(motion);\n");
            code.push_str("    let motion_weight = exp(-motion_len * 2.0);\n");
            code.push_str("    \n");
            code.push_str("    return depth_weight * normal_weight * motion_weight;\n");
            code.push_str("}\n");
        }

        code
    }
}

