/// Compiled single bounce GI pipeline ready for execution.
///
/// Created by `SingleBounceGiEffect::build()`.
#[derive(Debug, Clone)]
pub struct GiPipeline {
    /// Generated WGSL shader code.
    pub shader_code: String,
    /// Diffuse ray configuration.
    pub config: DiffuseRayConfig,
    /// Hemisphere sampler.
    pub sampler: GiHemisphereSampler,
    /// Indirect light accumulator.
    pub accumulator: IndirectLightAccumulator,
    /// Denoise hook configuration.
    pub denoise: GiDenoiseHook,
    /// Whether TLAS is required.
    pub requires_tlas: bool,
}

impl GiPipeline {
    /// Check if the pipeline is valid for execution.
    pub fn is_valid(&self) -> bool {
        !self.shader_code.is_empty()
    }
}

// ---------------------------------------------------------------------------
// Single Bounce GI Effect
// ---------------------------------------------------------------------------

/// Single bounce GI effect builder.
///
/// Configures and builds a single bounce global illumination pipeline.
#[derive(Debug, Clone, Default)]
pub struct SingleBounceGiEffect {
    /// Diffuse ray configuration.
    pub config: DiffuseRayConfig,
    /// Hemisphere sampler.
    pub sampler: GiHemisphereSampler,
    /// Indirect light accumulator.
    pub accumulator: IndirectLightAccumulator,
    /// Denoise hook configuration.
    pub denoise: GiDenoiseHook,
    /// Whether TLAS is bound.
    tlas_bound: bool,
}

impl SingleBounceGiEffect {
    /// Create a new single bounce GI effect with default settings.
    pub fn new() -> Self {
        Self {
            config: DiffuseRayConfig::default(),
            sampler: GiHemisphereSampler::default(),
            accumulator: IndirectLightAccumulator::default(),
            denoise: GiDenoiseHook::default(),
            tlas_bound: false,
        }
    }

    /// Create a low quality GI effect (1 sample, no denoise).
    pub fn low_quality() -> Self {
        Self {
            config: DiffuseRayConfig::low_quality(),
            sampler: GiHemisphereSampler::new(1, true),
            accumulator: IndirectLightAccumulator::default(),
            denoise: GiDenoiseHook::disabled(),
            tlas_bound: false,
        }
    }

    /// Create a high quality GI effect.
    pub fn high_quality() -> Self {
        Self {
            config: DiffuseRayConfig::high_quality(),
            sampler: GiHemisphereSampler::new(32, true),
            accumulator: IndirectLightAccumulator::default(),
            denoise: GiDenoiseHook::high_quality(),
            tlas_bound: false,
        }
    }

    /// Set the diffuse ray configuration.
    pub fn with_config(mut self, config: DiffuseRayConfig) -> Self {
        self.config = config;
        self
    }

    /// Set the hemisphere sampler.
    pub fn with_sampler(mut self, sampler: GiHemisphereSampler) -> Self {
        self.sampler = sampler;
        self
    }

    /// Set the indirect light accumulator.
    pub fn with_accumulator(mut self, accumulator: IndirectLightAccumulator) -> Self {
        self.accumulator = accumulator;
        self
    }

    /// Set the denoise hook.
    pub fn with_denoise(mut self, denoise: GiDenoiseHook) -> Self {
        self.denoise = denoise;
        self
    }

    /// Mark TLAS as bound.
    pub fn with_tlas_bound(mut self, bound: bool) -> Self {
        self.tlas_bound = bound;
        self
    }

    /// Build the single bounce GI pipeline.
    ///
    /// Validates all configuration and generates the WGSL shader code.
    pub fn build(self) -> Result<GiPipeline, GiError> {
        // Validate config
        self.config.validate()?;

        // Check TLAS requirement
        if !self.tlas_bound {
            return Err(GiError::TlasNotBound);
        }

        // Generate shader code
        let wgsl = GiWgsl::new(&self.config, &self.sampler, &self.accumulator, &self.denoise);
        let shader_code = wgsl.generate_full_shader();

        if shader_code.is_empty() {
            return Err(GiError::ShaderGenerationFailed(
                "Generated shader is empty".to_string(),
            ));
        }

        Ok(GiPipeline {
            shader_code,
            config: self.config,
            sampler: self.sampler,
            accumulator: self.accumulator,
            denoise: self.denoise,
            requires_tlas: true,
        })
    }
}

// ---------------------------------------------------------------------------
// GI WGSL Generator
// ---------------------------------------------------------------------------

/// WGSL code generator for single bounce GI.
///
/// Generates WGSL shader code for:
/// - Diffuse ray generation
/// - Hemisphere sampling
/// - Indirect light accumulation
/// - Denoise output preparation
pub struct GiWgsl<'a> {
    config: &'a DiffuseRayConfig,
    sampler: &'a GiHemisphereSampler,
    accumulator: &'a IndirectLightAccumulator,
    denoise: &'a GiDenoiseHook,
}

impl<'a> GiWgsl<'a> {
    /// Create a new WGSL generator.
    pub fn new(
        config: &'a DiffuseRayConfig,
        sampler: &'a GiHemisphereSampler,
        accumulator: &'a IndirectLightAccumulator,
        denoise: &'a GiDenoiseHook,
    ) -> Self {
        Self {
            config,
            sampler,
            accumulator,
            denoise,
        }
    }

    /// Generate WGSL code for diffuse ray tracing.
    pub fn generate_diffuse_ray(&self) -> String {
        let mut code = String::new();
        code.push_str("// T-WGPU-P5.9.5: Diffuse Ray Tracing\n\n");

        code.push_str(&format!(
            "const GI_MAX_DISTANCE: f32 = {};\n",
            self.config.max_distance
        ));
        code.push_str(&format!("const GI_BIAS: f32 = {};\n\n", self.config.bias));

        code.push_str("fn trace_gi_ray(\n");
        code.push_str("    origin: vec3<f32>,\n");
        code.push_str("    direction: vec3<f32>,\n");
        code.push_str("    tlas: acceleration_structure\n");
        code.push_str(") -> vec3<f32> {\n");
        code.push_str("    var rq: ray_query;\n");
        code.push_str("    rayQueryInitialize(\n");
        code.push_str("        &rq,\n");
        code.push_str("        tlas,\n");
        code.push_str("        RAY_FLAG_NONE,\n");
        code.push_str("        0xFFu,\n");
        code.push_str("        origin + direction * GI_BIAS,\n");
        code.push_str("        GI_BIAS,\n");
        code.push_str("        direction,\n");
        code.push_str("        GI_MAX_DISTANCE\n");
        code.push_str("    );\n");
        code.push_str("    rayQueryProceed(&rq);\n");
        code.push_str("    \n");
        code.push_str("    let intersection_type = rayQueryGetCommittedIntersectionType(&rq);\n");
        code.push_str("    if (intersection_type != RAY_QUERY_COMMITTED_INTERSECTION_NONE) {\n");
        code.push_str("        // Hit surface - sample albedo and emission\n");
        code.push_str("        let instance_id = rayQueryGetCommittedIntersectionInstanceId(&rq);\n");
        code.push_str("        let primitive_id = rayQueryGetCommittedIntersectionPrimitiveIndex(&rq);\n");
        code.push_str("        let barycentrics = rayQueryGetCommittedIntersectionBarycentrics(&rq);\n");
        code.push_str("        \n");
        code.push_str("        // Sample hit surface (simplified - actual implementation would read from material buffer)\n");
        code.push_str("        let hit_albedo = sample_hit_albedo(instance_id, primitive_id, barycentrics);\n");
        code.push_str("        let hit_emission = sample_hit_emission(instance_id, primitive_id);\n");
        code.push_str("        \n");
        code.push_str("        return hit_albedo * hit_emission;\n");
        code.push_str("    }\n");
        code.push_str("    \n");
        code.push_str("    // Miss - sample sky/environment\n");
        code.push_str("    return sample_sky(direction);\n");
        code.push_str("}\n");

        code
    }

    /// Generate WGSL code for hemisphere sampling.
    pub fn generate_hemisphere_sampling(&self) -> String {
        let mut code = String::new();
        code.push_str("// T-WGPU-P5.9.5: Hemisphere Sampling\n\n");

        code.push_str(&format!(
            "const GI_SAMPLE_COUNT: u32 = {}u;\n\n",
            self.sampler.sample_count
        ));

        // Add the appropriate sampling function
        if self.sampler.cos_weighted {
            code.push_str(&GiHemisphereSampler::generate_cosine_weighted_sample());
        } else {
            code.push_str(&GiHemisphereSampler::generate_uniform_sample());
        }

        // Add Hammersley sequence generator
        code.push_str("\n// Hammersley sequence for low-discrepancy sampling\n");
        code.push_str("fn hammersley(i: u32, n: u32) -> vec2<f32> {\n");
        code.push_str("    var bits = i;\n");
        code.push_str("    bits = (bits << 16u) | (bits >> 16u);\n");
        code.push_str("    bits = ((bits & 0x55555555u) << 1u) | ((bits & 0xAAAAAAAAu) >> 1u);\n");
        code.push_str("    bits = ((bits & 0x33333333u) << 2u) | ((bits & 0xCCCCCCCCu) >> 2u);\n");
        code.push_str("    bits = ((bits & 0x0F0F0F0Fu) << 4u) | ((bits & 0xF0F0F0F0u) >> 4u);\n");
        code.push_str("    bits = ((bits & 0x00FF00FFu) << 8u) | ((bits & 0xFF00FF00u) >> 8u);\n");
        code.push_str("    let radical_inverse = f32(bits) * 2.3283064365386963e-10;\n");
        code.push_str("    return vec2<f32>((f32(i) + 0.5) / f32(n), radical_inverse);\n");
        code.push_str("}\n");

        code
    }

    /// Generate WGSL code for indirect light accumulation.
    pub fn generate_accumulation(&self) -> String {
        self.accumulator.generate_accumulation_code()
    }

    /// Generate WGSL code for denoise output preparation.
    pub fn generate_denoise_output(&self) -> String {
        self.denoise.generate_denoise_prep()
    }

    /// Generate the complete GI shader.
    pub fn generate_full_shader(&self) -> String {
        let mut code = String::new();

        code.push_str("// =============================================================================\n");
        code.push_str("// T-WGPU-P5.9.5: Single Bounce Global Illumination Shader\n");
        code.push_str("// =============================================================================\n\n");

        // Add diffuse ray tracing
        code.push_str(&self.generate_diffuse_ray());
        code.push_str("\n");

        // Add hemisphere sampling
        code.push_str(&self.generate_hemisphere_sampling());
        code.push_str("\n");

        // Add accumulation
        code.push_str(&self.generate_accumulation());
        code.push_str("\n");

        // Add denoise output
        code.push_str(&self.generate_denoise_output());
        code.push_str("\n");

        // Add main GI function
        code.push_str("// Main single bounce GI function\n");
        code.push_str("fn compute_single_bounce_gi(\n");
        code.push_str("    origin: vec3<f32>,\n");
        code.push_str("    normal: vec3<f32>,\n");
        code.push_str("    tlas: acceleration_structure,\n");
        code.push_str("    frame_index: u32\n");
        code.push_str(") -> vec3<f32> {\n");
        code.push_str("    var result = IndirectLightResult(vec3<f32>(0.0), 0.0);\n");
        code.push_str("    \n");
        code.push_str("    for (var i = 0u; i < GI_SAMPLE_COUNT; i++) {\n");
        code.push_str("        // Generate sample direction\n");
        code.push_str("        let xi = hammersley(i + frame_index * GI_SAMPLE_COUNT, GI_SAMPLE_COUNT * 256u);\n");

        if self.sampler.cos_weighted {
            code.push_str("        let sample_dir = gi_cosine_weighted_sample(normal, xi);\n");
        } else {
            code.push_str("        let sample_dir = gi_uniform_hemisphere_sample(normal, xi);\n");
        }

        code.push_str("        \n");
        code.push_str("        // Trace ray and accumulate\n");
        code.push_str("        let radiance = trace_gi_ray(origin, sample_dir, tlas);\n");
        code.push_str("        accumulate_indirect_light(radiance, sample_dir, normal, &result);\n");
        code.push_str("    }\n");
        code.push_str("    \n");
        code.push_str("    return finalize_indirect_light(result);\n");
        code.push_str("}\n");

        code
    }
}

// === End T-WGPU-P5.9.5: Single Bounce GI ===

#[cfg(test)]
mod single_bounce_gi_tests {
    use super::*;

    // === T-WGPU-P5.9.5: Single Bounce GI Tests ===

    // Test 1: Diffuse ray config validation
    #[test]
    fn test_diffuse_ray_config_validation() {
        // Valid config
        let valid = DiffuseRayConfig::default();
        assert!(valid.validate().is_ok());

        // Invalid sample count (0)
        let zero_samples = DiffuseRayConfig {
            sample_count: 0,
            ..Default::default()
        };
        assert!(matches!(
            zero_samples.validate(),
            Err(GiError::InvalidSampleCount(0))
        ));

        // Invalid sample count (65)
        let too_many_samples = DiffuseRayConfig {
            sample_count: 65,
            ..Default::default()
        };
        assert!(matches!(
            too_many_samples.validate(),
            Err(GiError::InvalidSampleCount(65))
        ));

        // Invalid max distance (0)
        let zero_distance = DiffuseRayConfig {
            max_distance: 0.0,
            ..Default::default()
        };
        assert!(matches!(
            zero_distance.validate(),
            Err(GiError::InvalidRayDistance(_))
        ));

        // Invalid max distance (negative)
        let negative_distance = DiffuseRayConfig {
            max_distance: -10.0,
            ..Default::default()
        };
        assert!(matches!(
            negative_distance.validate(),
            Err(GiError::InvalidRayDistance(_))
        ));

        // Edge cases that should be valid
        let min_samples = DiffuseRayConfig {
            sample_count: 1,
            ..Default::default()
        };
        assert!(min_samples.validate().is_ok());

        let max_samples = DiffuseRayConfig {
            sample_count: 64,
            ..Default::default()
        };
        assert!(max_samples.validate().is_ok());
    }

    // Test 2: Diffuse ray config defaults
    #[test]
    fn test_diffuse_ray_config_defaults() {
        let config = DiffuseRayConfig::default();
        assert_eq!(config.sample_count, 8);
        assert!((config.max_distance - 100.0).abs() < 1e-6);
        assert!((config.bias - 0.001).abs() < 1e-6);
        assert!(config.cos_weighted);

        // Test presets
        let low = DiffuseRayConfig::low_quality();
        assert_eq!(low.sample_count, 1);
        assert!(low.validate().is_ok());

        let high = DiffuseRayConfig::high_quality();
        assert_eq!(high.sample_count, 32);
        assert!(high.validate().is_ok());

        let ultra = DiffuseRayConfig::ultra_quality();
        assert_eq!(ultra.sample_count, 64);
        assert!(ultra.validate().is_ok());
    }

    // Test 3: Hemisphere sampler uniform
    #[test]
    fn test_hemisphere_sampler_uniform() {
        let sampler = GiHemisphereSampler::uniform(16);
        assert_eq!(sampler.sample_count, 16);
        assert!(!sampler.cos_weighted);

        // Generate WGSL
        let wgsl = GiHemisphereSampler::generate_uniform_sample();
        assert!(wgsl.contains("gi_uniform_hemisphere_sample"));
        assert!(wgsl.contains("cos_theta"));
        assert!(wgsl.contains("sin_theta"));
        assert!(wgsl.contains("T-WGPU-P5.9.5"));
    }

    // Test 4: Hemisphere sampler cosine
    #[test]
    fn test_hemisphere_sampler_cosine() {
        let sampler = GiHemisphereSampler::cosine_weighted(32);
        assert_eq!(sampler.sample_count, 32);
        assert!(sampler.cos_weighted);

        // Generate WGSL
        let wgsl = GiHemisphereSampler::generate_cosine_weighted_sample();
        assert!(wgsl.contains("gi_cosine_weighted_sample"));
        assert!(wgsl.contains("sqrt(xi.x)"));
        assert!(wgsl.contains("sqrt(1.0 - xi.x)"));
        assert!(wgsl.contains("T-WGPU-P5.9.5"));
    }

    // Test 5: Hemisphere sample generation
    #[test]
    fn test_hemisphere_sample_generation() {
        let sampler = GiHemisphereSampler::new(8, true);

        // Test with up normal
        let up_normal = [0.0, 1.0, 0.0];
        let samples = sampler.generate_samples(up_normal);
        assert_eq!(samples.len(), 8);

        // All samples should be in the upper hemisphere (y > 0 or close to 0)
        for sample in &samples {
            let dot = sample[0] * up_normal[0] + sample[1] * up_normal[1] + sample[2] * up_normal[2];
            assert!(dot >= -0.01, "Sample should be in upper hemisphere, dot={}", dot);

            // Sample should be normalized
            let len = (sample[0] * sample[0] + sample[1] * sample[1] + sample[2] * sample[2]).sqrt();
            assert!((len - 1.0).abs() < 0.01, "Sample should be normalized, len={}", len);
        }

        // Test with different normal
        let tilted_normal = [0.0, 0.707, 0.707];
        let tilted_samples = sampler.generate_samples(tilted_normal);
        assert_eq!(tilted_samples.len(), 8);

        // Samples should be in hemisphere around tilted normal
        for sample in &tilted_samples {
            let dot = sample[0] * tilted_normal[0] + sample[1] * tilted_normal[1] + sample[2] * tilted_normal[2];
            assert!(dot >= -0.01, "Sample should be in hemisphere, dot={}", dot);
        }
    }

    // Test 6: Indirect light accumulator
    #[test]
    fn test_indirect_light_accumulator() {
        // Default accumulator
        let default_acc = IndirectLightAccumulator::default();
        assert!(default_acc.weight_by_cos);
        assert!(default_acc.normalize);

        let default_wgsl = default_acc.generate_accumulation_code();
        assert!(default_wgsl.contains("IndirectLightResult"));
        assert!(default_wgsl.contains("cos_theta"));
        assert!(default_wgsl.contains("/ accumulated.weight"));
        assert!(default_wgsl.contains("T-WGPU-P5.9.5"));

        // Unweighted accumulator
        let unweighted = IndirectLightAccumulator::new(false, false);
        let unweighted_wgsl = unweighted.generate_accumulation_code();
        assert!(unweighted_wgsl.contains("Unweighted accumulation"));
        assert!(!unweighted_wgsl.contains("cos_theta"));
        assert!(unweighted_wgsl.contains("return accumulated.radiance"));
    }

    // Test 7: GI denoise hook config
    #[test]
    fn test_gi_denoise_hook_config() {
        // Default denoise hook
        let default_hook = GiDenoiseHook::default();
        assert!(default_hook.enabled);
        assert!(default_hook.temporal);
        assert!((default_hook.spatial_sigma - 3.0).abs() < 1e-6);
        assert!((default_hook.color_sigma - 0.1).abs() < 1e-6);

        // Disabled hook
        let disabled = GiDenoiseHook::disabled();
        assert!(!disabled.enabled);
        assert!(!disabled.temporal);

        // High quality hook
        let high_quality = GiDenoiseHook::high_quality();
        assert!(high_quality.enabled);
        assert!(high_quality.temporal);
        assert!((high_quality.spatial_sigma - 5.0).abs() < 1e-6);
        assert!((high_quality.color_sigma - 0.05).abs() < 1e-6);
    }

    // Test 8: GI denoise hook WGSL
    #[test]
    fn test_gi_denoise_hook_wgsl() {
        // Enabled denoise hook with temporal
        let enabled = GiDenoiseHook::default();
        let enabled_wgsl = enabled.generate_denoise_prep();
        assert!(enabled_wgsl.contains("DenoiseInput"));
        assert!(enabled_wgsl.contains("variance"));
        assert!(enabled_wgsl.contains("compute_temporal_weight"));
        assert!(enabled_wgsl.contains("depth_weight"));
        assert!(enabled_wgsl.contains("normal_weight"));
        assert!(enabled_wgsl.contains("T-WGPU-P5.9.5"));

        // Disabled denoise hook
        let disabled = GiDenoiseHook::disabled();
        let disabled_wgsl = disabled.generate_denoise_prep();
        assert!(disabled_wgsl.contains("Denoising disabled"));
        assert!(disabled_wgsl.contains("passthrough"));
        assert!(!disabled_wgsl.contains("compute_temporal_weight"));
    }

    // Test 9: Single bounce GI effect build
    #[test]
    fn test_single_bounce_gi_effect_build() {
        // Build without TLAS should fail
        let no_tlas = SingleBounceGiEffect::new();
        assert!(matches!(no_tlas.build(), Err(GiError::TlasNotBound)));

        // Build with TLAS should succeed
        let with_tlas = SingleBounceGiEffect::new().with_tlas_bound(true);
        let result = with_tlas.build();
        assert!(result.is_ok());

        let pipeline = result.unwrap();
        assert!(pipeline.is_valid());
        assert!(!pipeline.shader_code.is_empty());
        assert!(pipeline.requires_tlas);
        assert!(pipeline.shader_code.contains("T-WGPU-P5.9.5"));

        // Build with invalid config should fail
        let invalid_config = SingleBounceGiEffect::new()
            .with_config(DiffuseRayConfig {
                sample_count: 100, // Invalid
                ..Default::default()
            })
            .with_tlas_bound(true);
        assert!(matches!(
            invalid_config.build(),
            Err(GiError::InvalidSampleCount(100))
        ));

        // Test presets
        let low_quality = SingleBounceGiEffect::low_quality().with_tlas_bound(true);
        assert!(low_quality.build().is_ok());

        let high_quality = SingleBounceGiEffect::high_quality().with_tlas_bound(true);
        assert!(high_quality.build().is_ok());
    }

    // Test 10: GI WGSL sampling
    #[test]
    fn test_gi_wgsl_sampling() {
        let config = DiffuseRayConfig::default();
        let sampler = GiHemisphereSampler::cosine_weighted(16);
        let accumulator = IndirectLightAccumulator::default();
        let denoise = GiDenoiseHook::default();

        let wgsl = GiWgsl::new(&config, &sampler, &accumulator, &denoise);

        // Test hemisphere sampling generation
        let sampling_code = wgsl.generate_hemisphere_sampling();
        assert!(sampling_code.contains("GI_SAMPLE_COUNT: u32 = 16u"));
        assert!(sampling_code.contains("gi_cosine_weighted_sample"));
        assert!(sampling_code.contains("hammersley"));
        assert!(sampling_code.contains("T-WGPU-P5.9.5"));

        // Test with uniform sampling
        let uniform_sampler = GiHemisphereSampler::uniform(8);
        let uniform_wgsl = GiWgsl::new(&config, &uniform_sampler, &accumulator, &denoise);
        let uniform_code = uniform_wgsl.generate_hemisphere_sampling();
        assert!(uniform_code.contains("gi_uniform_hemisphere_sample"));
        assert!(!uniform_code.contains("gi_cosine_weighted_sample"));
    }

    // Test 11: GI WGSL accumulation
    #[test]
    fn test_gi_wgsl_accumulation() {
        let config = DiffuseRayConfig::default();
        let sampler = GiHemisphereSampler::default();
        let accumulator = IndirectLightAccumulator::new(true, true);
        let denoise = GiDenoiseHook::default();

        let wgsl = GiWgsl::new(&config, &sampler, &accumulator, &denoise);

        // Test accumulation code
        let acc_code = wgsl.generate_accumulation();
        assert!(acc_code.contains("IndirectLightResult"));
        assert!(acc_code.contains("accumulate_indirect_light"));
        assert!(acc_code.contains("finalize_indirect_light"));
        assert!(acc_code.contains("cos_theta"));
        assert!(acc_code.contains("T-WGPU-P5.9.5"));

        // Full shader should include everything
        let full_shader = wgsl.generate_full_shader();
        assert!(full_shader.contains("trace_gi_ray"));
        assert!(full_shader.contains("compute_single_bounce_gi"));
        assert!(full_shader.contains("GI_MAX_DISTANCE"));
        assert!(full_shader.contains("GI_BIAS"));
    }

    // Test 12: GI error display
    #[test]
    fn test_gi_error_display() {
        // Test InvalidSampleCount
        let e1 = GiError::InvalidSampleCount(100);
        let display1 = format!("{}", e1);
        assert!(display1.contains("Invalid sample count"));
        assert!(display1.contains("100"));
        assert!(display1.contains("1-64"));

        // Test InvalidRayDistance
        let e2 = GiError::InvalidRayDistance("-5.0".to_string());
        let display2 = format!("{}", e2);
        assert!(display2.contains("Invalid ray distance"));
        assert!(display2.contains("-5.0"));

        // Test TlasNotBound
        let e3 = GiError::TlasNotBound;
        let display3 = format!("{}", e3);
        assert!(display3.contains("TLAS not bound"));

        // Test ShaderGenerationFailed
        let e4 = GiError::ShaderGenerationFailed("parse error".to_string());
        let display4 = format!("{}", e4);
        assert!(display4.contains("Shader generation failed"));
        assert!(display4.contains("parse error"));

        // Test error is std::error::Error
        let error: &dyn std::error::Error = &e1;
        let _ = format!("{}", error);
    }

    // === End T-WGPU-P5.9.5: Single Bounce GI Tests ===
}

