/// Image format for reference images
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ImageFormat {
    /// RGBA 8-bit per channel
    Rgba8,
    /// RGB 8-bit per channel (no alpha)
    Rgb8,
    /// Grayscale 8-bit
    Gray8,
    /// RGBA 16-bit per channel (HDR)
    Rgba16,
}

impl Default for ImageFormat {
    fn default() -> Self {
        Self::Rgba8
    }
}

impl ImageFormat {
    /// Returns bytes per pixel for this format
    pub fn bytes_per_pixel(&self) -> usize {
        match self {
            Self::Rgba8 => 4,
            Self::Rgb8 => 3,
            Self::Gray8 => 1,
            Self::Rgba16 => 8,
        }
    }

    /// Returns number of channels for this format
    pub fn channels(&self) -> usize {
        match self {
            Self::Rgba8 | Self::Rgba16 => 4,
            Self::Rgb8 => 3,
            Self::Gray8 => 1,
        }
    }
}

/// Reference image for visual testing
#[derive(Debug, Clone)]
pub struct ReferenceImage {
    /// Image width in pixels
    pub width: u32,
    /// Image height in pixels
    pub height: u32,
    /// RGBA pixel data
    pub data: Vec<[u8; 4]>,
    /// Image format
    pub format: ImageFormat,
}

impl ReferenceImage {
    /// Create a new reference image with given dimensions
    pub fn new(width: u32, height: u32) -> Self {
        let pixel_count = (width * height) as usize;
        Self {
            width,
            height,
            data: vec![[0, 0, 0, 255]; pixel_count],
            format: ImageFormat::Rgba8,
        }
    }

    /// Create a new reference image with specific format
    pub fn with_format(width: u32, height: u32, format: ImageFormat) -> Self {
        let pixel_count = (width * height) as usize;
        Self {
            width,
            height,
            data: vec![[0, 0, 0, 255]; pixel_count],
            format,
        }
    }

    /// Generate a checkerboard pattern for testing
    pub fn generate_checkerboard(width: u32, height: u32, tile_size: u32) -> Self {
        let pixel_count = (width * height) as usize;
        let mut data = Vec::with_capacity(pixel_count);

        for y in 0..height {
            for x in 0..width {
                let tile_x = x / tile_size;
                let tile_y = y / tile_size;
                let is_white = (tile_x + tile_y) % 2 == 0;

                if is_white {
                    data.push([255, 255, 255, 255]);
                } else {
                    data.push([0, 0, 0, 255]);
                }
            }
        }

        Self {
            width,
            height,
            data,
            format: ImageFormat::Rgba8,
        }
    }

    /// Generate a gradient pattern for testing
    pub fn generate_gradient(width: u32, height: u32) -> Self {
        let pixel_count = (width * height) as usize;
        let mut data = Vec::with_capacity(pixel_count);

        for y in 0..height {
            for x in 0..width {
                let r = ((x as f32 / width as f32) * 255.0) as u8;
                let g = ((y as f32 / height as f32) * 255.0) as u8;
                let b = (((x + y) as f32 / (width + height) as f32) * 255.0) as u8;
                data.push([r, g, b, 255]);
            }
        }

        Self {
            width,
            height,
            data,
            format: ImageFormat::Rgba8,
        }
    }

    /// Generate a solid color image
    pub fn generate_solid(width: u32, height: u32, color: [u8; 4]) -> Self {
        let pixel_count = (width * height) as usize;
        Self {
            width,
            height,
            data: vec![color; pixel_count],
            format: ImageFormat::Rgba8,
        }
    }

    /// Convert to a different image format
    pub fn convert_format(&self, target_format: ImageFormat) -> Self {
        let mut result = Self {
            width: self.width,
            height: self.height,
            data: self.data.clone(),
            format: target_format,
        };

        // Apply format-specific conversions
        match target_format {
            ImageFormat::Gray8 => {
                // Convert to grayscale using luminance formula
                for pixel in &mut result.data {
                    let gray = (0.299 * pixel[0] as f32
                              + 0.587 * pixel[1] as f32
                              + 0.114 * pixel[2] as f32) as u8;
                    *pixel = [gray, gray, gray, pixel[3]];
                }
            }
            ImageFormat::Rgb8 => {
                // Just mark as RGB (alpha channel preserved in data but ignored)
            }
            ImageFormat::Rgba16 => {
                // Mark as 16-bit (actual data stays 8-bit for simplicity)
            }
            ImageFormat::Rgba8 => {
                // No conversion needed
            }
        }

        result
    }

    /// Get pixel at coordinates
    pub fn get_pixel(&self, x: u32, y: u32) -> Option<[u8; 4]> {
        if x >= self.width || y >= self.height {
            return None;
        }
        let idx = (y * self.width + x) as usize;
        self.data.get(idx).copied()
    }

    /// Set pixel at coordinates
    pub fn set_pixel(&mut self, x: u32, y: u32, color: [u8; 4]) -> bool {
        if x >= self.width || y >= self.height {
            return false;
        }
        let idx = (y * self.width + x) as usize;
        if idx < self.data.len() {
            self.data[idx] = color;
            true
        } else {
            false
        }
    }

    /// Get total pixel count
    pub fn pixel_count(&self) -> usize {
        (self.width * self.height) as usize
    }
}

/// Result of comparing two images
#[derive(Debug, Clone)]
pub struct ComparisonResult {
    /// Whether the images match within threshold
    pub matches: bool,
    /// Percentage of pixels that differ (0.0 - 100.0)
    pub difference_percentage: f32,
    /// Maximum per-channel difference found
    pub max_difference: u8,
    /// Average difference across all pixels
    pub average_difference: f32,
    /// Difference map (optional, showing where differences occur)
    pub difference_map: Option<ReferenceImage>,
}

impl ComparisonResult {
    /// Create a result indicating a perfect match
    pub fn perfect_match() -> Self {
        Self {
            matches: true,
            difference_percentage: 0.0,
            max_difference: 0,
            average_difference: 0.0,
            difference_map: None,
        }
    }

    /// Create a result indicating images don't match
    pub fn no_match(diff_pct: f32, max_diff: u8, avg_diff: f32) -> Self {
        Self {
            matches: false,
            difference_percentage: diff_pct,
            max_difference: max_diff,
            average_difference: avg_diff,
            difference_map: None,
        }
    }
}

/// Configuration for image comparison
#[derive(Debug, Clone)]
pub struct ImageComparison {
    /// Overall threshold for match (0.0 - 1.0, percentage of pixels that can differ)
    pub threshold: f32,
    /// Per-pixel tolerance (max allowed difference per channel)
    pub per_pixel_tolerance: u8,
    /// Whether to generate a difference map
    pub generate_difference_map: bool,
    /// Channels to compare (bitmask: R=1, G=2, B=4, A=8)
    pub channel_mask: u8,
}

impl Default for ImageComparison {
    fn default() -> Self {
        Self {
            threshold: 0.01,           // 1% of pixels can differ
            per_pixel_tolerance: 2,    // 2 units tolerance per channel
            generate_difference_map: false,
            channel_mask: 0b1111,      // Compare all channels
        }
    }
}

impl ImageComparison {
    /// Create a strict comparison (exact match required)
    pub fn strict() -> Self {
        Self {
            threshold: 0.0,
            per_pixel_tolerance: 0,
            generate_difference_map: false,
            channel_mask: 0b1111,
        }
    }

    /// Create a lenient comparison for RT effects (some variation expected)
    pub fn lenient_rt() -> Self {
        Self {
            threshold: 0.05,           // 5% of pixels can differ
            per_pixel_tolerance: 10,   // Allow more variation for RT noise
            generate_difference_map: true,
            channel_mask: 0b0111,      // Ignore alpha for RT comparisons
        }
    }

    /// Compare two reference images
    pub fn compare(&self, a: &ReferenceImage, b: &ReferenceImage) -> ComparisonResult {
        // Check dimensions match
        if a.width != b.width || a.height != b.height {
            return ComparisonResult::no_match(100.0, 255, 255.0);
        }

        if a.data.len() != b.data.len() {
            return ComparisonResult::no_match(100.0, 255, 255.0);
        }

        let mut differing_pixels = 0u64;
        let mut max_diff: u8 = 0;
        let mut total_diff: f64 = 0.0;
        let mut diff_map_data = if self.generate_difference_map {
            Some(Vec::with_capacity(a.data.len()))
        } else {
            None
        };

        for (idx, (pixel_a, pixel_b)) in a.data.iter().zip(b.data.iter()).enumerate() {
            let mut pixel_differs = false;
            let mut pixel_max_diff: u8 = 0;
            let mut pixel_diff_color = [0u8, 0, 0, 255];

            for ch in 0..4 {
                // Check if this channel should be compared
                if (self.channel_mask & (1 << ch)) == 0 {
                    continue;
                }

                let diff = (pixel_a[ch] as i16 - pixel_b[ch] as i16).unsigned_abs() as u8;

                if diff > self.per_pixel_tolerance {
                    pixel_differs = true;
                }

                pixel_max_diff = pixel_max_diff.max(diff);
                total_diff += diff as f64;

                // Color code the difference map
                if diff > 0 {
                    pixel_diff_color[ch] = diff;
                }
            }

            if pixel_differs {
                differing_pixels += 1;
            }

            max_diff = max_diff.max(pixel_max_diff);

            if let Some(ref mut map) = diff_map_data {
                map.push(pixel_diff_color);
            }
        }

        let total_pixels = a.data.len() as f64;
        let channels_compared = self.channel_mask.count_ones() as f64;
        let difference_percentage = (differing_pixels as f32 / total_pixels as f32) * 100.0;
        let average_difference = (total_diff / (total_pixels * channels_compared)) as f32;

        let matches = (difference_percentage / 100.0) <= self.threshold;

        let difference_map = diff_map_data.map(|data| ReferenceImage {
            width: a.width,
            height: a.height,
            data,
            format: ImageFormat::Rgba8,
        });

        ComparisonResult {
            matches,
            difference_percentage,
            max_difference: max_diff,
            average_difference,
            difference_map,
        }
    }
}

/// Type of visual test scene
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum VisualTestSceneType {
    /// Shadow ray testing scene
    Shadow,
    /// Reflection ray testing scene
    Reflection,
    /// Ambient occlusion testing scene
    AmbientOcclusion,
    /// Combined RT effects scene
    Combined,
}

/// Visual test scene configuration
#[derive(Debug, Clone)]
pub struct VisualTestScene {
    /// Type of scene
    pub scene_type: VisualTestSceneType,
    /// Scene width in pixels
    pub width: u32,
    /// Scene height in pixels
    pub height: u32,
    /// Light position for shadow tests
    pub light_position: [f32; 3],
    /// Camera position
    pub camera_position: [f32; 3],
    /// Number of geometry instances
    pub geometry_count: u32,
    /// Expected shadow coverage (0.0 - 1.0)
    pub expected_shadow_coverage: f32,
    /// Expected reflection intensity (0.0 - 1.0)
    pub expected_reflection_intensity: f32,
    /// Expected AO intensity (0.0 - 1.0)
    pub expected_ao_intensity: f32,
}

impl Default for VisualTestScene {
    fn default() -> Self {
        Self {
            scene_type: VisualTestSceneType::Combined,
            width: 256,
            height: 256,
            light_position: [10.0, 10.0, 10.0],
            camera_position: [0.0, 5.0, 10.0],
            geometry_count: 4,
            expected_shadow_coverage: 0.25,
            expected_reflection_intensity: 0.5,
            expected_ao_intensity: 0.3,
        }
    }
}

impl VisualTestScene {
    /// Create a shadow test scene
    pub fn setup_shadow_test_scene() -> Self {
        Self {
            scene_type: VisualTestSceneType::Shadow,
            width: 256,
            height: 256,
            light_position: [5.0, 10.0, 5.0],
            camera_position: [0.0, 5.0, 15.0],
            geometry_count: 2,  // Ground plane + shadow caster
            expected_shadow_coverage: 0.15,
            expected_reflection_intensity: 0.0,
            expected_ao_intensity: 0.0,
        }
    }

    /// Create a reflection test scene
    pub fn setup_reflection_test_scene() -> Self {
        Self {
            scene_type: VisualTestSceneType::Reflection,
            width: 256,
            height: 256,
            light_position: [0.0, 20.0, 0.0],
            camera_position: [0.0, 3.0, 10.0],
            geometry_count: 3,  // Reflective surface + 2 reflected objects
            expected_shadow_coverage: 0.0,
            expected_reflection_intensity: 0.7,
            expected_ao_intensity: 0.0,
        }
    }

    /// Create an ambient occlusion test scene
    pub fn setup_ao_test_scene() -> Self {
        Self {
            scene_type: VisualTestSceneType::AmbientOcclusion,
            width: 256,
            height: 256,
            light_position: [0.0, 100.0, 0.0],  // Distant ambient
            camera_position: [0.0, 2.0, 8.0],
            geometry_count: 5,  // Cornell box-like setup
            expected_shadow_coverage: 0.0,
            expected_reflection_intensity: 0.0,
            expected_ao_intensity: 0.4,
        }
    }

    /// Generate expected output image for this scene
    pub fn generate_expected_output(&self) -> ReferenceImage {
        let mut image = ReferenceImage::new(self.width, self.height);

        match self.scene_type {
            VisualTestSceneType::Shadow => {
                self.generate_shadow_reference(&mut image);
            }
            VisualTestSceneType::Reflection => {
                self.generate_reflection_reference(&mut image);
            }
            VisualTestSceneType::AmbientOcclusion => {
                self.generate_ao_reference(&mut image);
            }
            VisualTestSceneType::Combined => {
                self.generate_combined_reference(&mut image);
            }
        }

        image
    }

    fn generate_shadow_reference(&self, image: &mut ReferenceImage) {
        let center_x = self.width / 2;
        let center_y = self.height / 2;
        let shadow_radius = (self.width as f32 * self.expected_shadow_coverage.sqrt()) as u32;

        for y in 0..self.height {
            for x in 0..self.width {
                let dx = x as i32 - center_x as i32;
                let dy = y as i32 - center_y as i32;
                let dist = ((dx * dx + dy * dy) as f32).sqrt();

                let color = if dist < shadow_radius as f32 {
                    // Shadow region (darker)
                    let shadow_factor = 1.0 - (dist / shadow_radius as f32);
                    let intensity = (180.0 - 80.0 * shadow_factor) as u8;
                    [intensity, intensity, intensity, 255]
                } else {
                    // Lit region
                    [200, 200, 200, 255]
                };

                image.set_pixel(x, y, color);
            }
        }
    }

    fn generate_reflection_reference(&self, image: &mut ReferenceImage) {
        let reflect_y = (self.height as f32 * 0.6) as u32;

        for y in 0..self.height {
            for x in 0..self.width {
                let color = if y > reflect_y {
                    // Reflective surface (mirror-like, shows reflection)
                    let reflect_source_y = reflect_y - (y - reflect_y);
                    let reflected_val = if reflect_source_y < self.height / 3 {
                        // Sky reflection
                        let blend = self.expected_reflection_intensity;
                        let sky = 180;
                        let surface = 100;
                        ((sky as f32 * blend + surface as f32 * (1.0 - blend)) as u8)
                    } else {
                        100
                    };
                    [reflected_val, reflected_val, (reflected_val as f32 * 1.1).min(255.0) as u8, 255]
                } else if y < self.height / 3 {
                    // Sky
                    [180, 200, 220, 255]
                } else {
                    // Object
                    [150, 150, 150, 255]
                };

                image.set_pixel(x, y, color);
            }
        }
    }

    fn generate_ao_reference(&self, image: &mut ReferenceImage) {
        // Cornell box-like AO pattern
        for y in 0..self.height {
            for x in 0..self.width {
                // Calculate AO based on distance to corners/edges
                let nx = x as f32 / self.width as f32;
                let ny = y as f32 / self.height as f32;

                // More AO near edges and corners
                let edge_dist_x = (0.5 - (nx - 0.5).abs()) * 2.0;
                let edge_dist_y = (0.5 - (ny - 0.5).abs()) * 2.0;
                let edge_factor = edge_dist_x.min(edge_dist_y);

                // AO intensity increases near edges
                let ao = self.expected_ao_intensity * (1.0 - edge_factor);
                let base_intensity = 200u8;
                let intensity = (base_intensity as f32 * (1.0 - ao)) as u8;

                image.set_pixel(x, y, [intensity, intensity, intensity, 255]);
            }
        }
    }

    fn generate_combined_reference(&self, image: &mut ReferenceImage) {
        // Combine all effects
        for y in 0..self.height {
            for x in 0..self.width {
                let nx = x as f32 / self.width as f32;
                let ny = y as f32 / self.height as f32;

                // Base color
                let mut r = 180.0f32;
                let mut g = 180.0f32;
                let mut b = 180.0f32;

                // Apply shadow (center region)
                let shadow_dist = ((nx - 0.5).powi(2) + (ny - 0.5).powi(2)).sqrt();
                if shadow_dist < 0.3 {
                    let shadow_factor = self.expected_shadow_coverage * (1.0 - shadow_dist / 0.3);
                    r *= 1.0 - shadow_factor * 0.4;
                    g *= 1.0 - shadow_factor * 0.4;
                    b *= 1.0 - shadow_factor * 0.4;
                }

                // Apply reflection (bottom region)
                if ny > 0.7 {
                    let reflect_factor = self.expected_reflection_intensity * ((ny - 0.7) / 0.3);
                    b += 30.0 * reflect_factor;
                }

                // Apply AO (edges)
                let edge_factor = (0.5 - (nx - 0.5).abs()).min(0.5 - (ny - 0.5).abs()) * 2.0;
                let ao_factor = self.expected_ao_intensity * (1.0 - edge_factor.max(0.0));
                r *= 1.0 - ao_factor * 0.3;
                g *= 1.0 - ao_factor * 0.3;
                b *= 1.0 - ao_factor * 0.3;

                image.set_pixel(x, y, [
                    r.clamp(0.0, 255.0) as u8,
                    g.clamp(0.0, 255.0) as u8,
                    b.clamp(0.0, 255.0) as u8,
                    255,
                ]);
            }
        }
    }

    /// Validate scene configuration
    pub fn validate(&self) -> bool {
        self.width > 0
            && self.height > 0
            && self.geometry_count > 0
            && self.expected_shadow_coverage >= 0.0
            && self.expected_shadow_coverage <= 1.0
            && self.expected_reflection_intensity >= 0.0
            && self.expected_reflection_intensity <= 1.0
            && self.expected_ao_intensity >= 0.0
            && self.expected_ao_intensity <= 1.0
    }
}

/// Visual test configuration combining scene and comparison settings
#[derive(Debug, Clone)]
pub struct VisualTestConfig {
    /// Test scene configuration
    pub scene: VisualTestScene,
    /// Image comparison settings
    pub comparison: ImageComparison,
    /// Test name for identification
    pub name: String,
    /// Whether to save failed comparison images
    pub save_failures: bool,
    /// Maximum allowed render time in milliseconds
    pub max_render_time_ms: u64,
}

impl Default for VisualTestConfig {
    fn default() -> Self {
        Self {
            scene: VisualTestScene::default(),
            comparison: ImageComparison::default(),
            name: String::from("unnamed_visual_test"),
            save_failures: true,
            max_render_time_ms: 5000,
        }
    }
}

impl VisualTestConfig {
    /// Create a shadow visual test
    pub fn shadow_test() -> Self {
        Self {
            scene: VisualTestScene::setup_shadow_test_scene(),
            comparison: ImageComparison::lenient_rt(),
            name: String::from("rt_shadow_test"),
            save_failures: true,
            max_render_time_ms: 3000,
        }
    }

    /// Create a reflection visual test
    pub fn reflection_test() -> Self {
        Self {
            scene: VisualTestScene::setup_reflection_test_scene(),
            comparison: ImageComparison::lenient_rt(),
            name: String::from("rt_reflection_test"),
            save_failures: true,
            max_render_time_ms: 4000,
        }
    }

    /// Create an AO visual test
    pub fn ao_test() -> Self {
        Self {
            scene: VisualTestScene::setup_ao_test_scene(),
            comparison: ImageComparison::lenient_rt(),
            name: String::from("rt_ao_test"),
            save_failures: true,
            max_render_time_ms: 4000,
        }
    }

    /// Validate the entire test configuration
    pub fn validate(&self) -> bool {
        // Scene must be valid
        if !self.scene.validate() {
            return false;
        }

        // Comparison threshold must be valid
        if self.comparison.threshold < 0.0 || self.comparison.threshold > 1.0 {
            return false;
        }

        // Name must not be empty
        if self.name.is_empty() {
            return false;
        }

        // Render time must be reasonable
        if self.max_render_time_ms == 0 || self.max_render_time_ms > 60000 {
            return false;
        }

        true
    }

    /// Run the visual test and return comparison result
    pub fn run_test(&self) -> ComparisonResult {
        // Generate expected reference image
        let expected = self.scene.generate_expected_output();

        // In a real implementation, this would render the scene using RT
        // For testing purposes, we generate a "rendered" image with slight variations
        let rendered = self.simulate_render(&expected);

        // Compare images
        self.comparison.compare(&expected, &rendered)
    }

    /// Simulate rendering with slight variations (for testing the comparison system)
    fn simulate_render(&self, reference: &ReferenceImage) -> ReferenceImage {
        let mut rendered = reference.clone();

        // Add slight noise to simulate render variations
        for pixel in &mut rendered.data {
            for ch in 0..3 {
                let noise = ((pixel[ch] as i16 % 5) - 2) as i8;
                pixel[ch] = (pixel[ch] as i16 + noise as i16).clamp(0, 255) as u8;
            }
        }

        rendered
    }
}

#[cfg(test)]
mod visual_tests {
    use super::*;

    mod reference_image {
        use super::*;

        // Test 1: Basic reference image creation
        #[test]
        fn test_reference_image_creation() {
            let img = ReferenceImage::new(64, 64);

            assert_eq!(img.width, 64);
            assert_eq!(img.height, 64);
            assert_eq!(img.data.len(), 64 * 64);
            assert_eq!(img.format, ImageFormat::Rgba8);

            // All pixels should be black with full alpha
            for pixel in &img.data {
                assert_eq!(*pixel, [0, 0, 0, 255]);
            }
        }

        // Test 2: Checkerboard pattern generation
        #[test]
        fn test_checkerboard_generation() {
            let img = ReferenceImage::generate_checkerboard(64, 64, 8);

            assert_eq!(img.width, 64);
            assert_eq!(img.height, 64);

            // Check corners follow checkerboard pattern
            // Top-left (0,0) should be white (tile 0,0 -> sum=0 -> white)
            assert_eq!(img.get_pixel(0, 0), Some([255, 255, 255, 255]));

            // (8,0) should be black (tile 1,0 -> sum=1 -> black)
            assert_eq!(img.get_pixel(8, 0), Some([0, 0, 0, 255]));

            // (0,8) should be black (tile 0,1 -> sum=1 -> black)
            assert_eq!(img.get_pixel(0, 8), Some([0, 0, 0, 255]));

            // (8,8) should be white (tile 1,1 -> sum=2 -> white)
            assert_eq!(img.get_pixel(8, 8), Some([255, 255, 255, 255]));
        }

        // Test 3: Gradient pattern generation
        #[test]
        fn test_gradient_generation() {
            let img = ReferenceImage::generate_gradient(256, 256);

            assert_eq!(img.width, 256);
            assert_eq!(img.height, 256);

            // Top-left corner should be dark
            let tl = img.get_pixel(0, 0).unwrap();
            assert_eq!(tl[0], 0);  // R at x=0
            assert_eq!(tl[1], 0);  // G at y=0

            // Bottom-right corner should be bright
            let br = img.get_pixel(255, 255).unwrap();
            assert!(br[0] > 200);  // R at x=255
            assert!(br[1] > 200);  // G at y=255

            // Gradient should be smooth
            let mid = img.get_pixel(128, 128).unwrap();
            assert!(mid[0] > 100 && mid[0] < 150);
            assert!(mid[1] > 100 && mid[1] < 150);
        }

        // Test 4: Format conversion
        #[test]
        fn test_format_conversion() {
            let color_img = ReferenceImage::generate_gradient(32, 32);

            // Convert to grayscale
            let gray_img = color_img.convert_format(ImageFormat::Gray8);
            assert_eq!(gray_img.format, ImageFormat::Gray8);

            // Grayscale pixels should have R=G=B
            for pixel in &gray_img.data {
                assert_eq!(pixel[0], pixel[1]);
                assert_eq!(pixel[1], pixel[2]);
            }

            // Convert to RGB (removes alpha from consideration)
            let rgb_img = color_img.convert_format(ImageFormat::Rgb8);
            assert_eq!(rgb_img.format, ImageFormat::Rgb8);

            // Verify bytes per pixel
            assert_eq!(ImageFormat::Rgba8.bytes_per_pixel(), 4);
            assert_eq!(ImageFormat::Rgb8.bytes_per_pixel(), 3);
            assert_eq!(ImageFormat::Gray8.bytes_per_pixel(), 1);
            assert_eq!(ImageFormat::Rgba16.bytes_per_pixel(), 8);
        }
    }

    mod image_comparison {
        use super::*;

        // Test 5: Exact match comparison
        #[test]
        fn test_exact_match() {
            let img_a = ReferenceImage::generate_checkerboard(32, 32, 4);
            let img_b = ReferenceImage::generate_checkerboard(32, 32, 4);

            let comparison = ImageComparison::strict();
            let result = comparison.compare(&img_a, &img_b);

            assert!(result.matches);
            assert_eq!(result.difference_percentage, 0.0);
            assert_eq!(result.max_difference, 0);
            assert_eq!(result.average_difference, 0.0);
        }

        // Test 6: Within threshold comparison
        #[test]
        fn test_within_threshold() {
            let img_a = ReferenceImage::generate_solid(32, 32, [100, 100, 100, 255]);

            // Create slightly different image
            let mut img_b = img_a.clone();
            for pixel in &mut img_b.data {
                pixel[0] = 101;  // Slightly different red
            }

            // With tolerance of 2, should match
            let comparison = ImageComparison {
                threshold: 0.0,
                per_pixel_tolerance: 2,
                generate_difference_map: false,
                channel_mask: 0b1111,
            };
            let result = comparison.compare(&img_a, &img_b);

            assert!(result.matches);
            assert_eq!(result.max_difference, 1);
        }

        // Test 7: Outside threshold comparison
        #[test]
        fn test_outside_threshold() {
            let img_a = ReferenceImage::generate_solid(32, 32, [100, 100, 100, 255]);
            let img_b = ReferenceImage::generate_solid(32, 32, [200, 200, 200, 255]);

            let comparison = ImageComparison::strict();
            let result = comparison.compare(&img_a, &img_b);

            assert!(!result.matches);
            assert_eq!(result.difference_percentage, 100.0);
            assert_eq!(result.max_difference, 100);
        }

        // Test 8: Difference map generation
        #[test]
        fn test_difference_map_generation() {
            let img_a = ReferenceImage::generate_solid(16, 16, [100, 100, 100, 255]);

            // Create image with differences in specific region
            let mut img_b = img_a.clone();
            for y in 0..8 {
                for x in 0..8 {
                    let idx = (y * 16 + x) as usize;
                    img_b.data[idx] = [200, 100, 100, 255];  // Red tint in top-left
                }
            }

            let comparison = ImageComparison {
                threshold: 1.0,  // Allow all differences
                per_pixel_tolerance: 0,
                generate_difference_map: true,
                channel_mask: 0b1111,
            };
            let result = comparison.compare(&img_a, &img_b);

            // Should have generated a difference map
            assert!(result.difference_map.is_some());

            let diff_map = result.difference_map.unwrap();
            assert_eq!(diff_map.width, 16);
            assert_eq!(diff_map.height, 16);

            // Top-left quadrant should show red difference
            let diff_pixel = diff_map.get_pixel(4, 4).unwrap();
            assert!(diff_pixel[0] > 0);  // Red channel difference
        }
    }

    mod test_scenes {
        use super::*;

        // Test 9: Shadow test scene setup
        #[test]
        fn test_shadow_scene_setup() {
            let scene = VisualTestScene::setup_shadow_test_scene();

            assert_eq!(scene.scene_type, VisualTestSceneType::Shadow);
            assert!(scene.validate());
            assert!(scene.expected_shadow_coverage > 0.0);
            assert_eq!(scene.expected_reflection_intensity, 0.0);
            assert_eq!(scene.expected_ao_intensity, 0.0);

            // Generate reference and verify it has content
            let reference = scene.generate_expected_output();
            assert_eq!(reference.width, scene.width);
            assert_eq!(reference.height, scene.height);

            // Shadow region should have darker pixels
            let center = reference.get_pixel(scene.width / 2, scene.height / 2).unwrap();
            let edge = reference.get_pixel(0, 0).unwrap();
            assert!(center[0] <= edge[0], "Center should be darker or equal (shadow)");
        }

        // Test 10: Reflection test scene setup
        #[test]
        fn test_reflection_scene_setup() {
            let scene = VisualTestScene::setup_reflection_test_scene();

            assert_eq!(scene.scene_type, VisualTestSceneType::Reflection);
            assert!(scene.validate());
            assert_eq!(scene.expected_shadow_coverage, 0.0);
            assert!(scene.expected_reflection_intensity > 0.0);

            // Generate reference
            let reference = scene.generate_expected_output();

            // Bottom region (reflection) should differ from middle
            let middle = reference.get_pixel(scene.width / 2, scene.height / 2).unwrap();
            let bottom = reference.get_pixel(scene.width / 2, scene.height - 10).unwrap();

            // Reflection region should have blue tint
            assert!(bottom[2] >= middle[2], "Bottom should have reflection characteristics");
        }

        // Test 11: AO test scene setup
        #[test]
        fn test_ao_scene_setup() {
            let scene = VisualTestScene::setup_ao_test_scene();

            assert_eq!(scene.scene_type, VisualTestSceneType::AmbientOcclusion);
            assert!(scene.validate());
            assert_eq!(scene.expected_shadow_coverage, 0.0);
            assert_eq!(scene.expected_reflection_intensity, 0.0);
            assert!(scene.expected_ao_intensity > 0.0);

            // Generate reference
            let reference = scene.generate_expected_output();

            // Edges should be darker (more AO)
            let edge = reference.get_pixel(5, 5).unwrap();
            let center = reference.get_pixel(scene.width / 2, scene.height / 2).unwrap();

            // Center should be brighter (less AO)
            assert!(center[0] >= edge[0], "Center should have less AO than edges");
        }

        // Test 12: Combined validation
        #[test]
        fn test_combined_validation() {
            // Test all visual test configs validate properly
            let shadow_config = VisualTestConfig::shadow_test();
            assert!(shadow_config.validate());
            assert_eq!(shadow_config.scene.scene_type, VisualTestSceneType::Shadow);

            let reflection_config = VisualTestConfig::reflection_test();
            assert!(reflection_config.validate());
            assert_eq!(reflection_config.scene.scene_type, VisualTestSceneType::Reflection);

            let ao_config = VisualTestConfig::ao_test();
            assert!(ao_config.validate());
            assert_eq!(ao_config.scene.scene_type, VisualTestSceneType::AmbientOcclusion);

            // Run tests and verify they produce results
            let shadow_result = shadow_config.run_test();
            assert!(shadow_result.difference_percentage < 50.0); // Simulated render is similar

            let reflection_result = reflection_config.run_test();
            assert!(reflection_result.difference_percentage < 50.0);

            let ao_result = ao_config.run_test();
            assert!(ao_result.difference_percentage < 50.0);

            // Invalid configs should fail validation
            let mut invalid_config = VisualTestConfig::default();
            invalid_config.name = String::new();
            assert!(!invalid_config.validate());

            invalid_config.name = String::from("test");
            invalid_config.comparison.threshold = 2.0;  // Invalid threshold
            assert!(!invalid_config.validate());
        }
    }
}

