    // Test 9: RT Pipeline Validation
    #[test]
    fn test_rt_pipeline_validation() {
        let features = RtPipelineFeatures::full_support();

        // Valid descriptor
        let descriptor = RtPipelineDescriptor::default();
        assert!(descriptor.validate(&features).is_ok());

        // Valid with layout
        let descriptor = RtPipelineDescriptor::for_effect(RtEffect::Reflections)
            .with_layout(RtPipelineLayout::minimal_with_tlas());
        assert!(descriptor.validate(&features).is_ok());

        // Invalid - no feature support
        let no_features = RtPipelineFeatures::no_support();
        let result = descriptor.validate(&no_features);
        assert!(matches!(result, Err(RtPipelineError::FeatureNotSupported)));

        // Invalid - recursion depth too high
        let mut limited_features = features.clone();
        limited_features.max_recursion_depth = 4;
        let descriptor = RtPipelineDescriptor::default()
            .with_max_recursion_depth(8);
        let result = descriptor.validate(&limited_features);
        assert!(matches!(result, Err(RtPipelineError::InvalidRecursionDepth(_))));

        // Invalid - payload too large
        let mut limited_features = features.clone();
        limited_features.max_payload_size = 32;
        let descriptor = RtPipelineDescriptor::default()
            .with_max_payload_size(64);
        let result = descriptor.validate(&limited_features);
        assert!(matches!(result, Err(RtPipelineError::InvalidPayloadSize(_))));
    }

    // Test 10: RT Pipeline Error Display
    #[test]
    fn test_rt_pipeline_error_display() {
        // Feature not supported
        let err = RtPipelineError::FeatureNotSupported;
        assert!(err.to_string().contains("not supported"));

        // Invalid recursion depth
        let err = RtPipelineError::InvalidRecursionDepth(50);
        assert!(err.to_string().contains("50"));
        assert!(err.to_string().contains("recursion depth"));

        // Invalid payload size
        let err = RtPipelineError::InvalidPayloadSize(200);
        assert!(err.to_string().contains("200"));
        assert!(err.to_string().contains("payload"));

        // Invalid attribute size
        let err = RtPipelineError::InvalidAttributeSize(64);
        assert!(err.to_string().contains("64"));
        assert!(err.to_string().contains("attribute"));

        // Layout mismatch
        let err = RtPipelineError::LayoutMismatch;
        assert!(err.to_string().contains("layout"));

        // Duplicate binding
        let err = RtPipelineError::DuplicateBinding(3);
        assert!(err.to_string().contains("3"));
        assert!(err.to_string().contains("Duplicate"));

        // Overlapping push constants
        let err = RtPipelineError::OverlappingPushConstants;
        assert!(err.to_string().contains("Overlapping"));

        // Invalid push constant size
        let err = RtPipelineError::InvalidPushConstantSize(13);
        assert!(err.to_string().contains("13"));

        // Invalid push constant offset
        let err = RtPipelineError::InvalidPushConstantOffset(5);
        assert!(err.to_string().contains("5"));

        // Missing shader stage
        let err = RtPipelineError::MissingShaderStage(RtShaderStages::RAYGEN);
        assert!(err.to_string().contains("RAYGEN"));

        // Shader compilation error
        let err = RtPipelineError::ShaderCompilationError("syntax error".to_string());
        assert!(err.to_string().contains("syntax error"));
    }

