    // Test 2: CameraRayGenerator
    #[test]
    fn test_camera_ray_generator() {
        let generator = CameraRayGenerator::default();
        assert!((generator.fov_y - std::f32::consts::FRAC_PI_4).abs() < 0.001);
        assert!((generator.aspect_ratio - 16.0 / 9.0).abs() < 0.001);

        // Test custom creation
        let generator = CameraRayGenerator::new(
            std::f32::consts::FRAC_PI_3, // 60 degrees
            1.0, // Square aspect
        )
        .with_range(0.1, 1000.0);

        assert!((generator.fov_y - std::f32::consts::FRAC_PI_3).abs() < 0.001);
        assert!((generator.aspect_ratio - 1.0).abs() < 0.001);
        assert!((generator.near - 0.1).abs() < 0.001);
        assert!((generator.far - 1000.0).abs() < 0.001);

        // Test primary ray generation - center pixel
        let ray = generator.primary_ray([500, 500], [1000, 1000]);
        assert_eq!(ray.origin, [0.0, 0.0, 0.0]);
        // Center ray should point roughly down -Z
        assert!(ray.direction[2] < -0.5);
        assert!((ray.t_min - 0.1).abs() < 0.001);
        assert!((ray.t_max - 1000.0).abs() < 0.001);

        // Direction should be normalized
        let len = (ray.direction[0].powi(2) + ray.direction[1].powi(2) + ray.direction[2].powi(2)).sqrt();
        assert!((len - 1.0).abs() < 0.001);

        // Test validation
        assert!(generator.validate().is_ok());

        // Test invalid FOV
        let bad_fov = CameraRayGenerator::new(0.0, 1.0);
        assert!(bad_fov.validate().is_err());

        let bad_fov2 = CameraRayGenerator::new(std::f32::consts::PI, 1.0);
        assert!(bad_fov2.validate().is_err());

        // Test invalid aspect
        let bad_aspect = CameraRayGenerator::new(1.0, 0.0);
        assert!(bad_aspect.validate().is_err());

        // Test invalid near/far
        let bad_range = CameraRayGenerator::new(1.0, 1.0).with_range(-1.0, 100.0);
        assert!(bad_range.validate().is_err());

        let bad_range2 = CameraRayGenerator::new(1.0, 1.0).with_range(100.0, 10.0);
        assert!(bad_range2.validate().is_err());
    }

    // Test 3: CameraRayGenerator jittered rays
    #[test]
    fn test_camera_ray_jittered() {
        let generator = CameraRayGenerator::default();

        // Generate base ray and jittered ray
        let base_ray = generator.primary_ray([100, 100], [1920, 1080]);
        let jittered_ray = generator.jittered_ray([100, 100], [1920, 1080], [0.25, -0.25]);

        // Jittered ray should have same origin
        assert_eq!(jittered_ray.origin, base_ray.origin);

        // Jittered ray should have slightly different direction
        assert!((jittered_ray.direction[0] - base_ray.direction[0]).abs() < 0.01);
        assert!((jittered_ray.direction[1] - base_ray.direction[1]).abs() < 0.01);

        // Test that direction is still normalized
        let len = (jittered_ray.direction[0].powi(2)
            + jittered_ray.direction[1].powi(2)
            + jittered_ray.direction[2].powi(2))
        .sqrt();
        assert!((len - 1.0).abs() < 0.001);

        // Zero jitter should equal primary ray
        let no_jitter = generator.jittered_ray([100, 100], [1920, 1080], [0.0, 0.0]);
        assert!((no_jitter.direction[0] - base_ray.direction[0]).abs() < 0.0001);
        assert!((no_jitter.direction[1] - base_ray.direction[1]).abs() < 0.0001);
        assert!((no_jitter.direction[2] - base_ray.direction[2]).abs() < 0.0001);
    }

    // Test 4: CameraTransform layout
    #[test]
    fn test_camera_transform_layout() {
        // Check size is correct (2 * mat4x4<f32> = 128 bytes)
        assert_eq!(CameraTransform::size_bytes(), 128);

        // Check bytemuck traits work
        let transform = CameraTransform::identity();
        let bytes: &[u8] = bytemuck::bytes_of(&transform);
        assert_eq!(bytes.len(), 128);

        // Identity should have 1s on diagonal
        assert!((transform.view_inverse[0][0] - 1.0).abs() < 0.001);
        assert!((transform.view_inverse[1][1] - 1.0).abs() < 0.001);
        assert!((transform.view_inverse[2][2] - 1.0).abs() < 0.001);
        assert!((transform.view_inverse[3][3] - 1.0).abs() < 0.001);

        assert!((transform.proj_inverse[0][0] - 1.0).abs() < 0.001);
        assert!((transform.proj_inverse[1][1] - 1.0).abs() < 0.001);
        assert!((transform.proj_inverse[2][2] - 1.0).abs() < 0.001);
        assert!((transform.proj_inverse[3][3] - 1.0).abs() < 0.001);
    }

    // Test 5: CameraTransform from look_at
    #[test]
    fn test_camera_transform_from_look_at() {
        let transform = CameraTransform::from_look_at(
            [0.0, 1.0, 5.0],    // eye
            [0.0, 0.0, 0.0],    // target
            [0.0, 1.0, 0.0],    // up
            std::f32::consts::FRAC_PI_4, // 45 degrees FOV
            16.0 / 9.0,         // aspect ratio
        );

        // Camera position should be stored in view_inverse
        let pos = transform.camera_position();
        assert!((pos[0] - 0.0).abs() < 0.001);
        assert!((pos[1] - 1.0).abs() < 0.001);
        assert!((pos[2] - 5.0).abs() < 0.001);

        // Test ray direction at center of screen
        let center_dir = transform.ray_direction([0.0, 0.0]);
        // Should point toward target (roughly -Z after normalization)
        let dir_len = (center_dir[0].powi(2) + center_dir[1].powi(2) + center_dir[2].powi(2)).sqrt();
        assert!((dir_len - 1.0).abs() < 0.001, "Direction should be normalized");

        // Center ray direction should point toward target
        // From eye [0,1,5] to target [0,0,0] is direction [0,-1,-5] normalized
        // Due to projection transform, we test general direction
        assert!(center_dir[2] < 0.0, "Center ray should point in -Z direction");
    }

