    // Test 1: IntersectionShaderDesc validation
    #[test]
    fn test_intersection_shader_desc_validation() {
        // Default descriptor should be valid
        let desc = IntersectionShaderDesc::default();
        assert!(desc.validate().is_ok());
        assert!(desc.label.is_none());
        assert_eq!(desc.entry_point, "intersection_main");
        assert_eq!(desc.procedural_type, ProceduralType::Sphere);

        // Test new() equals default()
        let desc2 = IntersectionShaderDesc::new();
        assert_eq!(desc.entry_point, desc2.entry_point);
        assert_eq!(desc.procedural_type, desc2.procedural_type);

        // Test with_procedural_type
        let desc3 = IntersectionShaderDesc::with_procedural_type(ProceduralType::Box);
        assert_eq!(desc3.procedural_type, ProceduralType::Box);

        // Test builder methods
        let desc4 = IntersectionShaderDesc::new()
            .label("test_intersection")
            .entry_point("custom_intersect")
            .procedural_type(ProceduralType::Cylinder);
        assert_eq!(desc4.label, Some("test_intersection".to_string()));
        assert_eq!(desc4.entry_point, "custom_intersect");
        assert_eq!(desc4.procedural_type, ProceduralType::Cylinder);
        assert!(desc4.validate().is_ok());

        // Test empty entry point fails validation
        let bad_desc = IntersectionShaderDesc::new().entry_point("");
        assert!(matches!(
            bad_desc.validate(),
            Err(IntersectionError::InvalidEntryPoint)
        ));

        // Test empty SDF fails validation
        let bad_sdf = IntersectionShaderDesc::new()
            .procedural_type(ProceduralType::Sdf("".to_string()));
        assert!(matches!(
            bad_sdf.validate(),
            Err(IntersectionError::InvalidSdfFunction(_))
        ));

        // Test SDF without return fails validation
        let bad_sdf2 = IntersectionShaderDesc::new()
            .procedural_type(ProceduralType::Sdf("let x = 1.0;".to_string()));
        assert!(matches!(
            bad_sdf2.validate(),
            Err(IntersectionError::InvalidSdfFunction(_))
        ));

        // Test valid SDF passes
        let valid_sdf = IntersectionShaderDesc::new()
            .procedural_type(ProceduralType::Sdf("return length(p) - 1.0;".to_string()));
        assert!(valid_sdf.validate().is_ok());
    }

    // Test 2: ProceduralType enum
    #[test]
    fn test_procedural_type_enum() {
        // Test type names
        assert_eq!(ProceduralType::Sphere.type_name(), "sphere");
        assert_eq!(ProceduralType::Box.type_name(), "box");
        assert_eq!(ProceduralType::Cylinder.type_name(), "cylinder");
        assert_eq!(ProceduralType::Cone.type_name(), "cone");
        assert_eq!(ProceduralType::Sdf("test".to_string()).type_name(), "sdf");

        // Test is_sdf
        assert!(!ProceduralType::Sphere.is_sdf());
        assert!(!ProceduralType::Box.is_sdf());
        assert!(ProceduralType::Sdf("test".to_string()).is_sdf());

        // Test default
        assert_eq!(ProceduralType::default(), ProceduralType::Sphere);

        // Test display
        assert_eq!(format!("{}", ProceduralType::Sphere), "Sphere");
        assert_eq!(format!("{}", ProceduralType::Box), "Box");
        assert_eq!(format!("{}", ProceduralType::Cylinder), "Cylinder");
        assert_eq!(format!("{}", ProceduralType::Cone), "Cone");
        assert!(format!("{}", ProceduralType::Sdf("return length(p);".to_string())).contains("SDF"));

        // Test equality
        assert_eq!(ProceduralType::Sphere, ProceduralType::Sphere);
        assert_ne!(ProceduralType::Sphere, ProceduralType::Box);
    }

