    // Test 9: IntersectionShaderBuilder
    #[test]
    fn test_intersection_shader_builder() {
        // Test basic building
        let desc = IntersectionShaderBuilder::new()
            .label("test_builder")
            .entry_point("builder_intersect")
            .sphere()
            .build()
            .unwrap();

        assert_eq!(desc.label, Some("test_builder".to_string()));
        assert_eq!(desc.entry_point, "builder_intersect");
        assert_eq!(desc.procedural_type, ProceduralType::Sphere);

        // Test box_type
        let desc2 = IntersectionShaderBuilder::new()
            .box_type()
            .build()
            .unwrap();
        assert_eq!(desc2.procedural_type, ProceduralType::Box);

        // Test cylinder
        let desc3 = IntersectionShaderBuilder::new()
            .cylinder()
            .build()
            .unwrap();
        assert_eq!(desc3.procedural_type, ProceduralType::Cylinder);

        // Test cone
        let desc4 = IntersectionShaderBuilder::new()
            .cone()
            .build()
            .unwrap();
        assert_eq!(desc4.procedural_type, ProceduralType::Cone);

        // Test sdf
        let desc5 = IntersectionShaderBuilder::new()
            .sdf("return length(p) - 0.5;")
            .build()
            .unwrap();
        assert!(matches!(desc5.procedural_type, ProceduralType::Sdf(_)));

        // Test build_shader
        let shader = IntersectionShaderBuilder::new()
            .sphere()
            .entry_point("main")
            .build_shader()
            .unwrap();
        assert!(shader.contains("fn intersect_sphere"));
        assert!(shader.contains("fn main"));

        // Test validation failure
        let result = IntersectionShaderBuilder::new()
            .entry_point("")
            .build();
        assert!(result.is_err());

        // Test SDF validation failure
        let result2 = IntersectionShaderBuilder::new()
            .sdf("")
            .build();
        assert!(result2.is_err());
    }

    // Test 10: IntersectionError display
    #[test]
    fn test_intersection_error_display() {
        let err1 = IntersectionError::InvalidGeometry("bad mesh".to_string());
        assert!(format!("{}", err1).contains("Invalid geometry"));
        assert!(format!("{}", err1).contains("bad mesh"));

        let err2 = IntersectionError::MissingAttribute("normal".to_string());
        assert!(format!("{}", err2).contains("Missing required attribute"));
        assert!(format!("{}", err2).contains("normal"));

        let err3 = IntersectionError::InvalidEntryPoint;
        assert!(format!("{}", err3).contains("Invalid entry point"));

        let err4 = IntersectionError::InvalidSdfFunction("no return".to_string());
        assert!(format!("{}", err4).contains("Invalid SDF function"));

        let err5 = IntersectionError::InvalidHitDistance(-5.0);
        assert!(format!("{}", err5).contains("Invalid hit distance"));
        assert!(format!("{}", err5).contains("-5"));

        let err6 = IntersectionError::InvalidHitKind(999);
        assert!(format!("{}", err6).contains("Invalid hit kind"));
        assert!(format!("{}", err6).contains("999"));

        let err7 = IntersectionError::InvalidAabbBounds;
        assert!(format!("{}", err7).contains("Invalid AABB bounds"));

        let err8 = IntersectionError::UnsupportedProceduralType("fractal".to_string());
        assert!(format!("{}", err8).contains("Unsupported procedural type"));
        assert!(format!("{}", err8).contains("fractal"));

        // Test Error trait
        let _: &dyn std::error::Error = &err1;
    }

    // Test 11: Edge cases - degenerate geometry
    #[test]
    fn test_intersection_edge_cases() {
        // Test hit attributes with zero normal (invalid but shouldn't panic)
        let zero_normal = ProceduralHitAttributes::new([0.0, 0.0, 0.0]);
        // Zero normal fails validation (not normalized)
        assert!(zero_normal.validate().is_ok()); // Zero vector special case

        // Test hit attributes with very large values
        let large_attrs = ProceduralHitAttributes::new([1e10, 0.0, 0.0])
            .with_uv([1e10, 1e10])
            .with_hit_kind(u32::MAX)
            .with_custom(u32::MAX);
        // Should not panic
        let _bytes: &[u8] = bytemuck::bytes_of(&large_attrs);

        // Test long SDF function
        let long_sdf = "let a = 1.0; ".repeat(100) + "return length(p);";
        let result = IntersectionShaderBuilder::new()
            .sdf(long_sdf)
            .build();
        assert!(result.is_ok());

        // Test special characters in entry point (should be allowed by our validator)
        let special_entry = IntersectionShaderDesc::new()
            .entry_point("_intersect_main_123");
        assert!(special_entry.validate().is_ok());
    }

