    // Test 1: AnyHitShaderDesc validation
    #[test]
    fn test_any_hit_shader_desc_validation() {
        // Default descriptor should be valid
        let desc = AnyHitShaderDesc::default();
        assert!(desc.validate().is_ok());
        assert!(desc.label.is_none());
        assert_eq!(desc.entry_point, "anyhit_main");
        assert_eq!(desc.alpha_mode, AlphaMode::Opaque);

        // Test new() equals default()
        let desc2 = AnyHitShaderDesc::new();
        assert_eq!(desc.entry_point, desc2.entry_point);
        assert_eq!(desc.alpha_mode, desc2.alpha_mode);

        // Test with_alpha_mode
        let desc3 = AnyHitShaderDesc::with_alpha_mode(AlphaMode::Cutout(0.5));
        assert_eq!(desc3.alpha_mode, AlphaMode::Cutout(0.5));
        assert!(desc3.validate().is_ok());

        // Test builder methods
        let desc4 = AnyHitShaderDesc::new()
            .label("test_anyhit")
            .entry_point("custom_anyhit")
            .alpha_mode(AlphaMode::Dithered);
        assert_eq!(desc4.label, Some("test_anyhit".to_string()));
        assert_eq!(desc4.entry_point, "custom_anyhit");
        assert_eq!(desc4.alpha_mode, AlphaMode::Dithered);
        assert!(desc4.validate().is_ok());

        // Test empty entry point fails validation
        let bad_desc = AnyHitShaderDesc::new().entry_point("");
        assert!(matches!(
            bad_desc.validate(),
            Err(AnyHitError::InvalidEntryPoint)
        ));

        // Test invalid cutout threshold fails validation
        let bad_cutout = AnyHitShaderDesc::new()
            .alpha_mode(AlphaMode::Cutout(1.5));
        assert!(matches!(
            bad_cutout.validate(),
            Err(AnyHitError::InvalidAlphaThreshold(_))
        ));

        // Test negative cutout threshold fails
        let bad_cutout2 = AnyHitShaderDesc::new()
            .alpha_mode(AlphaMode::Cutout(-0.1));
        assert!(matches!(
            bad_cutout2.validate(),
            Err(AnyHitError::InvalidAlphaThreshold(_))
        ));

        // Test requires_alpha_test
        assert!(!AnyHitShaderDesc::new().alpha_mode(AlphaMode::Opaque).requires_alpha_test());
        assert!(AnyHitShaderDesc::new().alpha_mode(AlphaMode::Cutout(0.5)).requires_alpha_test());
        assert!(AnyHitShaderDesc::new().alpha_mode(AlphaMode::Blended).requires_alpha_test());
        assert!(AnyHitShaderDesc::new().alpha_mode(AlphaMode::Dithered).requires_alpha_test());
    }

    // Test 2: AlphaMode enum
    #[test]
    fn test_any_hit_alpha_mode_enum() {
        // Test mode names
        assert_eq!(AlphaMode::Opaque.mode_name(), "opaque");
        assert_eq!(AlphaMode::Cutout(0.5).mode_name(), "cutout");
        assert_eq!(AlphaMode::Blended.mode_name(), "blended");
        assert_eq!(AlphaMode::Dithered.mode_name(), "dithered");

        // Test requires_alpha_test
        assert!(!AlphaMode::Opaque.requires_alpha_test());
        assert!(AlphaMode::Cutout(0.5).requires_alpha_test());
        assert!(AlphaMode::Blended.requires_alpha_test());
        assert!(AlphaMode::Dithered.requires_alpha_test());

        // Test threshold
        assert_eq!(AlphaMode::Opaque.threshold(), None);
        assert_eq!(AlphaMode::Cutout(0.75).threshold(), Some(0.75));
        assert_eq!(AlphaMode::Blended.threshold(), None);
        assert_eq!(AlphaMode::Dithered.threshold(), None);

        // Test default
        assert_eq!(AlphaMode::default(), AlphaMode::Opaque);

        // Test display
        assert_eq!(format!("{}", AlphaMode::Opaque), "Opaque");
        assert_eq!(format!("{}", AlphaMode::Cutout(0.5)), "Cutout(0.5)");
        assert_eq!(format!("{}", AlphaMode::Blended), "Blended");
        assert_eq!(format!("{}", AlphaMode::Dithered), "Dithered");

        // Test equality
        assert_eq!(AlphaMode::Opaque, AlphaMode::Opaque);
        assert_ne!(AlphaMode::Opaque, AlphaMode::Blended);
        assert_eq!(AlphaMode::Cutout(0.5), AlphaMode::Cutout(0.5));
        assert_ne!(AlphaMode::Cutout(0.5), AlphaMode::Cutout(0.6));

        // Test validation
        assert!(AlphaMode::Opaque.validate().is_ok());
        assert!(AlphaMode::Cutout(0.0).validate().is_ok());
        assert!(AlphaMode::Cutout(1.0).validate().is_ok());
        assert!(AlphaMode::Cutout(0.5).validate().is_ok());
        assert!(AlphaMode::Cutout(1.1).validate().is_err());
        assert!(AlphaMode::Cutout(-0.1).validate().is_err());
        assert!(AlphaMode::Blended.validate().is_ok());
        assert!(AlphaMode::Dithered.validate().is_ok());
    }

    // Test 3: AnyHitDecision enum
    #[test]
    fn test_any_hit_decision_enum() {
        // Test is_accept
        assert!(AnyHitDecision::Accept.is_accept());
        assert!(!AnyHitDecision::Reject.is_accept());
        assert!(!AnyHitDecision::Continue.is_accept());

        // Test is_reject
        assert!(!AnyHitDecision::Accept.is_reject());
        assert!(AnyHitDecision::Reject.is_reject());
        assert!(!AnyHitDecision::Continue.is_reject());

        // Test should_continue
        assert!(!AnyHitDecision::Accept.should_continue());
        assert!(AnyHitDecision::Reject.should_continue());
        assert!(AnyHitDecision::Continue.should_continue());

        // Test default
        assert_eq!(AnyHitDecision::default(), AnyHitDecision::Accept);

        // Test display
        assert_eq!(format!("{}", AnyHitDecision::Accept), "Accept");
        assert_eq!(format!("{}", AnyHitDecision::Reject), "Reject");
        assert_eq!(format!("{}", AnyHitDecision::Continue), "Continue");

        // Test to_wgsl_confirm
        assert_eq!(AnyHitDecision::Accept.to_wgsl_confirm(), "true");
        assert_eq!(AnyHitDecision::Reject.to_wgsl_confirm(), "false");
        assert_eq!(AnyHitDecision::Continue.to_wgsl_confirm(), "false");
    }

    // Test 4: AnyHitHitAttributes struct
    #[test]
    fn test_any_hit_hit_attributes() {
        // Test default
        let attrs = AnyHitHitAttributes::default();
        assert_eq!(attrs.barycentrics, [0.0, 0.0]);
        assert_eq!(attrs.instance_id, 0);
        assert_eq!(attrs.primitive_id, 0);
        assert_eq!(attrs.t_hit, 0.0);
        assert_eq!(attrs.hit_kind, 0xFE); // Front face
        assert_eq!(attrs.geometry_index, 0);

        // Test new with barycentrics
        let attrs2 = AnyHitHitAttributes::new([0.3, 0.4]);
        assert_eq!(attrs2.barycentrics, [0.3, 0.4]);

        // Test with_all
        let attrs3 = AnyHitHitAttributes::with_all([0.2, 0.3], 5, 10, 1.5);
        assert_eq!(attrs3.barycentrics, [0.2, 0.3]);
        assert_eq!(attrs3.instance_id, 5);
        assert_eq!(attrs3.primitive_id, 10);
        assert_eq!(attrs3.t_hit, 1.5);

        // Test builder methods
        let attrs4 = AnyHitHitAttributes::new([0.1, 0.2])
            .with_instance_id(3)
            .with_primitive_id(7)
            .with_t_hit(2.5)
            .with_hit_kind(0xFF)
            .with_geometry_index(2);
        assert_eq!(attrs4.instance_id, 3);
        assert_eq!(attrs4.primitive_id, 7);
        assert_eq!(attrs4.t_hit, 2.5);
        assert_eq!(attrs4.hit_kind, 0xFF);
        assert_eq!(attrs4.geometry_index, 2);

        // Test barycentric_w calculation
        let attrs5 = AnyHitHitAttributes::new([0.3, 0.4]);
        let w = attrs5.barycentric_w();
        assert!((w - 0.3).abs() < 0.0001);

        // Test face detection
        let front_face = AnyHitHitAttributes::default().with_hit_kind(0xFE);
        assert!(front_face.is_front_face());
        assert!(!front_face.is_back_face());

        let back_face = AnyHitHitAttributes::default().with_hit_kind(0xFF);
        assert!(!back_face.is_front_face());
        assert!(back_face.is_back_face());

        // Test size_bytes
        assert_eq!(AnyHitHitAttributes::size_bytes(), 32); // 2*4 + 4 + 4 + 4 + 4 + 4 + 4 = 32

        // Test bytemuck
        let bytes: &[u8] = bytemuck::bytes_of(&attrs);
        assert_eq!(bytes.len(), 32);

        // Test WGSL struct generation
        let wgsl = AnyHitHitAttributes::generate_wgsl_struct();
        assert!(wgsl.contains("struct AnyHitHitAttributes"));
        assert!(wgsl.contains("barycentrics: vec2<f32>"));
        assert!(wgsl.contains("instance_id: u32"));
        assert!(wgsl.contains("primitive_id: u32"));
        assert!(wgsl.contains("t_hit: f32"));
        assert!(wgsl.contains("hit_kind: u32"));

        // Test WGSL extraction generation
        let extraction = AnyHitHitAttributes::generate_wgsl_extraction();
        assert!(extraction.contains("extract_anyhit_attributes"));
        assert!(extraction.contains("rayQueryGetCandidateIntersection"));
    }

