    // Test 1: ClosestHitShaderDesc validation
    #[test]
    fn test_closest_hit_shader_desc_validation() {
        // Default descriptor should be valid
        let desc = ClosestHitShaderDesc::default();
        assert!(desc.validate().is_ok());
        assert!(desc.label.is_empty());
        assert_eq!(desc.entry_point, "closest_hit_main");
        assert_eq!(desc.max_recursion, 4);
        assert_eq!(desc.payload_size, 48);

        // Test new() equals default()
        let desc2 = ClosestHitShaderDesc::new();
        assert_eq!(desc.entry_point, desc2.entry_point);
        assert_eq!(desc.max_recursion, desc2.max_recursion);

        // Test with_max_recursion constructor
        let desc3 = ClosestHitShaderDesc::with_max_recursion(8);
        assert_eq!(desc3.max_recursion, 8);
        assert!(desc3.validate().is_ok());

        // Test builder methods
        let desc4 = ClosestHitShaderDesc::new()
            .label("test_closest_hit")
            .entry_point("custom_closesthit")
            .max_recursion(2)
            .payload_size(64);
        assert_eq!(desc4.label, "test_closest_hit");
        assert_eq!(desc4.entry_point, "custom_closesthit");
        assert_eq!(desc4.max_recursion, 2);
        assert_eq!(desc4.payload_size, 64);
        assert!(desc4.validate().is_ok());

        // Test empty entry point fails validation
        let bad_desc = ClosestHitShaderDesc::new().entry_point("");
        assert!(matches!(
            bad_desc.validate(),
            Err(ClosestHitError::InvalidEntryPoint)
        ));

        // Test max recursion > 31 fails validation
        let bad_recursion = ClosestHitShaderDesc::new().max_recursion(32);
        assert!(matches!(
            bad_recursion.validate(),
            Err(ClosestHitError::InvalidMaxRecursion(32))
        ));

        // Test zero payload size fails validation
        let bad_payload = ClosestHitShaderDesc::new().payload_size(0);
        assert!(matches!(
            bad_payload.validate(),
            Err(ClosestHitError::InvalidPayloadSize(0))
        ));

        // Test supports_recursion
        assert!(ClosestHitShaderDesc::new().max_recursion(4).supports_recursion());
        assert!(!ClosestHitShaderDesc::new().max_recursion(0).supports_recursion());
    }

    // Test 2: HitPayload struct and bytemuck
    #[test]
    fn test_closest_hit_payload_struct() {
        // Test default payload
        let payload = HitPayload::default();
        assert_eq!(payload.color, [0.0, 0.0, 0.0, 1.0]);
        assert_eq!(payload.depth, f32::MAX);
        assert_eq!(payload.normal, [0.0, 1.0, 0.0]);
        assert_eq!(payload.hit_kind, 0);

        // Test new() with color
        let payload2 = HitPayload::new([1.0, 0.0, 0.0, 1.0]);
        assert_eq!(payload2.color, [1.0, 0.0, 0.0, 1.0]);

        // Test miss payload
        let miss = HitPayload::miss();
        assert_eq!(miss.color, [0.0, 0.0, 0.0, 0.0]);
        assert_eq!(miss.depth, f32::MAX);
        assert_eq!(miss.hit_kind, u32::MAX);
        assert!(miss.is_miss());
        assert!(!miss.is_hit());

        // Test with_all constructor
        let full = HitPayload::with_all(
            [0.5, 0.5, 0.5, 1.0],
            10.0,
            [0.0, 0.0, 1.0],
            1,
        );
        assert_eq!(full.color, [0.5, 0.5, 0.5, 1.0]);
        assert_eq!(full.depth, 10.0);
        assert_eq!(full.normal, [0.0, 0.0, 1.0]);
        assert_eq!(full.hit_kind, 1);
        assert!(full.is_hit());
        assert!(!full.is_miss());

        // Test builder methods
        let payload3 = HitPayload::default()
            .with_color([1.0, 1.0, 0.0, 1.0])
            .with_depth(5.0)
            .with_normal([1.0, 0.0, 0.0])
            .with_hit_kind(2);
        assert_eq!(payload3.color, [1.0, 1.0, 0.0, 1.0]);
        assert_eq!(payload3.depth, 5.0);
        assert_eq!(payload3.normal, [1.0, 0.0, 0.0]);
        assert_eq!(payload3.hit_kind, 2);

        // Test color accessors
        assert_eq!(payload3.color_vec4(), [1.0, 1.0, 0.0, 1.0]);
        assert_eq!(payload3.color_rgb(), [1.0, 1.0, 0.0]);

        // Test size
        assert_eq!(HitPayload::size_bytes(), 48); // 16 + 4 + 12 + 4 + 12 = 48

        // Test bytemuck traits
        let bytes: &[u8] = bytemuck::bytes_of(&payload);
        assert_eq!(bytes.len(), HitPayload::size_bytes());

        let zeroed: HitPayload = bytemuck::Zeroable::zeroed();
        assert_eq!(zeroed.color, [0.0, 0.0, 0.0, 0.0]);
        assert_eq!(zeroed.depth, 0.0);

        // Test WGSL struct generation
        let wgsl = HitPayload::generate_wgsl_struct();
        assert!(wgsl.contains("struct HitPayload"));
        assert!(wgsl.contains("color: vec4<f32>"));
        assert!(wgsl.contains("depth: f32"));
        assert!(wgsl.contains("normal: vec3<f32>"));
        assert!(wgsl.contains("hit_kind: u32"));

        // Test WGSL miss generation
        let miss_wgsl = HitPayload::generate_wgsl_miss();
        assert!(miss_wgsl.contains("init_miss_payload"));
        assert!(miss_wgsl.contains("0xFFFFFFFFu"));
    }

    // Test 3: MaterialProperties and MaterialLookup
    #[test]
    fn test_closest_hit_material_lookup() {
        // Test default material
        let mat = MaterialProperties::default();
        assert_eq!(mat.albedo, [1.0, 1.0, 1.0, 1.0]);
        assert_eq!(mat.roughness, 0.5);
        assert_eq!(mat.metallic, 0.0);
        assert_eq!(mat.emissive, [0.0, 0.0, 0.0]);
        assert_eq!(mat.ior, 1.5);
        assert!(!mat.has_textures());

        // Test with_albedo constructor
        let mat2 = MaterialProperties::with_albedo([1.0, 0.0, 0.0, 1.0]);
        assert_eq!(mat2.albedo, [1.0, 0.0, 0.0, 1.0]);

        // Test builder methods
        let mat3 = MaterialProperties::with_albedo([0.5, 0.5, 0.5, 1.0])
            .roughness(0.8)
            .metallic(1.0)
            .emissive([1.0, 1.0, 1.0])
            .ior(2.4);
        assert_eq!(mat3.roughness, 0.8);
        assert_eq!(mat3.metallic, 1.0);
        assert_eq!(mat3.emissive, [1.0, 1.0, 1.0]);
        assert_eq!(mat3.ior, 2.4);

        // Test size
        assert!(MaterialProperties::size_bytes() > 0);

        // Test bytemuck
        let bytes: &[u8] = bytemuck::bytes_of(&mat);
        assert_eq!(bytes.len(), MaterialProperties::size_bytes());

        // Test MaterialLookup WGSL generation
        let mat_struct = MaterialLookup::generate_material_struct();
        assert!(mat_struct.contains("struct MaterialProperties"));
        assert!(mat_struct.contains("albedo: vec4<f32>"));
        assert!(mat_struct.contains("roughness: f32"));
        assert!(mat_struct.contains("metallic: f32"));
        assert!(mat_struct.contains("emissive: vec3<f32>"));
        assert!(mat_struct.contains("ior: f32"));

        let inst_struct = MaterialLookup::generate_instance_data_struct();
        assert!(inst_struct.contains("struct InstanceData"));
        assert!(inst_struct.contains("material_id: u32"));
        assert!(inst_struct.contains("transform: mat4x4<f32>"));

        let fetch = MaterialLookup::generate_material_fetch();
        assert!(fetch.contains("fn fetch_material"));
        assert!(fetch.contains("instance_data[instance_id]"));
        assert!(fetch.contains("materials[mat_id]"));
        assert!(fetch.contains("fn get_material_id"));
        assert!(fetch.contains("fn get_instance_transform"));
        assert!(fetch.contains("fn get_normal_transform"));

        let complete = MaterialLookup::generate_complete();
        assert!(complete.contains("Material Lookup Utilities"));
        assert!(complete.contains("struct MaterialProperties"));
        assert!(complete.contains("struct InstanceData"));
        assert!(complete.contains("fn fetch_material"));
    }

    // Test 4: RecursiveTracer depth limiting
    #[test]
    fn test_closest_hit_recursive_tracer() {
        // Test default tracer
        let tracer = RecursiveTracer::default();
        assert_eq!(tracer.max_depth(), 4);

        // Test custom depth
        let tracer2 = RecursiveTracer::new(8);
        assert_eq!(tracer2.max_depth(), 8);

        // Test depth check generation
        let depth_check = tracer.generate_depth_check();
        assert!(depth_check.contains("MAX_RECURSION_DEPTH: u32 = 4u"));
        assert!(depth_check.contains("fn can_spawn_secondary_ray"));
        assert!(depth_check.contains("current_depth < MAX_RECURSION_DEPTH"));

        let depth_check2 = tracer2.generate_depth_check();
        assert!(depth_check2.contains("MAX_RECURSION_DEPTH: u32 = 8u"));

        // Test reflection ray generation
        let reflection = RecursiveTracer::generate_reflection_ray();
        assert!(reflection.contains("fn compute_reflection_ray"));
        assert!(reflection.contains("reflect(incident, normal)"));
        assert!(reflection.contains("fn compute_glossy_reflection"));
        assert!(reflection.contains("roughness"));

        // Test refraction ray generation
        let refraction = RecursiveTracer::generate_refraction_ray();
        assert!(refraction.contains("fn compute_refraction_ray"));
        assert!(refraction.contains("Snell's law"));
        assert!(refraction.contains("ior_ratio"));
        assert!(refraction.contains("Total internal reflection"));
        assert!(refraction.contains("fn fresnel_schlick"));
        assert!(refraction.contains("fn fresnel_dielectric"));

        // Test shadow ray generation
        let shadow = RecursiveTracer::generate_shadow_ray();
        assert!(shadow.contains("struct ShadowRayParams"));
        assert!(shadow.contains("fn setup_shadow_ray"));
        assert!(shadow.contains("fn trace_shadow_ray"));
        assert!(shadow.contains("normal * 0.001")); // Offset to avoid self-intersection

        // Test recursive trace generation
        let recursive = tracer.generate_recursive_trace();
        assert!(recursive.contains("struct SecondaryRayResult"));
        assert!(recursive.contains("fn trace_secondary_ray"));
        assert!(recursive.contains("current_depth >= 4u"));
        assert!(recursive.contains("ray_query"));
        assert!(recursive.contains("rayQueryInitialize"));
        assert!(recursive.contains("rayQueryProceed"));

        // Test complete generation
        let complete = tracer.generate_complete();
        assert!(complete.contains("Recursive Ray Tracing Utilities"));
        assert!(complete.contains("MAX_RECURSION_DEPTH"));
        assert!(complete.contains("compute_reflection_ray"));
        assert!(complete.contains("compute_refraction_ray"));
        assert!(complete.contains("ShadowRayParams"));
        assert!(complete.contains("trace_secondary_ray"));
    }

    // Test 5: PayloadWriter generation
    #[test]
    fn test_closest_hit_payload_writer() {
        // Test default writer
        let writer = PayloadWriter::new();
        assert!(writer.custom_fields().is_empty());

        // Test custom field types
        assert_eq!(PayloadFieldType::Float.wgsl_type(), "f32");
        assert_eq!(PayloadFieldType::Vec2.wgsl_type(), "vec2<f32>");
        assert_eq!(PayloadFieldType::Vec3.wgsl_type(), "vec3<f32>");
        assert_eq!(PayloadFieldType::Vec4.wgsl_type(), "vec4<f32>");
        assert_eq!(PayloadFieldType::U32.wgsl_type(), "u32");
        assert_eq!(PayloadFieldType::I32.wgsl_type(), "i32");

        assert_eq!(PayloadFieldType::Float.size_bytes(), 4);
        assert_eq!(PayloadFieldType::Vec2.size_bytes(), 8);
        assert_eq!(PayloadFieldType::Vec3.size_bytes(), 12);
        assert_eq!(PayloadFieldType::Vec4.size_bytes(), 16);
        assert_eq!(PayloadFieldType::U32.size_bytes(), 4);
        assert_eq!(PayloadFieldType::I32.size_bytes(), 4);

        // Test custom field
        let field = CustomPayloadField::new("ao_value", PayloadFieldType::Float);
        assert_eq!(field.name, "ao_value");
        assert_eq!(field.field_type, PayloadFieldType::Float);
        assert_eq!(field.generate_wgsl_field(), "    ao_value: f32,");

        // Test writer with custom fields
        let writer2 = PayloadWriter::new()
            .add_field(CustomPayloadField::new("ao", PayloadFieldType::Float))
            .add_field(CustomPayloadField::new("motion_vector", PayloadFieldType::Vec2));
        assert_eq!(writer2.custom_fields().len(), 2);

        // Test custom struct generation
        let custom_struct = writer2.generate_custom_struct();
        assert!(custom_struct.is_some());
        let struct_wgsl = custom_struct.unwrap();
        assert!(struct_wgsl.contains("struct CustomHitPayload"));
        assert!(struct_wgsl.contains("ao: f32"));
        assert!(struct_wgsl.contains("motion_vector: vec2<f32>"));
        assert!(struct_wgsl.contains("// Standard fields"));
        assert!(struct_wgsl.contains("// Custom fields"));

        // Test no custom struct when no custom fields
        let no_custom = writer.generate_custom_struct();
        assert!(no_custom.is_none());

        // Test payload write generation
        let write_wgsl = PayloadWriter::generate_payload_write();
        assert!(write_wgsl.contains("fn write_hit_payload"));
        assert!(write_wgsl.contains("fn write_payload_color"));
        assert!(write_wgsl.contains("fn write_payload_hit_info"));
        assert!(write_wgsl.contains("(*payload).color = color"));

        // Test complete generation
        let complete = writer2.generate_complete();
        assert!(complete.contains("Payload Writing Utilities"));
        assert!(complete.contains("struct HitPayload"));
        assert!(complete.contains("struct CustomHitPayload"));
        assert!(complete.contains("fn write_hit_payload"));
        assert!(complete.contains("fn init_miss_payload"));
    }

