    // Test 7: ClosestHitShaderBuilder
    #[test]
    fn test_closest_hit_shader_builder() {
        // Test default builder
        let default_result = ClosestHitShaderBuilder::new().build();
        assert!(default_result.is_ok());
        let default_desc = default_result.unwrap();
        assert_eq!(default_desc.entry_point, "closest_hit_main");
        assert_eq!(default_desc.max_recursion, 4);

        // Test customized builder
        let custom = ClosestHitShaderBuilder::new()
            .label("custom_shader")
            .entry_point("shade_hit")
            .max_recursion(8)
            .payload_size(64)
            .build();
        assert!(custom.is_ok());
        let custom_desc = custom.unwrap();
        assert_eq!(custom_desc.label, "custom_shader");
        assert_eq!(custom_desc.entry_point, "shade_hit");
        assert_eq!(custom_desc.max_recursion, 8);
        assert_eq!(custom_desc.payload_size, 64);

        // Test no_recursion
        let no_recur = ClosestHitShaderBuilder::new()
            .no_recursion()
            .build();
        assert!(no_recur.is_ok());
        assert_eq!(no_recur.unwrap().max_recursion, 0);

        // Test custom fields
        let with_fields = ClosestHitShaderBuilder::new()
            .add_custom_field("roughness_override", PayloadFieldType::Float)
            .add_custom_field("subsurface_color", PayloadFieldType::Vec3)
            .build_shader();
        assert!(with_fields.is_ok());
        let shader = with_fields.unwrap();
        assert!(shader.contains("struct CustomHitPayload"));
        assert!(shader.contains("roughness_override: f32"));
        assert!(shader.contains("subsurface_color: vec3<f32>"));

        // Test invalid entry point fails
        let bad_entry = ClosestHitShaderBuilder::new()
            .entry_point("")
            .build();
        assert!(matches!(bad_entry, Err(ClosestHitError::InvalidEntryPoint)));

        // Test invalid recursion fails
        let bad_recursion = ClosestHitShaderBuilder::new()
            .max_recursion(32)
            .build();
        assert!(matches!(bad_recursion, Err(ClosestHitError::InvalidMaxRecursion(32))));

        // Test invalid payload size fails
        let bad_payload = ClosestHitShaderBuilder::new()
            .payload_size(0)
            .build();
        assert!(matches!(bad_payload, Err(ClosestHitError::InvalidPayloadSize(0))));

        // Test build_shader produces valid output
        let shader_result = ClosestHitShaderBuilder::new()
            .entry_point("test_shader")
            .max_recursion(4)
            .build_shader();
        assert!(shader_result.is_ok());
        let shader = shader_result.unwrap();
        assert!(shader.contains("T-WGPU-P5.7.5: Closest-Hit Shader Stage"));
        assert!(shader.contains("fn test_shader"));
    }

