    #[test]
    fn test_closest_hit_error_display() {
        let entry_err = ClosestHitError::InvalidEntryPoint;
        assert_eq!(format!("{}", entry_err), "Invalid entry point name");

        let recursion_err = ClosestHitError::InvalidMaxRecursion(50);
        assert!(format!("{}", recursion_err).contains("50"));
        assert!(format!("{}", recursion_err).contains("max is 31"));

        let payload_err = ClosestHitError::InvalidPayloadSize(0);
        assert!(format!("{}", payload_err).contains("0"));
        assert!(format!("{}", payload_err).contains("must be > 0"));

        let buffer_err = ClosestHitError::MissingBufferBinding("materials".to_string());
        assert!(format!("{}", buffer_err).contains("materials"));

        let mat_err = ClosestHitError::InvalidMaterialProperty("albedo".to_string());
        assert!(format!("{}", mat_err).contains("albedo"));

        let depth_err = ClosestHitError::RecursionDepthExceeded(10, 4);
        assert!(format!("{}", depth_err).contains("10"));
        assert!(format!("{}", depth_err).contains("4"));
    }

