    // Test 1: MissShaderDesc validation
    #[test]
    fn test_miss_shader_desc_validation() {
        // Default descriptor should be valid
        let desc = MissShaderDesc::default();
        assert!(desc.validate().is_ok());
        assert!(desc.label.is_empty());
        assert_eq!(desc.entry_point, "miss_main");
        assert_eq!(desc.miss_index, 0);
        assert_eq!(desc.env_source, EnvironmentSource::ProceduralSky);

        // Test new() equals default()
        let desc2 = MissShaderDesc::new();
        assert_eq!(desc.entry_point, desc2.entry_point);
        assert_eq!(desc.miss_index, desc2.miss_index);

        // Test with_index constructor
        let desc3 = MissShaderDesc::with_index(2);
        assert_eq!(desc3.miss_index, 2);
        assert!(desc3.validate().is_ok());

        // Test with_env_source constructor
        let desc4 = MissShaderDesc::with_env_source(EnvironmentSource::Cubemap);
        assert_eq!(desc4.env_source, EnvironmentSource::Cubemap);
        assert!(desc4.validate().is_ok());

        // Test builder methods
        let desc5 = MissShaderDesc::new()
            .label("test_miss")
            .entry_point("custom_miss")
            .miss_index(1)
            .env_source(EnvironmentSource::Equirectangular);
        assert_eq!(desc5.label, "test_miss");
        assert_eq!(desc5.entry_point, "custom_miss");
        assert_eq!(desc5.miss_index, 1);
        assert_eq!(desc5.env_source, EnvironmentSource::Equirectangular);
        assert!(desc5.validate().is_ok());

        // Test empty entry point fails validation
        let bad_desc = MissShaderDesc::new().entry_point("");
        assert!(matches!(
            bad_desc.validate(),
            Err(MissShaderError::InvalidEntryPoint)
        ));

        // Test uses_texture
        assert!(MissShaderDesc::with_env_source(EnvironmentSource::Cubemap).uses_texture());
        assert!(MissShaderDesc::with_env_source(EnvironmentSource::Equirectangular).uses_texture());
        assert!(!MissShaderDesc::with_env_source(EnvironmentSource::ProceduralSky).uses_texture());
        assert!(!MissShaderDesc::with_env_source(EnvironmentSource::SolidColor([0.0; 4])).uses_texture());
    }

    // Test 2: EnvironmentSource variants
    #[test]
    fn test_miss_shader_environment_source_variants() {
        // Test Cubemap
        let cubemap = EnvironmentSource::Cubemap;
        assert!(cubemap.requires_texture());
        assert!(!cubemap.is_procedural());
        assert_eq!(cubemap.variant_name(), "Cubemap");

        // Test Equirectangular
        let equirect = EnvironmentSource::Equirectangular;
        assert!(equirect.requires_texture());
        assert!(!equirect.is_procedural());
        assert_eq!(equirect.variant_name(), "Equirectangular");

        // Test ProceduralSky
        let sky = EnvironmentSource::ProceduralSky;
        assert!(!sky.requires_texture());
        assert!(sky.is_procedural());
        assert_eq!(sky.variant_name(), "ProceduralSky");

        // Test SolidColor
        let solid = EnvironmentSource::SolidColor([1.0, 0.0, 0.0, 1.0]);
        assert!(!solid.requires_texture());
        assert!(solid.is_procedural());
        assert_eq!(solid.variant_name(), "SolidColor");

        // Test default is ProceduralSky
        assert_eq!(EnvironmentSource::default(), EnvironmentSource::ProceduralSky);
    }

    // Test 3: Cubemap and equirect UV math
    #[test]
    fn test_miss_shader_uv_math() {
        // Test EnvironmentSampler WGSL generation for cubemap
        let cubemap_wgsl = EnvironmentSampler::generate_cubemap_sample();
        assert!(cubemap_wgsl.contains("sample_cubemap_environment"));
        assert!(cubemap_wgsl.contains("textureSampleLevel"));
        assert!(cubemap_wgsl.contains("env_cubemap"));
        assert!(cubemap_wgsl.contains("texture_cube<f32>"));

        // Test EnvironmentSampler WGSL generation for equirect
        let equirect_wgsl = EnvironmentSampler::generate_equirect_sample();
        assert!(equirect_wgsl.contains("direction_to_equirect"));
        assert!(equirect_wgsl.contains("atan2"));
        assert!(equirect_wgsl.contains("asin"));
        assert!(equirect_wgsl.contains("sample_equirect_environment"));

        // Verify UV mapping formula
        assert!(equirect_wgsl.contains("phi / (2.0 * PI) + 0.5"));
        assert!(equirect_wgsl.contains("theta / PI + 0.5"));

        // Test glossy LOD generation
        let lod_wgsl = EnvironmentSampler::generate_glossy_lod();
        assert!(lod_wgsl.contains("compute_glossy_lod"));
        assert!(lod_wgsl.contains("roughness"));
        assert!(lod_wgsl.contains("max_lod"));
        assert!(lod_wgsl.contains("compute_glossy_lod_perceptual"));

        // Test complete sampler generation
        let sampler = EnvironmentSampler::new().lod_bias(0.5).glossy_lod(true);
        let complete_wgsl = sampler.generate_complete();
        assert!(complete_wgsl.contains("Environment Sampling Utilities"));
        assert!(complete_wgsl.contains("direction_to_equirect"));
        assert!(complete_wgsl.contains("sample_cubemap_environment"));
        assert!(complete_wgsl.contains("compute_glossy_lod"));
    }

    // Test 4: Procedural sky color
    #[test]
    fn test_miss_shader_procedural_sky() {
        // Test default ProceduralSky
        let sky = ProceduralSky::default();
        assert!(sky.validate().is_ok());
        assert_eq!(sky.sun_direction, [0.0, 0.707, 0.707]);
        assert_eq!(sky.horizon_color, [0.7, 0.8, 0.9]);
        assert_eq!(sky.zenith_color, [0.2, 0.4, 0.8]);

        // Test new() equals default()
        let sky2 = ProceduralSky::new();
        assert_eq!(sky.sun_direction, sky2.sun_direction);

        // Test with_sun_direction constructor
        let sky3 = ProceduralSky::with_sun_direction([0.0, 1.0, 0.0]);
        assert_eq!(sky3.sun_direction, [0.0, 1.0, 0.0]);

        // Test builder methods
        let sky4 = ProceduralSky::new()
            .sun_direction([0.0, 0.5, 0.866])
            .horizon_color([0.9, 0.6, 0.3])
            .zenith_color([0.1, 0.2, 0.5])
            .sun_color([1.0, 0.9, 0.8])
            .sun_radius(0.01)
            .rayleigh(1.5)
            .mie(0.01)
            .mie_direction(0.9);
        assert_eq!(sky4.sun_direction, [0.0, 0.5, 0.866]);
        assert_eq!(sky4.horizon_color, [0.9, 0.6, 0.3]);
        assert_eq!(sky4.rayleigh_coefficient, 1.5);
        assert_eq!(sky4.mie_coefficient, 0.01);
        assert_eq!(sky4.mie_direction, 0.9);

        // Test mie_direction clamping
        let sky5 = ProceduralSky::new().mie_direction(2.0);
        assert_eq!(sky5.mie_direction, 1.0);
        let sky6 = ProceduralSky::new().mie_direction(-2.0);
        assert_eq!(sky6.mie_direction, -1.0);

        // Test validation - non-normalized sun direction
        let bad_sky = ProceduralSky {
            sun_direction: [1.0, 1.0, 1.0], // Not normalized
            ..Default::default()
        };
        assert!(matches!(
            bad_sky.validate(),
            Err(MissShaderError::InvalidSkyParameters(_))
        ));

        // Test validation - negative sun radius
        let bad_sky2 = ProceduralSky {
            sun_radius: -0.01,
            ..Default::default()
        };
        assert!(matches!(
            bad_sky2.validate(),
            Err(MissShaderError::InvalidSkyParameters(_))
        ));

        // Test WGSL generation
        let wgsl = sky.generate_sky_color();
        assert!(wgsl.contains("compute_sky_color"));
        assert!(wgsl.contains("SKY_SUN_DIRECTION"));
        assert!(wgsl.contains("SKY_HORIZON_COLOR"));
        assert!(wgsl.contains("SKY_ZENITH_COLOR"));
        assert!(wgsl.contains("rayleigh_phase"));
        assert!(wgsl.contains("mie_phase"));
        assert!(wgsl.contains("Henyey-Greenstein"));
        assert!(wgsl.contains("compute_sky_color_simple"));
    }

    // Test 5: Miss shader table indexing
    #[test]
    fn test_miss_shader_table_indexing() {
        // Test empty table
        let table = MissShaderTable::new();
        assert!(table.is_empty());
        assert_eq!(table.len(), 0);
        assert!(table.default_shader().is_none());
        assert!(table.validate().is_ok()); // Empty table is valid

        // Test with_default constructor
        let table = MissShaderTable::with_default(MissShaderDesc::new());
        assert!(!table.is_empty());
        assert_eq!(table.len(), 1);
        assert!(table.default_shader().is_some());
        assert_eq!(table.default_shader().unwrap().miss_index, 0);

        // Test add
        let mut table = MissShaderTable::new();
        assert!(table.add(MissShaderDesc::new().miss_index(0)).is_ok());
        assert!(table.add(MissShaderDesc::new().miss_index(1).entry_point("shadow_miss")).is_ok());
        assert!(table.add(MissShaderDesc::new().miss_index(2).entry_point("ao_miss")).is_ok());
        assert_eq!(table.len(), 3);
        assert!(table.validate().is_ok());

        // Test get
        assert!(table.get(0).is_some());
        assert!(table.get(1).is_some());
        assert!(table.get(2).is_some());
        assert!(table.get(3).is_none());
        assert_eq!(table.get(1).unwrap().entry_point, "shadow_miss");

        // Test indices
        let indices = table.indices();
        assert_eq!(indices, vec![0, 1, 2]);

        // Test duplicate index error
        let mut table2 = MissShaderTable::new();
        table2.add(MissShaderDesc::new().miss_index(0)).unwrap();
        assert!(matches!(
            table2.add(MissShaderDesc::new().miss_index(0)),
            Err(MissShaderError::DuplicateMissIndex(0))
        ));

        // Test remove
        let removed = table.remove(1);
        assert!(removed.is_some());
        assert_eq!(removed.unwrap().entry_point, "shadow_miss");
        assert_eq!(table.len(), 2);

        // Test non-contiguous indices validation error
        let mut table3 = MissShaderTable::new();
        table3.add(MissShaderDesc::new().miss_index(0)).unwrap();
        table3.add(MissShaderDesc::new().miss_index(2)).unwrap(); // Skip index 1
        assert!(matches!(
            table3.validate(),
            Err(MissShaderError::NonContiguousIndices(_))
        ));

        // Test missing default shader validation error
        let mut table4 = MissShaderTable::new();
        table4.add(MissShaderDesc::new().miss_index(1)).unwrap(); // No index 0
        assert!(matches!(
            table4.validate(),
            Err(MissShaderError::MissingDefaultMissShader)
        ));

        // Test iter
        let table5 = MissShaderTable::with_default(MissShaderDesc::new());
        let count = table5.iter().count();
        assert_eq!(count, 1);
    }

