    // Test 7: Builder pattern
    #[test]
    fn test_miss_shader_builder() {
        // Test basic build
        let desc = MissShaderDescBuilder::new()
            .label("test_miss")
            .entry_point("custom_miss")
            .miss_index(1)
            .procedural_sky()
            .build()
            .expect("Build should succeed");

        assert_eq!(desc.label, "test_miss");
        assert_eq!(desc.entry_point, "custom_miss");
        assert_eq!(desc.miss_index, 1);
        assert_eq!(desc.env_source, EnvironmentSource::ProceduralSky);

        // Test cubemap builder
        let desc2 = MissShaderDescBuilder::new()
            .cubemap()
            .build()
            .expect("Cubemap build should succeed");
        assert_eq!(desc2.env_source, EnvironmentSource::Cubemap);

        // Test equirectangular builder
        let desc3 = MissShaderDescBuilder::new()
            .equirectangular()
            .build()
            .expect("Equirect build should succeed");
        assert_eq!(desc3.env_source, EnvironmentSource::Equirectangular);

        // Test solid color builder
        let desc4 = MissShaderDescBuilder::new()
            .solid_color([0.5, 0.5, 0.5, 1.0])
            .build()
            .expect("Solid color build should succeed");
        assert!(matches!(desc4.env_source, EnvironmentSource::SolidColor(_)));

        // Test build_shader
        let shader = MissShaderDescBuilder::new()
            .entry_point("test_miss")
            .procedural_sky()
            .build_shader()
            .expect("Build shader should succeed");
        assert!(shader.contains("fn test_miss"));
        assert!(shader.contains("compute_sky_color"));

        // Test build_shader_with_sky
        let sky = ProceduralSky::new()
            .sun_direction([0.123, 0.456, 0.881])  // Use decimals to ensure they appear in output
            .horizon_color([0.987, 0.654, 0.321]);
        let shader2 = MissShaderDescBuilder::new()
            .procedural_sky()
            .build_shader_with_sky(sky)
            .expect("Build with sky should succeed");
        assert!(shader2.contains("0.123")); // sun direction x
        assert!(shader2.contains("0.456")); // sun direction y
        assert!(shader2.contains("0.881")); // sun direction z (approximately normalized)
        assert!(shader2.contains("0.987")); // horizon color r
        assert!(shader2.contains("0.654")); // horizon color g
        assert!(shader2.contains("0.321")); // horizon color b

        // Test invalid entry point fails
        let result = MissShaderDescBuilder::new()
            .entry_point("")
            .build();
        assert!(result.is_err());
    }

    // Test 8: Complete shader output verification
    #[test]
    fn test_miss_shader_complete_output() {
        // Generate a fully configured shader
        let sky = ProceduralSky::new()
            .sun_direction([0.0, 0.707, 0.707])
            .horizon_color([0.8, 0.7, 0.6])
            .zenith_color([0.3, 0.5, 0.9]);

        let desc = MissShaderDesc::new()
            .label("pbr_miss")
            .entry_point("pbr_miss_main")
            .miss_index(0)
            .env_source(EnvironmentSource::ProceduralSky);

        let generator = MissWgslGenerator::new(desc)
            .with_procedural_sky(sky);
        let shader = generator.generate_complete_shader();

        // Verify all major components are present

        // 1. Header with task marker
        assert!(shader.contains("T-WGPU-P5.7.6: Miss Shader Stage"));
        assert!(shader.contains("Entry point: pbr_miss_main"));
        assert!(shader.contains("Miss index: 0"));
        assert!(shader.contains("Environment source: ProceduralSky"));

        // 2. @miss attribute conceptual entry point
        assert!(shader.contains("fn pbr_miss_main"));
        assert!(shader.contains("@miss attribute (conceptual"));

        // 3. Miss payload structure
        assert!(shader.contains("struct MissPayload"));
        assert!(shader.contains("depth: f32"));
        assert!(shader.contains("-1.0"));

        // 4. HitPayload reuse
        assert!(shader.contains("struct HitPayload"));

        // 5. Procedural sky components
        assert!(shader.contains("compute_sky_color"));
        assert!(shader.contains("SKY_SUN_DIRECTION"));
        assert!(shader.contains("SKY_HORIZON_COLOR"));
        assert!(shader.contains("SKY_ZENITH_COLOR"));

        // 6. Scattering functions
        assert!(shader.contains("rayleigh_phase"));
        assert!(shader.contains("mie_phase"));
        assert!(shader.contains("Henyey-Greenstein"));

        // 7. Payload write
        assert!(shader.contains("(*payload).color"));
        assert!(shader.contains("(*payload).depth = -1.0"));
        assert!(shader.contains("(*payload).hit_kind = 0xFFFFFFFFu"));

        // 8. Ray query integration
        assert!(shader.contains("fn process_miss"));
        assert!(shader.contains("COMMITTED_NOTHING"));
        assert!(shader.contains("rayQueryGetCommittedIntersectionType"));
        assert!(shader.contains("rayQueryGetWorldRayDirection"));

        // 9. PI constant
        assert!(shader.contains("const PI: f32 = 3.14159"));

        // 10. Custom sky parameters embedded
        assert!(shader.contains("0.8, 0.7, 0.6")); // horizon color
        assert!(shader.contains("0.3, 0.5, 0.9")); // zenith color
    }

    // Test 9: Error display
    #[test]
    fn test_miss_shader_error_display() {
        let err1 = MissShaderError::InvalidEntryPoint;
        assert!(format!("{}", err1).contains("Invalid entry point"));

        let err2 = MissShaderError::InvalidMissIndex(5, "out of bounds".to_string());
        assert!(format!("{}", err2).contains("5"));
        assert!(format!("{}", err2).contains("out of bounds"));

        let err3 = MissShaderError::DuplicateMissIndex(2);
        assert!(format!("{}", err3).contains("Duplicate"));
        assert!(format!("{}", err3).contains("2"));

        let err4 = MissShaderError::MissingDefaultMissShader;
        assert!(format!("{}", err4).contains("Missing default"));
        assert!(format!("{}", err4).contains("index 0"));

        let err5 = MissShaderError::NonContiguousIndices(vec![0, 2, 3]);
        assert!(format!("{}", err5).contains("contiguous"));
        assert!(format!("{}", err5).contains("[0, 2, 3]"));

        let err6 = MissShaderError::InvalidEnvironmentTexture("missing".to_string());
        assert!(format!("{}", err6).contains("environment texture"));
        assert!(format!("{}", err6).contains("missing"));

        let err7 = MissShaderError::InvalidSkyParameters("bad sun".to_string());
        assert!(format!("{}", err7).contains("sky parameters"));
        assert!(format!("{}", err7).contains("bad sun"));
    }

