        // Test GGX BRDF
        let ggx = BrdfCallable::generate_ggx();
        assert!(ggx.contains("ggx_distribution"));
        assert!(ggx.contains("geometry_schlick_ggx"));
        assert!(ggx.contains("geometry_smith"));
        assert!(ggx.contains("fresnel_schlick"));
        assert!(ggx.contains("callable_brdf_ggx"));
        assert!(ggx.contains("Cook-Torrance"));

        // Test Disney BRDF
        let disney = BrdfCallable::generate_disney();
        assert!(disney.contains("callable_brdf_disney"));
        assert!(disney.contains("fd90"));
        assert!(disney.contains("diffuse"));
